import { expect, test } from '@playwright/test';

test.describe('Signed QR to guest order flow', () => {
    test('validates signed QR context and submits guest order', async ({ page }) => {
        const slug = 'saba-grill';
        const table = 'T1';
        const sig = 'abcdef1234567890';
        const exp = String(Date.now() + 60 * 60 * 1000);

        let capturedOrderPayload: any = null;

        await page.route('**/api/guest/context**', async route => {
            const url = new URL(route.request().url());
            expect(url.searchParams.get('slug')).toBe(slug);
            expect(url.searchParams.get('table')).toBe(table);
            expect(url.searchParams.get('sig')).toBe(sig);
            expect(url.searchParams.get('exp')).toBe(exp);

            await route.fulfill({
                status: 200,
                contentType: 'application/json',
                body: JSON.stringify({
                    data: {
                        restaurant_id: 'rest-1',
                        table_id: 'table-1',
                        table_number: table,
                        slug,
                        sig,
                        exp: Number(exp),
                    },
                }),
            });
        });

        await page.route('**/rest/v1/categories**', async route => {
            await route.fulfill({
                status: 200,
                contentType: 'application/json',
                body: JSON.stringify([{ id: 'cat-1', name: 'Burgers', section: 'food' }]),
            });
        });

        await page.route('**/rest/v1/menu_items**', async route => {
            await route.fulfill({
                status: 200,
                contentType: 'application/json',
                body: JSON.stringify([
                    {
                        id: '11111111-1111-4111-8111-111111111111',
                        name: 'Scan Burger',
                        price: 299,
                        image_url: null,
                        rating: 4.8,
                        preparation_time: 12,
                        description: 'Guest E2E burger',
                        description_am: null,
                        popularity: 90,
                        likes_count: 20,
                        category_id: 'cat-1',
                    },
                ]),
            });
        });

        await page.route('**/api/payments/sessions', async route => {
            capturedOrderPayload = route.request().postDataJSON();
            await route.fulfill({
                status: 200,
                contentType: 'application/json',
                body: JSON.stringify({
                    data: {
                        mode: 'deferred',
                        order_id: 'order-guest-1',
                        order_number: 'ORD-2001',
                    },
                }),
            });
        });

        // Mock guest session so auth_state='authenticated' is returned immediately,
        // causing the pre-menu splash screen to auto-dismiss and the menu to load.
        await page.route('**/api/guest/session**', async route => {
            await route.fulfill({
                status: 200,
                contentType: 'application/json',
                body: JSON.stringify({
                    data: {
                        session_id: 'e2e-guest-session-1',
                        auth_state: 'authenticated',
                    },
                }),
            });
        });

        await page.goto(`/${slug}?table=${table}&sig=${sig}&exp=${exp}`);

        // The pre-menu splash may be shown. Try the legacy "Skip to Menu" name first,
        // then fall back to the actual "Continue as guest" button.
        // (The session mock above should auto-dismiss the splash, but guard here too.)
        const skipToMenuButton = page.getByRole('button', { name: 'Skip to Menu' });
        const continueAsGuestButton = page.getByRole('button', { name: /Continue as guest/i });
        if (await skipToMenuButton.isVisible({ timeout: 3000 }).catch(() => false)) {
            await skipToMenuButton.click();
        } else if (await continueAsGuestButton.isVisible({ timeout: 3000 }).catch(() => false)) {
            await continueAsGuestButton.click();
        }
        // Wait for menu items to load after context is established
        await page.waitForLoadState('networkidle', { timeout: 15000 }).catch(() => undefined);

        await expect(page.getByText('Scan Burger')).toBeVisible({ timeout: 15000 });

        await page.getByText('Scan Burger').first().click();
        await page.getByRole('button', { name: 'Add to Order' }).click();

        await expect(page.locator('button.fixed.right-6.bottom-6')).toBeVisible();
        await page.locator('button.fixed.right-6.bottom-6').click();

        await expect(page.getByRole('heading', { name: 'Your Order', exact: true })).toBeVisible();
        await page.getByRole('button', { name: /Choose checkout option/i }).click();

        await expect(
            page.getByRole('heading', { name: 'Payment Method', exact: true })
        ).toBeVisible();
        await page.getByRole('button', { name: 'Order and pay later', exact: true }).click();

        await expect(page.getByRole('heading', { name: 'Order Placed!', exact: true })).toBeVisible(
            { timeout: 5000 }
        );
        await expect(page.getByText(/Your order has been sent to the kitchen/i)).toBeVisible();

        expect(capturedOrderPayload).toBeTruthy();
        expect(capturedOrderPayload.guest_context).toEqual({
            slug,
            table,
            sig,
            exp: Number(exp),
        });
        expect(capturedOrderPayload.items).toHaveLength(1);
        expect(capturedOrderPayload.items[0]).toMatchObject({
            id: '11111111-1111-4111-8111-111111111111',
            name: 'Scan Burger',
            quantity: 1,
            price: 299,
        });
    });
});

