/**
 * Gebeta Peak-Flow Load Tests
 *
 * Tests critical API endpoints under load to validate SLO compliance.
 *
 * SLO Targets:
 * - GET /api/merchant/command-center: P95 <= 500ms, error < 1%
 * - GET /api/orders: P95 <= 400ms, error < 1%
 * - PATCH /api/orders/:id/status: P95 <= 300ms, error < 0.5%
 *
 * Usage:
 *   k6 run k6/peak-flow-scenarios.js
 *
 * Environment Variables:
 *   K6_BASE_URL - Base URL for the API (default: http://localhost:3000)
 *   K6_AUTH_TOKEN - Bearer token for authentication
 *   K6_USE_BYPASS_AUTH - Set to "true" to use x-e2e-bypass-auth header
 *   K6_ORDER_ID - Valid order ID for status update tests
 */

import http from 'k6/http';
import { check, sleep } from 'k6';
import { Rate, Trend } from 'k6/metrics';

// Custom metrics
const commandCenterLatency = new Trend('command_center_latency');
const ordersLatency = new Trend('orders_latency');
const orderStatusLatency = new Trend('order_status_latency');
const errorRate = new Rate('error_rate');

// Configuration
const BASE_URL = __ENV.K6_BASE_URL || 'http://localhost:3000';
const AUTH_TOKEN = __ENV.K6_AUTH_TOKEN || '';
const USE_BYPASS_AUTH = __ENV.K6_USE_BYPASS_AUTH === 'true';
const ORDER_ID = __ENV.K6_ORDER_ID || 'test-order-id';

// Default headers
function getHeaders() {
    const headers = {
        'Content-Type': 'application/json',
    };

    if (USE_BYPASS_AUTH) {
        headers['x-e2e-bypass-auth'] = '1';
    } else if (AUTH_TOKEN) {
        headers['Authorization'] = `Bearer ${AUTH_TOKEN}`;
    }

    return headers;
}

// Test scenarios
export const options = {
    scenarios: {
        // Command center load test
        command_center: {
            executor: 'ramping-vus',
            startVUs: 0,
            stages: [
                { duration: '30s', target: 20 }, // Ramp up to 20 users
                { duration: '1m', target: 20 }, // Hold at 20 users
                { duration: '30s', target: 0 }, // Ramp down
            ],
            gracefulRampDown: '30s',
            exec: 'testCommandCenter',
        },
        // Orders list load test
        orders_list: {
            executor: 'ramping-vus',
            startVUs: 0,
            stages: [
                { duration: '30s', target: 25 }, // Ramp up to 25 users
                { duration: '1m', target: 25 }, // Hold at 25 users
                { duration: '30s', target: 0 }, // Ramp down
            ],
            gracefulRampDown: '30s',
            exec: 'testOrdersList',
        },
        // Order status update load test
        order_status_update: {
            executor: 'ramping-vus',
            startVUs: 0,
            stages: [
                { duration: '30s', target: 15 }, // Ramp up to 15 users
                { duration: '1m', target: 15 }, // Hold at 15 users
                { duration: '30s', target: 0 }, // Ramp down
            ],
            gracefulRampDown: '30s',
            exec: 'testOrderStatusUpdate',
        },
    },

    // Thresholds based on SLOs
    thresholds: {
        // Command center: P95 <= 500ms, error < 1%
        command_center_latency: ['p(95)<=500'],
        command_center_errors: ['rate<0.01'],

        // Orders list: P95 <= 400ms, error < 1%
        orders_latency: ['p(95)<=400'],
        orders_errors: ['rate<0.01'],

        // Order status update: P95 <= 300ms, error < 0.5%
        order_status_latency: ['p(95)<=300'],
        order_status_errors: ['rate<0.005'],

        // Global error rate
        error_rate: ['rate<0.01'],
    },

    // Setup and teardown
    setup: () => {
        console.log(`Starting load tests against: ${BASE_URL}`);
        console.log(`Using bypass auth: ${USE_BYPASS_AUTH}`);
        console.log(`Using bearer token: ${!!AUTH_TOKEN}`);
    },
};

// Test: GET /api/merchant/command-center
export function testCommandCenter() {
    const url = `${BASE_URL}/api/merchant/command-center?range=today`;
    const params = { headers: getHeaders() };

    const res = http.get(url, params);

    // Track latency
    commandCenterLatency.add(res.timings.duration);

    // Check response
    const success = check(res, {
        'command_center status is 200': r => r.status === 200,
        'command_center response time < 500ms': r => r.timings.duration < 500,
    });

    // Track errors
    if (!success) {
        errorRate.add(1);
    } else {
        errorRate.add(0);
    }

    sleep(1);
}

// Test: GET /api/orders
export function testOrdersList() {
    const url = `${BASE_URL}/api/orders`;
    const params = { headers: getHeaders() };

    const res = http.get(url, params);

    // Track latency
    ordersLatency.add(res.timings.duration);

    // Check response
    const success = check(res, {
        'orders status is 200': r => r.status === 200,
        'orders response time < 400ms': r => r.timings.duration < 400,
    });

    // Track errors
    if (!success) {
        errorRate.add(1);
    } else {
        errorRate.add(0);
    }

    sleep(1);
}

// Test: PATCH /api/orders/:id/status
export function testOrderStatusUpdate() {
    const url = `${BASE_URL}/api/orders/${ORDER_ID}/status`;
    const params = {
        headers: getHeaders(),
    };

    const payload = JSON.stringify({
        status: 'preparing',
    });

    const res = http.patch(url, payload, params);

    // Track latency
    orderStatusLatency.add(res.timings.duration);

    // Check response (allow 404 for non-existent order, but still measure latency)
    const _success = check(res, {
        'order_status status is 2xx or 404': r => r.status >= 200 && r.status < 500,
        'order_status response time < 300ms': r => r.timings.duration < 300,
    });

    // Track errors (only count 5xx as errors, not 404 for test orders)
    if (res.status >= 500) {
        errorRate.add(1);
    } else {
        errorRate.add(0);
    }

    sleep(1);
}

// Teardown
export function teardown() {
    console.log('Load tests completed');
}

#!/usr/bin/env node
/**
 * Generate CSS Custom Properties from design/tokens.json
 *
 * This script reads the canonical design tokens from design/tokens.json
 * and generates CSS custom properties for use in globals.css.
 *
 * Usage: node scripts/generate-css-tokens.mjs
 *
 * The output is written to stdout and can be piped into a CSS file or
 * copied manually to globals.css.
 */

import { readFileSync } from 'fs';
import { join } from 'path';
import { fileURLToPath } from 'url';
import { dirname } from 'path';

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

// Read tokens from JSON file
const tokensPath = join(__dirname, '../design/tokens.json');
const tokens = JSON.parse(readFileSync(tokensPath, 'utf-8'));

/**
 * Convert a token path to a CSS custom property name
 * e.g., { "color": { "bg": { "surface": { "0": ... } } } } => --color-bg-surface-0
 */
function pathToCssName(path) {
    return path.join('-').toLowerCase();
}

/**
 * Flatten nested token object into an array of [path, value] pairs
 */
function flattenTokens(obj, path = []) {
    const result = [];

    for (const [key, value] of Object.entries(obj)) {
        const currentPath = [...path, key];

        // Check if this is a leaf node with a $value property (Design Tokens Format)
        if (value && typeof value === 'object') {
            if ('$value' in value) {
                // This is a token value
                result.push([currentPath, value.$value]);
            } else {
                // Recurse into nested object
                result.push(...flattenTokens(value, currentPath));
            }
        }
    }

    return result;
}

/**
 * Generate CSS custom property declaration
 */
function generateCssProperty(path, value) {
    const name = pathToCssName(path);
    return `    --${name}: ${value};`;
}

/**
 * Generate all CSS custom properties from tokens
 */
function generateCss() {
    const flatTokens = flattenTokens(tokens);

    // Group tokens by category for better organization
    const categories = {
        color: [],
        typography: [],
        spacing: [],
        'border-radius': [],
        shadow: [],
        breakpoint: [],
        transition: [],
        'z-index': [],
    };

    const uncategorized = [];

    for (const [path, value] of flatTokens) {
        const category = path[0];
        if (categories[category]) {
            categories[category].push([path, value]);
        } else {
            uncategorized.push([path, value]);
        }
    }

    let output = `/**
 * DESIGN TOKENS - AUTO-GENERATED
 * Source: design/tokens.json
 * Generated: ${new Date().toISOString()}
 *
 * DO NOT EDIT DIRECTLY - Update design/tokens.json and re-run:
 * node scripts/generate-css-tokens.mjs
 */

:root {
`;

    // Generate each category
    for (const [categoryName, tokens] of Object.entries(categories)) {
        if (tokens.length === 0) continue;

        output += `\n    /* ═══════════════════════════════════════════════════════════════\n`;
        output += `     * ${categoryName.toUpperCase()}\n`;
        output += `     * ═══════════════════════════════════════════════════════════════ */\n`;

        for (const [path, value] of tokens) {
            output += generateCssProperty(path, value) + '\n';
        }
    }

    // Add uncategorized tokens
    if (uncategorized.length > 0) {
        output += `\n    /* ═══════════════════════════════════════════════════════════════\n`;
        output += `     * OTHER\n`;
        output += `     * ═══════════════════════════════════════════════════════════════ */\n`;

        for (const [path, value] of uncategorized) {
            output += generateCssProperty(path, value) + '\n';
        }
    }

    output += `}\n`;

    return output;
}

// Run the generator
console.log(generateCss());

#!/usr/bin/env node
/* eslint-disable @typescript-eslint/no-require-imports */
const sharp = require('sharp');
const fs = require('fs');
const path = require('path');

const args = process.argv.slice(2);

if (args.length < 1) {
    console.error('Usage: node scripts/optimize-image.js <input-path> [output-path] [--base64]');
    console.error('Example: node scripts/optimize-image.js public/splash-bg.webp --base64');
    process.exit(1);
}

const inputPath = path.resolve(args[0]);
let outputPath =
    args[1] && !args[1].startsWith('--')
        ? path.resolve(args[1])
        : path.resolve(path.dirname(inputPath), path.parse(inputPath).name + '-opt.webp');

const generateBase64 = args.includes('--base64');

if (!fs.existsSync(inputPath)) {
    console.error(`Error: File not found at ${inputPath}`);
    process.exit(1);
}

async function optimizeImage() {
    try {
        console.log(`Optimizing: ${inputPath}`);

        const originalSize = fs.statSync(inputPath).size;

        // This process maintains aspect ratio and limits width to 750px (Retina mobile width)
        const optimized = await sharp(inputPath)
            .resize({ width: 750, withoutEnlargement: true })
            .webp({ quality: 65, effort: 6 })
            .toFile(outputPath);

        console.log(`\n✅ Successfully optimized image!`);
        console.log(`- Original Size: ${(originalSize / 1024).toFixed(2)} KB`);
        console.log(`- New Size: ${(optimized.size / 1024).toFixed(2)} KB`);
        console.log(`- Saved to: ${outputPath}`);

        if (generateBase64) {
            const b64 = fs.readFileSync(outputPath).toString('base64');
            const dataUri = `data:image/webp;base64,${b64}`;

            const b64Path = outputPath.replace('.webp', '-base64.txt');
            fs.writeFileSync(b64Path, dataUri, 'utf8');
            console.log(`- Base64 String saved to: ${b64Path}\n`);
        }
    } catch (error) {
        console.error('❌ Optimization failed:', error);
        process.exit(1);
    }
}

optimizeImage();

#!/usr/bin/env node
/**
 * Gebeta Restaurant OS - Deprecated Dependencies Checker
 *
 * This script checks for deprecated packages in the dependency tree
 * by analyzing the pnpm-lock.yaml file and running pnpm list.
 *
 * Usage: node scripts/security/check-deprecated.mjs
 *
 * Exit codes:
 * 0 - No deprecated packages found
 * 1 - Deprecated packages found (warning)
 * 2 - Critical error
 */

import { execSync } from 'child_process';
import { readFileSync, existsSync } from 'fs';
import { join } from 'path';

const ROOT_DIR = process.cwd();

// ANSI color codes
const colors = {
    reset: '\x1b[0m',
    red: '\x1b[31m',
    yellow: '\x1b[33m',
    green: '\x1b[32m',
    cyan: '\x1b[36m',
    dim: '\x1b[2m',
};

function log(message, color = 'reset') {
    console.log(`${colors[color]}${message}${colors.reset}`);
}

function getDeprecatedPackagesFromLockfile() {
    const lockfilePath = join(ROOT_DIR, 'pnpm-lock.yaml');

    if (!existsSync(lockfilePath)) {
        log('⚠️  pnpm-lock.yaml not found', 'yellow');
        return [];
    }

    try {
        // Use pnpm list to find deprecated packages
        const output = execSync('pnpm list --depth=Infinity --json 2>/dev/null', {
            encoding: 'utf-8',
            maxBuffer: 50 * 1024 * 1024, // 50MB buffer for large projects
        });

        const packages = JSON.parse(output);
        const deprecated = [];

        function findDeprecated(deps, path = '') {
            if (!deps) return;

            for (const [name, info] of Object.entries(deps)) {
                if (info.deprecated) {
                    deprecated.push({
                        name,
                        version: info.version,
                        reason: info.deprecated,
                        path: path ? `${path} > ${name}` : name,
                    });
                }

                if (info.dependencies) {
                    findDeprecated(info.dependencies, path ? `${path} > ${name}` : name);
                }
            }
        }

        if (Array.isArray(packages)) {
            for (const pkg of packages) {
                if (pkg.dependencies) {
                    findDeprecated(pkg.dependencies, pkg.name);
                }
            }
        } else {
            findDeprecated(packages.dependencies);
        }

        return deprecated;
    } catch (_error) {
        // If pnpm list fails, try alternative method
        return getDeprecatedFromPnpmWhy();
    }
}

function getDeprecatedFromPnpmWhy() {
    try {
        // Run pnpm install to see deprecation warnings
        const output = execSync('pnpm install --dry-run 2>&1', {
            encoding: 'utf-8',
            maxBuffer: 10 * 1024 * 1024,
        });

        const deprecatedMatches = output.matchAll(/deprecated.*?:\s*(.+)/gi);
        const deprecated = [];

        for (const match of deprecatedMatches) {
            deprecated.push({
                name: 'unknown',
                version: 'unknown',
                reason: match[1],
                path: 'unknown',
            });
        }

        return deprecated;
    } catch (_error) {
        return [];
    }
}

function checkPackageJsonForDeprecated() {
    const packageJsonPath = join(ROOT_DIR, 'package.json');

    if (!existsSync(packageJsonPath)) {
        return { deprecated: [], warnings: [] };
    }

    const packageJson = JSON.parse(readFileSync(packageJsonPath, 'utf-8'));
    const warnings = [];

    // Check for known deprecated packages
    const knownDeprecated = [
        { name: 'request', reason: 'Deprecated - use node-fetch, axios, or got instead' },
        { name: 'node-uuid', reason: 'Deprecated - use uuid instead' },
        { name: 'uuid', reason: 'Version < 3.4.0 has security issues', minVersion: '3.4.0' },
        { name: 'colors', reason: 'Deprecated - use chalk or kleur instead' },
        { name: 'mkdirp', reason: 'Deprecated - use fs.mkdir with recursive: true' },
        { name: 'left-pad', reason: 'Deprecated - use String.prototype.padStart' },
        { name: 'core-js@2', reason: 'Deprecated - use core-js@3 for polyfills' },
        { name: 'babel-eslint', reason: 'Deprecated - use @babel/eslint-parser' },
        { name: 'eslint-plugin-node', reason: 'Deprecated - use eslint-plugin-n' },
        { name: 'npm', reason: 'Do not bundle npm as dependency' },
        { name: 'jquery', reason: 'Consider using modern alternatives for new projects' },
    ];

    const allDeps = {
        ...packageJson.dependencies,
        ...packageJson.devDependencies,
    };

    const deprecated = [];

    for (const [name, version] of Object.entries(allDeps)) {
        const known = knownDeprecated.find(d => name === d.name || name.startsWith(d.name + '@'));
        if (known) {
            deprecated.push({
                name,
                version,
                reason: known.reason,
                path: 'package.json (direct dependency)',
            });
        }
    }

    return { deprecated, warnings };
}

function main() {
    log('\n📦 Gebeta Restaurant OS - Deprecated Dependencies Check\n', 'cyan');

    let _hasWarnings = false;
    let _hasErrors = false;

    // Check package.json for known deprecated packages
    log('Checking package.json for known deprecated packages...', 'cyan');
    const { deprecated: directDeprecated } = checkPackageJsonForDeprecated();

    if (directDeprecated.length > 0) {
        _hasWarnings = true;
        log('\n⚠️  Deprecated packages found in package.json:\n', 'yellow');
        for (const pkg of directDeprecated) {
            log(`  • ${pkg.name}@${pkg.version}`, 'yellow');
            log(`    Reason: ${pkg.reason}`, 'dim');
            log(`    Path: ${pkg.path}\n`, 'dim');
        }
    } else {
        log('✅ No deprecated packages in package.json\n', 'green');
    }

    // Check for deprecated transitive dependencies
    log('Checking for deprecated transitive dependencies...', 'cyan');
    const transitiveDeprecated = getDeprecatedPackagesFromLockfile();

    if (transitiveDeprecated.length > 0) {
        _hasWarnings = true;
        log('\n⚠️  Deprecated transitive dependencies found:\n', 'yellow');
        for (const pkg of transitiveDeprecated.slice(0, 20)) {
            // Limit output
            log(`  • ${pkg.name}@${pkg.version}`, 'yellow');
            log(`    Reason: ${pkg.reason}`, 'dim');
            log(`    Path: ${pkg.path}\n`, 'dim');
        }
        if (transitiveDeprecated.length > 20) {
            log(`  ... and ${transitiveDeprecated.length - 20} more\n`, 'dim');
        }
    } else {
        log('✅ No deprecated transitive dependencies found\n', 'green');
    }

    // Summary
    log('━'.repeat(50), 'dim');
    const totalDeprecated = directDeprecated.length + transitiveDeprecated.length;

    if (totalDeprecated === 0) {
        log('✅ All dependencies are up to date!', 'green');
        process.exit(0);
    } else {
        log(`\n⚠️  Found ${totalDeprecated} deprecated package(s)`, 'yellow');
        log('\nRecommended actions:', 'cyan');
        log('  1. Update direct dependencies: pnpm deps:update', 'dim');
        log('  2. For transitive deps, add overrides in package.json:', 'dim');
        log('     "pnpm": { "overrides": { "package-name": "^version" } }', 'dim');
        log('  3. Run: pnpm install to apply changes\n', 'dim');

        // Exit with warning code (not error) for deprecated packages
        process.exit(1);
    }
}

main();

#!/usr/bin/env node
/**
 * Gebeta Restaurant OS - Unused Overrides Checker
 *
 * This script checks for unused pnpm overrides in package.json.
 * Overrides that no longer apply to any dependency should be removed.
 *
 * Usage: node scripts/security/check-unused-overrides.mjs
 *
 * Exit codes:
 * 0 - All overrides are in use
 * 1 - Unused overrides found
 */

import { execSync } from 'child_process';
import { readFileSync, existsSync } from 'fs';
import { join } from 'path';

const ROOT_DIR = process.cwd();

// ANSI color codes
const colors = {
    reset: '\x1b[0m',
    red: '\x1b[31m',
    yellow: '\x1b[33m',
    green: '\x1b[32m',
    cyan: '\x1b[36m',
    dim: '\x1b[2m',
};

function log(message, color = 'reset') {
    console.log(`${colors[color]}${message}${colors.reset}`);
}

function getPackageJson() {
    const packageJsonPath = join(ROOT_DIR, 'package.json');
    if (!existsSync(packageJsonPath)) {
        throw new Error('package.json not found');
    }
    return JSON.parse(readFileSync(packageJsonPath, 'utf-8'));
}

function _getInstalledVersions(packageName) {
    try {
        const output = execSync(`pnpm list ${packageName} --depth=Infinity --json 2>/dev/null`, {
            encoding: 'utf-8',
            maxBuffer: 10 * 1024 * 1024,
        });

        const packages = JSON.parse(output);
        const versions = new Set();

        function extractVersions(deps, depth = 0) {
            if (!deps) return;
            for (const [name, info] of Object.entries(deps)) {
                if (name === packageName || name.startsWith(packageName + '@')) {
                    versions.add(info.version);
                }
                if (info.dependencies) {
                    extractVersions(info.dependencies, depth + 1);
                }
            }
        }

        if (Array.isArray(packages)) {
            for (const pkg of packages) {
                extractVersions(pkg.dependencies);
            }
        } else {
            extractVersions(packages.dependencies);
        }

        return Array.from(versions);
    } catch (_error) {
        return [];
    }
}

function parseOverrideKey(key) {
    // Handle patterns like "minimatch@<3.1.3" or "minimatch@>=5.0.0 <5.1.7"
    const match = key.match(/^(@?[^@]+)@?(.*)$/);
    if (match) {
        return {
            packageName: match[1],
            versionRange: match[2] || '*',
        };
    }
    return { packageName: key, versionRange: '*' };
}

function checkOverrideInUse(overrideKey, _overrideValue) {
    const { packageName, versionRange: _versionRange } = parseOverrideKey(overrideKey);

    // Check if the package exists in the dependency tree
    try {
        const output = execSync(`pnpm why ${packageName} --json 2>/dev/null`, {
            encoding: 'utf-8',
            maxBuffer: 10 * 1024 * 1024,
        });

        if (output.includes(packageName)) {
            return { inUse: true, reason: 'Package found in dependency tree' };
        }
    } catch (_error) {
        // pnpm why failed - package might not be installed
    }

    // Check if it's a direct dependency
    const packageJson = getPackageJson();
    const allDeps = {
        ...packageJson.dependencies,
        ...packageJson.devDependencies,
    };

    if (allDeps[packageName]) {
        return { inUse: true, reason: 'Direct dependency' };
    }

    return { inUse: false, reason: 'Package not found in dependency tree' };
}

function main() {
    log('\n📦 Gebeta Restaurant OS - Unused Overrides Checker\n', 'cyan');

    const packageJson = getPackageJson();
    const overrides = packageJson.pnpm?.overrides || {};

    if (Object.keys(overrides).length === 0) {
        log('✅ No overrides defined in package.json\n', 'green');
        process.exit(0);
    }

    log(`Checking ${Object.keys(overrides).length} override(s)...\n`, 'cyan');

    const unusedOverrides = [];
    const usedOverrides = [];

    for (const [key, value] of Object.entries(overrides)) {
        const result = checkOverrideInUse(key, value);

        if (result.inUse) {
            usedOverrides.push({ key, value, reason: result.reason });
            log(`  ✅ ${key} -> ${value}`, 'green');
            log(`     ${result.reason}`, 'dim');
        } else {
            unusedOverrides.push({ key, value, reason: result.reason });
            log(`  ⚠️  ${key} -> ${value}`, 'yellow');
            log(`     ${result.reason}`, 'dim');
        }
    }

    // Summary
    log('\n' + '━'.repeat(50), 'dim');

    if (unusedOverrides.length === 0) {
        log(`\n✅ All ${usedOverrides.length} override(s) are in use!`, 'green');
        process.exit(0);
    } else {
        log(`\n⚠️  Found ${unusedOverrides.length} unused override(s):`, 'yellow');
        for (const { key, value } of unusedOverrides) {
            log(`  • ${key}: "${value}"`, 'yellow');
        }

        log('\nRecommended action:', 'cyan');
        log('Remove unused overrides from package.json:', 'dim');
        log('"pnpm": { "overrides": { ... } }', 'dim');
        log('\nNote: Some overrides may be intentionally kept for:', 'dim');
        log('  - Security patches for future versions', 'dim');
        log('  - Known vulnerable version ranges', 'dim');
        log('  - Compatibility fixes\n', 'dim');

        process.exit(1);
    }
}

main();

#!/usr/bin/env node
import { spawnSync } from 'node:child_process';
import { existsSync } from 'node:fs';
import { join } from 'node:path';

function run(command, args, options = {}) {
    const result = spawnSync(command, args, {
        stdio: 'inherit',
        shell: false,
        ...options,
    });
    if (result.status !== 0) {
        process.exit(result.status ?? 1);
    }
}

function commandExists(command) {
    const checker = process.platform === 'win32' ? 'where' : 'which';
    const result = spawnSync(checker, [command], { stdio: 'ignore' });
    return result.status === 0;
}

function resolveTrivy() {
    if (commandExists('trivy')) return { command: 'trivy', argsPrefix: [] };

    const localAppData = process.env.LOCALAPPDATA;
    if (localAppData) {
        const wingetPath = join(
            localAppData,
            'Microsoft',
            'WinGet',
            'Packages',
            'AquaSecurity.Trivy_Microsoft.Winget.Source_8wekyb3d8bbwe',
            'trivy.exe'
        );
        if (existsSync(wingetPath)) {
            return { command: wingetPath, argsPrefix: [] };
        }
    }

    return null;
}

function resolveGgshield() {
    if (commandExists('ggshield')) return { command: 'ggshield', argsPrefix: [] };
    if (commandExists('python')) return { command: 'python', argsPrefix: ['-m', 'ggshield'] };
    return null;
}

console.log('Running GitGuardian secret scan (ggshield)...');
const gg = resolveGgshield();
if (!gg) {
    console.error(
        'ggshield is not installed or not on PATH. Install with: python -m pip install --user ggshield'
    );
    process.exit(1);
}
run(gg.command, [...gg.argsPrefix, 'secret', 'scan', 'pre-commit']);

console.log('Running Trivy vulnerability scan...');
