                            ) : (
                                <p className="text-xs font-semibold text-gray-400 italic">
                                    No zones created yet.
                                </p>
                            )}
                        </div>

                        <div className="relative flex gap-2">
                            <input
                                value={newZoneName}
                                onChange={e => setNewZoneName(e.target.value)}
