                                    if (e.key === 'Enter') {
                                        e.preventDefault();
                                        if (!newZoneName.trim()) return;
                                        const next = [...availableZones, newZoneName.trim()];
                                        setAvailableZones(next);
                                        setNewZoneName('');
                                        await fetch('/api/restaurants/zones', {
