            {
                created_at: '2026-02-17T10:00:00.000Z',
                metadata: {
                    endpoint: '/api/orders',
                    duration_ms: 120,
                    is_error: false,
                },
            },
            {
                created_at: '2026-02-17T10:05:00.000Z',
                metadata: {
                    endpoint: '/api/orders',
                    duration_ms: 480,
                    is_error: true,
                },
            },
            {
                created_at: '2026-02-17T10:10:00.000Z',
                metadata: {
                    endpoint: '/api/orders',
                    duration_ms: 320,
                    is_error: false,
                },
            },
