                    body: JSON.stringify({ action: 'start' }),
                }
            ),
            { params: Promise.resolve({ kdsItemId: 'aaaaaaaa-aaaa-4aaa-8aaa-aaaaaaaaaaaa' }) }
        );

        expect(response.status).toBe(401);
    });

