import { z } from 'zod';
import { apiError, apiSuccess } from '@/lib/api/response';
import { getAuthenticatedUser, getAuthorizedRestaurantContext } from '@/lib/api/authz';
import { parseJsonBody } from '@/lib/api/validation';
import { writeAuditLog } from '@/lib/api/audit';
import { isIdempotencyKeyValid, resolveIdempotencyKey } from '@/lib/api/idempotency';
import type { Json } from '@/types/database';

const RuleIdSchema = z.string().uuid();

const AlertRulePatchSchema = z
    .object({
        name: z.string().trim().min(2).max(120).optional(),
        severity: z.enum(['low', 'medium', 'high', 'critical']).optional(),
        enabled: z.boolean().optional(),
        condition_json: z.record(z.string(), z.unknown()).optional(),
        target_json: z.record(z.string(), z.unknown()).optional(),
    })
    .refine(value => Object.keys(value).length > 0, {
        message: 'At least one field is required',
    });

export async function PATCH(
    request: Request,
    routeContext: { params: Promise<{ ruleId: string }> }
) {
    const auth = await getAuthenticatedUser();
    if (!auth.ok) {
        return auth.response;
    }

    const context = await getAuthorizedRestaurantContext(auth.user.id, { phase: 'p1' });
    if (!context.ok) {
        return context.response;
    }

    const explicitIdempotencyKey = request.headers.get('x-idempotency-key');
    if (explicitIdempotencyKey && !isIdempotencyKeyValid(explicitIdempotencyKey)) {
        return apiError('Invalid idempotency key', 400, 'INVALID_IDEMPOTENCY_KEY');
    }
    const idempotencyKey = resolveIdempotencyKey(explicitIdempotencyKey);

    const parsedBody = await parseJsonBody(request, AlertRulePatchSchema);
    if (!parsedBody.success) {
        return parsedBody.response;
    }

    const { ruleId } = await routeContext.params;
    const parsedRuleId = RuleIdSchema.safeParse(ruleId);
    if (!parsedRuleId.success) {
        return apiError(
            'Invalid alert rule id',
            400,
            'INVALID_ALERT_RULE_ID',
            parsedRuleId.error.flatten()
        );
    }

    const { data: existing, error: fetchError } = await context.supabase
        .from('alert_rules')
        .select('id, name, severity, enabled, condition_json, target_json')
        .eq('id', parsedRuleId.data)
        .eq('restaurant_id', context.restaurantId)
        .maybeSingle();

    if (fetchError) {
        return apiError(
            'Failed to load alert rule',
            500,
            'ALERT_RULE_FETCH_FAILED',
            fetchError.message
        );
    }
    if (!existing) {
        return apiError('Alert rule not found', 404, 'ALERT_RULE_NOT_FOUND');
    }

    const updatePayload = {
        ...parsedBody.data,
        condition_json: parsedBody.data.condition_json as Json | undefined,
        target_json: parsedBody.data.target_json as Json | undefined,
    };

    const { data: updated, error: updateError } = await context.supabase
        .from('alert_rules')
        .update(updatePayload)
        .eq('id', parsedRuleId.data)
        .eq('restaurant_id', context.restaurantId)
        .select('*')
        .single();

    if (updateError) {
        return apiError(
            'Failed to update alert rule',
            500,
            'ALERT_RULE_UPDATE_FAILED',
            updateError.message
        );
    }

    await writeAuditLog(context.supabase, {
        restaurant_id: context.restaurantId,
        user_id: auth.user.id,
        action: 'alert_rule_updated',
        entity_type: 'alert_rule',
        entity_id: updated.id,
        old_value: existing as any,
        new_value: updated as any,
        metadata: {
            source: 'merchant_dashboard',
            idempotency_key: idempotencyKey,
        },
    });

    return apiSuccess({ rule: updated, idempotency_key: idempotencyKey });
}

import { z } from 'zod';
import { apiError, apiSuccess } from '@/lib/api/response';
import { getAuthenticatedUser, getAuthorizedRestaurantContext } from '@/lib/api/authz';
import { parseJsonBody } from '@/lib/api/validation';
import { writeAuditLog } from '@/lib/api/audit';
import { isIdempotencyKeyValid, resolveIdempotencyKey } from '@/lib/api/idempotency';
import type { Json } from '@/types/database';

const AlertRuleSchema = z.object({
    name: z.string().trim().min(2).max(120),
    severity: z.enum(['low', 'medium', 'high', 'critical']),
    enabled: z.boolean().optional(),
    condition_json: z.record(z.string(), z.unknown()),
    target_json: z.record(z.string(), z.unknown()).optional(),
});

export async function GET() {
    const auth = await getAuthenticatedUser();
    if (!auth.ok) {
        return auth.response;
    }

    const context = await getAuthorizedRestaurantContext(auth.user.id, { phase: 'p1' });
    if (!context.ok) {
        return context.response;
    }

    const { data, error } = await context.supabase
        .from('alert_rules')
        .select('id, name, severity, enabled, condition_json, target_json, created_at, updated_at')
        .eq('restaurant_id', context.restaurantId)
        .order('created_at', { ascending: false });

    if (error) {
        return apiError(
            'Failed to fetch alert rules',
            500,
            'ALERT_RULES_FETCH_FAILED',
            error.message
        );
    }

    return apiSuccess({ rules: data ?? [] });
}

export async function POST(request: Request) {
    const auth = await getAuthenticatedUser();
    if (!auth.ok) {
        return auth.response;
    }

    const context = await getAuthorizedRestaurantContext(auth.user.id, { phase: 'p1' });
    if (!context.ok) {
        return context.response;
    }

    const explicitIdempotencyKey = request.headers.get('x-idempotency-key');
    if (explicitIdempotencyKey && !isIdempotencyKeyValid(explicitIdempotencyKey)) {
        return apiError('Invalid idempotency key', 400, 'INVALID_IDEMPOTENCY_KEY');
    }
    const idempotencyKey = resolveIdempotencyKey(explicitIdempotencyKey);

    const parsed = await parseJsonBody(request, AlertRuleSchema);
    if (!parsed.success) {
        return parsed.response;
    }

    const payload = {
        restaurant_id: context.restaurantId,
        name: parsed.data.name,
        severity: parsed.data.severity,
        enabled: parsed.data.enabled ?? true,
        condition_json: parsed.data.condition_json as Json,
        target_json: (parsed.data.target_json ?? {}) as Json,
    };

    const { data: inserted, error: insertError } = await context.supabase
        .from('alert_rules')
        .insert(payload)
        .select('*')
        .single();

    if (insertError) {
        return apiError(
            'Failed to create alert rule',
            500,
            'ALERT_RULE_CREATE_FAILED',
            insertError.message
        );
    }

    await writeAuditLog(context.supabase, {
        restaurant_id: context.restaurantId,
        user_id: auth.user.id,
        action: 'alert_rule_created',
        entity_type: 'alert_rule',
        entity_id: inserted.id,
        metadata: {
            source: 'merchant_dashboard',
            idempotency_key: idempotencyKey,
        },
        new_value: inserted as any,
    });

    return apiSuccess({ rule: inserted, idempotency_key: idempotencyKey }, 201);
}

import { apiError, apiSuccess } from '@/lib/api/response';
import { getAuthenticatedUser, getAuthorizedRestaurantContext } from '@/lib/api/authz';
import {
    getAnalyticsOverview,
    getRangeStart,
    type AnalyticsRange,
} from '@/lib/services/timescaleAnalyticsService';

export async function GET(request: Request) {
    const auth = await getAuthenticatedUser();
    if (!auth.ok) {
        return auth.response;
    }

    const context = await getAuthorizedRestaurantContext(auth.user.id);
    if (!context.ok) {
        return context.response;
    }

    const url = new URL(request.url);
    const rangeParam = (url.searchParams.get('range') as AnalyticsRange) || 'today';
    const since = getRangeStart(rangeParam);

    // Calculate previous period start
    const sinceDate = new Date(since);
    const prevDate = new Date(sinceDate);
    if (rangeParam === 'week') prevDate.setDate(prevDate.getDate() - 7);
    else if (rangeParam === 'month') prevDate.setMonth(prevDate.getMonth() - 1);
    else if (rangeParam === 'year') prevDate.setFullYear(prevDate.getFullYear() - 1);
    else prevDate.setDate(prevDate.getDate() - 1); // Default is today (1 day)

    const prevSince = prevDate.toISOString();

    // Try to get TimescaleDB analytics first (faster for large datasets)
    let timeseriesMetrics: Awaited<ReturnType<typeof getAnalyticsOverview>> | null = null;
    try {
        timeseriesMetrics = await getAnalyticsOverview(
            context.supabase,
            context.restaurantId,
            rangeParam
        );
    } catch (error) {
        console.warn('[analytics/overview] TimescaleDB not available, using direct queries', error);
    }

    // If TimescaleDB has data, use it; otherwise fall back to direct queries
    const useTimeseries = timeseriesMetrics && timeseriesMetrics.total_orders > 0;

    const [ordersRes, prevOrdersRes, requestsRes, tablesRes, reviewsRes] = await Promise.all([
        // Only fetch orders if not using timeseries
        useTimeseries
            ? Promise.resolve({ data: [], error: null })
            : context.supabase
                  .from('orders')
                  .select('id, status, total_price, created_at, order_items(name, quantity, price)')
                  .eq('restaurant_id', context.restaurantId)
                  .gte('created_at', since),
        useTimeseries
            ? Promise.resolve({ count: timeseriesMetrics?.previous_completed_orders || 0 })
            : context.supabase
                  .from('orders')
                  .select('id', { count: 'exact', head: true })
                  .eq('restaurant_id', context.restaurantId)
                  .in('status', ['served', 'completed'])
                  .gte('created_at', prevSince)
                  .lt('created_at', since),
        context.supabase
            .from('service_requests')
            .select('id, status, created_at')
            .eq('restaurant_id', context.restaurantId)
            .gte('created_at', since),
        context.supabase
            .from('tables')
            .select('id, status, is_active')
            .eq('restaurant_id', context.restaurantId),
        context.supabase
            .from('reviews')
            .select('rating, created_at')
            .eq('restaurant_id', context.restaurantId),
    ]);

    if (ordersRes.error) {
        return apiError(
            'Failed to fetch analytics orders data',
            500,
            'ANALYTICS_ORDERS_FETCH_FAILED',
            ordersRes.error.message
        );
    }
    if (requestsRes.error) {
        return apiError(
            'Failed to fetch analytics requests data',
            500,
            'ANALYTICS_REQUESTS_FETCH_FAILED',
            requestsRes.error.message
        );
    }
    if (tablesRes.error) {
        return apiError(
            'Failed to fetch analytics tables data',
            500,
            'ANALYTICS_TABLES_FETCH_FAILED',
            tablesRes.error.message
        );
    }
    // review fetch failure is non-critical, we can default to 0

    const orders = ordersRes.data ?? [];
    const requests = requestsRes.data ?? [];
    const tables = tablesRes.data ?? [];
    const reviews = reviewsRes.data ?? [];

    // total_price is stored in santim — divide by 100 to get ETB
    const totalRevenue =
        orders.reduce((sum, order) => sum + Number(order.total_price ?? 0), 0) / 100;
    const totalOrders = orders.length;
    const completedOrders = orders.filter(order =>
        ['served', 'completed'].includes(order.status ?? '')
    ).length;
    const previousCompletedOrders = prevOrdersRes.count ?? 0;

    const pendingOrders = orders.filter(order =>
        ['pending', 'acknowledged', 'preparing', 'ready'].includes(order.status ?? '')
    ).length;
    const openRequests = requests.filter(r => (r.status ?? 'pending') === 'pending').length;

    // Table Metrics
    const activeTables = tables.filter(
        t => t.is_active !== false && t.status !== 'available'
    ).length;
    const totalTables = tables.length;

    // Review Metrics
    const totalReviews = reviews.length;
    const avgRating =
        totalReviews > 0
            ? Number(
                  (reviews.reduce((acc, r) => acc + (r.rating || 0), 0) / totalReviews).toFixed(1)
              )
            : 0;

    const oneWeekAgo = new Date();
    oneWeekAgo.setDate(oneWeekAgo.getDate() - 7);
    const reviewsThisWeek = reviews.filter(
        r => r.created_at && new Date(r.created_at) > oneWeekAgo
    ).length;

    // Calculate Top Selling Items
    const itemSales: Record<string, { count: number; revenue: number }> = {};
    orders.forEach(order => {
        const items = order.order_items || [];
        items.forEach((item: any) => {
            const name = item.name || 'Unknown Item';
            const qty = item.quantity || 1;
            const price = item.price || 0;

            if (!itemSales[name]) {
                itemSales[name] = { count: 0, revenue: 0 };
            }
            itemSales[name].count += qty;
            itemSales[name].revenue += (price / 100) * qty;
        });
    });

    const topItems = Object.entries(itemSales)
        .map(([name, stats]) => ({ name, ...stats }))
        .sort((a, b) => b.count - a.count)
        .slice(0, 5);

    // Calculate Trends (buckets)
    const trendBuckets: Record<string, { revenue: number; orders: number }> = {};
    const now = new Date();
    const isToday = !url.searchParams.get('range') || url.searchParams.get('range') === 'today';

    // Initialize buckets
    for (let i = 0; i < (isToday ? 24 : 7); i++) {
        const key = isToday
            ? i.toString().padStart(2, '0') + ':00'
            : new Date(now.getTime() - (6 - i) * 86400000).toLocaleDateString('en-US', {
                  weekday: 'short',
              });
        trendBuckets[key] = { revenue: 0, orders: 0 };
    }

    orders.forEach(order => {
        if (!order.created_at) return;
        const date = new Date(order.created_at);
        let key = '';

        if (isToday) {
            key = date.getHours().toString().padStart(2, '0') + ':00';
        } else {
            key = date.toLocaleDateString('en-US', { weekday: 'short' });
        }

        if (trendBuckets[key]) {
            trendBuckets[key].revenue += Number(order.total_price ?? 0) / 100;
            trendBuckets[key].orders += 1;
        }
    });

    const trends = Object.entries(trendBuckets).map(([label, data]) => ({
        label,
        ...data,
    }));

    return apiSuccess({
        range_start: since,
        metrics: {
            total_revenue: totalRevenue,
            total_orders: totalOrders,
            completed_orders: completedOrders,
            previous_completed_orders: previousCompletedOrders,
            pending_orders: pendingOrders,
            open_requests: openRequests,
            active_tables: activeTables,
            total_tables: totalTables,
            conversion_rate:
                totalOrders > 0 ? Math.round((completedOrders / totalOrders) * 100) : 0,
            avg_order_value: totalOrders > 0 ? Math.round(totalRevenue / totalOrders) : 0,
            avg_rating: avgRating,
            total_reviews: totalReviews,
            reviews_this_week: reviewsThisWeek,
            top_items: topItems,
            trends: trends,
        },
    });
}

import { z } from 'zod';
import { apiError, apiSuccess } from '@/lib/api/response';
import { getAuthenticatedUser, getAuthorizedRestaurantContext } from '@/lib/api/authz';
import { parseJsonBody } from '@/lib/api/validation';
import { writeAuditLog } from '@/lib/api/audit';
import { isIdempotencyKeyValid, resolveIdempotencyKey } from '@/lib/api/idempotency';
import type { Json } from '@/types/database';

const CampaignIdSchema = z.string().uuid();

const LaunchCampaignSchema = z.object({
    limit: z.coerce.number().int().min(1).max(2000).optional().default(500),
    dry_run: z.boolean().optional().default(false),
});

function normalizeSegmentRules(ruleJson: unknown) {
    if (!ruleJson || typeof ruleJson !== 'object') {
        return {
            tags_any: [] as string[],
            vip_only: false,
            minimum_visits: 0,
            language: null as string | null,
        };
    }

    const candidate = ruleJson as Record<string, unknown>;
    return {
        tags_any: Array.isArray(candidate.tags_any)
            ? candidate.tags_any
                  .filter(item => typeof item === 'string')
                  .map(item => item.trim())
                  .filter(Boolean)
            : [],
        vip_only: candidate.vip_only === true,
        minimum_visits:
            typeof candidate.minimum_visits === 'number' &&
            Number.isFinite(candidate.minimum_visits)
                ? Math.max(0, Math.floor(candidate.minimum_visits))
                : 0,
        language:
            typeof candidate.language === 'string' && candidate.language.length > 0
                ? candidate.language
                : null,
    };
}

export async function POST(
    request: Request,
    routeContext: { params: Promise<{ campaignId: string }> }
) {
    const auth = await getAuthenticatedUser();
    if (!auth.ok) {
        return auth.response;
    }

    const context = await getAuthorizedRestaurantContext(auth.user.id, { phase: 'p2' });
    if (!context.ok) {
        return context.response;
    }

    const db = context.supabase as any;

    const { campaignId } = await routeContext.params;
    const campaignIdParsed = CampaignIdSchema.safeParse(campaignId);
    if (!campaignIdParsed.success) {
        return apiError(
            'Invalid campaign id',
            400,
            'INVALID_CAMPAIGN_ID',
            campaignIdParsed.error.flatten()
        );
    }

    const explicitIdempotencyKey = request.headers.get('x-idempotency-key');
    if (explicitIdempotencyKey && !isIdempotencyKeyValid(explicitIdempotencyKey)) {
        return apiError('Invalid idempotency key', 400, 'INVALID_IDEMPOTENCY_KEY');
    }
    const idempotencyKey = resolveIdempotencyKey(explicitIdempotencyKey);

    const parsed = await parseJsonBody(request, LaunchCampaignSchema);
    if (!parsed.success) {
        return parsed.response;
    }

    const { data: campaign, error: campaignError } = await db
        .from('campaigns' as any)
        .select('*')
        .eq('id', campaignIdParsed.data)
        .eq('restaurant_id', context.restaurantId)
        .maybeSingle();

    if (campaignError) {
        return apiError(
            'Failed to load campaign',
            500,
            'CAMPAIGN_FETCH_FAILED',
            campaignError.message
        );
    }
    if (!campaign) {
        return apiError('Campaign not found', 404, 'CAMPAIGN_NOT_FOUND');
    }

    let segmentRules = {
        tags_any: [] as string[],
        vip_only: false,
        minimum_visits: 0,
        language: null as string | null,
    };

    if (campaign.segment_id) {
        const { data: segment, error: segmentError } = await db
            .from('segments' as any)
            .select('id, rule_json')
            .eq('id', campaign.segment_id)
            .eq('restaurant_id', context.restaurantId)
            .maybeSingle();

        if (segmentError) {
            return apiError(
                'Failed to load campaign segment',
                500,
                'SEGMENT_FETCH_FAILED',
                segmentError.message
            );
        }
        if (!segment) {
            return apiError('Campaign segment not found', 404, 'SEGMENT_NOT_FOUND');
        }

        segmentRules = normalizeSegmentRules(segment.rule_json);
    }

    const guestFetchLimit = Math.min(parsed.data.limit * 4, 5000);

    // Use campaign service to get only verified recipients
    const { getVerifiedRecipients } = await import('@/lib/services/campaignService');

    const allGuests = await getVerifiedRecipients(context.restaurantId, {
        hasPhone: campaign.channel === 'sms' || campaign.channel === 'whatsapp',
        hasEmail: campaign.channel === 'email',
    });

    // Apply segment rules to filter verified guests
    const selectedGuests = allGuests
        .filter((guest: any) => {
            if (segmentRules.vip_only && !guest.is_verified) return false;
            // Note: segment rules for tags, visit_count etc would need additional data
            // For now, just use verified guests
            return true;
        })
        .slice(0, parsed.data.limit);

    if (parsed.data.dry_run) {
        return apiSuccess({
            campaign_id: campaign.id,
            eligible_guest_count: selectedGuests.length,
            launched: false,
            dry_run: true,
        });
    }

    if (selectedGuests.length > 0) {
        const { error: deliveryError } = await db.from('campaign_deliveries' as any).upsert(
            selectedGuests.map((guest: any) => ({
                campaign_id: campaign.id,
                guest_id: guest.guestId,
                status: 'queued',
                metadata: {
                    source: 'campaign_launch',
                    idempotency_key: idempotencyKey,
                } as Json,
            })),
            { onConflict: 'campaign_id,guest_id' }
        );

        if (deliveryError) {
            return apiError(
                'Failed to queue campaign deliveries',
                500,
                'CAMPAIGN_DELIVERY_CREATE_FAILED',
                deliveryError.message
            );
        }
    }

    const nextStatus = selectedGuests.length > 0 ? 'running' : 'completed';

    const { data: updatedCampaign, error: updateError } = await db
        .from('campaigns' as any)
        .update({
            status: nextStatus,
            launched_at: new Date().toISOString(),
            updated_at: new Date().toISOString(),
        })
        .eq('id', campaign.id)
        .eq('restaurant_id', context.restaurantId)
        .select('*')
        .single();

    if (updateError) {
        return apiError(
            'Failed to update campaign launch state',
            500,
            'CAMPAIGN_UPDATE_FAILED',
            updateError.message
        );
    }

    await writeAuditLog(context.supabase, {
        restaurant_id: context.restaurantId,
        user_id: auth.user.id,
        action: 'campaign_launched',
        entity_type: 'campaign',
        entity_id: campaign.id,
        old_value: {
            status: campaign.status,
            launched_at: campaign.launched_at,
        },
        new_value: {
            status: updatedCampaign.status,
            launched_at: updatedCampaign.launched_at,
            queued_deliveries: selectedGuests.length,
        },
        metadata: {
            idempotency_key: idempotencyKey,
            segment_id: campaign.segment_id,
        },
    });

    return apiSuccess({
        campaign: updatedCampaign,
        queued_deliveries: selectedGuests.length,
        idempotency_key: idempotencyKey,
        launched: true,
    });
}

