/**
 * GET /api/device/orders  — active orders for the POS (kitchen/waiter view)
 * POST /api/device/orders — place a new order from the POS
 * Requires X-Device-Token header.
 *
 * @openapi
 * /api/device/orders:
 *   get:
 *     summary: Get active orders for POS
 *     tags: [Device, Orders]
 *     security:
 *       - deviceToken: []
 *     parameters:
 *       - in: query
 *         name: table_number
 *         schema:
 *           type: string
 *         description: Filter by table number
 *     responses:
 *       200:
 *         description: List of active orders
 *       401:
 *         description: Unauthorized - invalid device token
 *       429:
 *         description: Rate limit exceeded
 *   post:
 *     summary: Create order from POS device
 *     tags: [Device, Orders]
 *     security:
 *       - deviceToken: []
 *     requestBody:
 *       required: true
 *       content:
 *         application/json:
 *           schema:
 *             type: object
 *             required:
 *               - items
 *             properties:
 *               table_number:
 *                 type: string
 *               order_type:
 *                 type: string
 *                 enum: [dine_in, pickup, delivery, online]
 *               items:
 *                 type: array
 *                 items:
 *                   type: object
 *     responses:
 *       201:
 *         description: Order created
 *       400:
 *         description: Invalid request
 *       429:
 *         description: Rate limit exceeded
 */
import { apiError, apiSuccess } from '@/lib/api/response';
import { getDeviceContext } from '@/lib/api/authz';
import { createServiceRoleClient } from '@/lib/supabase/service-role';
import { z } from 'zod';
import { parseJsonBody } from '@/lib/api/validation';
import { createGebetaEvent } from '@/lib/events/contracts';
import { publishEvent } from '@/lib/events/runtime';
import { isIdempotencyKeyValid, resolveIdempotencyKey } from '@/lib/api/idempotency';
import { prepareOrderDiscount } from '@/lib/discounts/service';
import {
    withRateLimit,
    RATE_LIMIT_CONFIGS,
    getClientIdentifier,
    logRateLimitedRequest,
} from '@/lib/security/rateLimiter';
import { NextRequest } from 'next/server';

const ACTIVE_STATUSES = ['pending', 'acknowledged', 'preparing', 'ready', 'served'];

export async function GET(request: Request) {
    const ctx = await getDeviceContext(request);
    if (!ctx.ok) return ctx.response;

    const { searchParams } = new URL(request.url);
    const tableNumber = searchParams.get('table_number');

    const admin = createServiceRoleClient();
    let query = admin
        .from('orders')
        .select('*')
        .eq('restaurant_id', ctx.restaurantId)
        .in('status', ACTIVE_STATUSES)
        .order('created_at', { ascending: false });

    if (tableNumber) {
        query = query.eq('table_number', tableNumber);
    }

    const { data, error } = await query;
    if (error) {
        return apiError('Failed to fetch orders', 500, 'ORDERS_FETCH_FAILED', error.message);
    }

    return apiSuccess({ orders: data ?? [] });
}

const PlaceOrderSchema = z.object({
    table_number: z.string().min(1).optional(),
    order_type: z.enum(['dine_in', 'pickup', 'delivery', 'online']).optional().default('dine_in'),
    customer_name: z.string().max(120).optional().nullable(),
    customer_phone: z.string().max(30).optional().nullable(),
    delivery_address: z.string().max(500).optional().nullable(),
    discount_id: z.string().uuid().optional().nullable(),
    manager_pin: z.string().min(4).max(12).optional().nullable(),
    items: z
        .array(
            z.object({
                menu_item_id: z.string().uuid(),
                name: z.string(),
                quantity: z.number().int().positive(),
                // CRIT-02: unit_price is now in SANTIM (integer), not birr
                unit_price: z
                    .number()
                    .int()
                    .nonnegative('Unit price must be a non-negative integer (in santim)'),
                notes: z.string().optional().nullable(),
                course: z.enum(['appetizer', 'main', 'dessert', 'beverage', 'side']).optional(),
            })
        )
        .min(1),
    notes: z.string().optional().nullable(),
    staff_name: z.string().optional().nullable(),
});

export async function POST(request: Request) {
    // Rate limiting for order creation
    const nextRequest = request as NextRequest;
    const { fingerprint, ipAddress, userAgent } = getClientIdentifier(nextRequest);
    await logRateLimitedRequest(fingerprint, 'device_order_create', ipAddress, userAgent);

    const ctx = await getDeviceContext(request);
    if (!ctx.ok) return ctx.response;

    // Check rate limit after device context is validated
    const rateCheck = await withRateLimit(
        async () => apiSuccess({}),
        RATE_LIMIT_CONFIGS.orderCreate
    )(nextRequest);
    if (rateCheck.status === 429) {
        return rateCheck;
    }

    const explicitIdempotencyKey = request.headers.get('x-idempotency-key');
    if (explicitIdempotencyKey && !isIdempotencyKeyValid(explicitIdempotencyKey)) {
        return apiError('Invalid idempotency key', 400, 'INVALID_IDEMPOTENCY_KEY');
    }
    const idempotencyKey = resolveIdempotencyKey(explicitIdempotencyKey);

    const parsed = await parseJsonBody(request, PlaceOrderSchema);
    if (!parsed.success) return parsed.response;

    const {
        table_number,
        order_type,
        customer_name,
        customer_phone,
        delivery_address,
        discount_id,
        manager_pin,
        items,
        notes,
        staff_name,
    } = parsed.data;
    const admin = createServiceRoleClient();

    const orderNumber = `ORD-${Date.now().toString().slice(-6)}`;

    if (order_type === 'dine_in' && !table_number) {
        return apiError('table_number is required for dine-in orders', 400, 'TABLE_REQUIRED');
    }
    if (order_type === 'delivery' && !delivery_address) {
        return apiError(
            'delivery_address is required for delivery orders',
            400,
            'DELIVERY_ADDRESS_REQUIRED'
        );
    }

    let table: { id: string; status: string } | null = null;
    if (table_number) {
        const { data, error: tableError } = await admin
            .from('tables')
            .select('id, status')
            .eq('restaurant_id', ctx.restaurantId)
            .eq('table_number', table_number)
            .maybeSingle();

        if (tableError) {
            return apiError(
                'Failed to resolve table',
                500,
                'TABLE_FETCH_FAILED',
                tableError.message
            );
        }
        table = data;
    }
    if (order_type === 'dine_in' && !table) {
        return apiError('Table not found', 404, 'TABLE_NOT_FOUND');
    }

    const menuItemIds = items.map(item => item.menu_item_id);
    const { data: menuRows } = await admin
        .from('menu_items')
        .select('id, course')
        .in('id', menuItemIds);
    const menuCourseMap = new Map(
        ((menuRows ?? []) as Array<{ id?: string; course?: string | null }>)
            .filter(row => row.id)
            .map(row => [String(row.id), String(row.course ?? 'main')])
    );

    const normalizedItems = items.map(item => ({
        id: item.menu_item_id,
        name: item.name,
        quantity: item.quantity,
        price: item.unit_price,
        notes: item.notes ?? null,
        status: 'pending',
        course: item.course ?? menuCourseMap.get(item.menu_item_id) ?? 'main',
    }));

    let discountRuntime;
    try {
        discountRuntime = await prepareOrderDiscount({
            supabase: admin as any,
            restaurantId: ctx.restaurantId,
            discountId: discount_id ?? null,
            managerPin: manager_pin ?? null,
            items: items.map(item => ({
                id: item.menu_item_id,
                price: item.unit_price,
                quantity: item.quantity,
            })),
        });
    } catch (error) {
        return apiError(
            error instanceof Error ? error.message : 'Failed to validate discount',
            400,
            'DISCOUNT_INVALID'
        );
    }

    const { data: order, error: orderError } = await admin
        .from('orders')
        .insert({
            restaurant_id: ctx.restaurantId,
            table_number: table_number ?? null,
            status: 'pending',
            total_price: discountRuntime.calculation.total,
            order_number: orderNumber,
            idempotency_key: idempotencyKey,
            notes: notes ?? (staff_name ? `POS waiter: ${staff_name}` : null),
            items: normalizedItems,
            order_type,
            customer_name: customer_name ?? null,
            customer_phone: customer_phone ?? null,
            delivery_address: delivery_address ?? null,
            ...(discountRuntime.discount ? { discount_id: discountRuntime.discount.id } : {}),
            ...(discountRuntime.calculation.discountAmount > 0
                ? { discount_amount: discountRuntime.calculation.discountAmount }
                : {}),
        } as Record<string, unknown>)
        .select('*')
        .single();

    if (orderError || !order) {
        return apiError('Failed to create order', 500, 'ORDER_CREATE_FAILED', orderError?.message);
    }

    const orderItems = items.map(item => ({
        order_id: order.id,
        item_id: item.menu_item_id,
        name: item.name,
        quantity: item.quantity,
        price: item.unit_price,
        notes: item.notes ?? null,
        status: 'pending',
        course: item.course ?? menuCourseMap.get(item.menu_item_id) ?? 'main',
    }));

    const { error: itemsError } = await admin.from('order_items').insert(orderItems);
    if (itemsError) {
        await admin.from('orders').delete().eq('id', order.id);
        return apiError(
            'Failed to save order items',
            500,
            'ORDER_ITEMS_FAILED',
            itemsError.message
        );
    }

    if (order_type === 'dine_in' && table) {
        const { data: existingSession } = await admin
            .from('table_sessions')
            .select('id')
            .eq('restaurant_id', ctx.restaurantId)
            .eq('table_id', table.id)
            .eq('status', 'open')
            .maybeSingle();

        if (!existingSession) {
            await admin.from('table_sessions').insert({
                restaurant_id: ctx.restaurantId,
                table_id: table.id,
                guest_count: 1,
                status: 'open',
                notes: staff_name
                    ? `Opened by ${staff_name} via waiter POS`
                    : 'Opened via waiter POS',
            });
        }
    }

    await admin.from('order_events').insert({
        restaurant_id: ctx.restaurantId,
        order_id: order.id,
        event_type: 'created',
        from_status: null,
        to_status: 'pending',
        actor_user_id: null,
        metadata: {
            source: 'waiter_pos_device',
            staff_name: staff_name ?? null,
            table_number: table_number ?? null,
            order_type,
            customer_name: customer_name ?? null,
            customer_phone: customer_phone ?? null,
            discount_id: discountRuntime.discount?.id ?? null,
            discount_amount: discountRuntime.calculation.discountAmount,
        },
    });

    // Mark the table as occupied for dine-in flows only.
    if (order_type === 'dine_in' && table_number) {
        await admin
            .from('tables')
            .update({ status: 'occupied', active_order_id: order.id })
            .eq('restaurant_id', ctx.restaurantId)
            .eq('table_number', table_number);
    }

    await publishEvent(
        createGebetaEvent('order.created', {
            restaurant_id: ctx.restaurantId,
            order_id: order.id,
            idempotency_key: idempotencyKey,
            source: 'waiter_pos_device',
            order_type,
        })
    );

    return apiSuccess({ order }, 201);
}

/**
 * POST /api/device/tables/close
 * Settle a dine-in table and close its open table session.
 * Requires X-Device-Token header.
 *
 * IMPORTANT: This endpoint now publishes order.completed events to the
 * event bus instead of processing loyalty/ERCA synchronously. Background
 * jobs handle those side effects asynchronously.
 */
import { z } from 'zod';
import { apiError, apiSuccess } from '@/lib/api/response';
import { getDeviceContext } from '@/lib/api/authz';
import { createServiceRoleClient } from '@/lib/supabase/service-role';
import { parseJsonBody } from '@/lib/api/validation';
import { isChapaConfigured, verifyChapaTransaction } from '@/lib/services/chapaService';
import { ensurePaymentSessionForRecordedPayment } from '@/lib/payments/payment-sessions';
import { createGebetaEvent } from '@/lib/events/contracts';
import { enqueueInternalJob } from '@/lib/events/runtime';

const CloseTableSchema = z.object({
    table_id: z.string().uuid().optional(),
    table_number: z.string().trim().min(1).optional(),
    payment: z.object({
        provider: z.enum(['cash', 'chapa', 'other']),
        tx_ref: z.string().trim().min(3).optional(),
        amount: z.number().nonnegative().optional(),
        tip_amount: z.number().nonnegative().optional().default(0),
    }),
    notes: z.string().trim().max(500).optional(),
});

const BLOCKING_ORDER_STATUSES = [
    'payment_pending',
    'pending',
    'acknowledged',
    'preparing',
] as const;
const FINALIZABLE_ORDER_STATUSES = ['ready', 'served'] as const;

export async function POST(request: Request) {
    const ctx = await getDeviceContext(request);
    if (!ctx.ok) return ctx.response;

    const parsed = await parseJsonBody(request, CloseTableSchema);
    if (!parsed.success) return parsed.response;

    const admin = createServiceRoleClient();
    const { table_id, table_number, payment, notes } = parsed.data;

    if (!table_id && !table_number) {
        return apiError('table_id or table_number is required', 400, 'TABLE_SELECTOR_REQUIRED');
    }

    let tableQuery = admin
        .from('tables')
        .select('id, table_number, status')
        .eq('restaurant_id', ctx.restaurantId);

    if (table_id) {
        tableQuery = tableQuery.eq('id', table_id);
    } else if (table_number) {
        tableQuery = tableQuery.eq('table_number', table_number);
    }

    const { data: table, error: tableError } = await tableQuery.maybeSingle();
    if (tableError) {
        return apiError('Failed to fetch table', 500, 'TABLE_FETCH_FAILED', tableError.message);
    }
    if (!table) {
        return apiError('Table not found', 404, 'TABLE_NOT_FOUND');
    }

    const { data: openSession, error: sessionError } = await admin
        .from('table_sessions')
        .select('id, notes')
        .eq('restaurant_id', ctx.restaurantId)
        .eq('table_id', table.id)
        .eq('status', 'open')
        .maybeSingle();

    const { data: tableOrders, error: ordersError } = await admin
        .from('orders')
        .select('id, status, total_price, chapa_tx_ref, paid_at, chapa_verified')
        .eq('restaurant_id', ctx.restaurantId)
        .eq('table_number', table.table_number)
        .in('status', [
            'payment_pending',
            'pending',
            'acknowledged',
            'preparing',
            'ready',
            'served',
        ]);

    if (sessionError) {
        return apiError(
            'Failed to resolve table session',
            500,
            'TABLE_SESSION_FETCH_FAILED',
            sessionError.message
        );
    }
    if (ordersError) {
        return apiError(
            'Failed to fetch table orders',
            500,
            'TABLE_ORDERS_FETCH_FAILED',
            ordersError.message
        );
    }

    let ensuredOpenSession = openSession;
    if (!ensuredOpenSession) {
        const { data: createdSession, error: createSessionError } = await admin
            .from('table_sessions')
            .insert({
                restaurant_id: ctx.restaurantId,
                table_id: table.id,
                guest_count: 1,
                status: 'open',
                notes: 'Auto-recovered during waiter settlement (missing legacy open session)',
            })
            .select('id, notes')
            .single();

        if (createSessionError) {
            if (createSessionError.code === '23505') {
                const { data: recoveredSession, error: recoverSessionError } = await admin
                    .from('table_sessions')
                    .select('id, notes')
                    .eq('restaurant_id', ctx.restaurantId)
                    .eq('table_id', table.id)
                    .eq('status', 'open')
                    .maybeSingle();
                if (recoverSessionError) {
                    return apiError(
                        'Failed to recover open table session',
                        500,
                        'TABLE_SESSION_RECOVERY_FAILED',
                        recoverSessionError.message
                    );
                }
                ensuredOpenSession = recoveredSession;
            } else {
                return apiError(
                    'Failed to auto-create open table session',
                    500,
                    'TABLE_SESSION_CREATE_FAILED',
                    createSessionError.message
                );
            }
        } else {
            ensuredOpenSession = createdSession;
        }
    }

    if (!ensuredOpenSession) {
        return apiError('Open table session not found', 409, 'TABLE_SESSION_NOT_OPEN');
    }

    const tableStatus = String(table.status ?? 'available');
    if (tableStatus !== 'bill_requested') {
        return apiError(
            'Table must be in bill requested state before settlement',
            409,
            'TABLE_NOT_BILL_REQUESTED'
        );
    }

    const activeOrders = tableOrders ?? [];
    const blockingOrders = activeOrders.filter(order =>
        BLOCKING_ORDER_STATUSES.includes(
            String(order.status) as (typeof BLOCKING_ORDER_STATUSES)[number]
        )
    );
    if (blockingOrders.length > 0) {
        return apiError(
            'Table has unpaid or in-progress orders. Complete prep/payment first.',
            409,
            'TABLE_CLOSE_BLOCKED',
            {
                blocking_order_ids: blockingOrders.map(order => order.id),
                blocking_statuses: [...new Set(blockingOrders.map(order => order.status))],
            }
        );
    }

    const settlementAmount = Number(
        activeOrders.reduce((sum, order) => sum + Number(order.total_price ?? 0), 0).toFixed(2)
    );

    if (activeOrders.length === 0) {
        const now = new Date().toISOString();
        const mergedCloseNotes =
            [ensuredOpenSession.notes, notes, 'Closed via waiter POS (no active orders)']
                .filter(Boolean)
                .join(' | ') || null;

        await Promise.all([
            admin
                .from('table_sessions')
                .update({
                    status: 'closed',
                    closed_at: now,
                    notes: mergedCloseNotes,
                    updated_at: now,
                })
                .eq('id', ensuredOpenSession.id)
                .eq('restaurant_id', ctx.restaurantId),
            admin
                .from('tables')
                .update({
                    status: 'available',
                    active_order_id: null,
                    updated_at: now,
                })
                .eq('id', table.id)
                .eq('restaurant_id', ctx.restaurantId),
            admin.from('audit_logs').insert({
                restaurant_id: ctx.restaurantId,
                user_id: null,
                action: 'waiter_table_closed',
                entity_type: 'table',
                entity_id: table.id,
                metadata: {
                    source: 'waiter_pos_device',
                    table_number: table.table_number,
                    session_id: ensuredOpenSession.id,
                    settled_amount: 0,
                },
            }),
        ]);

        return apiSuccess({
            table_id: table.id,
            table_number: table.table_number,
            closed_session_id: ensuredOpenSession.id,
            payment: null,
            completed_order_ids: [],
        });
    }

    if (settlementAmount <= 0) {
        return apiError(
            'No billable orders found for this table',
            409,
            'TABLE_CLOSE_NO_BILLABLE_ORDERS'
        );
    }

    if (typeof payment.amount === 'number') {
        const provided = Number(payment.amount.toFixed(2));
        if (Math.abs(provided - settlementAmount) > 0.01) {
            return apiError(
                `Settlement amount mismatch. Expected ${settlementAmount.toFixed(2)} ETB`,
                409,
                'TABLE_CLOSE_AMOUNT_MISMATCH'
            );
        }
    }

    const paymentProvider = payment.provider;
    const hasTxRef = Boolean(payment.tx_ref?.trim());
    if (paymentProvider === 'chapa' && hasTxRef) {
        if (isChapaConfigured()) {
            const verified = await verifyChapaTransaction(String(payment.tx_ref));
            const verifiedStatus = String(verified.data?.status ?? '').toLowerCase();
            if (verifiedStatus !== 'success') {
                return apiError(
                    'Chapa payment is not verified as successful',
                    409,
                    'CHAPA_PAYMENT_NOT_VERIFIED',
                    verified.data ?? null
                );
            }
        }
    } else if (paymentProvider === 'chapa') {
        const unpaidOrders = activeOrders.filter(
            order =>
                !order.paid_at ||
                order.chapa_verified !== true ||
                !String(order.chapa_tx_ref ?? '').trim()
        );
        if (unpaidOrders.length > 0) {
            return apiError(
                'Missing Chapa tx_ref. Some orders are not marked as paid via Chapa.',
                409,
                'TABLE_CLOSE_MISSING_TX_REF'
            );
        }
    }

    const now = new Date().toISOString();
    const finalizableOrders = activeOrders.filter(order =>
        FINALIZABLE_ORDER_STATUSES.includes(
            String(order.status) as (typeof FINALIZABLE_ORDER_STATUSES)[number]
        )
    );
    const finalizableOrderIds = finalizableOrders.map(order => order.id);

    const paymentSession = await ensurePaymentSessionForRecordedPayment(admin as any, {
        restaurantId: ctx.restaurantId,
        orderId: null,
        surface: ctx.device.device_type === 'terminal' ? 'terminal' : 'waiter_pos',
        channel: 'dine_in',
        method:
            paymentProvider === 'cash'
                ? 'cash'
                : paymentProvider === 'other'
                  ? 'other'
                  : paymentProvider,
        provider:
            paymentProvider === 'cash' || paymentProvider === 'other'
                ? 'internal'
                : paymentProvider,
        amount: settlementAmount,
        status: 'captured',
        metadata: {
            source: `${ctx.device.device_type}_close_table`,
            table_id: table.id,
            table_number: table.table_number,
            order_ids: activeOrders.map(order => order.id),
        },
    });

    const { data: paymentRecord, error: paymentError } = await admin
        .from('payments')
        .insert({
            restaurant_id: ctx.restaurantId,
            order_id: null,
            payment_session_id: paymentSession.id,
            method: paymentProvider,
            provider:
                paymentProvider === 'cash' || paymentProvider === 'other'
                    ? 'internal'
                    : paymentProvider,
            provider_reference: payment.tx_ref?.trim() || null,
            amount: settlementAmount,
            tip_amount: Number((payment.tip_amount ?? 0).toFixed(2)),
            currency: 'ETB',
            status: 'captured',
            captured_at: now,
            metadata: {
                source: `${ctx.device.device_type}_close_table`,
                payment_session_id: paymentSession.id,
                table_id: table.id,
                table_number: table.table_number,
                order_ids: activeOrders.map(order => order.id),
                paid_order_tx_refs: activeOrders
                    .map(order => String(order.chapa_tx_ref ?? '').trim())
                    .filter(Boolean),
            },
            created_by: null,
        })
        .select('id, amount, provider_reference')
        .single();

    if (paymentError || !paymentRecord) {
        return apiError(
            'Failed to record settlement payment',
            500,
            'PAYMENT_RECORD_FAILED',
            paymentError?.message
        );
    }

    if (finalizableOrderIds.length > 0) {
        await admin
            .from('orders')
            .update({
                status: 'completed',
                completed_at: now,
                updated_at: now,
            })
            .in('id', finalizableOrderIds)
            .eq('restaurant_id', ctx.restaurantId);

        await admin.from('order_events').insert(
            finalizableOrders.map(order => ({
                restaurant_id: ctx.restaurantId,
                order_id: order.id,
                event_type: 'status_changed',
                from_status: String(order.status ?? 'ready'),
                to_status: 'completed',
                actor_user_id: null,
                metadata: {
                    source: 'waiter_pos_close_table',
                    payment_id: paymentRecord.id,
                    tx_ref: payment.tx_ref?.trim() || null,
                },
            }))
        );

        // Queue background jobs for each completed order
        // This removes synchronous cross-domain side effects (loyalty, ERCA, etc.)
        const jobQueuePromises = finalizableOrderIds.map(orderId =>
            enqueueInternalJob({
                path: '/api/jobs/orders/completed',
                body: createGebetaEvent('order.completed', {
                    order_id: orderId,
                    restaurant_id: ctx.restaurantId,
                    completed_at: now,
                    trigger: 'table_close',
                }) as unknown as Record<string, unknown>,
                deduplicationKey: `order-completed-${orderId}`,
            }).catch(err => {
                console.error(`[close-table] Failed to queue job for order ${orderId}:`, err);
                return undefined;
            })
        );

        // Fire and forget - don't block the response on job queuing
        Promise.all(jobQueuePromises).catch(() => {});
    }

    const mergedCloseNotes =
        [
            ensuredOpenSession.notes,
            notes,
            payment.tx_ref?.trim()
                ? `Settled via ${paymentProvider}: ${payment.tx_ref}`
                : `Settled via ${paymentProvider}`,
        ]
            .filter(Boolean)
            .join(' | ') || null;

    await Promise.all([
        admin
            .from('table_sessions')
            .update({
                status: 'closed',
                closed_at: now,
                notes: mergedCloseNotes,
                updated_at: now,
            })
            .eq('id', ensuredOpenSession.id)
            .eq('restaurant_id', ctx.restaurantId),
        admin
            .from('tables')
            .update({
                status: 'available',
                active_order_id: null,
                updated_at: now,
            })
            .eq('id', table.id)
            .eq('restaurant_id', ctx.restaurantId),
        admin.from('audit_logs').insert({
            restaurant_id: ctx.restaurantId,
            user_id: null,
            action: 'waiter_table_closed',
            entity_type: 'table',
            entity_id: table.id,
            metadata: {
                source: `${ctx.device.device_type}_device`,
                table_number: table.table_number,
                session_id: ensuredOpenSession.id,
                payment_id: paymentRecord.id,
                payment_session_id: paymentSession.id,
                tx_ref: payment.tx_ref,
                settled_amount: settlementAmount,
            },
        }),
    ]);

    return apiSuccess({
        table_id: table.id,
        table_number: table.table_number,
        closed_session_id: ensuredOpenSession.id,
        payment: paymentRecord,
        completed_order_ids: finalizableOrderIds,
    });
}

import { apiError, apiSuccess } from '@/lib/api/response';
import { getAuthenticatedUser, getAuthorizedRestaurantContext } from '@/lib/api/authz';
import { writeAuditLog } from '@/lib/api/audit';

export async function DELETE(
    _request: Request,
    { params }: { params: Promise<{ deviceId: string }> }
) {
    const { deviceId } = await params;

    const auth = await getAuthenticatedUser();
    if (!auth.ok) return auth.response;

    const context = await getAuthorizedRestaurantContext(auth.user.id);
    if (!context.ok) return context.response;

    // Verify the device belongs to this restaurant before deleting
    const { data: device, error: fetchError } = await (context.supabase as any)
        .from('hardware_devices')
        .select('id, name, device_type')
        .eq('id', deviceId)
        .eq('restaurant_id', context.restaurantId)
        .single();

    if (fetchError || !device) {
        return apiError('Device not found or access denied', 404, 'DEVICE_NOT_FOUND');
    }

    const { error: deleteError } = await (context.supabase as any)
        .from('hardware_devices')
        .delete()
        .eq('id', deviceId)
        .eq('restaurant_id', context.restaurantId);

    if (deleteError) {
        return apiError(
            'Failed to delete device',
            500,
            'DEVICE_DELETE_FAILED',
            deleteError.message
        );
    }

    await writeAuditLog(context.supabase, {
        restaurant_id: context.restaurantId,
        user_id: auth.user.id,
        action: 'device_deleted',
        entity_type: 'hardware_devices',
        entity_id: deviceId,
        metadata: { name: device.name, device_type: device.device_type },
    });

    return apiSuccess({ deleted: true });
}

import { z } from 'zod';
import { apiError, apiSuccess } from '@/lib/api/response';
import { getAuthenticatedUser, getAuthorizedRestaurantContext } from '@/lib/api/authz';
import { parseJsonBody } from '@/lib/api/validation';
import { createServiceRoleClient } from '@/lib/supabase/service-role';
import {
    HardwareDeviceMetadataSchema,
    HardwareDeviceTypeSchema,
    normalizeDeviceMetadata,
} from '@/lib/devices/config';

const ProvisionDeviceSchema = z.object({
    name: z.string().trim().min(2).max(120),
    device_type: HardwareDeviceTypeSchema,
    assigned_zones: z.array(z.string()).optional(),
    metadata: HardwareDeviceMetadataSchema.optional(),
});

export async function POST(request: Request) {
    const auth = await getAuthenticatedUser();
    if (!auth.ok) {
        return auth.response;
    }

    const context = await getAuthorizedRestaurantContext(auth.user.id);
    if (!context.ok) {
        return context.response;
    }

    const parsed = await parseJsonBody(request, ProvisionDeviceSchema);
    if (!parsed.success) {
        return parsed.response;
    }

    // Generate a 4-digit random code
    const pairing_code = Math.floor(1000 + Math.random() * 9000).toString();
    const adminClient = createServiceRoleClient();

    const { data, error } = await (adminClient as any)
        .from('hardware_devices')
        .insert({
            restaurant_id: context.restaurantId,
            name: parsed.data.name,
            device_type: parsed.data.device_type,
            pairing_code,
            assigned_zones: parsed.data.assigned_zones ?? [],
            metadata: normalizeDeviceMetadata(parsed.data.device_type, parsed.data.metadata),
        })
        .select('*')
        .single();

    if (error) {
        if (
            parsed.data.device_type === 'terminal' &&
            /device_type|hardware_devices_device_type_check|violates check constraint/i.test(
                error.message
            )
        ) {
            return apiError(
                'Terminal provisioning requires the latest database migration. Apply the new hardware device migration and try again.',
                500,
                'TERMINAL_DEVICE_MIGRATION_REQUIRED',
                error.message
            );
        }

        return apiError(
            'Failed to provision device',
            500,
            'DEVICE_PROVISION_FAILED',
            error.message
        );
    }

    return apiSuccess(
        {
            device: data,
        },
        201
    );
}

import { apiError, apiSuccess } from '@/lib/api/response';
import { getAuthenticatedUser, getAuthorizedRestaurantContext } from '@/lib/api/authz';

export async function GET() {
