import { z } from 'zod';
import { apiError, apiSuccess } from '@/lib/api/response';
import { getAuthenticatedUser, getAuthorizedRestaurantContext } from '@/lib/api/authz';
import { parseJsonBody } from '@/lib/api/validation';
import { writeAuditLog } from '@/lib/api/audit';
import { listActiveDiscountsForRestaurant } from '@/lib/discounts/service';

const CreateDiscountSchema = z.object({
    name: z.string().trim().min(1).max(120),
    name_am: z.string().trim().max(120).optional().nullable(),
    type: z.enum(['percentage', 'fixed_amount', 'bogo', 'item_override']),
    value: z.number().int().min(0),
    applies_to: z.enum(['order', 'item', 'category']).default('order'),
    target_menu_item_id: z.string().uuid().optional().nullable(),
    target_category_id: z.string().uuid().optional().nullable(),
    requires_manager_pin: z.boolean().optional().default(false),
    max_uses_per_day: z.number().int().min(1).optional().nullable(),
    valid_from: z.string().datetime().optional().nullable(),
    valid_until: z.string().datetime().optional().nullable(),
    is_active: z.boolean().optional().default(true),
});

export async function GET() {
    const auth = await getAuthenticatedUser();
    if (!auth.ok) {
        return auth.response;
    }

    const context = await getAuthorizedRestaurantContext(auth.user.id, { phase: 'p1' });
    if (!context.ok) {
        return context.response;
    }

    try {
        const discounts = await listActiveDiscountsForRestaurant(
            context.supabase,
            context.restaurantId
        );
        return apiSuccess({ discounts });
    } catch (error) {
        return apiError(
            'Failed to load discounts',
            500,
            'DISCOUNTS_FETCH_FAILED',
            error instanceof Error ? error.message : 'Unknown discount fetch error'
        );
    }
}

export async function POST(request: Request) {
    const auth = await getAuthenticatedUser();
    if (!auth.ok) {
        return auth.response;
    }

    const context = await getAuthorizedRestaurantContext(auth.user.id, { phase: 'p1' });
    if (!context.ok) {
        return context.response;
    }

    const parsed = await parseJsonBody(request, CreateDiscountSchema);
    if (!parsed.success) {
        return parsed.response;
    }

    if (parsed.data.applies_to === 'item' && !parsed.data.target_menu_item_id) {
        return apiError(
            'target_menu_item_id is required for item discounts',
            400,
            'DISCOUNT_TARGET_REQUIRED'
        );
    }

    if (parsed.data.applies_to === 'category' && !parsed.data.target_category_id) {
        return apiError(
            'target_category_id is required for category discounts',
            400,
            'DISCOUNT_TARGET_REQUIRED'
        );
    }

    const db = context.supabase as any;
    const { data, error } = await db
        .from('discounts')
        .insert({
            restaurant_id: context.restaurantId,
            ...parsed.data,
        })
        .select('*')
        .single();

    if (error || !data) {
        return apiError('Failed to create discount', 500, 'DISCOUNT_CREATE_FAILED', error?.message);
    }

    await writeAuditLog(context.supabase, {
        restaurant_id: context.restaurantId,
        user_id: auth.user.id,
        action: 'discount_created',
        entity_type: 'discount',
        entity_id: data.id,
        metadata: { source: 'discounts_api' },
        new_value: data,
    });

    return apiSuccess({ discount: data }, 201);
}

import { z } from 'zod';
import { apiError, apiSuccess } from '@/lib/api/response';
import { getAuthenticatedUser, getAuthorizedRestaurantContext } from '@/lib/api/authz';
import { parseJsonBody } from '@/lib/api/validation';
import { writeAuditLog } from '@/lib/api/audit';
import { isIdempotencyKeyValid, resolveIdempotencyKey } from '@/lib/api/idempotency';
import type { Json } from '@/types/database';

const GiftCardIdSchema = z.string().uuid();

const RedeemGiftCardSchema = z.object({
    amount: z.coerce.number().min(0.01).max(500000),
    order_id: z.string().uuid().optional(),
    metadata: z.record(z.string(), z.unknown()).optional(),
});

export async function POST(
    request: Request,
    routeContext: { params: Promise<{ giftCardId: string }> }
) {
    const auth = await getAuthenticatedUser();
    if (!auth.ok) {
        return auth.response;
    }

    const context = await getAuthorizedRestaurantContext(auth.user.id, { phase: 'p2' });
    if (!context.ok) {
        return context.response;
    }

    const db = context.supabase as any;

    const { giftCardId } = await routeContext.params;
    const giftCardIdParsed = GiftCardIdSchema.safeParse(giftCardId);
    if (!giftCardIdParsed.success) {
        return apiError(
            'Invalid gift card id',
            400,
            'INVALID_GIFT_CARD_ID',
            giftCardIdParsed.error.flatten()
        );
    }

    const explicitIdempotencyKey = request.headers.get('x-idempotency-key');
    if (explicitIdempotencyKey && !isIdempotencyKeyValid(explicitIdempotencyKey)) {
        return apiError('Invalid idempotency key', 400, 'INVALID_IDEMPOTENCY_KEY');
    }
    const idempotencyKey = resolveIdempotencyKey(explicitIdempotencyKey);

    const parsed = await parseJsonBody(request, RedeemGiftCardSchema);
    if (!parsed.success) {
        return parsed.response;
    }

    const { data: giftCard, error: giftCardError } = await db
        .from('gift_cards' as any)
        .select('*')
        .eq('id', giftCardIdParsed.data)
        .eq('restaurant_id', context.restaurantId)
        .maybeSingle();

    if (giftCardError) {
        return apiError(
            'Failed to load gift card',
            500,
            'GIFT_CARD_FETCH_FAILED',
            giftCardError.message
        );
    }
    if (!giftCard) {
        return apiError('Gift card not found', 404, 'GIFT_CARD_NOT_FOUND');
    }
    if (giftCard.status !== 'active') {
        return apiError('Gift card is not active', 409, 'GIFT_CARD_NOT_ACTIVE');
    }

    if (giftCard.expires_at && new Date(giftCard.expires_at).getTime() < Date.now()) {
        return apiError('Gift card is expired', 409, 'GIFT_CARD_EXPIRED');
    }

    const nextBalance =
        Number(Number(giftCard.current_balance).toFixed(2)) - Number(parsed.data.amount.toFixed(2));
    if (nextBalance < 0) {
        return apiError('Insufficient gift card balance', 409, 'GIFT_CARD_INSUFFICIENT_BALANCE');
    }

    const nextStatus = nextBalance === 0 ? 'redeemed' : 'active';

    const { data: updated, error: updateError } = await db
        .from('gift_cards' as any)
        .update({
            current_balance: nextBalance,
            status: nextStatus,
            updated_at: new Date().toISOString(),
        })
        .eq('id', giftCard.id)
        .eq('restaurant_id', context.restaurantId)
        .select('*')
        .single();

    if (updateError) {
        return apiError(
            'Failed to redeem gift card',
            500,
            'GIFT_CARD_REDEEM_FAILED',
            updateError.message
        );
    }

    const { data: transaction, error: txError } = await db
        .from('gift_card_transactions' as any)
        .insert({
            restaurant_id: context.restaurantId,
            gift_card_id: giftCard.id,
            order_id: parsed.data.order_id ?? null,
            amount_delta: -Number(parsed.data.amount.toFixed(2)),
            balance_after: nextBalance,
            type: 'redeem',
            metadata: {
                source: 'merchant_dashboard',
                ...parsed.data.metadata,
                idempotency_key: idempotencyKey,
            } as Json,
            created_by: auth.user.id,
        })
        .select('*')
        .single();

    if (txError) {
        return apiError(
            'Failed to create gift card transaction',
            500,
            'GIFT_CARD_TRANSACTION_CREATE_FAILED',
            txError.message
        );
    }

    await writeAuditLog(context.supabase, {
        restaurant_id: context.restaurantId,
        user_id: auth.user.id,
        action: 'gift_card_redeemed',
        entity_type: 'gift_card',
        entity_id: giftCard.id,
        old_value: {
            current_balance: giftCard.current_balance,
            status: giftCard.status,
        },
        new_value: {
            current_balance: updated.current_balance,
            status: updated.status,
            amount: parsed.data.amount,
        },
        metadata: {
            order_id: parsed.data.order_id ?? null,
            transaction_id: transaction.id,
            idempotency_key: idempotencyKey,
        },
    });

    return apiSuccess({
        gift_card: updated,
        transaction,
        idempotency_key: idempotencyKey,
    });
}

import { z } from 'zod';
import { apiError, apiSuccess } from '@/lib/api/response';
import { getAuthenticatedUser, getAuthorizedRestaurantContext } from '@/lib/api/authz';
import { parseJsonBody } from '@/lib/api/validation';
import { writeAuditLog } from '@/lib/api/audit';

const UpdateGiftCardSchema = z.object({
    status: z.enum(['active', 'redeemed', 'expired', 'archived', 'voided']).optional(),
    metadata: z.record(z.string(), z.unknown()).optional(),
});

export async function PATCH(
    request: Request,
    { params }: { params: Promise<{ giftCardId: string }> }
) {
    const { giftCardId } = await params;

    const auth = await getAuthenticatedUser();
    if (!auth.ok) return auth.response;

    const context = await getAuthorizedRestaurantContext(auth.user.id, { phase: 'p2' });
    if (!context.ok) return context.response;

    const parsed = await parseJsonBody(request, UpdateGiftCardSchema);
    if (!parsed.success) return parsed.response;

    const db = context.supabase as any;

    const { data: giftCard, error: fetchError } = await db
        .from('gift_cards')
        .select('*')
        .eq('id', giftCardId)
        .eq('restaurant_id', context.restaurantId)
        .single();

    if (fetchError || !giftCard) {
        return apiError('Gift card not found', 404, 'GIFT_CARD_NOT_FOUND');
    }

    const { data, error } = await db
        .from('gift_cards')
        .update({
            ...parsed.data,
            updated_at: new Date().toISOString(),
        })
        .eq('id', giftCardId)
        .select('*')
        .single();

    if (error) {
        return apiError(
            'Failed to update gift card',
            500,
            'GIFT_CARD_UPDATE_FAILED',
            error.message
        );
    }

    await writeAuditLog(context.supabase, {
        restaurant_id: context.restaurantId,
        user_id: auth.user.id,
