import { randomBytes } from 'crypto';
import { z } from 'zod';
import { apiError, apiSuccess } from '@/lib/api/response';
import { getAuthenticatedUser, getAuthorizedRestaurantContext } from '@/lib/api/authz';
import { parseJsonBody, parseQuery } from '@/lib/api/validation';
import { writeAuditLog } from '@/lib/api/audit';
import { isIdempotencyKeyValid, resolveIdempotencyKey } from '@/lib/api/idempotency';
import { isSchemaNotReadyError } from '@/lib/api/schemaFallback';
import type { Json } from '@/types/database';

const GiftCardsQuerySchema = z.object({
    status: z.enum(['active', 'redeemed', 'expired', 'voided']).optional(),
    limit: z.coerce.number().int().min(1).max(200).optional().default(100),
});

const CreateGiftCardSchema = z.object({
    code: z.string().trim().min(6).max(32).optional(),
    currency: z.string().trim().min(3).max(3).optional().default('ETB'),
    initial_balance: z.coerce.number().min(1).max(500000),
    expires_at: z.string().datetime().optional(),
    metadata: z.record(z.string(), z.unknown()).optional(),
});

function generateGiftCardCode() {
    return `GC-${randomBytes(4).toString('hex').toUpperCase()}`;
}

export async function GET(request: Request) {
    const auth = await getAuthenticatedUser();
    if (!auth.ok) {
        return auth.response;
    }

    const context = await getAuthorizedRestaurantContext(auth.user.id, { phase: 'p2' });
    if (!context.ok) {
        return context.response;
    }

    const db = context.supabase as any;

    const url = new URL(request.url);
    const parsed = parseQuery(
        {
            status: url.searchParams.get('status') ?? undefined,
            limit: url.searchParams.get('limit') ?? undefined,
        },
        GiftCardsQuerySchema
    );
    if (!parsed.success) {
        return parsed.response;
    }

    let query = db
        .from('gift_cards' as any)
        .select('*')
        .eq('restaurant_id', context.restaurantId)
        .order('created_at', { ascending: false })
        .limit(parsed.data.limit);

    if (parsed.data.status) {
        query = query.eq('status', parsed.data.status);
    }

    const { data, error } = await query;

    if (error) {
        if (isSchemaNotReadyError(error)) {
            return apiSuccess({ gift_cards: [] });
        }
        return apiError(
            'Failed to fetch gift cards',
            500,
            'GIFT_CARDS_FETCH_FAILED',
            error.message
        );
    }

    return apiSuccess({ gift_cards: data ?? [] });
}

export async function POST(request: Request) {
    const auth = await getAuthenticatedUser();
    if (!auth.ok) {
        return auth.response;
    }

    const context = await getAuthorizedRestaurantContext(auth.user.id, { phase: 'p2' });
    if (!context.ok) {
        return context.response;
    }

    const db = context.supabase as any;

    const explicitIdempotencyKey = request.headers.get('x-idempotency-key');
    if (explicitIdempotencyKey && !isIdempotencyKeyValid(explicitIdempotencyKey)) {
        return apiError('Invalid idempotency key', 400, 'INVALID_IDEMPOTENCY_KEY');
    }
    const idempotencyKey = resolveIdempotencyKey(explicitIdempotencyKey);

    const parsed = await parseJsonBody(request, CreateGiftCardSchema);
    if (!parsed.success) {
        return parsed.response;
    }

    const code = parsed.data.code?.trim().toUpperCase() || generateGiftCardCode();
    const balance = Number(parsed.data.initial_balance.toFixed(2));

    const { data: giftCard, error } = await db
        .from('gift_cards' as any)
        .insert({
            restaurant_id: context.restaurantId,
            code,
            currency: parsed.data.currency.toUpperCase(),
            initial_balance: balance,
            current_balance: balance,
            status: 'active',
            expires_at: parsed.data.expires_at ?? null,
            metadata: (parsed.data.metadata ?? {}) as Json,
            created_by: auth.user.id,
        })
        .select('*')
        .single();

    if (error) {
        return apiError(
            'Failed to create gift card',
            500,
            'GIFT_CARD_CREATE_FAILED',
            error.message
        );
    }

    const { error: txError } = await db.from('gift_card_transactions' as any).insert({
        restaurant_id: context.restaurantId,
        gift_card_id: giftCard.id,
        amount_delta: balance,
        balance_after: balance,
        type: 'issue',
        metadata: { source: 'merchant_dashboard', idempotency_key: idempotencyKey } as Json,
        created_by: auth.user.id,
    });

    if (txError) {
        return apiError(
            'Failed to write gift card transaction',
            500,
            'GIFT_CARD_TRANSACTION_CREATE_FAILED',
            txError.message
        );
    }

    await writeAuditLog(context.supabase, {
        restaurant_id: context.restaurantId,
        user_id: auth.user.id,
        action: 'gift_card_created',
        entity_type: 'gift_card',
        entity_id: giftCard.id,
        new_value: {
            code: giftCard.code,
            initial_balance: giftCard.initial_balance,
            current_balance: giftCard.current_balance,
            currency: giftCard.currency,
        },
        metadata: {
            source: 'merchant_dashboard',
            idempotency_key: idempotencyKey,
        },
    });

    return apiSuccess({ gift_card: giftCard, idempotency_key: idempotencyKey }, 201);
}

import { apiError, apiSuccess } from '@/lib/api/response';
import { createServiceRoleClient } from '@/lib/supabase/service-role';
import { listActiveDiscountsForRestaurant } from '@/lib/discounts/service';

export async function GET(request: Request) {
    const { searchParams } = new URL(request.url);
    const slug = searchParams.get('slug');

    if (!slug) {
        return apiError('slug is required', 400, 'MISSING_SLUG');
    }

    const admin = createServiceRoleClient();
    const { data: restaurant, error } = await admin
        .from('restaurants')
        .select('id')
        .eq('slug', slug)
        .maybeSingle();

    if (error) {
        return apiError(
            'Failed to resolve restaurant',
            500,
            'RESTAURANT_RESOLVE_FAILED',
            error.message
        );
    }

    if (!restaurant) {
        return apiError('Restaurant not found', 404, 'RESTAURANT_NOT_FOUND');
    }

    try {
        const discounts = await listActiveDiscountsForRestaurant(admin as any, restaurant.id, {
            excludeManagerApproval: true,
        });
        return apiSuccess({ discounts });
    } catch (fetchError) {
        return apiError(
            'Failed to load discounts',
            500,
            'DISCOUNTS_FETCH_FAILED',
            fetchError instanceof Error ? fetchError.message : 'Unknown discount fetch error'
        );
    }
}

import { NextRequest, NextResponse } from 'next/server';
import { z } from 'zod';
import { createClient } from '@/lib/supabase/server';
import { createServiceRoleClient } from '@/lib/supabase/service-role';
import { resolveGuestContext } from '@/lib/security/guestContext';

const UpsertGuestSessionSchema = z.object({
    session_id: z.string().uuid().optional(),
    guest_context: z.object({
        slug: z.string().min(1),
        table: z.string().min(1),
        sig: z.string().min(1),
        exp: z.union([z.string(), z.number()]),
    }),
    source: z.enum(['qr', 'campaign_qr', 'direct_link', 'other']).optional(),
    skip_selected: z.boolean().optional().default(false),
});

export async function POST(request: NextRequest) {
    try {
        const body = await request.json();
        const parsed = UpsertGuestSessionSchema.safeParse(body);
        if (!parsed.success) {
            return NextResponse.json(
                { error: 'Invalid request payload', details: parsed.error.flatten() },
                { status: 400 }
            );
        }

        const supabase = await createClient();
        const guestContext = await resolveGuestContext(supabase, parsed.data.guest_context);
        if (!guestContext.valid) {
            return NextResponse.json(
                { error: guestContext.reason },
                { status: guestContext.status }
            );
        }

        const {
            data: { user },
        } = await supabase.auth.getUser();

        const authState = user ? 'authenticated' : 'guest';
        const now = new Date().toISOString();
        const db = createServiceRoleClient();

        if (parsed.data.session_id) {
            const { data: existingSession, error: sessionLookupError } = await db
                .from('guest_menu_sessions' as any)
                .select('id, restaurant_id, table_id, auth_state')
                .eq('id', parsed.data.session_id)
                .maybeSingle();

            if (sessionLookupError) {
                return NextResponse.json({ error: sessionLookupError.message }, { status: 500 });
            }

            if (
                existingSession &&
                existingSession.restaurant_id === guestContext.data.restaurantId &&
                existingSession.table_id === guestContext.data.tableId
            ) {
                const patch: Record<string, unknown> = { last_seen_at: now };

                if (authState === 'authenticated' && user) {
                    patch.auth_state = 'authenticated';
                    patch.user_id = user.id;
                    if (existingSession.auth_state === 'guest') {
                        patch.converted_at = now;
                    }
                }

                if (parsed.data.skip_selected) {
                    patch.metadata = { skip_selected_at: now };
                }

                const { data: updatedSession, error: updateError } = await db
                    .from('guest_menu_sessions' as any)
                    .update(patch)
                    .eq('id', existingSession.id)
                    .select('id, auth_state, user_id, started_at, last_seen_at')
                    .single();

                if (updateError) {
                    return NextResponse.json({ error: updateError.message }, { status: 500 });
                }

                return NextResponse.json({
                    data: {
                        session_id: updatedSession.id,
                        auth_state: updatedSession.auth_state,
                        is_authenticated: updatedSession.auth_state === 'authenticated',
                    },
                });
            }
        }

        const { data: createdSession, error: insertError } = await db
            .from('guest_menu_sessions' as any)
            .insert({
                restaurant_id: guestContext.data.restaurantId,
                table_id: guestContext.data.tableId,
                table_number: guestContext.data.tableNumber,
                slug: guestContext.data.slug,
                source: parsed.data.source ?? 'qr',
                auth_state: authState,
                user_id: user?.id ?? null,
                converted_at: authState === 'authenticated' ? now : null,
                metadata: parsed.data.skip_selected ? { skip_selected_at: now } : {},
            })
            .select('id, auth_state')
            .single();

        if (insertError || !createdSession) {
            return NextResponse.json(
                { error: insertError?.message ?? 'Failed to create session.' },
                { status: 500 }
            );
        }

        return NextResponse.json({
            data: {
                session_id: createdSession.id,
                auth_state: createdSession.auth_state,
                is_authenticated: createdSession.auth_state === 'authenticated',
            },
        });
    } catch (error) {
        return NextResponse.json(
            {
                error: 'Internal server error',
                details: error instanceof Error ? error.message : 'Unknown error',
            },
            { status: 500 }
        );
    }
}

import { z } from 'zod';
import { apiError, apiSuccess } from '@/lib/api/response';
import { getAuthenticatedUser, getAuthorizedRestaurantContext } from '@/lib/api/authz';
import { parseJsonBody } from '@/lib/api/validation';
import { writeAuditLog } from '@/lib/api/audit';
import { redisRateLimiters } from '@/lib/security';

const GuestIdSchema = z.string().uuid();

const UpdateGuestSchema = z
    .object({
        name: z.string().trim().min(1).max(140).optional(),
        language: z.enum(['en', 'am']).optional(),
        tags: z.array(z.string().trim().min(1).max(40)).max(20).optional(),
        is_vip: z.boolean().optional(),
        notes: z.string().trim().max(1000).nullable().optional(),
    })
    .refine(value => Object.keys(value).length > 0, {
        message: 'At least one field is required',
    });

export async function GET(
    _request: Request,
    routeContext: { params: Promise<{ guestId: string }> }
) {
    const auth = await getAuthenticatedUser();
    if (!auth.ok) {
        return auth.response;
    }

    const context = await getAuthorizedRestaurantContext(auth.user.id, { phase: 'p1' });
    if (!context.ok) {
        return context.response;
    }

    const { guestId } = await routeContext.params;
    const guestIdParsed = GuestIdSchema.safeParse(guestId);
    if (!guestIdParsed.success) {
        return apiError('Invalid guest id', 400, 'INVALID_GUEST_ID', guestIdParsed.error.flatten());
    }

    const { data, error } = await context.supabase
        .from('guests')
        .select('*')
        .eq('id', guestIdParsed.data)
        .eq('restaurant_id', context.restaurantId)
        .maybeSingle();

    if (error) {
        return apiError('Failed to fetch guest', 500, 'GUEST_FETCH_FAILED', error.message);
    }
    if (!data) {
        return apiError('Guest not found', 404, 'GUEST_NOT_FOUND');
    }

    return apiSuccess(data);
}

export async function PATCH(
    request: Request,
    routeContext: { params: Promise<{ guestId: string }> }
) {
    // Apply rate limiting for guest mutations
    const rateLimitResponse = await redisRateLimiters.guestCreate(request as any);
    if (rateLimitResponse) {
        return rateLimitResponse;
    }

    const auth = await getAuthenticatedUser();
    if (!auth.ok) {
        return auth.response;
    }

    const context = await getAuthorizedRestaurantContext(auth.user.id, { phase: 'p1' });
    if (!context.ok) {
        return context.response;
    }

    const { guestId } = await routeContext.params;
    const guestIdParsed = GuestIdSchema.safeParse(guestId);
    if (!guestIdParsed.success) {
        return apiError('Invalid guest id', 400, 'INVALID_GUEST_ID', guestIdParsed.error.flatten());
    }

    const parsed = await parseJsonBody(request, UpdateGuestSchema);
    if (!parsed.success) {
        return parsed.response;
    }

    const { data: existing, error: existingError } = await context.supabase
        .from('guests')
        .select('id, name, language, tags, is_vip, notes')
        .eq('id', guestIdParsed.data)
        .eq('restaurant_id', context.restaurantId)
        .maybeSingle();

    if (existingError) {
        return apiError('Failed to load guest', 500, 'GUEST_FETCH_FAILED', existingError.message);
    }
    if (!existing) {
        return apiError('Guest not found', 404, 'GUEST_NOT_FOUND');
    }

    const payload: Record<string, unknown> = {
        updated_at: new Date().toISOString(),
    };
    if (parsed.data.name !== undefined) {
        payload.name = parsed.data.name;
    }
    if (parsed.data.language !== undefined) {
        payload.language = parsed.data.language;
    }
    if (parsed.data.tags !== undefined) {
        payload.tags = parsed.data.tags;
    }
    if (parsed.data.is_vip !== undefined) {
        payload.is_vip = parsed.data.is_vip;
    }
    if (parsed.data.notes !== undefined) {
        payload.notes = parsed.data.notes;
    }

    const { data, error } = await context.supabase
        .from('guests')
        .update(payload)
        .eq('id', guestIdParsed.data)
        .eq('restaurant_id', context.restaurantId)
        .select('*')
        .single();

    if (error) {
        return apiError('Failed to update guest', 500, 'GUEST_UPDATE_FAILED', error.message);
    }

    await writeAuditLog(context.supabase, {
        restaurant_id: context.restaurantId,
        user_id: auth.user.id,
        action: 'guest_updated',
        entity_type: 'guest',
        entity_id: guestIdParsed.data,
        old_value: {
            name: existing.name,
            language: existing.language,
            tags: existing.tags,
            is_vip: existing.is_vip,
            notes: existing.notes,
        },
        new_value: {
            name: data.name,
            language: data.language,
            tags: data.tags,
            is_vip: data.is_vip,
            notes: data.notes,
        },
        metadata: { source: 'merchant_dashboard' },
    });

    return apiSuccess(data);
}

import { z } from 'zod';
import { apiError, apiSuccess } from '@/lib/api/response';
import { getAuthenticatedUser, getAuthorizedRestaurantContext } from '@/lib/api/authz';
import { parseJsonBody } from '@/lib/api/validation';
import { writeAuditLog } from '@/lib/api/audit';

const CreateHappyHourSchema = z.object({
    name: z.string().trim().min(1).max(120),
    name_am: z.string().trim().max(120).optional().nullable(),
    description: z.string().trim().max(500).optional().nullable(),
    description_am: z.string().trim().max(500).optional().nullable(),
    is_active: z.boolean().optional().default(true),
    schedule_days: z
        .array(z.enum(['mon', 'tue', 'wed', 'thu', 'fri', 'sat', 'sun']))
        .optional()
        .default(['mon', 'tue', 'wed', 'thu', 'fri', 'sat', 'sun']),
    schedule_start_time: z
        .string()
        .regex(/^([01]\d|2[0-3]):([0-5]\d)$/, 'Time must be in HH:MM format'),
    schedule_end_time: z
        .string()
        .regex(/^([01]\d|2[0-3]):([0-5]\d)$/, 'Time must be in HH:MM format'),
    discount_percentage: z.number().int().min(0).max(10000).optional().nullable(),
    discount_fixed_amount: z.number().int().min(0).optional().nullable(),
    applies_to: z.enum(['order', 'item', 'category']).default('order'),
    target_category_id: z.string().uuid().optional().nullable(),
    target_menu_item_ids: z.array(z.string().uuid()).optional().default([]),
    priority: z.number().int().min(0).optional().default(0),
    requires_manager_pin: z.boolean().optional().default(false),
});

const _UpdateHappyHourSchema = CreateHappyHourSchema.partial();

export async function GET() {
    const auth = await getAuthenticatedUser();
    if (!auth.ok) {
        return auth.response;
    }

    const context = await getAuthorizedRestaurantContext(auth.user.id, { phase: 'p1' });
    if (!context.ok) {
        return context.response;
    }

    try {
        const db = context.supabase as any;
        const { data, error } = await db
            .from('happy_hour_schedules')
            .select('*')
            .eq('restaurant_id', context.restaurantId)
            .order('priority', { ascending: false })
            .order('created_at', { ascending: false });

        if (error) {
            return apiError(
                'Failed to load happy hour schedules',
                500,
                'HAPPY_HOUR_FETCH_FAILED',
                error.message
            );
        }

        return apiSuccess({ happy_hours: data ?? [] });
    } catch (error) {
        return apiError(
            'Failed to load happy hour schedules',
            500,
            'HAPPY_HOUR_FETCH_FAILED',
            error instanceof Error ? error.message : 'Unknown error'
        );
    }
}

export async function POST(request: Request) {
    const auth = await getAuthenticatedUser();
    if (!auth.ok) {
        return auth.response;
    }

    const context = await getAuthorizedRestaurantContext(auth.user.id, { phase: 'p1' });
    if (!context.ok) {
        return context.response;
    }

    const parsed = await parseJsonBody(request, CreateHappyHourSchema);
    if (!parsed.success) {
        return parsed.response;
    }

    // Validate time range
    if (parsed.data.schedule_start_time >= parsed.data.schedule_end_time) {
        return apiError('End time must be after start time', 400, 'HAPPY_HOUR_INVALID_TIME');
    }

    // Validate that at least one discount type is provided
    if (!parsed.data.discount_percentage && !parsed.data.discount_fixed_amount) {
        return apiError(
            'Either discount_percentage or discount_fixed_amount is required',
            400,
            'HAPPY_HOUR_DISCOUNT_REQUIRED'
        );
    }

    // Validate applies_to for category
    if (parsed.data.applies_to === 'category' && !parsed.data.target_category_id) {
        return apiError(
            'target_category_id is required for category-based happy hour',
            400,
            'HAPPY_HOUR_CATEGORY_REQUIRED'
        );
    }

    const db = context.supabase as any;
    const { data, error } = await db
        .from('happy_hour_schedules')
        .insert({
            restaurant_id: context.restaurantId,
            created_by: auth.user.id,
            ...parsed.data,
        })
        .select('*')
        .single();

    if (error || !data) {
        return apiError(
            'Failed to create happy hour',
            500,
            'HAPPY_HOUR_CREATE_FAILED',
            error?.message
        );
    }

    await writeAuditLog(context.supabase, {
        restaurant_id: context.restaurantId,
        user_id: auth.user.id,
        action: 'happy_hour_created',
        entity_type: 'happy_hour_schedule',
        entity_id: data.id,
        metadata: { name: data.name },
    });

    return apiSuccess({ happy_hour: data }, 201);
}

/**
 * Health Check API Endpoint
 *
 * Addresses CRIT-08 from ENTERPRISE_MASTER_BLUEPRINT Section 13
 * Provides comprehensive health status for monitoring and observability.
 *
 * Monitors:
 * - Database connectivity (Supabase)
 * - Redis connectivity (Upstash)
 * - QStash availability (job queue)
 * - Environment configuration
 * - Payment providers (Chapa, Telebirr)
 * - Circuit breaker status
 * - Performance metrics
 *
 * Used by Better Uptime for monitoring with Telegram alerting on non-200.
 *
 * @see docs/1. Engineering Foundation/0. ENTERPRISE_MASTER_BLUEPRINT.md - Sprint 1.7
 */

import { NextRequest, NextResponse } from 'next/server';
import { createClient } from '@/lib/supabase/server';
import { getPoolConfig } from '@/lib/supabase/pool';
import { circuitBreakerRegistry } from '@/lib/api/circuit-breaker';
import { performanceMetricsStore, getPerformanceSummary } from '@/lib/monitoring/performance';
import { gracefulServiceRegistry } from '@/lib/api/graceful-degradation';

/**
 * Payment provider health check result
 */
interface PaymentProviderHealth {
    name: string;
    status: 'pass' | 'fail' | 'not_configured';
    latency_ms?: number;
    message?: string;
}

/**
 * Circuit breaker health status
 */
interface CircuitBreakerHealth {
    name: string;
    state: 'CLOSED' | 'OPEN' | 'HALF_OPEN';
    failureCount: number;
}

/**
 * Performance health summary
 */
interface PerformanceHealth {
    totalOperations: number;
    slowOperations: number;
    criticalOperations: number;
    alerts: Array<{ type: string; message: string; severity: string }>;
}

/**
 * Health check response interface
 * MED-025: Enhanced with payment providers, circuit breakers, and performance metrics
 */
interface HealthStatus {
    status: 'healthy' | 'unhealthy' | 'degraded';
    timestamp: string;
    uptime: number;
    version: string;
    commit?: string;
    checks: {
        database: {
            status: 'pass' | 'fail';
            latency_ms?: number;
            message?: string;
        };
        redis: {
            status: 'pass' | 'fail' | 'not_configured';
            latency_ms?: number;
            message?: string;
        };
        supabase: {
            status: 'pass' | 'fail';
            latency_ms?: number;
            message?: string;
            pool_enabled?: boolean;
            pool_mode?: string;
            pool_size?: number;
        };
        qstash: {
            status: 'pass' | 'fail' | 'not_configured';
            latency_ms?: number;
            message?: string;
        };
        memory: {
            status: 'pass' | 'fail';
            used_mb?: number;
            limit_mb?: number;
            message?: string;
        };
        environment: {
            status: 'pass' | 'fail';
            configured: string[];
            missing: string[];
        };
        /** MED-025: Payment providers health */
        payments?: PaymentProviderHealth[];
        /** MED-025: Circuit breaker status */
        circuitBreakers?: CircuitBreakerHealth[];
        /** MED-025: Performance metrics */
        performance?: PerformanceHealth;
    };
    region?: string;
}

/**
 * Time when the server started
 * Note: In serverless, this resets per cold start
 */
const startTime = Date.now();

/**
 * Required environment variables for critical functionality
 */
const REQUIRED_ENV_VARS = [
    'NEXT_PUBLIC_SUPABASE_URL',
    'NEXT_PUBLIC_SUPABASE_PUBLISHABLE_KEY',
    'SUPABASE_SECRET_KEY',
];

/**
 * Optional environment variables for enhanced features
 */
const OPTIONAL_ENV_VARS = [
    'DATABASE_URL',
    'REDIS_URL',
    'UPSTASH_REDIS_REST_URL',
    'UPSTASH_REDIS_REST_TOKEN',
    'QSTASH_TOKEN',
    'QSTASH_CURRENT_SIGNING_KEY',
    'CHAPA_SECRET_KEY',
    'CHAPA_WEBHOOK_SECRET',
    'SENTRY_AUTH_TOKEN',
    'TELEGRAM_BOT_TOKEN',
    'TELEGRAM_ALERT_CHAT_ID',
    // Connection pool env vars
    'NEXT_PUBLIC_SUPABASE_POOLER_ENABLED',
    'SUPABASE_POOL_MODE',
    'SUPABASE_POOL_SIZE',
    'SUPABASE_POOL_MAX_CLIENTS',
    'SUPABASE_POOL_CONNECTION_TIMEOUT',
    'SUPABASE_POOL_IDLE_TIMEOUT',
    'SUPABASE_POOLER_URL',
];

/**
 * Check database connectivity
 */
async function checkDatabase(): Promise<{
    status: 'pass' | 'fail';
    latency_ms?: number;
    message?: string;
}> {
    try {
        const start = Date.now();
        const supabase = await createClient();

        // Simple query to check connectivity
        const { error } = await supabase.from('restaurants').select('id').limit(1);

        const latency_ms = Date.now() - start;

        if (error && error.code !== 'PGRST116') {
            // PGRST116 = no rows found, which is fine
            return {
                status: 'fail',
                latency_ms,
                message: error.message,
            };
        }

        return {
            status: 'pass',
            latency_ms,
            message: 'Database connected',
        };
    } catch (error) {
        return {
            status: 'fail',
            message: error instanceof Error ? error.message : 'Unknown error',
        };
    }
}

/**
 * Check Supabase connectivity (alias for database check)
 * This is a separate check as per requirements
 */
async function checkSupabase(): Promise<{
    status: 'pass' | 'fail';
    latency_ms?: number;
    message?: string;
    pool_enabled?: boolean;
    pool_mode?: string;
    pool_size?: number;
}> {
    // Supabase uses the same connection as database
    const dbCheck = await checkDatabase();

    // Get pool configuration
    const poolConfig = getPoolConfig();

    return {
        status: dbCheck.status,
        latency_ms: dbCheck.latency_ms,
        message: dbCheck.message,
        pool_enabled: poolConfig.enabled,
        pool_mode: poolConfig.mode,
        pool_size: poolConfig.poolSize,
    };
}
async function checkRedis(): Promise<{
    status: 'pass' | 'fail' | 'not_configured';
    latency_ms?: number;
    message?: string;
}> {
    const redisUrl = process.env.UPSTASH_REDIS_REST_URL;
    const redisToken = process.env.UPSTASH_REDIS_REST_TOKEN;

    if (!redisUrl || !redisToken) {
        // Fallback to legacy Redis URL
        const legacyRedisUrl = process.env.REDIS_URL;
        if (!legacyRedisUrl) {
            return { status: 'not_configured', message: 'Redis not configured' };
        }
        // Legacy Redis doesn't support HTTP ping, just check URL exists
        return { status: 'pass', message: 'Redis configured (legacy URL)' };
    }

    try {
        const start = Date.now();

        // Use Upstash REST API to ping Redis
        // @see https://upstash.com/docs/redis/features/restapi
        const response = await fetch(`${redisUrl}/ping`, {
            method: 'GET',
            headers: {
                Authorization: `Bearer ${redisToken}`,
            },
        });

        const latency_ms = Date.now() - start;

        if (!response.ok) {
            const errorText = await response.text();
            return {
                status: 'fail',
                latency_ms,
                message: `Redis ping failed: ${response.status} ${errorText}`,
            };
        }

        const result = await response.text();
        if (result !== 'PONG' && result !== '"PONG"' && !result.includes('PONG')) {
            return {
                status: 'fail',
                latency_ms,
                message: `Unexpected Redis response: ${result}`,
            };
        }

        return {
            status: 'pass',
            latency_ms,
            message: 'Redis connected',
        };
    } catch (error) {
        return {
            status: 'fail',
            message: error instanceof Error ? error.message : 'Unknown error',
        };
    }
}

/**
 * Check QStash availability
 * QStash is critical for background jobs: payment retries, ERCA submissions, EOD reports
 */
async function checkQStash(): Promise<{
    status: 'pass' | 'fail' | 'not_configured';
    latency_ms?: number;
    message?: string;
}> {
    const qstashToken = process.env.QSTASH_TOKEN;

    if (!qstashToken) {
        return { status: 'not_configured', message: 'QStash not configured' };
    }

    try {
        const start = Date.now();

        // Query QStash API to check queue status
        // @see https://upstash.com/docs/qstash/api/overview
        const response = await fetch('https://qstash.upstash.io/v2/messages', {
            method: 'GET',
            headers: {
                Authorization: `Bearer ${qstashToken}`,
            },
        });

        const latency_ms = Date.now() - start;

        if (!response.ok) {
            const errorText = await response.text();
            // 401 = invalid token
            // 403 = token doesn't have access
            // 5xx = QStash service issue
            return {
                status: 'fail',
                latency_ms,
                message: `QStash check failed: ${response.status} ${errorText}`,
            };
        }

        // Response is OK, QStash is available
        return {
            status: 'pass',
            latency_ms,
            message: 'QStash connected',
        };
    } catch (error) {
        return {
            status: 'fail',
            message: error instanceof Error ? error.message : 'Unknown error',
        };
    }
}

/**
 * Check environment variables configuration
 */
function checkEnvironment(): {
    status: 'pass' | 'fail';
    configured: string[];
    missing: string[];
} {
    const configured: string[] = [];
    const missing: string[] = [];

    // Check required variables
    for (const varName of REQUIRED_ENV_VARS) {
        if (process.env[varName]) {
            configured.push(varName);
        } else {
            missing.push(varName);
        }
    }

    // Check optional variables
    for (const varName of OPTIONAL_ENV_VARS) {
        if (process.env[varName]) {
            configured.push(varName);
        }
    }

    return {
        status: missing.length > 0 ? 'fail' : 'pass',
        configured,
        missing,
    };
}

/**
 * Check memory usage
 * In serverless environments, memory usage is per-request
 * but we can still check the process memory footprint
 */
function checkMemory(): {
    status: 'pass' | 'fail';
    used_mb?: number;
    limit_mb?: number;
    message?: string;
} {
    // In Node.js/Next.js serverless, we can check memory usage
    // Note: In serverless, memory limit is set at deployment time
    const memoryUsage = process.memoryUsage();

    // Convert bytes to MB
    const used_mb = Math.round(memoryUsage.heapUsed / (1024 * 1024));
    const limit_mb = process.env.VERCEL_MEMORY_LIMIT
        ? parseInt(process.env.VERCEL_MEMORY_LIMIT, 10) / (1024 * 1024)
        : Math.round(memoryUsage.heapTotal / (1024 * 1024));

    // Default limit for Vercel is 1024MB (1GB) for Pro
    const defaultLimit = 1024;
    const effectiveLimit = limit_mb || defaultLimit;

    // Check if memory usage is within acceptable limits (80% threshold)
    const usagePercent = (used_mb / effectiveLimit) * 100;

    if (usagePercent > 90) {
        return {
            status: 'fail',
            used_mb,
            limit_mb: effectiveLimit,
            message: `Memory usage critical: ${usagePercent.toFixed(1)}%`,
        };
    }

    if (usagePercent > 80) {
        return {
            status: 'pass',
            used_mb,
            limit_mb: effectiveLimit,
            message: `Memory usage high: ${usagePercent.toFixed(1)}%`,
        };
    }

    return {
        status: 'pass',
        used_mb,
        limit_mb: effectiveLimit,
        message: `Memory usage normal: ${usagePercent.toFixed(1)}%`,
    };
}

/**
