export async function POST(request: NextRequest): Promise<NextResponse> {
    if (!isAuthorized(request)) {
        return NextResponse.json(
            {
                error: {
                    code: 'UNAUTHORIZED_JOB',
                    message: 'Job request is not authorized',
                },
            },
            { status: 401 }
        );
    }

    const body = await request.json().catch(() => null);
    const parsed = ERCAJobPayloadSchema.safeParse(body);

    if (!parsed.success) {
        return NextResponse.json(
            {
                error: {
                    code: 'INVALID_JOB_PAYLOAD',
                    message: 'Invalid ERCA job payload',
                    details: parsed.error.flatten(),
                },
            },
            { status: 400 }
        );
    }

    const { order_id, restaurant_id, trigger } = parsed.data;

    // Generate ERCA-compliant invoice
    const invoiceResult = await generateERCAInvoice(order_id, restaurant_id);

    if (!invoiceResult.success) {
        // Store failed attempt
        await storeERCAInvoice(order_id, restaurant_id, null, '', 'failed').catch(console.error);

        return NextResponse.json({
            data: {
                order_id,
                restaurant_id,
                status: 'failed',
                error: invoiceResult.error,
            },
        });
    }

    // Submit to ERCA
    const admin = createServiceRoleClient();
    const { data: restaurant } = await admin
        .from('restaurants')
        .select('vat_number')
        .eq('id', restaurant_id)
        .maybeSingle();

    const submitResult = await submitToERCA(
        invoiceResult.invoiceData,
        restaurant?.vat_number || ''
    );

    // Store the invoice record
    await storeERCAInvoice(
        order_id,
        restaurant_id,
        invoiceResult.invoiceData,
        submitResult.reference || '',
        submitResult.success ? 'submitted' : 'failed'
    );

    return NextResponse.json({
        data: {
            order_id,
            restaurant_id,
            trigger,
            status: submitResult.success ? 'submitted' : 'failed',
            invoice_number: invoiceResult.invoiceData?.invoiceNumber,
            erca_reference: submitResult.reference,
            error: submitResult.error,
        },
    });
}

/**
 * POST /api/jobs/payments/retry
 *
 * Job handler for payment retry logic.
 * Processes failed payments and attempts to retry/verify them.
 *
 * This is triggered via QStash when:
 * 1. A payment webhook indicates failure
 * 2. A manual retry is requested
 * 3. A scheduled retry check runs
 */
import { NextRequest, NextResponse } from 'next/server';
import { z } from 'zod';
import { createPaymentLifecycleEvent } from '@/lib/events/contracts';
import { createServiceRoleClient } from '@/lib/supabase/service-role';
import { verifyChapaTransaction } from '@/lib/services/chapaService';
import { processPaymentLifecycleEvent } from '@/lib/payments/payment-event-consumer';

const PaymentRetryJobSchema = z.object({
    payment_session_id: z.string().uuid().optional(),
    order_id: z.string().uuid().optional(),
    provider: z.enum(['chapa']).default('chapa'),
    provider_transaction_id: z.string().optional(),
    retry_count: z.number().int().min(0).max(5).default(0),
    trigger: z.enum(['webhook_failed', 'manual', 'scheduled']).default('scheduled'),
});

function isAuthorized(request: NextRequest): boolean {
    const configuredKey = process.env.QSTASH_TOKEN;
    if (!configuredKey) {
        return process.env.NODE_ENV !== 'production';
    }
    return request.headers.get('x-gebeta-job-key') === configuredKey;
}

/**
 * Verify and process a Chapa payment
 */
async function verifyAndProcessChapaPayment(
    txRef: string,
    orderId: string | null,
    restaurantId: string
): Promise<{
    success: boolean;
    status: 'completed' | 'failed' | 'pending' | 'error';
    error?: string;
    data?: any;
}> {
    try {
        // Verify the transaction with Chapa
        const verificationResult = await verifyChapaTransaction(txRef);

        if (verificationResult.status !== 'success') {
            return {
                success: false,
                status: 'error',
                error: verificationResult.message || 'Verification failed',
            };
        }

        const data = verificationResult.data;
        const paymentStatus = data?.status === 'success' ? 'completed' : 'failed';

        // Create and process the payment lifecycle event
        const event = createPaymentLifecycleEvent(paymentStatus, {
            restaurant_id: restaurantId,
            order_id: orderId,
            payment_id: null,
            payment_session_id: null,
            provider: 'chapa',
            provider_transaction_id: txRef,
            idempotency_key: `retry-${txRef}-${Date.now()}`,
            status: paymentStatus,
            amount: data?.amount ? Math.round(parseFloat(data.amount) * 100) : null,
            currency: data?.currency || 'ETB',
            metadata: {
                retry: true,
                verified_at: new Date().toISOString(),
            },
            raw_payload: data || {},
        });

        await processPaymentLifecycleEvent(event);

        return {
            success: true,
            status: paymentStatus,
            data,
        };
    } catch (error) {
        return {
            success: false,
            status: 'error',
            error: error instanceof Error ? error.message : 'Unknown error',
        };
    }
}

/**
 * Check if payment session can be retried
 */
async function checkRetryEligibility(paymentSessionId: string): Promise<{
    eligible: boolean;
    reason?: string;
    txRef?: string;
    orderId?: string;
    restaurantId?: string;
    previousAttempts?: number;
}> {
    const admin = createServiceRoleClient();

    const { data: session, error } = await admin
        .from('payment_sessions')
        .select('id, order_id, restaurant_id, provider_reference, status, metadata')
        .eq('id', paymentSessionId)
        .maybeSingle();

    if (error || !session) {
        return { eligible: false, reason: 'Payment session not found' };
    }

    if (session.status === 'captured' || session.status === 'completed') {
        return { eligible: false, reason: 'Payment already completed' };
    }

    const previousAttempts = (session.metadata as any)?.retry_count || 0;
    if (previousAttempts >= 5) {
        return { eligible: false, reason: 'Max retry attempts reached' };
    }

    return {
        eligible: true,
        txRef: session.provider_reference,
        orderId: session.order_id,
        restaurantId: session.restaurant_id,
        previousAttempts,
    };
}

export async function POST(request: NextRequest): Promise<NextResponse> {
    if (!isAuthorized(request)) {
        return NextResponse.json(
            {
                error: {
                    code: 'UNAUTHORIZED_JOB',
                    message: 'Job request is not authorized',
                },
            },
            { status: 401 }
        );
    }

    const body = await request.json().catch(() => null);
    const parsed = PaymentRetryJobSchema.safeParse(body);

    if (!parsed.success) {
        return NextResponse.json(
            {
                error: {
                    code: 'INVALID_JOB_PAYLOAD',
                    message: 'Invalid payment retry payload',
                    details: parsed.error.flatten(),
                },
            },
            { status: 400 }
        );
    }

    const {
        payment_session_id,
        order_id,
        provider,
        provider_transaction_id,
        retry_count,
        ..._rest
    } = parsed.data;
    let resolvedOrderId = order_id;
    let resolvedProviderTxRef = provider_transaction_id;
    const admin = createServiceRoleClient();

    // If payment_session_id provided, check eligibility
    if (payment_session_id) {
        const eligibility = await checkRetryEligibility(payment_session_id);

        if (!eligibility.eligible) {
            return NextResponse.json({
                data: {
                    payment_session_id,
                    status: 'skipped',
                    reason: eligibility.reason,
                },
            });
        }

        if (eligibility.txRef) {
            resolvedProviderTxRef = eligibility.txRef;
        }
        if (eligibility.orderId) {
            resolvedOrderId = eligibility.orderId;
        }
    }

    // If we have a transaction ID, verify with provider
    if (provider === 'chapa' && resolvedProviderTxRef) {
        const restaurantId = resolvedOrderId
            ? (
                  await admin
                      .from('orders')
                      .select('restaurant_id')
                      .eq('id', resolvedOrderId)
                      .maybeSingle()
              )?.data?.restaurant_id
            : payment_session_id
              ? (
                    await admin
                        .from('payment_sessions')
                        .select('restaurant_id')
                        .eq('id', payment_session_id)
                        .maybeSingle()
                )?.data?.restaurant_id
              : null;

        if (!restaurantId) {
            return NextResponse.json(
                {
                    error: {
                        code: 'RESTAURANT_NOT_FOUND',
                        message: 'Could not determine restaurant for payment retry',
                    },
                },
                { status: 400 }
            );
        }

        const result = await verifyAndProcessChapaPayment(
            resolvedProviderTxRef!,
            resolvedOrderId || null,
            restaurantId
        );

        // Update retry count in payment session
        if (payment_session_id) {
            const { data: session } = await admin
                .from('payment_sessions')
                .select('metadata')
                .eq('id', payment_session_id)
                .maybeSingle();

            const currentRetryCount = (session?.metadata as any)?.retry_count || 0;

            await admin
                .from('payment_sessions')
                .update({
                    metadata: {
                        ...((session?.metadata as any) || {}),
                        retry_count: currentRetryCount + 1,
                        last_retry_at: new Date().toISOString(),
                        last_retry_status: result.status,
                    },
                })
                .eq('id', payment_session_id);
        }

        // If failed and not max retries, schedule another retry
        if (!result.success && retry_count < 5) {
            // Could queue another retry job here with exponential backoff
            // For now, just return the failure status
        }

        return NextResponse.json({
            data: {
                payment_session_id,
                order_id: resolvedOrderId,
                provider,
                provider_transaction_id: resolvedProviderTxRef,
                status: result.status,
                retry_count: retry_count + 1,
                error: result.error,
            },
        });
    }

    return NextResponse.json(
        {
            error: {
                code: 'INSUFFICIENT_DATA',
                message: 'payment_session_id or provider_transaction_id required',
            },
        },
        { status: 400 }
    );
}

import { z } from 'zod';
import { apiError, apiSuccess } from '@/lib/api/response';
import { getAuthenticatedUser, getAuthorizedRestaurantContext } from '@/lib/api/authz';
import { parseJsonBody } from '@/lib/api/validation';
import { isIdempotencyKeyValid, resolveIdempotencyKey } from '@/lib/api/idempotency';
import { writeAuditLog } from '@/lib/api/audit';

const KdsItemActionSchema = z.object({
    action: z.enum(['start', 'hold', 'ready', 'recall']),
    reason: z.string().trim().min(2).max(240).optional(),
});

const KdsItemIdParamSchema = z.object({
    kdsItemId: z.string().uuid(),
});

const ALLOWED_TRANSITIONS: Record<string, string[]> = {
    queued: ['start', 'hold'],
    in_progress: ['hold', 'ready'],
    on_hold: ['start'],
    ready: ['recall'],
    recalled: ['start', 'hold', 'ready'],
};

const RECALL_OVERRIDE_ROLES = new Set(['owner', 'admin', 'manager']);

function toKdsStatus(action: z.infer<typeof KdsItemActionSchema>['action']) {
    if (action === 'start') return 'in_progress';
    if (action === 'hold') return 'on_hold';
    if (action === 'ready') return 'ready';
    return 'recalled';
}

function toOrderItemStatus(kdsStatus: string): 'pending' | 'cooking' | 'ready' {
    if (kdsStatus === 'ready') return 'ready';
    if (kdsStatus === 'in_progress' || kdsStatus === 'recalled') return 'cooking';
    return 'pending';
}

function deriveStationStatus(
    items: Array<{ station: string; status: string }>,
    stations: string[]
): string | null {
    const scoped = items.filter(item => stations.includes(item.station));
    if (scoped.length === 0) return null;
    if (scoped.every(item => item.status === 'ready')) return 'ready';
    if (scoped.some(item => item.status === 'in_progress' || item.status === 'recalled'))
        return 'preparing';
    if (scoped.some(item => item.status === 'on_hold')) return 'acknowledged';
    return 'pending';
}

export async function POST(request: Request, context: { params: Promise<{ kdsItemId: string }> }) {
    const auth = await getAuthenticatedUser();
    if (!auth.ok) {
        return auth.response;
    }

    const restaurantContext = await getAuthorizedRestaurantContext(auth.user.id, { phase: 'p1' });
    if (!restaurantContext.ok) {
        return restaurantContext.response;
    }

    const parsedParams = KdsItemIdParamSchema.safeParse(await context.params);
    if (!parsedParams.success) {
        return apiError('Invalid item id', 400, 'INVALID_ITEM_ID', parsedParams.error.flatten());
    }

    const explicitIdempotencyKey = request.headers.get('x-idempotency-key');
    if (explicitIdempotencyKey && !isIdempotencyKeyValid(explicitIdempotencyKey)) {
        return apiError('Invalid idempotency key', 400, 'INVALID_IDEMPOTENCY_KEY');
    }
    const idempotencyKey = resolveIdempotencyKey(explicitIdempotencyKey);

    const parsedBody = await parseJsonBody(request, KdsItemActionSchema);
    if (!parsedBody.success) {
        return parsedBody.response;
    }

    const db = restaurantContext.supabase;
    const dbAny = db as any;
    const { kdsItemId } = parsedParams.data;
    const { action, reason } = parsedBody.data;

    const { data: item, error: itemError } = await dbAny
        .from('kds_order_items')
        .select('id, restaurant_id, order_id, order_item_id, station, status')
        .eq('id', kdsItemId)
        .eq('restaurant_id', restaurantContext.restaurantId)
        .maybeSingle();

    if (itemError) {
        return apiError('Failed to load KDS item', 500, 'KDS_ITEM_FETCH_FAILED', itemError.message);
    }
    if (!item) {
        return apiError('KDS item not found', 404, 'KDS_ITEM_NOT_FOUND');
    }

    const allowedActions = ALLOWED_TRANSITIONS[item.status] ?? [];
    if (!allowedActions.includes(action)) {
        return apiError(
            `Invalid item transition from "${item.status}" via "${action}"`,
            409,
            'INVALID_ITEM_TRANSITION'
        );
    }

    if (action === 'recall') {
        const [
            { data: staffRole, error: staffRoleError },
            { data: agencyRole, error: agencyRoleError },
        ] = await Promise.all([
            db
                .from('restaurant_staff')
                .select('role')
                .eq('restaurant_id', restaurantContext.restaurantId)
                .eq('user_id', auth.user.id)
                .eq('is_active', true)
                .maybeSingle(),
            db.from('agency_users').select('role').eq('user_id', auth.user.id).maybeSingle(),
        ]);

        if (staffRoleError || agencyRoleError) {
            return apiError(
                'Failed to verify recall permissions',
                500,
                'KDS_RECALL_PERMISSION_CHECK_FAILED',
                staffRoleError?.message ?? agencyRoleError?.message
            );
        }

        const staffRoleValue = String(staffRole?.role ?? '');
        const agencyRoleValue = String(agencyRole?.role ?? '');
        const canRecall = RECALL_OVERRIDE_ROLES.has(staffRoleValue) || agencyRoleValue === 'admin';

        if (!canRecall) {
            return apiError(
                'Recall is restricted to manager/expeditor override roles',
                403,
                'KDS_RECALL_FORBIDDEN'
            );
        }
    }

    const now = new Date().toISOString();
    const nextStatus = toKdsStatus(action);
    const updatePayload: Record<string, unknown> = {
        status: nextStatus,
        last_action_by: auth.user.id,
        last_action_at: now,
        updated_at: now,
    };
    if (action === 'start') updatePayload.started_at = now;
    if (action === 'hold') updatePayload.held_at = now;
    if (action === 'ready') updatePayload.ready_at = now;
    if (action === 'recall') updatePayload.recalled_at = now;

    const { data: updatedItem, error: updateError } = await dbAny
        .from('kds_order_items')
        .update(updatePayload)
        .eq('id', item.id)
        .eq('restaurant_id', restaurantContext.restaurantId)
        .select('*')
        .single();

    if (updateError || !updatedItem) {
        return apiError(
            'Failed to update KDS item',
            500,
            'KDS_ITEM_UPDATE_FAILED',
            updateError?.message
        );
    }

    const { error: eventError } = await dbAny.from('kds_item_events').insert({
        restaurant_id: restaurantContext.restaurantId,
        kds_order_item_id: updatedItem.id,
        order_id: updatedItem.order_id,
        event_type: action,
        from_status: item.status,
        to_status: updatedItem.status,
        actor_user_id: auth.user.id,
        reason: reason ?? null,
        metadata: {
            source: 'kds_web',
            idempotency_key: idempotencyKey,
        },
    });
    if (eventError) {
        return apiError(
            'Failed to write KDS item event',
            500,
            'KDS_ITEM_EVENT_FAILED',
            eventError.message
        );
    }

    if (updatedItem.order_item_id) {
        await db
            .from('order_items')
            .update({
                status: toOrderItemStatus(updatedItem.status),
                started_at: action === 'start' ? now : undefined,
                completed_at: action === 'ready' ? now : undefined,
            })
            .eq('id', updatedItem.order_item_id);
    }

    const [{ data: siblingItems }, { data: order }] = await Promise.all([
        dbAny
            .from('kds_order_items')
            .select('station, status')
            .eq('order_id', updatedItem.order_id)
            .eq('restaurant_id', restaurantContext.restaurantId),
        db
            .from('orders')
            .select('id, status, kitchen_status, bar_status')
            .eq('id', updatedItem.order_id)
            .maybeSingle(),
    ]);

    const nextOrderUpdate: Record<string, unknown> = {};
    const normalizedSiblings = (
        (siblingItems ?? []) as Array<{ station?: string; status?: string }>
    ).map(row => ({
        station: row.station ?? 'kitchen',
        status: row.status ?? 'queued',
    }));

    if (normalizedSiblings.length > 0 && order) {
        const kitchenStatus = deriveStationStatus(normalizedSiblings, [
            'kitchen',
            'dessert',
            'coffee',
        ]);
        const barStatus = deriveStationStatus(normalizedSiblings, ['bar']);
        if (kitchenStatus) nextOrderUpdate.kitchen_status = kitchenStatus;
        if (barStatus) nextOrderUpdate.bar_status = barStatus;

        const allReady = normalizedSiblings.every(row => row.status === 'ready');
        if (allReady && !['served', 'completed', 'cancelled'].includes(order.status ?? '')) {
            nextOrderUpdate.status = 'ready';
            nextOrderUpdate.completed_at = now;
        } else if (
            (action === 'start' || action === 'recall') &&
            ['pending', 'acknowledged', 'ready'].includes(order.status ?? '')
        ) {
            nextOrderUpdate.status = 'preparing';
        }

        if (Object.keys(nextOrderUpdate).length > 0) {
            nextOrderUpdate.updated_at = now;
            await db.from('orders').update(nextOrderUpdate).eq('id', updatedItem.order_id);
        }
    }

    await writeAuditLog(db, {
        restaurant_id: restaurantContext.restaurantId,
        user_id: auth.user.id,
        action: `kds_item_${action}`,
        entity_type: 'kds_order_item',
        entity_id: updatedItem.id,
        metadata: {
            source: 'kds_web',
            station: updatedItem.station,
            reason: reason ?? null,
            idempotency_key: idempotencyKey,
            order_id: updatedItem.order_id,
        },
        old_value: {
            status: item.status,
        },
        new_value: {
            status: updatedItem.status,
        },
    });

    return apiSuccess({
        item: updatedItem,
        idempotency_key: idempotencyKey,
    });
}

import { z } from 'zod';
import { apiError, apiSuccess } from '@/lib/api/response';
import { getAuthenticatedUser, getAuthorizedRestaurantContext } from '@/lib/api/authz';
import { parseJsonBody } from '@/lib/api/validation';
import { writeAuditLog } from '@/lib/api/audit';

const HandoffParamsSchema = z.object({
    orderId: z.string().uuid(),
});

const HandoffBodySchema = z.object({
    action: z.literal('bump'),
    reason: z.string().trim().min(2).max(240).optional(),
});

const EXPEDITOR_HANDOFF_ROLES = new Set(['owner', 'admin', 'manager']);

export async function POST(request: Request, context: { params: Promise<{ orderId: string }> }) {
    const auth = await getAuthenticatedUser();
    if (!auth.ok) {
        return auth.response;
    }

    const restaurantContext = await getAuthorizedRestaurantContext(auth.user.id, { phase: 'p1' });
    if (!restaurantContext.ok) {
        return restaurantContext.response;
    }

    const parsedParams = HandoffParamsSchema.safeParse(await context.params);
    if (!parsedParams.success) {
        return apiError('Invalid order id', 400, 'INVALID_ORDER_ID', parsedParams.error.flatten());
    }

    const parsedBody = await parseJsonBody(request, HandoffBodySchema);
    if (!parsedBody.success) {
        return parsedBody.response;
    }

    const db = restaurantContext.supabase;
    const dbAny = db as any;
    const { orderId } = parsedParams.data;
    const { reason } = parsedBody.data;

    const { data: staffRoleRow, error: staffRoleError } = await db
        .from('restaurant_staff')
        .select('role')
        .eq('restaurant_id', restaurantContext.restaurantId)
        .eq('user_id', auth.user.id)
        .eq('is_active', true)
        .maybeSingle();

    if (staffRoleError) {
        return apiError(
            'Failed to verify expeditor permissions',
            500,
            'EXPEDITOR_PERMISSION_CHECK_FAILED',
            staffRoleError.message
        );
    }

    const actorRole = String(staffRoleRow?.role ?? '');
    if (!EXPEDITOR_HANDOFF_ROLES.has(actorRole)) {
        return apiError(
            'Final handoff is restricted to expeditor override roles',
            403,
            'KDS_HANDOFF_FORBIDDEN'
        );
    }

    const [{ data: order, error: orderError }, { data: kdsItems, error: kdsItemsError }] =
        await Promise.all([
            db
                .from('orders')
                .select('id, status')
                .eq('id', orderId)
                .eq('restaurant_id', restaurantContext.restaurantId)
                .maybeSingle(),
            dbAny
                .from('kds_order_items')
                .select('id, status')
                .eq('order_id', orderId)
                .eq('restaurant_id', restaurantContext.restaurantId),
        ]);

    if (orderError) {
        return apiError('Failed to fetch order', 500, 'ORDER_FETCH_FAILED', orderError.message);
    }
    if (!order) {
        return apiError('Order not found', 404, 'ORDER_NOT_FOUND');
    }
    if (kdsItemsError) {
        return apiError(
            'Failed to verify KDS ticket readiness',
            500,
            'KDS_ITEMS_FETCH_FAILED',
            kdsItemsError.message
        );
    }

    const normalizedKdsItems = ((kdsItems ?? []) as Array<{ status?: string }>).map(item =>
        String(item.status ?? 'queued')
    );
    if (normalizedKdsItems.length > 0 && normalizedKdsItems.some(status => status !== 'ready')) {
        return apiError(
            'Ticket is not fully ready for final handoff',
            409,
            'KDS_HANDOFF_NOT_READY'
        );
    }

    if (['served', 'completed', 'cancelled'].includes(String(order.status ?? ''))) {
        return apiError(
            `Ticket cannot be bumped from "${order.status}"`,
            409,
            'KDS_HANDOFF_INVALID_STATE'
        );
    }
    const currentStatus = String(order.status ?? '');
    if (!currentStatus) {
        return apiError('Ticket status is invalid', 409, 'KDS_HANDOFF_INVALID_STATE');
    }

    const now = new Date().toISOString();
    const { data: updatedOrder, error: updateError } = await db
        .from('orders')
        .update({
            status: 'served',
            updated_at: now,
        })
        .eq('id', order.id)
        .eq('restaurant_id', restaurantContext.restaurantId)
        .eq('status', currentStatus)
        .select('*')
        .single();

    if (updateError || !updatedOrder) {
        return apiError(
            'Failed to complete final handoff',
            500,
            'KDS_HANDOFF_UPDATE_FAILED',
            updateError?.message
        );
    }

    await Promise.all([
        dbAny.from('order_events').insert({
            restaurant_id: restaurantContext.restaurantId,
            order_id: order.id,
            event_type: 'status_changed',
            from_status: currentStatus,
            to_status: 'served',
            actor_user_id: auth.user.id,
            metadata: {
                source: 'kds_expeditor_handoff',
                action: 'bump',
                reason: reason ?? null,
            },
        }),
        writeAuditLog(db, {
            restaurant_id: restaurantContext.restaurantId,
            user_id: auth.user.id,
            action: 'kds_ticket_bumped',
            entity_type: 'order',
            entity_id: order.id,
            metadata: {
                source: 'kds_expeditor_handoff',
                action: 'bump',
                reason: reason ?? null,
            },
            old_value: { status: currentStatus },
            new_value: { status: 'served' },
        }),
    ]);

    return apiSuccess({
        order: updatedOrder,
    });
}

import { z } from 'zod';
import { apiError, apiSuccess } from '@/lib/api/response';
import { getAuthenticatedUser, getAuthorizedRestaurantContext } from '@/lib/api/authz';
import { parseJsonBody } from '@/lib/api/validation';
import { writeAuditLog } from '@/lib/api/audit';
import {
    DEFAULT_KDS_PRINT_POLICY,
    dispatchKdsPrintJob,
    normalizeKdsPrintPolicy,
} from '@/lib/kds/printer';

const PrintTicketBodySchema = z.object({
    reason: z.string().trim().min(2).max(120).optional().default('manual_print'),
});

export async function POST(request: Request, context: { params: Promise<{ orderId: string }> }) {
    const auth = await getAuthenticatedUser();
    if (!auth.ok) {
        return auth.response;
    }

    const restaurantContext = await getAuthorizedRestaurantContext(auth.user.id, { phase: 'p1' });
    if (!restaurantContext.ok) {
        return restaurantContext.response;
    }

    const { orderId } = await context.params;
    const parsedBody = await parseJsonBody(request, PrintTicketBodySchema);
    if (!parsedBody.success) return parsedBody.response;

    const db = restaurantContext.supabase;

    const [{ data: order, error: orderError }, { data: restaurant, error: restaurantError }] =
        await Promise.all([
            db
                .from('orders')
                .select('id, restaurant_id, order_number, table_number')
                .eq('restaurant_id', restaurantContext.restaurantId)
                .eq('id', orderId)
                .maybeSingle(),
            db
                .from('restaurants')
                .select('settings')
                .eq('id', restaurantContext.restaurantId)
                .maybeSingle(),
        ]);

    if (orderError) {
        return apiError(
            'Failed to load order for print',
            500,
            'KDS_PRINT_ORDER_FETCH_FAILED',
            orderError.message
        );
    }
    if (!order) {
        return apiError('Order not found', 404, 'ORDER_NOT_FOUND');
    }
    if (restaurantError) {
        return apiError(
            'Failed to load printer settings',
            500,
            'KDS_PRINT_SETTINGS_FETCH_FAILED',
            restaurantError.message
        );
    }

    const settings = (restaurant?.settings ?? {}) as Record<string, unknown>;
    const kds = (settings.kds ?? {}) as Record<string, unknown>;
    const policy = normalizeKdsPrintPolicy(
        (kds.print_policy as Record<string, unknown> | undefined) ?? DEFAULT_KDS_PRINT_POLICY
    );

    if (policy.mode === 'off') {
        return apiError('Printer fallback is disabled', 409, 'KDS_PRINT_MODE_OFF');
    }

    const { data: rows, error: itemsError } = await (db as any)
        .from('kds_order_items')
        .select('name, quantity, station, notes, status')
        .eq('restaurant_id', restaurantContext.restaurantId)
        .eq('order_id', order.id)
        .order('created_at', { ascending: true });

    if (itemsError) {
        return apiError(
            'Failed to load ticket lines for print',
            500,
            'KDS_PRINT_ITEMS_FETCH_FAILED',
            itemsError.message
        );
    }

    const payload = {
        restaurantId: restaurantContext.restaurantId,
        orderId: order.id,
        orderNumber: String(order.order_number ?? order.id),
        tableNumber: order.table_number ?? null,
        firedAt: new Date().toISOString(),
        reason: parsedBody.data.reason,
        items: ((rows ?? []) as Array<Record<string, unknown>>).map(item => ({
            name: String(item.name ?? 'Item'),
            quantity: Number(item.quantity ?? 1),
            station: item.station ? String(item.station) : null,
            notes: item.notes ? String(item.notes) : null,
            status: item.status ? String(item.status) : null,
        })),
    };

    try {
        const result = await dispatchKdsPrintJob(policy, payload);

        await writeAuditLog(db, {
            restaurant_id: restaurantContext.restaurantId,
            user_id: auth.user.id,
            action: 'kds_ticket_printed',
            entity_type: 'order',
            entity_id: order.id,
            metadata: {
                source: 'kds_print_endpoint',
                reason: parsedBody.data.reason,
                provider: result.provider,
                mode: policy.mode,
                attempts: result.attempts,
                event_id: result.event_id,
                bridge_status: result.bridge_status ?? null,
            },
            new_value: {
                provider: result.provider,
                dispatched: result.dispatched,
                reason: result.reason,
                attempts: result.attempts,
                event_id: result.event_id,
                bridge_status: result.bridge_status ?? null,
            },
        });

        return apiSuccess({
            printed: result.dispatched,
            provider: result.provider,
            mode: policy.mode,
            reason: result.reason,
            attempts: result.attempts,
            event_id: result.event_id,
            bridge_status: result.bridge_status ?? null,
        });
    } catch (error: any) {
        await writeAuditLog(db, {
            restaurant_id: restaurantContext.restaurantId,
            user_id: auth.user.id,
            action: 'kds_ticket_print_failed',
            entity_type: 'order',
            entity_id: order.id,
            metadata: {
                source: 'kds_print_endpoint',
                reason: parsedBody.data.reason,
                mode: policy.mode,
            },
            new_value: {
                error: String(error?.message ?? 'unknown_error'),
            },
        });

        return apiError('Failed to print ticket', 502, 'KDS_PRINT_DISPATCH_FAILED', error?.message);
    }
}

/**
 * KDS Unified Queue API
 *
 * GET /api/kds/queue
 *
 * Dedicated queue endpoint for KDS and expeditor surfaces with:
 * - auth/device scoped restaurant context
 * - station and SLA filters
 * - cursor pagination
 */

import { z } from 'zod';
import { apiError, apiSuccess } from '@/lib/api/response';
import {
    getAuthenticatedUser,
    getAuthorizedRestaurantContext,
    getDeviceContext,
} from '@/lib/api/authz';
import { parseQuery } from '@/lib/api/validation';

type StationFilter = 'all' | 'kitchen' | 'bar' | 'dessert' | 'coffee' | 'expeditor';
type SlaFilter = 'on_track' | 'at_risk' | 'breached';

const ACTIVE_KDS_STATUSES = ['pending', 'confirmed', 'acknowledged', 'preparing', 'ready'] as const;

const DEFAULT_READY_AUTO_ARCHIVE_MINUTES = 15;

const QueueRequestSchema = z.object({
    status: z.enum(ACTIVE_KDS_STATUSES).optional(),
    station: z.enum(['all', 'kitchen', 'bar', 'dessert', 'coffee', 'expeditor']).default('all'),
    sla_status: z.enum(['on_track', 'at_risk', 'breached']).optional(),
    sla_minutes: z.coerce.number().int().min(5).max(180).default(30),
    cursor: z.string().min(8).max(400).optional(),
    limit: z.coerce.number().int().min(1).max(100).default(50),
});

interface CursorToken {
    createdAt: string;
    id: string;
}

interface QueueResponse {
    orders: QueueItem[];
    total: number;
    summary: {
        dineIn: number;
        directDelivery: number;
        directPickup: number;
        partners: number;
    };
    cursor: {
        next: string | null;
        has_more: boolean;
    };
    filters: {
        status: string | null;
        station: string;
        sla_status: string | null;
        sla_minutes: number;
    };
    policies: {
        ready_auto_archive_minutes: number;
        auto_archived_in_this_fetch: number;
    };
}

interface QueueItem {
    id: string;
    source:
        | 'dine-in'
        | 'direct_delivery'
        | 'direct_pickup'
        | 'beu'
        | 'zmall'
        | 'deliver_addis'
        | 'esoora';
    sourceLabel: string;
    sourceColor: string;
    orderNumber: string;
    tableNumber?: string;
    customerName?: string;
    items: Array<{
        id: string;
        kds_item_id?: string;
        name: string;
        quantity: number;
        notes?: string;
        station?: string;
        course?: 'appetizer' | 'main' | 'dessert' | 'beverage' | 'side';
        status?: string;
        order_item_id?: string;
        modifiers?: string[];
    }>;
    station: string;
    status: string;
    priority: 'normal' | 'high' | 'urgent';
    createdAt: string;
    acknowledgedAt?: string;
    elapsedMinutes: number;
    slaStatus: SlaFilter;
    driverInfo?: {
        status: 'pending' | 'assigned' | 'arrived';
        name?: string;
        phone?: string;
        etaMinutes?: number;
    };
    externalOrderId?: string;
    fireMode?: 'auto' | 'manual';
    currentCourse?: 'appetizer' | 'main' | 'dessert' | 'beverage' | 'side' | null;
}

export type UnifiedKDSOrder = QueueItem;

const SOURCE_CONFIG = {
    'dine-in': { label: 'Dine In', color: '#DC2626' },
    direct_delivery: { label: 'Delivery', color: '#2563EB' },
    direct_pickup: { label: 'Pickup', color: '#16A34A' },
    beu: { label: 'Beu', color: '#F97316' },
    zmall: { label: 'Zmall', color: '#22C55E' },
    deliver_addis: { label: 'Deliver Addis', color: '#8B5CF6' },
    esoora: { label: 'Esoora', color: '#06B6D4' },
};

function calculateElapsedMinutes(createdAt: string): number {
    return Math.max(0, Math.floor((Date.now() - new Date(createdAt).getTime()) / 60000));
}

function resolvePriority(elapsedMinutes: number, slaMinutes: number): 'normal' | 'high' | 'urgent' {
    if (elapsedMinutes >= slaMinutes + 10) return 'urgent';
    if (elapsedMinutes >= slaMinutes) return 'high';
    return 'normal';
}

function resolveSlaStatus(elapsedMinutes: number, slaMinutes: number): SlaFilter {
    if (elapsedMinutes >= slaMinutes) return 'breached';
    if (elapsedMinutes >= Math.floor(slaMinutes * 0.75)) return 'at_risk';
    return 'on_track';
}

function decodeCursor(cursor: string): CursorToken | null {
    try {
        const raw = Buffer.from(cursor, 'base64url').toString('utf-8');
        const parsed = JSON.parse(raw) as CursorToken;
        if (!parsed?.createdAt || !parsed?.id) return null;
        if (Number.isNaN(new Date(parsed.createdAt).getTime())) return null;
        return parsed;
    } catch {
        try {
            const raw = Buffer.from(cursor, 'base64').toString('utf-8');
            const parsed = JSON.parse(raw) as CursorToken;
            if (!parsed?.createdAt || !parsed?.id) return null;
            if (Number.isNaN(new Date(parsed.createdAt).getTime())) return null;
            return parsed;
        } catch {
            return null;
        }
    }
}

function encodeCursor(cursor: CursorToken): string {
    return Buffer.from(JSON.stringify(cursor), 'utf-8').toString('base64url');
}

function isAfterCursor(item: QueueItem, cursor: CursorToken): boolean {
    const itemTs = new Date(item.createdAt).getTime();
    const cursorTs = new Date(cursor.createdAt).getTime();
    if (itemTs > cursorTs) return true;
    if (itemTs < cursorTs) return false;
    return item.id > cursor.id;
}

function stationMatches(item: QueueItem, station: StationFilter): boolean {
    if (station === 'all' || station === 'expeditor') return true;
    if (item.station === station || item.station === 'multi') return true;
    return item.items.some(line => (line.station ?? 'kitchen') === station);
}

function resolveItemStation(station: unknown): string {
    if (typeof station !== 'string' || station.trim() === '') return 'kitchen';
    return station.trim().toLowerCase();
}

function resolveTicketStation(stations: string[]): string {
    const unique = [...new Set(stations.filter(Boolean))];
    if (unique.length === 0) return 'unassigned';
    if (unique.length > 1) return 'multi';
    return unique[0];
}

const COURSE_SEQUENCE = ['appetizer', 'main', 'dessert', 'beverage', 'side'] as const;
type CourseType = (typeof COURSE_SEQUENCE)[number];

function normalizeCourse(value: unknown): CourseType {
    if (typeof value !== 'string') return 'main';
    const normalized = value.trim().toLowerCase();
    return (COURSE_SEQUENCE as readonly string[]).includes(normalized)
        ? (normalized as CourseType)
        : 'main';
}

function shouldIncludeItemByFireMode(params: {
    fireMode: unknown;
    currentCourse: unknown;
    itemCourse: unknown;
}): boolean {
    const fireMode = String(params.fireMode ?? 'auto').toLowerCase();
    if (fireMode !== 'manual') return true;

    const currentCourseRaw = params.currentCourse;
    const activeCourse =
        typeof currentCourseRaw === 'string' && currentCourseRaw.trim().length > 0
            ? normalizeCourse(currentCourseRaw)
            : 'appetizer';
    const itemCourse = normalizeCourse(params.itemCourse);

    return itemCourse === activeCourse;
}

function mapOrderStatusToKdsItemStatus(orderStatus: string): string {
    if (orderStatus === 'ready') return 'ready';
    if (orderStatus === 'preparing' || orderStatus === 'acknowledged') return 'in_progress';
    return 'queued';
}

function resolveReadyAutoArchiveMinutes(settings: unknown): number {
    if (!settings || typeof settings !== 'object') {
        return DEFAULT_READY_AUTO_ARCHIVE_MINUTES;
    }

    const kds = (settings as Record<string, unknown>).kds;
    if (!kds || typeof kds !== 'object') {
        return DEFAULT_READY_AUTO_ARCHIVE_MINUTES;
    }

    const rawMinutes = (kds as Record<string, unknown>).ready_auto_archive_minutes;
    if (typeof rawMinutes !== 'number' || Number.isNaN(rawMinutes)) {
        return DEFAULT_READY_AUTO_ARCHIVE_MINUTES;
    }

    return Math.max(0, Math.min(180, Math.floor(rawMinutes)));
}

async function autoArchiveReadyOrders(params: {
    db: any;
    restaurantId: string;
    actorUserId: string | null;
    readyAutoArchiveMinutes: number;
}) {
    const { db, restaurantId, actorUserId, readyAutoArchiveMinutes } = params;

    if (readyAutoArchiveMinutes <= 0) {
        return 0;
    }

    const archiveBuilder = db?.from?.('orders');
    if (!archiveBuilder || typeof archiveBuilder.update !== 'function') {
        return 0;
    }

    const now = new Date();
    const nowIso = now.toISOString();
    const cutoffIso = new Date(now.getTime() - readyAutoArchiveMinutes * 60_000).toISOString();

    const { data: archivedOrders, error: archiveError } = await archiveBuilder
        .update({
            status: 'served',
            updated_at: nowIso,
        })
        .eq('restaurant_id', restaurantId)
        .eq('status', 'ready')
        .lte('completed_at', cutoffIso)
        .select('id');

    if (archiveError) {
        return 0;
    }

    const orderIds = ((archivedOrders ?? []) as Array<{ id?: string }>)
        .map(row => String(row.id ?? ''))
        .filter(Boolean);
    if (orderIds.length === 0) {
        return 0;
    }

    await Promise.all([
        db.from('order_events').insert(
            orderIds.map(orderId => ({
                restaurant_id: restaurantId,
                order_id: orderId,
                event_type: 'status_changed',
                from_status: 'ready',
                to_status: 'served',
                actor_user_id: actorUserId,
                metadata: {
                    source: 'kds_auto_archive',
                    ready_auto_archive_minutes: readyAutoArchiveMinutes,
                },
            }))
        ),
        db.from('audit_logs').insert(
            orderIds.map(orderId => ({
                restaurant_id: restaurantId,
                user_id: actorUserId,
                action: 'kds_ticket_auto_archived',
                entity_type: 'order',
                entity_id: orderId,
                metadata: {
                    source: 'kds_auto_archive',
                    ready_auto_archive_minutes: readyAutoArchiveMinutes,
                },
                old_value: { status: 'ready' },
                new_value: { status: 'served' },
            }))
        ),
    ]);

    return orderIds.length;
}

export async function GET(request: Request) {
    const auth = await getAuthenticatedUser();

    let restaurantId: string | null = null;
    let db: any = null;

    if (auth.ok) {
        const context = await getAuthorizedRestaurantContext(auth.user.id, { phase: 'p1' });
        if (!context.ok) {
            return context.response;
        }
        restaurantId = context.restaurantId;
        db = context.supabase;
    } else {
        const hasDeviceToken = Boolean(request.headers.get('x-device-token'));
        if (!hasDeviceToken) {
            return auth.response;
        }

        const device = await getDeviceContext(request);
        if (!device.ok) {
            return device.response;
        }

        restaurantId = device.restaurantId;
        db = device.admin;
    }

    const url = new URL(request.url);
    const parsed = parseQuery(
        {
            status: url.searchParams.get('status') ?? undefined,
            station: url.searchParams.get('station') ?? undefined,
            sla_status: url.searchParams.get('sla_status') ?? undefined,
            sla_minutes: url.searchParams.get('sla_minutes') ?? undefined,
            cursor: url.searchParams.get('cursor') ?? undefined,
            limit: url.searchParams.get('limit') ?? undefined,
        },
        QueueRequestSchema
    );
    if (!parsed.success) {
        return parsed.response;
    }

    const { status, station, sla_status, sla_minutes, limit, cursor } = parsed.data;
    const decodedCursor = cursor ? decodeCursor(cursor) : null;
    if (cursor && !decodedCursor) {
        return apiError('Invalid cursor token', 400, 'INVALID_CURSOR');
    }

    const statuses = status ? [status] : [...ACTIVE_KDS_STATUSES];
    const fetchLimit = Math.min(limit * 4, 400);
    const actorUserId = auth.ok ? auth.user.id : null;

    const restaurantSettingsBuilder = db
        .from('restaurants')
        .select('settings')
        .eq('id', restaurantId);
    const { data: restaurantSettingsRows } = await (typeof restaurantSettingsBuilder.maybeSingle ===
    'function'
        ? restaurantSettingsBuilder.maybeSingle()
        : restaurantSettingsBuilder.limit(1));
    const restaurantSettingsRow = Array.isArray(restaurantSettingsRows)
        ? restaurantSettingsRows[0]
        : restaurantSettingsRows;
    const readyAutoArchiveMinutes = resolveReadyAutoArchiveMinutes(restaurantSettingsRow?.settings);
    const autoArchivedCount = restaurantId
        ? await autoArchiveReadyOrders({
              db,
              restaurantId,
              actorUserId,
              readyAutoArchiveMinutes,
          })
        : 0;

    const { data: dineInOrders, error: dineInError } = await db
        .from('orders')
        .select(
            'id, order_number, table_number, created_at, acknowledged_at, status, items, fire_mode, current_course'
        )
        .eq('restaurant_id', restaurantId)
        .in('status', statuses)
        .order('created_at', { ascending: true })
        .order('id', { ascending: true })
        .limit(fetchLimit);

    if (dineInError) {
        return apiError(
            'Failed to fetch KDS dine-in queue',
            500,
            'KDS_QUEUE_FETCH_FAILED',
            dineInError.message
        );
    }

    const { data: externalOrders, error: externalError } = await db
        .from('external_orders')
        .select(
            'id, provider, provider_order_id, payload_json, normalized_status, created_at, acknowledged_at'
        )
        .eq('restaurant_id', restaurantId)
        .in('normalized_status', statuses)
        .order('created_at', { ascending: true })
        .order('id', { ascending: true })
        .limit(fetchLimit);

    if (externalError) {
        return apiError(
            'Failed to fetch KDS external queue',
            500,
            'KDS_QUEUE_FETCH_FAILED',
            externalError.message
        );
    }

    const unified: QueueItem[] = [];

    const dineInOrderIds = ((dineInOrders ?? []) as Array<{ id: string }>)
        .map(row => row.id)
        .filter(Boolean);
    const orderItemsByOrder = new Map<string, Array<Record<string, unknown>>>();
    const kdsItemsByOrder = new Map<string, Array<Record<string, unknown>>>();

    if (dineInOrderIds.length > 0) {
        const [
            { data: orderItems, error: orderItemsError },
            { data: kdsItems, error: kdsItemsError },
        ] = await Promise.all([
            db
                .from('order_items')
                .select('id, order_id, name, quantity, notes, station, modifiers, course')
                .in('order_id', dineInOrderIds),
            db
                .from('kds_order_items')
                .select(
                    'id, order_id, order_item_id, name, quantity, notes, station, status, modifiers'
                )
                .eq('restaurant_id', restaurantId)
                .in('order_id', dineInOrderIds),
        ]);

        if (!orderItemsError) {
            for (const item of (orderItems ?? []) as Array<Record<string, unknown>>) {
                const orderId = String(item.order_id ?? '');
                if (!orderId) continue;
                const bucket = orderItemsByOrder.get(orderId) ?? [];
                bucket.push(item);
                orderItemsByOrder.set(orderId, bucket);
            }
        }

        if (!kdsItemsError) {
            for (const item of (kdsItems ?? []) as Array<Record<string, unknown>>) {
                const orderId = String(item.order_id ?? '');
                if (!orderId) continue;
                const bucket = kdsItemsByOrder.get(orderId) ?? [];
                bucket.push(item);
                kdsItemsByOrder.set(orderId, bucket);
            }
        }
    }

    // Auto-hydrate missing KDS item rows for legacy orders that only have items JSON.
    const hydrationRows: Array<Record<string, unknown>> = [];
    for (const rawOrder of (dineInOrders ?? []) as Array<Record<string, unknown>>) {
        const orderId = String(rawOrder.id ?? '');
        if (!orderId) continue;
        if ((kdsItemsByOrder.get(orderId)?.length ?? 0) > 0) continue;
        if ((orderItemsByOrder.get(orderId)?.length ?? 0) > 0) continue;

        const fallbackItems = Array.isArray(rawOrder.items)
            ? (rawOrder.items as Array<Record<string, unknown>>)
            : [];
        if (fallbackItems.length === 0) continue;

        for (let idx = 0; idx < fallbackItems.length; idx += 1) {
            const item = fallbackItems[idx];
            hydrationRows.push({
                restaurant_id: restaurantId,
                order_id: orderId,
                order_item_id: null,
                station: resolveItemStation(item.station),
                status: mapOrderStatusToKdsItemStatus(String(rawOrder.status ?? 'pending')),
                name: String(item.name ?? 'Item'),
                quantity: Number(item.quantity ?? 1),
                notes: item.notes ? String(item.notes) : null,
                modifiers: Array.isArray(item.modifiers) ? item.modifiers : [],
                metadata: {
                    source: 'kds_queue_auto_hydration',
                    fallback_index: idx,
                },
            });
        }
    }

    if (hydrationRows.length > 0) {
        const hydrationBuilder = db.from('kds_order_items');
        if (typeof hydrationBuilder?.insert === 'function') {
            const { data: hydratedItems } = await hydrationBuilder
                .insert(hydrationRows)
                .select(
                    'id, order_id, order_item_id, name, quantity, notes, station, status, modifiers'
                );

            for (const item of (hydratedItems ?? []) as Array<Record<string, unknown>>) {
                const orderId = String(item.order_id ?? '');
                if (!orderId) continue;
                const bucket = kdsItemsByOrder.get(orderId) ?? [];
                bucket.push(item);
                kdsItemsByOrder.set(orderId, bucket);
            }
        }
    }

    for (const rawOrder of (dineInOrders ?? []) as Array<Record<string, unknown>>) {
        const createdAt = String(rawOrder.created_at ?? '');
        if (!createdAt) {
            continue;
        }

        const elapsedMinutes = calculateElapsedMinutes(createdAt);
        const slaState = resolveSlaStatus(elapsedMinutes, sla_minutes);

        const orderId = String(rawOrder.id ?? '');
        const orderItems = orderItemsByOrder.get(orderId) ?? [];
        const orderItemCourseById = new Map<string, string>();
        for (const row of orderItems) {
            const orderItemId = String(row.id ?? '');
            if (!orderItemId) continue;
            orderItemCourseById.set(orderItemId, normalizeCourse(row.course));
        }
        const kdsItems = kdsItemsByOrder.get(orderId) ?? [];

        const fallbackItems = Array.isArray(rawOrder.items)
            ? (rawOrder.items as Array<Record<string, unknown>>)
            : [];

        const normalizedItems =
            kdsItems.length > 0
                ? kdsItems.map((item, idx) => ({
                      id: String(item.id ?? `${rawOrder.id}-kds-${idx}`),
                      kds_item_id: item.id ? String(item.id) : undefined,
                      name: String(item.name ?? 'Item'),
                      quantity: Number(item.quantity ?? 1),
                      notes: item.notes ? String(item.notes) : undefined,
                      station: resolveItemStation(item.station),
                      course: normalizeCourse(
                          item.order_item_id
                              ? orderItemCourseById.get(String(item.order_item_id))
                              : undefined
                      ),
                      status: String(item.status ?? 'queued'),
                      order_item_id: item.order_item_id ? String(item.order_item_id) : undefined,
                      modifiers: Array.isArray(item.modifiers)
                          ? item.modifiers.map(mod => String(mod))
                          : undefined,
                  }))
                : orderItems.length > 0
                  ? orderItems.map((item, idx) => ({
                        id: String(item.id ?? `${rawOrder.id}-oi-${idx}`),
                        kds_item_id: undefined,
                        name: String(item.name ?? 'Item'),
                        quantity: Number(item.quantity ?? 1),
                        notes: item.notes ? String(item.notes) : undefined,
                        station: resolveItemStation(item.station),
                        course: normalizeCourse(item.course),
                        status: 'queued',
                        modifiers: Array.isArray(item.modifiers)
                            ? item.modifiers.map(mod => String(mod))
                            : undefined,
                    }))
                  : fallbackItems.map((item, idx) => ({
                        id: String(item.id ?? `${rawOrder.id}-item-${idx}`),
                        kds_item_id: undefined,
                        name: String(item.name ?? 'Item'),
                        quantity: Number(item.quantity ?? 1),
                        notes: item.notes ? String(item.notes) : undefined,
                        station: resolveItemStation(item.station),
                        course: normalizeCourse(item.course),
                        status: 'queued',
                        modifiers: Array.isArray(item.modifiers)
                            ? item.modifiers.map(mod => String(mod))
                            : undefined,
                    }));

        const visibleItems = normalizedItems.filter(item =>
            shouldIncludeItemByFireMode({
                fireMode: rawOrder.fire_mode,
                currentCourse: rawOrder.current_course,
                itemCourse: item.course,
            })
        );

        if (visibleItems.length === 0) {
            continue;
        }

        const ticketStation = resolveTicketStation(
            visibleItems.map(item => item.station ?? 'kitchen')
        );

        unified.push({
            id: String(rawOrder.id),
            source: 'dine-in',
            sourceLabel: SOURCE_CONFIG['dine-in'].label,
            sourceColor: SOURCE_CONFIG['dine-in'].color,
            orderNumber: String(rawOrder.order_number ?? rawOrder.id),
            tableNumber: rawOrder.table_number ? String(rawOrder.table_number) : undefined,
            items: visibleItems,
            station: ticketStation,
            status: String(rawOrder.status ?? 'pending'),
            priority: resolvePriority(elapsedMinutes, sla_minutes),
            createdAt,
            acknowledgedAt: rawOrder.acknowledged_at ? String(rawOrder.acknowledged_at) : undefined,
            elapsedMinutes,
            slaStatus: slaState,
            fireMode: String(rawOrder.fire_mode ?? 'auto') === 'manual' ? 'manual' : 'auto',
            currentCourse: rawOrder.current_course
                ? normalizeCourse(rawOrder.current_course)
                : null,
        });
    }

    for (const rawOrder of (externalOrders ?? []) as Array<Record<string, unknown>>) {
        const createdAt = String(rawOrder.created_at ?? '');
        if (!createdAt) {
            continue;
        }

        const payloadJson =
            rawOrder.payload_json && typeof rawOrder.payload_json === 'object'
                ? (rawOrder.payload_json as Record<string, unknown>)
                : {};
        const provider = String(rawOrder.provider ?? 'direct_delivery');

        const source =
            provider === 'custom_local'
                ? payloadJson?.fulfillment_type === 'pickup'
                    ? 'direct_pickup'
                    : 'direct_delivery'
                : provider;

        const config =
            SOURCE_CONFIG[source as keyof typeof SOURCE_CONFIG] ?? SOURCE_CONFIG['direct_delivery'];

        const elapsedMinutes = calculateElapsedMinutes(createdAt);
        const slaState = resolveSlaStatus(elapsedMinutes, sla_minutes);

        const payloadItems = Array.isArray(payloadJson.items)
            ? (payloadJson.items as Array<Record<string, unknown>>)
            : [];

        const normalizedItems = payloadItems.map((item, idx) => ({
            id: String(item.id ?? `${rawOrder.id}-ext-${idx}`),
            name: String(item.name ?? 'Item'),
            quantity: Number(item.quantity ?? 1),
            notes: item.notes ? String(item.notes) : undefined,
            station: resolveItemStation(item.station),
            modifiers: Array.isArray(item.modifiers)
                ? item.modifiers.map(mod => String(mod))
                : undefined,
        }));

        const ticketStation = resolveTicketStation(
            normalizedItems.map(item => item.station ?? 'kitchen')
        );

        unified.push({
            id: String(rawOrder.id),
            source: source as UnifiedKDSOrder['source'],
            sourceLabel: config.label,
            sourceColor: config.color,
            orderNumber: String(rawOrder.provider_order_id ?? `EXT-${rawOrder.id}`),
            customerName: payloadJson.customer_name ? String(payloadJson.customer_name) : undefined,
            items: normalizedItems,
            station: ticketStation,
            status: String(rawOrder.normalized_status ?? 'pending'),
            priority: resolvePriority(elapsedMinutes, sla_minutes),
            createdAt,
            acknowledgedAt: rawOrder.acknowledged_at ? String(rawOrder.acknowledged_at) : undefined,
            elapsedMinutes,
            slaStatus: slaState,
            externalOrderId: rawOrder.provider_order_id
                ? String(rawOrder.provider_order_id)
                : undefined,
            driverInfo:
                payloadJson.driver_info && typeof payloadJson.driver_info === 'object'
                    ? (payloadJson.driver_info as UnifiedKDSOrder['driverInfo'])
                    : undefined,
        });
    }

    const filtered = unified.filter(item => {
        if (!stationMatches(item, station as StationFilter)) return false;
        if (sla_status && item.slaStatus !== sla_status) return false;
        if (decodedCursor && !isAfterCursor(item, decodedCursor)) return false;
        return true;
    });

    filtered.sort((a, b) => {
        const aTs = new Date(a.createdAt).getTime();
        const bTs = new Date(b.createdAt).getTime();
        if (aTs !== bTs) return aTs - bTs;
        return a.id.localeCompare(b.id);
    });

    const page = filtered.slice(0, limit);
    const hasMore = filtered.length > limit;

    return apiSuccess<QueueResponse>({
        orders: page,
        total: page.length,
        summary: {
            dineIn: page.filter(o => o.source === 'dine-in').length,
            directDelivery: page.filter(o => o.source === 'direct_delivery').length,
            directPickup: page.filter(o => o.source === 'direct_pickup').length,
            partners: page.filter(o =>
                ['beu', 'zmall', 'deliver_addis', 'esoora'].includes(o.source)
            ).length,
        },
        cursor: {
            next:
                hasMore && page.length > 0
                    ? encodeCursor({
                          createdAt: page[page.length - 1].createdAt,
                          id: page[page.length - 1].id,
                      })
                    : null,
            has_more: hasMore,
        },
        filters: {
            status: status ?? null,
            station,
            sla_status: sla_status ?? null,
            sla_minutes,
        },
        policies: {
            ready_auto_archive_minutes: readyAutoArchiveMinutes,
            auto_archived_in_this_fetch: autoArchivedCount,
        },
    });
}

import { z } from 'zod';
import { apiError, apiSuccess } from '@/lib/api/response';
import { getAuthenticatedUser, getAuthorizedRestaurantContext } from '@/lib/api/authz';
import { parseJsonBody } from '@/lib/api/validation';
import { writeAuditLog } from '@/lib/api/audit';
import { isIdempotencyKeyValid, resolveIdempotencyKey } from '@/lib/api/idempotency';
import type { Json } from '@/types/database';

const AccountIdSchema = z.string().uuid();

const AdjustLoyaltySchema = z.object({
    points_delta: z.coerce
        .number()
        .int()
        .min(-100000)
        .max(100000)
        .refine(value => value !== 0, {
            message: 'points_delta must not be 0',
        }),
    reason: z.string().trim().min(2).max(200),
    order_id: z.string().uuid().optional(),
});

export async function POST(
    request: Request,
    routeContext: { params: Promise<{ accountId: string }> }
) {
    const auth = await getAuthenticatedUser();
    if (!auth.ok) {
        return auth.response;
    }

    const context = await getAuthorizedRestaurantContext(auth.user.id, { phase: 'p2' });
    if (!context.ok) {
        return context.response;
    }

    const { accountId } = await routeContext.params;
    const accountIdParsed = AccountIdSchema.safeParse(accountId);
    if (!accountIdParsed.success) {
        return apiError(
            'Invalid account id',
            400,
            'INVALID_LOYALTY_ACCOUNT_ID',
            accountIdParsed.error.flatten()
        );
    }

    const explicitIdempotencyKey = request.headers.get('x-idempotency-key');
    if (explicitIdempotencyKey && !isIdempotencyKeyValid(explicitIdempotencyKey)) {
        return apiError('Invalid idempotency key', 400, 'INVALID_IDEMPOTENCY_KEY');
    }
    const idempotencyKey = resolveIdempotencyKey(explicitIdempotencyKey);

    const db = context.supabase as any;

    const parsed = await parseJsonBody(request, AdjustLoyaltySchema);
    if (!parsed.success) {
        return parsed.response;
    }

    const { data: account, error: accountError } = await db
        .from('loyalty_accounts' as any)
        .select('id, points_balance, guest_id, program_id, status')
        .eq('id', accountIdParsed.data)
        .eq('restaurant_id', context.restaurantId)
        .maybeSingle();

    if (accountError) {
        return apiError(
            'Failed to load loyalty account',
            500,
            'LOYALTY_ACCOUNT_FETCH_FAILED',
            accountError.message
        );
    }
    if (!account) {
        return apiError('Loyalty account not found', 404, 'LOYALTY_ACCOUNT_NOT_FOUND');
    }
    if (account.status !== 'active') {
        return apiError('Loyalty account is not active', 409, 'LOYALTY_ACCOUNT_INACTIVE');
    }

    const balanceAfter = Number(account.points_balance) + parsed.data.points_delta;
    if (balanceAfter < 0) {
        return apiError(
            'Insufficient points balance for adjustment',
            409,
            'LOYALTY_INSUFFICIENT_POINTS'
        );
    }

    const { data: updated, error: updateError } = await db
        .from('loyalty_accounts' as any)
        .update({
            points_balance: balanceAfter,
            updated_at: new Date().toISOString(),
        })
        .eq('id', account.id)
        .eq('restaurant_id', context.restaurantId)
        .select('*')
        .single();

    if (updateError) {
        return apiError(
            'Failed to update loyalty balance',
            500,
            'LOYALTY_ACCOUNT_UPDATE_FAILED',
            updateError.message
        );
    }

    const transactionType = parsed.data.points_delta > 0 ? 'adjustment_credit' : 'adjustment_debit';

    const { data: transaction, error: txError } = await db
        .from('loyalty_transactions' as any)
        .insert({
            restaurant_id: context.restaurantId,
            account_id: account.id,
            order_id: parsed.data.order_id ?? null,
            points_delta: parsed.data.points_delta,
            balance_after: balanceAfter,
            transaction_type: transactionType,
            reason: parsed.data.reason,
            metadata: {
                source: 'merchant_dashboard',
                idempotency_key: idempotencyKey,
            } as Json,
            created_by: auth.user.id,
        })
        .select('*')
        .single();

    if (txError) {
        return apiError(
            'Failed to write loyalty transaction',
            500,
            'LOYALTY_TRANSACTION_CREATE_FAILED',
            txError.message
        );
    }

    await writeAuditLog(context.supabase, {
        restaurant_id: context.restaurantId,
        user_id: auth.user.id,
        action: 'loyalty_account_adjusted',
        entity_type: 'loyalty_account',
        entity_id: account.id,
        old_value: { points_balance: account.points_balance },
        new_value: { points_balance: balanceAfter, points_delta: parsed.data.points_delta },
        metadata: {
            reason: parsed.data.reason,
            transaction_id: transaction.id,
            idempotency_key: idempotencyKey,
        },
    });

    return apiSuccess({ account: updated, transaction, idempotency_key: idempotencyKey });
}

import { z } from 'zod';
import { apiError, apiSuccess } from '@/lib/api/response';
import { getAuthenticatedUser, getAuthorizedRestaurantContext } from '@/lib/api/authz';
import { parseJsonBody } from '@/lib/api/validation';
import { writeAuditLog } from '@/lib/api/audit';

const UpdateProgramSchema = z.object({
    name: z.string().trim().min(2).max(120).optional(),
    points_rule_json: z.record(z.string(), z.unknown()).optional(),
    tier_rule_json: z.record(z.string(), z.unknown()).optional(),
    status: z.enum(['draft', 'active', 'paused', 'archived']).optional(),
});

export async function PATCH(
    request: Request,
    { params }: { params: Promise<{ programId: string }> }
) {
    const { programId } = await params;
    const auth = await getAuthenticatedUser();
    if (!auth.ok) return auth.response;

    const context = await getAuthorizedRestaurantContext(auth.user.id, { phase: 'p2' });
    if (!context.ok) return context.response;

    const parsed = await parseJsonBody(request, UpdateProgramSchema);
    if (!parsed.success) return parsed.response;

    const db = context.supabase as any;

    const { data: program, error: fetchError } = await db
        .from('loyalty_programs')
        .select('*')
        .eq('id', programId)
        .eq('restaurant_id', context.restaurantId)
        .single();

    if (fetchError || !program) {
        return apiError('Program not found', 404, 'LOYALTY_PROGRAM_NOT_FOUND');
    }

    const { data, error } = await db
        .from('loyalty_programs')
        .update({
            ...parsed.data,
            updated_at: new Date().toISOString(),
        })
        .eq('id', programId)
        .select('*')
        .single();

    if (error) {
        return apiError(
            'Failed to update program',
            500,
            'LOYALTY_PROGRAM_UPDATE_FAILED',
            error.message
        );
    }

    await writeAuditLog(context.supabase, {
        restaurant_id: context.restaurantId,
        user_id: auth.user.id,
        action: 'loyalty_program_updated',
        entity_type: 'loyalty_program',
        entity_id: programId,
        old_value: program,
        new_value: data,
        metadata: { source: 'merchant_dashboard' },
    });

    return apiSuccess({ program: data });
}

export async function DELETE(
    request: Request,
    { params }: { params: Promise<{ programId: string }> }
) {
    const { programId } = await params;

    const auth = await getAuthenticatedUser();
    if (!auth.ok) return auth.response;

    const context = await getAuthorizedRestaurantContext(auth.user.id, { phase: 'p2' });
    if (!context.ok) return context.response;

    const db = context.supabase as any;

    const { error } = await db
        .from('loyalty_programs')
        .delete()
        .eq('id', programId)
        .eq('restaurant_id', context.restaurantId);

    if (error) {
        return apiError(
            'Failed to delete program',
            500,
            'LOYALTY_PROGRAM_DELETE_FAILED',
            error.message
        );
    }

    await writeAuditLog(context.supabase, {
        restaurant_id: context.restaurantId,
        user_id: auth.user.id,
        action: 'loyalty_program_deleted',
        entity_type: 'loyalty_program',
        entity_id: programId,
        metadata: { source: 'merchant_dashboard' },
    });

    return apiSuccess({ deleted: true });
}

import { z } from 'zod';
import { apiError, apiSuccess } from '@/lib/api/response';
import { getAuthenticatedUser, getAuthorizedRestaurantContext } from '@/lib/api/authz';
import { parseJsonBody } from '@/lib/api/validation';
import { writeAuditLog } from '@/lib/api/audit';
import { isIdempotencyKeyValid, resolveIdempotencyKey } from '@/lib/api/idempotency';
import { isSchemaNotReadyError } from '@/lib/api/schemaFallback';
import type { Json } from '@/types/database';

const CreateProgramSchema = z.object({
    name: z.string().trim().min(2).max(120),
    points_rule_json: z.record(z.string(), z.unknown()).optional(),
    tier_rule_json: z.record(z.string(), z.unknown()).optional(),
    status: z.enum(['draft', 'active', 'paused', 'archived']).optional(),
});

export async function GET() {
    const auth = await getAuthenticatedUser();
    if (!auth.ok) {
        return auth.response;
    }

    const context = await getAuthorizedRestaurantContext(auth.user.id, { phase: 'p2' });
    if (!context.ok) {
        return context.response;
    }

    const db = context.supabase as any;

    const { data, error } = await db
        .from('loyalty_programs' as any)
        .select('*')
        .eq('restaurant_id', context.restaurantId)
        .order('created_at', { ascending: false });

    if (error) {
        if (isSchemaNotReadyError(error)) {
            return apiSuccess({ programs: [] });
        }
        return apiError(
            'Failed to fetch loyalty programs',
            500,
            'LOYALTY_PROGRAMS_FETCH_FAILED',
            error.message
        );
    }

    return apiSuccess({ programs: data ?? [] });
}

export async function POST(request: Request) {
    const auth = await getAuthenticatedUser();
    if (!auth.ok) {
        return auth.response;
    }

    const context = await getAuthorizedRestaurantContext(auth.user.id, { phase: 'p2' });
    if (!context.ok) {
        return context.response;
    }

    const explicitIdempotencyKey = request.headers.get('x-idempotency-key');
    if (explicitIdempotencyKey && !isIdempotencyKeyValid(explicitIdempotencyKey)) {
        return apiError('Invalid idempotency key', 400, 'INVALID_IDEMPOTENCY_KEY');
    }
    const idempotencyKey = resolveIdempotencyKey(explicitIdempotencyKey);

    const db = context.supabase as any;

    const parsed = await parseJsonBody(request, CreateProgramSchema);
    if (!parsed.success) {
        return parsed.response;
    }

    const payload = {
        restaurant_id: context.restaurantId,
        name: parsed.data.name,
        points_rule_json: (parsed.data.points_rule_json ?? {
            points_per_currency_unit: 1,
            currency_unit: 1,
        }) as Json,
        tier_rule_json: (parsed.data.tier_rule_json ?? {}) as Json,
        status: parsed.data.status ?? 'draft',
        created_by: auth.user.id,
    };

    const { data, error } = await db
        .from('loyalty_programs' as any)
        .insert(payload)
        .select('*')
        .single();

    if (error) {
        return apiError(
            'Failed to create loyalty program',
            500,
            'LOYALTY_PROGRAM_CREATE_FAILED',
            error.message
        );
    }

    await writeAuditLog(context.supabase, {
        restaurant_id: context.restaurantId,
        user_id: auth.user.id,
        action: 'loyalty_program_created',
        entity_type: 'loyalty_program',
        entity_id: data.id,
        new_value: {
            name: data.name,
            status: data.status,
            points_rule_json: data.points_rule_json,
        },
        metadata: {
            source: 'merchant_dashboard',
            idempotency_key: idempotencyKey,
        },
    });

    return apiSuccess({ program: data, idempotency_key: idempotencyKey }, 201);
}

import { z } from 'zod';
import { apiError, apiSuccess } from '@/lib/api/response';
import { getAuthenticatedUser, getAuthorizedRestaurantContext } from '@/lib/api/authz';

const ItemIdSchema = z.string().uuid();

const UpsellQuerySchema = z.object({
    guest_id: z.string().uuid().optional(),
    cart_items: z.string().optional(), // JSON string of cart item IDs
    limit: z.coerce.number().int().min(1).max(10).default(4),
});

interface UpsellRecommendation {
    id: string;
    name: string;
    price: number;
    image_url: string | null;
    category_name: string;
    reason: 'complementary' | 'popular' | 'category_based' | 'personalized';
    reason_text: string;
    order_count?: number;
}

/**
 * GET /api/menu/items/[itemId]/upsell
 *
 * Returns upsell recommendations for a menu item.
 * Uses rule-based logic (no AI/ML):
 * 1. Complementary items (manually configured)
 * 2. Popular items (most ordered)
 * 3. Category-based items
 * 4. Personalized (based on guest history)
 */
export async function GET(request: Request, routeContext: { params: Promise<{ itemId: string }> }) {
    const auth = await getAuthenticatedUser();
    if (!auth.ok) {
        return auth.response;
    }

    const context = await getAuthorizedRestaurantContext(auth.user.id);
    if (!context.ok) {
        return context.response;
    }

    const { itemId } = await routeContext.params;
    const itemIdParsed = ItemIdSchema.safeParse(itemId);
    if (!itemIdParsed.success) {
        return apiError('Invalid item id', 400, 'INVALID_ITEM_ID', itemIdParsed.error.flatten());
    }

    // Parse query parameters
    const url = new URL(request.url);
    const queryParams = Object.fromEntries(url.searchParams.entries());
    const parsedQuery = UpsellQuerySchema.safeParse(queryParams);

    if (!parsedQuery.success) {
        return apiError(
            'Invalid query parameters',
            400,
            'VALIDATION_ERROR',
            parsedQuery.error.flatten()
        );
    }

    const { guest_id, cart_items, limit } = parsedQuery.data;
    const db = context.supabase as any;

    try {
        // Get the current item details
        const { data: currentItem, error: itemError } = await db
            .from('menu_items')
            .select('id, name, category_id, upsell_tags, complementary_items, categories(name)')
            .eq('id', itemIdParsed.data)
            .eq('restaurant_id', context.restaurantId)
            .maybeSingle();

        if (itemError) {
            return apiError('Failed to fetch item', 500, 'ITEM_FETCH_FAILED', itemError.message);
        }

        if (!currentItem) {
            return apiError('Item not found', 404, 'ITEM_NOT_FOUND');
        }

        const recommendations: UpsellRecommendation[] = [];
        const addedItemIds = new Set<string>([itemIdParsed.data]);

        // Parse cart items if provided
        let cartItemIds: string[] = [];
        if (cart_items) {
            try {
                cartItemIds = JSON.parse(cart_items);
                cartItemIds.forEach(id => addedItemIds.add(id));
            } catch {
                // Invalid JSON, ignore
            }
        }

        // 1. Complementary items (manually configured)
        if (currentItem.complementary_items && Array.isArray(currentItem.complementary_items)) {
            const complementaryIds = currentItem.complementary_items.filter(
                (id: string) => !addedItemIds.has(id)
            );

            if (complementaryIds.length > 0) {
                const { data: complementaryItems } = await db
                    .from('menu_items')
                    .select('id, name, price, image_url, categories(name), order_count')
                    .in('id', complementaryIds)
                    .eq('restaurant_id', context.restaurantId)
                    .eq('is_available', true);

                for (const item of complementaryItems ?? []) {
                    if (recommendations.length >= limit) break;
                    if (addedItemIds.has(item.id)) continue;

                    recommendations.push({
                        id: item.id,
                        name: item.name,
                        price: item.price,
                        image_url: item.image_url,
                        category_name: item.categories?.name ?? '',
                        reason: 'complementary',
                        reason_text: `Pairs well with ${currentItem.name}`,
                        order_count: item.order_count,
                    });
                    addedItemIds.add(item.id);
                }
            }
        }

        // 2. Popular items (most ordered globally)
        if (recommendations.length < limit) {
            const { data: popularItems } = await db
                .from('menu_items')
                .select('id, name, price, image_url, categories(name), order_count')
                .eq('restaurant_id', context.restaurantId)
                .eq('is_available', true)
                .not(
                    'id',
                    'in',
                    `(${Array.from(addedItemIds)
                        .map(id => `'${id}'`)
                        .join(',')})`
                )
                .order('order_count', { ascending: false })
                .limit(limit - recommendations.length);

            for (const item of popularItems ?? []) {
                if (recommendations.length >= limit) break;

                recommendations.push({
                    id: item.id,
                    name: item.name,
                    price: item.price,
                    image_url: item.image_url,
                    category_name: item.categories?.name ?? '',
                    reason: 'popular',
                    reason_text: 'Popular with other guests',
                    order_count: item.order_count,
                });
                addedItemIds.add(item.id);
            }
        }

        // 3. Category-based items (from same category)
        if (recommendations.length < limit && currentItem.category_id) {
            const { data: categoryItems } = await db
                .from('menu_items')
                .select('id, name, price, image_url, categories(name), order_count')
                .eq('restaurant_id', context.restaurantId)
                .eq('category_id', currentItem.category_id)
                .eq('is_available', true)
                .not(
                    'id',
                    'in',
                    `(${Array.from(addedItemIds)
                        .map(id => `'${id}'`)
                        .join(',')})`
                )
                .order('order_count', { ascending: false })
                .limit(limit - recommendations.length);

            for (const item of categoryItems ?? []) {
                if (recommendations.length >= limit) break;

                recommendations.push({
                    id: item.id,
                    name: item.name,
                    price: item.price,
                    image_url: item.image_url,
                    category_name: item.categories?.name ?? '',
                    reason: 'category_based',
                    reason_text: `More from ${item.categories?.name ?? 'this category'}`,
                    order_count: item.order_count,
                });
                addedItemIds.add(item.id);
            }
        }

        // 4. Personalized recommendations (based on guest history)
        if (recommendations.length < limit && guest_id) {
            // Get items the guest has ordered before
            const { data: guestOrders } = await db
                .from('orders')
                .select('id')
                .eq('guest_id', guest_id)
                .eq('restaurant_id', context.restaurantId)
                .order('created_at', { ascending: false })
                .limit(10);

            if (guestOrders && guestOrders.length > 0) {
                const orderIds = guestOrders.map((o: { id: string }) => o.id);

                // Get items from these orders
                const { data: orderItems } = await db
                    .from('order_items')
                    .select('menu_item_id, count:count(*)')
                    .in('order_id', orderIds)
                    .not(
                        'menu_item_id',
                        'in',
                        `(${Array.from(addedItemIds)
                            .map(id => `'${id}'`)
                            .join(',')})`
                    )
                    .group('menu_item_id')
                    .order('count', { ascending: false })
                    .limit(limit - recommendations.length);

                if (orderItems && orderItems.length > 0) {
                    const menuItemIds = orderItems.map(
                        (oi: { menu_item_id: string }) => oi.menu_item_id
                    );

                    const { data: guestFavoriteItems } = await db
                        .from('menu_items')
                        .select('id, name, price, image_url, categories(name), order_count')
                        .in('id', menuItemIds)
                        .eq('restaurant_id', context.restaurantId)
                        .eq('is_available', true);

                    for (const item of guestFavoriteItems ?? []) {
                        if (recommendations.length >= limit) break;

                        recommendations.push({
                            id: item.id,
                            name: item.name,
                            price: item.price,
                            image_url: item.image_url,
                            category_name: item.categories?.name ?? '',
                            reason: 'personalized',
                            reason_text: 'Based on your past orders',
                            order_count: item.order_count,
                        });
                        addedItemIds.add(item.id);
                    }
                }
            }
        }

        // Log upsell analytics (async, don't wait)
        if (guest_id) {
            db.from('upsell_analytics')
                .insert({
                    restaurant_id: context.restaurantId,
                    guest_id,
                    item_viewed: itemIdParsed.data,
                    recommended_items: recommendations.map(r => r.id),
                    created_at: new Date().toISOString(),
                })
                .then(() => {})
                .catch(() => {});
        }

        return apiSuccess({
            item_id: itemIdParsed.data,
            recommendations,
            total: recommendations.length,
        });
    } catch (error) {
        const errorMessage = error instanceof Error ? error.message : 'Unknown error';
        return apiError('Failed to generate recommendations', 500, 'UPSELL_ERROR', errorMessage);
    }
}

/**
 * POST /api/menu/items/[itemId]/upsell
 *
 * Track upsell interaction (click, add to cart)
 */
export async function POST(
    request: Request,
    routeContext: { params: Promise<{ itemId: string }> }
) {
    const auth = await getAuthenticatedUser();
    if (!auth.ok) {
        return auth.response;
    }

    const context = await getAuthorizedRestaurantContext(auth.user.id);
    if (!context.ok) {
        return context.response;
    }

    const { itemId } = await routeContext.params;
    const itemIdParsed = ItemIdSchema.safeParse(itemId);
    if (!itemIdParsed.success) {
        return apiError('Invalid item id', 400, 'INVALID_ITEM_ID');
    }

    const body = await request.json().catch(() => ({}));
    const { guest_id, clicked_item, added_to_cart, upsell_analytics_id } = body as {
        guest_id?: string;
        clicked_item?: string;
        added_to_cart?: boolean;
        upsell_analytics_id?: string;
    };

    const db = context.supabase as any;

    try {
        // Update existing analytics record or create new one
        if (upsell_analytics_id) {
            await db
                .from('upsell_analytics')
                .update({
                    clicked_item: clicked_item ?? null,
                    added_to_cart: added_to_cart ?? false,
                    updated_at: new Date().toISOString(),
                })
                .eq('id', upsell_analytics_id);
        } else if (guest_id) {
            await db.from('upsell_analytics').insert({
                restaurant_id: context.restaurantId,
                guest_id,
                item_viewed: itemIdParsed.data,
                clicked_item: clicked_item ?? null,
                added_to_cart: added_to_cart ?? false,
                created_at: new Date().toISOString(),
            });
        }

        return apiSuccess({ tracked: true });
    } catch {
        return apiSuccess({ tracked: false });
    }
}

import { createClient } from '@/lib/supabase/server';
import { NextResponse } from 'next/server';
import { enforcePilotAccess } from '@/lib/api/pilotGate';
import { ORDER_LIST_COLUMNS, columnsToString } from '@/lib/constants/query-columns';

export async function GET(request: Request) {
    try {
        console.log('[API] Starting merchant activity fetch...');
        const supabase = await createClient();

        // Get the current user
        const {
            data: { user },
            error: userError,
        } = await supabase.auth.getUser();

        console.log('[API] User check:', {
            hasUser: !!user,
            userId: user?.id,
            userError: userError?.message,
        });

        if (userError || !user) {
            console.log('[API] No user found, returning 401');
            return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
        }

        // Get the user's restaurant ID
        const { data: staffEntry, error: staffError } = await supabase
            .from('restaurant_staff')
            .select('restaurant_id')
            .eq('user_id', user.id)
            .eq('is_active', true)
            .order('created_at', { ascending: false })
            .limit(1)
            .maybeSingle();

        console.log('[API] Staff lookup:', {
            staffEntry,
            staffError: staffError?.message,
        });

        let restaurantId = staffEntry?.restaurant_id;

        // Fallback to agency_users
        if (!restaurantId) {
            const { data: agencyUser, error: agencyError } = await supabase
                .from('agency_users')
                .select('restaurant_ids')
                .eq('user_id', user.id)
                .maybeSingle();

            console.log('[API] Agency lookup:', {
                agencyUser,
                agencyError: agencyError?.message,
            });

            if (agencyUser?.restaurant_ids?.[0]) {
                restaurantId = agencyUser.restaurant_ids[0];
            }
        }

        console.log('[API] Final restaurant ID:', restaurantId);

        if (!restaurantId) {
            console.log('[API] No restaurant found for user');
            return NextResponse.json({ error: 'No restaurant found for user' }, { status: 404 });
        }

        const pilotGateResponse = enforcePilotAccess(restaurantId, request.method);
        if (pilotGateResponse) {
            return pilotGateResponse;
        }

        // MED-004: Use Promise.all for parallel queries
        // Fetch orders, service requests, and restaurant info in parallel
        const [ordersResult, requestsResult, restaurantResult] = await Promise.all([
            // Fetch orders
            supabase
                .from('orders')
                .select(columnsToString(ORDER_LIST_COLUMNS))
                .eq('restaurant_id', restaurantId)
                .order('created_at', { ascending: false })
                .limit(20),
            // Fetch service requests
            supabase
                .from('service_requests')
                .select('id, restaurant_id, table_number, request_type, status, created_at, notes')
                .eq('restaurant_id', restaurantId)
                .order('created_at', { ascending: false })
                .limit(20),
            // Get restaurant info
            supabase.from('restaurants').select('name, slug').eq('id', restaurantId).single(),
        ]);

        const { data: orders, error: orderError } = ordersResult;
        const { data: requests, error: requestError } = requestsResult;
        const { data: restaurant } = restaurantResult;

        console.log('[API] Orders fetch:', {
            count: orders?.length || 0,
            error: orderError?.message,
        });

        console.log('[API] Requests fetch:', {
            count: requests?.length || 0,
            error: requestError?.message,
        });

        console.log('[API] Restaurant info:', restaurant);

        const response = {
            orders: orders || [],
            requests: requests || [],
            restaurant: restaurant || { name: 'Restaurant', slug: 'restaurant' },
            restaurantId,
            errors: {
                orders: orderError?.message,
                requests: requestError?.message,
            },
        };

        console.log('[API] Returning response with:', {
            orderCount: response.orders.length,
            requestCount: response.requests.length,
            restaurantName: response.restaurant.name,
        });

        return NextResponse.json(response);
    } catch (error) {
        console.error('[API] Error:', error);
        return NextResponse.json(
            {
                error: 'Internal server error',
                details: error instanceof Error ? error.message : 'Unknown error',
            },
            { status: 500 }
        );
    }
}

import { NextRequest } from 'next/server';
import { createClient } from '@/lib/supabase/server';
import { apiError, apiSuccess } from '@/lib/api/response';
import { trackApiMetric } from '@/lib/api/metrics';
import { enforcePilotAccess } from '@/lib/api/pilotGate';

type AttentionItem = {
    id: string;
    type: 'order' | 'service_request' | 'alert';
    label: string;
    status: string;
    severity?: string | null;
    created_at: string | null;
    table_number: string | null;
};

function isInFlightStatus(status: string | null) {
    return ['pending', 'acknowledged', 'preparing', 'ready'].includes(status ?? '');
}

function resolveSince(range: string | null) {
    const now = new Date();
    const fallbackRange = 'today';

    if (range === 'week') {
        return {
            range: 'week',
            sinceIso: new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000).toISOString(),
        };
    }

    if (range === 'month') {
        return {
            range: 'month',
            sinceIso: new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000).toISOString(),
        };
    }

    const startOfToday = new Date();
    startOfToday.setHours(0, 0, 0, 0);
    return {
        range: fallbackRange,
        sinceIso: startOfToday.toISOString(),
    };
}

function resolvePreviousRange(range: string | null): { sinceIso: string; untilIso: string } {
    const now = new Date();
    const startOfToday = new Date();
    startOfToday.setHours(0, 0, 0, 0);

    if (range === 'week') {
        const until = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
        const since = new Date(now.getTime() - 14 * 24 * 60 * 60 * 1000);
        return { sinceIso: since.toISOString(), untilIso: until.toISOString() };
    }

    if (range === 'month') {
        const until = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);
        const since = new Date(now.getTime() - 60 * 24 * 60 * 60 * 1000);
        return { sinceIso: since.toISOString(), untilIso: until.toISOString() };
    }

    // Default: Yesterday
    const until = new Date(startOfToday.getTime());
    const since = new Date(startOfToday.getTime() - 24 * 60 * 60 * 1000);
    return { sinceIso: since.toISOString(), untilIso: until.toISOString() };
}

function resolvePriority(item: AttentionItem) {
    if (item.type === 'alert') {
        if (item.severity === 'critical') return 400;
        if (item.severity === 'high') return 350;
        if (item.severity === 'medium') return 300;
        return 250;
    }
    if (item.type === 'service_request') return 200;
    if (item.status === 'ready') return 180;
    if (item.status === 'preparing') return 160;
    if (item.status === 'acknowledged') return 140;
    return 120;
}

export async function GET(request: NextRequest) {
    const startedAt = Date.now();
    let responseStatus = 500;
    let restaurantIdForMetrics: string | null = null;
    let supabaseForMetrics: Awaited<ReturnType<typeof createClient>> | null = null;

    try {
        const supabase = await createClient();
        supabaseForMetrics = supabase;
        const {
            data: { user },
            error: userError,
        } = await supabase.auth.getUser();

        if (userError || !user) {
            responseStatus = 401;
            return apiError('Unauthorized', 401, 'UNAUTHORIZED');
        }

        const { data: staffEntry } = await supabase
            .from('restaurant_staff')
            .select('restaurant_id')
            .eq('user_id', user.id)
            .eq('is_active', true)
            .limit(1)
            .maybeSingle();

        let restaurantId = staffEntry?.restaurant_id ?? null;

        if (!restaurantId) {
            const { data: agencyUser } = await supabase
                .from('agency_users')
                .select('restaurant_ids')
                .eq('user_id', user.id)
                .maybeSingle();

            if (agencyUser?.restaurant_ids?.[0]) {
                restaurantId = agencyUser.restaurant_ids[0];
            }
        }

        if (!restaurantId) {
            responseStatus = 404;
            return apiError('No restaurant found for user', 404, 'RESTAURANT_NOT_FOUND');
        }
        restaurantIdForMetrics = restaurantId;

        const pilotGateResponse = enforcePilotAccess(restaurantId, request.method);
        if (pilotGateResponse) {
            responseStatus = pilotGateResponse.status;
            return pilotGateResponse;
        }

        const rangeParam = request.nextUrl.searchParams.get('range');
        const { range, sinceIso } = resolveSince(rangeParam);

        const [ordersRes, requestsRes, tablesRes, alertsRes, prevOrdersRes] = await Promise.all([
            supabase
                .from('orders')
                .select(
                    'id, order_number, status, table_number, created_at, completed_at, total_price'
                )
                .eq('restaurant_id', restaurantId)
                .gte('created_at', sinceIso)
                .order('created_at', { ascending: false })
                .limit(200),
            supabase
                .from('service_requests')
                .select('id, request_type, status, table_number, created_at')
                .eq('restaurant_id', restaurantId)
                .gte('created_at', sinceIso)
                .order('created_at', { ascending: false })
                .limit(200),
            supabase
                .from('tables')
                .select('id, status, is_active')
                .eq('restaurant_id', restaurantId),
            supabase
                .from('alert_events')
                .select('id, entity_type, entity_id, status, severity, created_at, resolved_at')
                .eq('restaurant_id', restaurantId)
                .is('resolved_at', null)
                .gte('created_at', sinceIso)
                .order('created_at', { ascending: false })
                .limit(50),
            supabase
                .from('orders')
                .select('total_price, created_at')
                .eq('restaurant_id', restaurantId)
                .gte('created_at', resolvePreviousRange(rangeParam).sinceIso)
                .lt('created_at', resolvePreviousRange(rangeParam).untilIso),
        ]);

        if (ordersRes.error) {
            responseStatus = 500;
            return apiError('Failed to load orders', 500, 'ORDERS_FETCH_FAILED');
        }
        if (requestsRes.error) {
            responseStatus = 500;
            return apiError('Failed to load service requests', 500, 'REQUESTS_FETCH_FAILED');
        }
        if (tablesRes.error) {
            responseStatus = 500;
            return apiError('Failed to load tables', 500, 'TABLES_FETCH_FAILED');
        }
        if (alertsRes.error) {
            responseStatus = 500;
            return apiError('Failed to load alerts', 500, 'ALERTS_FETCH_FAILED');
        }

        const orders = ordersRes.data ?? [];
        const requests = requestsRes.data ?? [];
        const tables = tablesRes.data ?? [];
        const alerts = alertsRes.data ?? [];
        const prevOrders = prevOrdersRes.data ?? [];

        const ordersInFlight = orders.filter(o => isInFlightStatus(o.status)).length;
        const completedOrders = orders.filter(
            o => o.status === 'completed' || o.status === 'served'
        );
        const activeTables = tables.filter(
            t => t.is_active !== false && t.status !== 'available'
        ).length;
        const openRequests = requests.filter(r => (r.status ?? 'pending') === 'pending').length;
        const grossSalesSantim = orders.reduce((sum, o) => sum + Number(o.total_price ?? 0), 0);
        const grossSales = grossSalesSantim / 100;
        const grossSalesPrevious =
            prevOrders.reduce((sum, o) => sum + Number(o.total_price ?? 0), 0) / 100;
        const avgOrderValue = orders.length > 0 ? Math.round(grossSales / orders.length) : 0;
        const uniqueTablesToday = new Set(orders.map(o => o.table_number).filter(Boolean)).size;

        let avgTicketMinutes = 0;
        if (completedOrders.length > 0) {
            const totalMinutes = completedOrders.reduce((sum, order) => {
                if (!order.created_at || !order.completed_at) {
                    return sum;
                }

                const created = new Date(order.created_at).getTime();
                const completed = new Date(order.completed_at).getTime();
                const diffMinutes = Math.max(0, Math.round((completed - created) / 60000));
                return sum + diffMinutes;
            }, 0);
            avgTicketMinutes = Math.round(totalMinutes / completedOrders.length);
        }

        const paymentSuccessRate =
            orders.length > 0 ? Math.round((completedOrders.length / orders.length) * 100) : 0;

        const attentionOrders: AttentionItem[] = orders
            .filter(o => isInFlightStatus(o.status))
            .slice(0, 10)
            .map(o => ({
                id: o.id,
                type: 'order',
                label: o.order_number || o.id,
                status: o.status ?? 'pending',
                created_at: o.created_at,
                table_number: o.table_number,
            }));

        const attentionRequests: AttentionItem[] = requests
            .filter(r => (r.status ?? 'pending') === 'pending')
            .slice(0, 10)
            .map(r => ({
                id: r.id,
                type: 'service_request',
                label: r.request_type,
                status: r.status ?? 'pending',
                created_at: r.created_at,
                table_number: r.table_number,
            }));

        const attentionAlerts: AttentionItem[] = alerts
            .filter(alert => (alert.status ?? 'open') !== 'resolved')
            .slice(0, 10)
            .map(alert => ({
                id: alert.id,
                type: 'alert',
                label: `${alert.entity_type} alert`,
                status: alert.status ?? 'open',
                severity: alert.severity ?? 'medium',
                created_at: alert.created_at,
                table_number: null,
            }));

        const attentionQueue = [...attentionAlerts, ...attentionRequests, ...attentionOrders].sort(
            (a, b) => {
                const priorityDiff = resolvePriority(b) - resolvePriority(a);
                if (priorityDiff !== 0) {
                    return priorityDiff;
                }
                const aTime = a.created_at ? new Date(a.created_at).getTime() : 0;
                const bTime = b.created_at ? new Date(b.created_at).getTime() : 0;
                return bTime - aTime;
            }
        );

        // Build chart data
        const chartPoints: any[] = [];
        const daysToTrack = rangeParam === 'month' ? 30 : 7;
        const now = new Date();

        for (let i = daysToTrack - 1; i >= 0; i--) {
            const d = new Date(now.getTime() - i * 24 * 60 * 60 * 1000);
            const label = d.toLocaleDateString('en-US', { weekday: 'short' });
            const dateStr = d.toISOString().split('T')[0];

            const dayIncome =
                orders
                    .filter(o => o.created_at?.startsWith(dateStr))
                    .reduce((sum, o) => sum + Number(o.total_price ?? 0), 0) / 100;

            const prevDate = new Date(
                d.getTime() -
                    (rangeParam === 'month' ? 30 : rangeParam === 'week' ? 7 : 1) *
                        24 *
                        60 *
                        60 *
                        1000
            );
            const prevDateStr = prevDate.toISOString().split('T')[0];
            const prevIncome =
                prevOrders
                    .filter(o => o.created_at?.startsWith(prevDateStr))
                    .reduce((sum, o) => sum + Number(o.total_price ?? 0), 0) / 100;

            chartPoints.push({
                label,
                income: Math.floor(dayIncome),
                previous: Math.floor(prevIncome),
            });
        }

        responseStatus = 200;
        return apiSuccess({
            restaurant_id: restaurantId,
            metrics: {
                orders_in_flight: ordersInFlight,
                avg_ticket_time_minutes: avgTicketMinutes,
                active_tables: activeTables,
                open_requests: openRequests,
                payment_success_rate: paymentSuccessRate,
                gross_sales_today: grossSales,
                gross_sales_previous: grossSalesPrevious,
                total_orders_today: orders.length,
                avg_order_value_etb: avgOrderValue,
                unique_tables_today: uniqueTablesToday,
            },
            attention_queue: attentionQueue,
            chart_data: chartPoints,
            alert_summary: {
                open_alerts: alerts.length,
            },
            filters: {
                range,
                since: sinceIso,
            },
            sync_status: {
                generated_at: new Date().toISOString(),
                source: 'postgres',
            },
        });
    } catch (error) {
        responseStatus = 500;
        return apiError(
            'Internal server error',
            500,
            'INTERNAL_ERROR',
            error instanceof Error ? error.message : 'Unknown error'
        );
    } finally {
        if (supabaseForMetrics) {
            const durationMs = Date.now() - startedAt;
            await trackApiMetric(supabaseForMetrics, {
                restaurantId: restaurantIdForMetrics,
                endpoint: '/api/merchant/command-center',
                method: 'GET',
                statusCode: responseStatus,
                durationMs,
            });
        }
    }
}

import { z } from 'zod';
import { apiError, apiSuccess } from '@/lib/api/response';
import { getAuthenticatedUser, getAuthorizedRestaurantContext } from '@/lib/api/authz';
import { parseJsonBody } from '@/lib/api/validation';
import { writeAuditLog } from '@/lib/api/audit';

const PresetSchema = z.enum(['owner', 'manager', 'kitchen_lead']);

const PatchPresetSchema = z.object({
    preset: PresetSchema,
});

function resolveRecommendedPreset(role: string | null | undefined): z.infer<typeof PresetSchema> {
    if (role === 'owner' || role === 'admin') return 'owner';
    if (role === 'manager') return 'manager';
    return 'kitchen_lead';
}

export async function GET() {
    const auth = await getAuthenticatedUser();
    if (!auth.ok) {
        return auth.response;
    }

    const context = await getAuthorizedRestaurantContext(auth.user.id, { phase: 'p1' });
    if (!context.ok) {
        return context.response;
    }

    const [restaurantRes, staffRes] = await Promise.all([
        context.supabase
            .from('restaurants')
            .select('settings')
            .eq('id', context.restaurantId)
            .single(),
        context.supabase
            .from('restaurant_staff')
            .select('role')
            .eq('restaurant_id', context.restaurantId)
            .eq('user_id', auth.user.id)
            .maybeSingle(),
    ]);

    if (restaurantRes.error || !restaurantRes.data) {
        return apiError(
            'Failed to fetch dashboard preset settings',
            500,
            'DASHBOARD_PRESET_FETCH_FAILED',
            restaurantRes.error?.message ?? 'Restaurant not found'
        );
    }

    const settings = (restaurantRes.data.settings ?? {}) as Record<string, unknown>;
    const currentPresetCandidate = (settings.dashboard_preset ?? null) as string | null;
    const currentPreset = PresetSchema.safeParse(currentPresetCandidate).success
        ? (currentPresetCandidate as z.infer<typeof PresetSchema>)
        : null;

    const recommendedPreset = resolveRecommendedPreset(staffRes.data?.role);

    return apiSuccess({
        current_preset: currentPreset,
        recommended_preset: recommendedPreset,
        available_presets: ['owner', 'manager', 'kitchen_lead'] as const,
    });
}

export async function PATCH(request: Request) {
    const auth = await getAuthenticatedUser();
    if (!auth.ok) {
        return auth.response;
    }

    const context = await getAuthorizedRestaurantContext(auth.user.id, { phase: 'p1' });
    if (!context.ok) {
        return context.response;
    }

    const parsed = await parseJsonBody(request, PatchPresetSchema);
    if (!parsed.success) {
        return parsed.response;
    }

    const { data: restaurant, error: fetchError } = await context.supabase
        .from('restaurants')
        .select('settings')
        .eq('id', context.restaurantId)
        .single();

    if (fetchError || !restaurant) {
        return apiError(
            'Failed to fetch current dashboard settings',
            500,
            'DASHBOARD_PRESET_FETCH_FAILED',
            fetchError?.message ?? 'Restaurant not found'
        );
    }

    const currentSettings = (restaurant.settings ?? {}) as Record<string, unknown>;
    const nextSettings = {
        ...currentSettings,
        dashboard_preset: parsed.data.preset,
    };

    const { error: updateError } = await context.supabase
        .from('restaurants')
        .update({ settings: nextSettings })
        .eq('id', context.restaurantId);

    if (updateError) {
        return apiError(
            'Failed to update dashboard preset',
            500,
            'DASHBOARD_PRESET_UPDATE_FAILED',
            updateError.message
        );
    }

    await writeAuditLog(context.supabase, {
        restaurant_id: context.restaurantId,
        user_id: auth.user.id,
        action: 'dashboard_preset_updated',
        entity_type: 'restaurant_settings',
        entity_id: context.restaurantId,
        old_value: { dashboard_preset: currentSettings.dashboard_preset ?? null } as any,
        new_value: { dashboard_preset: parsed.data.preset } as any,
        metadata: { source: 'merchant_dashboard' },
    });

    return apiSuccess({ preset: parsed.data.preset });
}

/**
 * Push Notification Subscription API
 *
 * Handles Web Push subscription registration and management.
 * Supports:
 * - POST /subscribe - Register a new push subscription
 * - DELETE /subscribe - Unsubscribe from push notifications
 * GET /subscribe - Get VAPID public key for client
 */

import { NextRequest } from 'next/server';
import { z } from 'zod';
import {
    registerDeviceToken,
    unsubscribeDevice,
    getVapidPublicKey,
    type WebPushSubscription,
} from '@/lib/notifications/push';
import { updateGuestPushPreference } from '@/lib/notifications/fallback';
import { parseJsonBody, parseQuery } from '@/lib/api/validation';
import { apiError, apiSuccess } from '@/lib/api/response';

// =========================================================
// Schemas
// =========================================================

/** Web Push subscription registration request */
const SubscribeRequestSchema = z.object({
    /** Web Push subscription object from the browser */
    subscription: z.object({
        endpoint: z.string().url(),
        keys: z.object({
            p256dh: z.string(),
            auth: z.string(),
        }),
    }),
    /** Device type: 'android' | 'ios' | 'web' */
    deviceType: z.enum(['android', 'ios', 'web']).default('web'),
    /** Device name (optional) */
    deviceName: z.string().optional(),
    /** Guest ID (optional, for authenticated guests) */
    guestId: z.string().uuid().optional(),
    /** Restaurant ID (required for tenant isolation) */
    restaurantId: z.string().uuid(),
    /** Whether to enable push notifications */
    pushEnabled: z.boolean().default(true),
});

/** Unsubscribe request */
const UnsubscribeRequestSchema = z.object({
    /** Device token or subscription endpoint to remove */
    token: z.string(),
});

/** GET request (get VAPID public key) */
const VapidKeyQuerySchema = z.object({
    restaurantId: z.string().uuid().optional(),
});

// =========================================================
// POST /subscribe - Register push subscription
// =========================================================

export async function POST(request: NextRequest) {
    try {
        // Parse request body
        const parseResult = await parseJsonBody(request, SubscribeRequestSchema);
        if (!parseResult.success) {
            return parseResult.response;
        }

        const { subscription, deviceType, deviceName, guestId, restaurantId, pushEnabled } =
            parseResult.data;

        // Serialize subscription to string for storage
        const token = JSON.stringify(subscription as WebPushSubscription);

        // Use provided guestId and restaurantId
        // In a full implementation, we'd also try to resolve from auth session
        const effectiveGuestId = guestId;
        const effectiveRestaurantId = restaurantId;

        // Register the device token
        await registerDeviceToken({
            guestId: effectiveGuestId,
            restaurantId: effectiveRestaurantId,
            token,
            deviceType,
            provider: 'webpush',
            deviceName,
            metadata: {
                endpoint: subscription.endpoint,
                p256dh: subscription.keys.p256dh,
                auth: subscription.keys.auth,
                subscribedAt: new Date().toISOString(),
            },
        });

        // Update guest push preferences if guest ID provided
        if (effectiveGuestId) {
            await updateGuestPushPreference({
                guestId: effectiveGuestId,
                restaurantId: effectiveRestaurantId,
                pushEnabled,
                preferredChannel: pushEnabled ? 'push' : 'sms',
            });
        }

        console.log('[push:subscribe] Subscription registered', {
            guestId: effectiveGuestId,
            restaurantId: effectiveRestaurantId,
            deviceType,
        });

        return apiSuccess({
            message: 'Push subscription registered successfully',
            subscription: {
                endpoint: subscription.endpoint,
                deviceType,
                pushEnabled,
            },
        });
    } catch (error) {
        console.error('[push:subscribe] Error:', error);
        return apiError(
            error instanceof Error ? error.message : 'Failed to register subscription',
            500,
            'SUBSCRIPTION_ERROR'
        );
    }
}

// =========================================================
// DELETE /subscribe - Unsubscribe from push notifications
// =========================================================

export async function DELETE(request: NextRequest) {
    try {
        // Parse request body
        const parseResult = await parseJsonBody(request, UnsubscribeRequestSchema);
        if (!parseResult.success) {
            return parseResult.response;
        }

        const { token } = parseResult.data;

        // Unsubscribe the device
        await unsubscribeDevice(token);

        console.log('[push:subscribe] Unsubscribed', {
            token: token.slice(0, 50) + '...',
        });

        return apiSuccess({
            message: 'Push subscription removed successfully',
        });
    } catch (error) {
        console.error('[push:unsubscribe] Error:', error);
        return apiError(
            error instanceof Error ? error.message : 'Failed to remove subscription',
            500,
            'UNSUBSCRIPTION_ERROR'
        );
    }
}

// =========================================================
// GET /subscribe - Get VAPID public key
// =========================================================

export async function GET(request: NextRequest) {
    try {
        const url = new URL(request.url);
        const restaurantId = url.searchParams.get('restaurantId') || undefined;

        // Parse and validate query params
        const parsed = parseQuery({ restaurantId }, VapidKeyQuerySchema);
        if (!parsed.success) {
            return parsed.response;
        }

        // Get VAPID public key
        const vapidPublicKey = getVapidPublicKey();

        if (!vapidPublicKey) {
            // Return a placeholder key for development
            return apiSuccess({
                publicKey: '',
                message: 'VAPID keys not configured - using development mode',
                isConfigured: false,
            });
        }

        return apiSuccess({
            publicKey: vapidPublicKey,
            isConfigured: true,
        });
    } catch (error) {
        console.error('[push:vapid] Error:', error);
        return apiError(
            error instanceof Error ? error.message : 'Failed to get VAPID key',
            500,
            'VAPID_KEY_ERROR'
        );
    }
}

