import { z } from 'zod';
import { apiError, apiSuccess } from '@/lib/api/response';
import { getAuthenticatedUser } from '@/lib/api/authz';
import { parseJsonBody } from '@/lib/api/validation';
import { writeAuditLog } from '@/lib/api/audit';
import { enforcePilotAccess } from '@/lib/api/pilotGate';

const AssignOrderSchema = z.object({
    staff_id: z.string().uuid(),
});

export async function POST(request: Request, context: { params: Promise<{ orderId: string }> }) {
    const auth = await getAuthenticatedUser();
    if (!auth.ok) {
        return auth.response;
    }

    const parsed = await parseJsonBody(request, AssignOrderSchema);
    if (!parsed.success) {
        return parsed.response;
    }

    const { orderId } = await context.params;
    const supabase = auth.supabase;

    const { data: order, error: orderError } = await supabase
        .from('orders')
        .select('id, restaurant_id')
        .eq('id', orderId)
        .maybeSingle();

    if (orderError) {
        return apiError('Failed to load order', 500, 'ORDER_FETCH_FAILED', orderError.message);
    }
    if (!order) {
        return apiError('Order not found', 404, 'ORDER_NOT_FOUND');
    }

    const pilotGateResponse = enforcePilotAccess(order.restaurant_id, request.method);
    if (pilotGateResponse) {
        return pilotGateResponse;
    }

    const { data: staffAssignee, error: assigneeError } = await supabase
        .from('restaurant_staff')
        .select('id, user_id, restaurant_id, is_active')
        .eq('id', parsed.data.staff_id)
        .eq('restaurant_id', order.restaurant_id)
        .eq('is_active', true)
        .maybeSingle();

    if (assigneeError) {
        return apiError(
            'Failed to verify assignee',
            500,
            'ASSIGNEE_LOOKUP_FAILED',
            assigneeError.message
        );
    }
    if (!staffAssignee) {
        return apiError('Assignee not found or inactive', 404, 'ASSIGNEE_NOT_FOUND');
    }

    const { error: eventError } = await (supabase as any).from('order_events').insert({
        restaurant_id: order.restaurant_id,
        order_id: order.id,
        event_type: 'assigned',
        actor_user_id: auth.user.id,
        metadata: {
            assigned_staff_id: staffAssignee.id,
            assigned_user_id: staffAssignee.user_id,
            source: 'merchant_dashboard',
        },
    });
    if (eventError) {
        return apiError(
            'Failed to record assignment event',
            500,
            'ORDER_ASSIGNMENT_EVENT_FAILED',
            eventError.message
        );
    }

    await writeAuditLog(supabase, {
        restaurant_id: order.restaurant_id,
        user_id: auth.user.id,
        action: 'order_assigned',
        entity_type: 'order',
        entity_id: order.id,
        metadata: {
            assigned_staff_id: staffAssignee.id,
            assigned_user_id: staffAssignee.user_id,
            source: 'merchant_dashboard',
        },
        new_value: { assigned_staff_id: staffAssignee.id },
    });

    return apiSuccess({
        order_id: order.id,
        assigned_staff_id: staffAssignee.id,
        assigned_user_id: staffAssignee.user_id,
    });
}

/**
 * Calculate Fire Times API Endpoint
 * TASK-KDS-001: Fire by Prep Time
 *
 * POST /api/orders/[orderId]/calculate-fire-times
 */
export const dynamic = 'force-dynamic';

import { NextRequest, NextResponse } from 'next/server';
import { createServerClient } from '@supabase/ssr';
import { cookies } from 'next/headers';
import { calculateOrderFireTimes, calculateCourseFireTimes } from '@/lib/kds/prepTimeCalculator';

export async function POST(
    request: NextRequest,
    { params }: { params: Promise<{ orderId: string }> }
) {
    try {
        const { orderId } = await params;
        const cookieStore = await cookies();

        const supabase = createServerClient(
            process.env.NEXT_PUBLIC_SUPABASE_URL!,
            process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
            {
                cookies: {
                    getAll() {
                        return cookieStore.getAll();
                    },
                    setAll(cookiesToSet) {
                        try {
                            cookiesToSet.forEach(({ name, value, options }) =>
                                cookieStore.set(name, value, options)
                            );
                        } catch {
                            // Ignore errors in middleware
                        }
                    },
                },
            }
        );

        // Get authenticated user
        const {
            data: { user },
            error: authError,
        } = await supabase.auth.getUser();

        if (authError || !user) {
            return NextResponse.json(
                { error: { code: 'UNAUTHORIZED', message: 'Authentication required' } },
                { status: 401 }
            );
        }

        // Get user's restaurant membership
        const { data: staffEntry, error: staffError } = await (supabase as any)
            .from('restaurant_staff')
            .select('restaurant_id, role')
            .eq('user_id', user.id)
            .eq('is_active', true)
            .maybeSingle();

        if (staffError || !staffEntry) {
            return NextResponse.json(
                { error: { code: 'FORBIDDEN', message: 'Not a staff member' } },
                { status: 403 }
            );
        }

        const _restaurantId = staffEntry.restaurant_id;

        // Parse request body
        const body = await request.json().catch(() => ({}));
        const targetCompletionTime = body.targetCompletionTime
            ? new Date(body.targetCompletionTime)
            : undefined;

        // Calculate fire times
        const result = await calculateOrderFireTimes(supabase, orderId, targetCompletionTime);

        if (!result.success) {
            return NextResponse.json(
                { error: { code: 'CALCULATION_FAILED', message: result.error } },
                { status: 400 }
            );
        }

        // Optionally use course-based firing
        if (body.courseBased) {
            const courseResult = await calculateCourseFireTimes(
                supabase,
                orderId,
                body.courseOptions
            );
            if (courseResult.success) {
                return NextResponse.json({
                    data: {
                        orderId,
                        calculation: courseResult.calculation,
                        courseBased: true,
                    },
                });
            }
        }

        return NextResponse.json({
            data: {
                orderId,
                calculation: result.calculation,
                courseBased: false,
            },
        });
    } catch (error) {
        console.error('[FireTimes API] Error:', error);
        return NextResponse.json(
            { error: { code: 'INTERNAL_ERROR', message: 'An unexpected error occurred' } },
            { status: 500 }
        );
    }
}

