import { z } from 'zod';
import { apiError, apiSuccess } from '@/lib/api/response';
import {
    getAuthenticatedUser,
    getAuthorizedRestaurantContext,
    getDeviceContext,
} from '@/lib/api/authz';
import { parseJsonBody } from '@/lib/api/validation';
import { writeAuditLog } from '@/lib/api/audit';

const CourseFireModeSchema = z.object({
    fire_mode: z.enum(['auto', 'manual']).optional(),
    current_course: z.enum(['appetizer', 'main', 'dessert', 'beverage', 'side']).optional(),
});

export async function PATCH(request: Request, context: { params: Promise<{ orderId: string }> }) {
    const auth = await getAuthenticatedUser();
    let actorUserId: string | null = null;
    let restaurantId: string;
    let db: any;

    if (auth.ok) {
        const restaurantContext = await getAuthorizedRestaurantContext(auth.user.id);
        if (!restaurantContext.ok) {
            return restaurantContext.response;
        }
        actorUserId = auth.user.id;
        restaurantId = restaurantContext.restaurantId;
        db = restaurantContext.supabase;
    } else {
        const deviceContext = await getDeviceContext(request);
        if (!deviceContext.ok) {
            return auth.response;
        }
        restaurantId = deviceContext.restaurantId;
        db = deviceContext.admin;
    }

    const parsed = await parseJsonBody(request, CourseFireModeSchema);
    if (!parsed.success) {
        return parsed.response;
    }

    const { orderId } = await context.params;

    // Get current order to check status
    const { data: order, error: orderError } = await db
        .from('orders')
        .select('id, status, fire_mode, current_course')
        .eq('restaurant_id', restaurantId)
        .eq('id', orderId)
        .maybeSingle();

    if (orderError) {
        return apiError('Failed to load order', 500, 'ORDER_FETCH_FAILED', orderError.message);
    }

    if (!order) {
        return apiError('Order not found', 404, 'ORDER_NOT_FOUND');
    }

    // Build update payload
    const updatePayload: Record<string, any> = {};

    if (parsed.data.fire_mode !== undefined) {
        updatePayload.fire_mode = parsed.data.fire_mode;
    }

    if (parsed.data.current_course !== undefined) {
        updatePayload.current_course = parsed.data.current_course;
    }

    if (Object.keys(updatePayload).length === 0) {
        return apiError('No valid fields to update', 400, 'NO_FIELDS_TO_UPDATE');
    }

    const { data: updatedOrder, error: updateError } = await db
        .from('orders')
        .update(updatePayload)
        .eq('restaurant_id', restaurantId)
        .eq('id', orderId)
        .select('id, fire_mode, current_course')
        .single();

    if (updateError) {
        return apiError('Failed to update order', 500, 'ORDER_UPDATE_FAILED', updateError.message);
    }

    await writeAuditLog(db, {
        restaurant_id: restaurantId,
        user_id: actorUserId,
        action: 'order_course_fire_updated',
        entity_type: 'order',
        entity_id: orderId,
        metadata: {
            previous_fire_mode: order.fire_mode,
            new_fire_mode: updatedOrder.fire_mode,
            previous_course: order.current_course,
            new_course: updatedOrder.current_course,
        },
    });

    return apiSuccess({
        order: {
            id: updatedOrder.id,
            fire_mode: updatedOrder.fire_mode,
            current_course: updatedOrder.current_course,
        },
    });
}

/**
 * Price Override API Endpoint
 * TASK-POS-001: Price Overrides with Audit Trail
 *
 * POST /api/orders/[orderId]/items/[itemId]/override-price
 */

import { NextRequest, NextResponse } from 'next/server';
import { createServerClient } from '@supabase/ssr';
import { cookies } from 'next/headers';
import {
    canOverridePrices,
    createPriceOverride,
    validatePriceOverrideInput,
} from '@/lib/services/priceOverrideService';

export async function POST(
    request: NextRequest,
    { params }: { params: Promise<{ orderId: string; itemId: string }> }
) {
    try {
        const { orderId, itemId } = await params;
        const cookieStore = await cookies();

        const supabase = createServerClient(
            process.env.NEXT_PUBLIC_SUPABASE_URL!,
            process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
            {
                cookies: {
                    getAll() {
                        return cookieStore.getAll();
                    },
                    setAll(cookiesToSet) {
                        try {
                            cookiesToSet.forEach(({ name, value, options }) =>
                                cookieStore.set(name, value, options)
                            );
                        } catch {
                            // Ignore errors in middleware
                        }
                    },
                },
            }
        );

        // Get authenticated user
        const {
            data: { user },
            error: authError,
        } = await supabase.auth.getUser();

        if (authError || !user) {
            return NextResponse.json(
                { error: { code: 'UNAUTHORIZED', message: 'Authentication required' } },
                { status: 401 }
            );
        }

        // Parse request body
        const body = await request.json();

        // Validate input
        const validation = validatePriceOverrideInput({
            orderId,
            orderItemId: itemId,
            ...body,
        });

        if (!validation.valid) {
            return NextResponse.json(
                {
                    error: {
                        code: 'VALIDATION_ERROR',
                        message: 'Invalid input',
                        details: validation.errors,
                    },
                },
                { status: 400 }
            );
        }

        // Get user's restaurant membership
        const { data: staffEntry, error: staffError } = await (supabase as any)
            .from('restaurant_staff')
            .select('restaurant_id, role')
            .eq('user_id', user.id)
            .eq('is_active', true)
            .maybeSingle();

        if (staffError || !staffEntry) {
            return NextResponse.json(
                { error: { code: 'FORBIDDEN', message: 'Not a staff member' } },
                { status: 403 }
            );
        }

        const restaurantId = staffEntry.restaurant_id;

        // Check permission
        const permissionCheck = await canOverridePrices(supabase, user.id, restaurantId);
        if (!permissionCheck.allowed) {
            return NextResponse.json(
                { error: { code: 'FORBIDDEN', message: permissionCheck.reason } },
                { status: 403 }
            );
        }

        // Create price override
        const result = await createPriceOverride(supabase, restaurantId, {
            orderId,
            orderItemId: itemId,
            originalPrice: body.originalPrice,
            newPrice: body.newPrice,
            reasonCode: body.reasonCode,
            reasonNotes: body.reasonNotes,
            staffId: user.id,
            approvedBy: body.approvedBy,
        });

        if (!result.success) {
            return NextResponse.json(
                { error: { code: 'OVERRIDE_FAILED', message: result.error } },
                { status: 400 }
            );
        }

        // Log to audit
        await (supabase as any).from('audit_logs').insert({
            action: 'price_override',
            entity_type: 'order_item',
            entity_id: itemId,
            restaurant_id: restaurantId,
            user_id: user.id,
            metadata: {
                order_id: orderId,
                original_price: body.originalPrice,
                new_price: body.newPrice,
                reason_code: body.reasonCode,
            },
        });

        return NextResponse.json({
            data: result.override,
            meta: { message: 'Price override applied successfully' },
        });
    } catch (error) {
        console.error('[PriceOverride API] Error:', error);
        return NextResponse.json(
            { error: { code: 'INTERNAL_ERROR', message: 'An unexpected error occurred' } },
            { status: 500 }
        );
    }
}

import { z } from 'zod';
import { apiError, apiSuccess } from '@/lib/api/response';
import { getAuthenticatedUser, getAuthorizedRestaurantContext } from '@/lib/api/authz';
import { sendOrderStatusSms } from '@/lib/notifications/sms';
import { writeAuditLog } from '@/lib/api/audit';
import { isIdempotencyKeyValid, resolveIdempotencyKey } from '@/lib/api/idempotency';

const OrderIdSchema = z.string().uuid();

const NotifyStatusSchema = z.object({
    status: z.enum(['preparing', 'ready', 'served', 'completed', 'cancelled']),
    notify_methods: z
        .array(z.enum(['sms', 'push']))
        .optional()
        .default(['sms']),
    custom_message: z.string().max(500).optional(),
    eta_minutes: z.number().int().min(1).max(180).optional(),
});

/**
 * POST /api/orders/[orderId]/notify-status
 *
 * Sends order status notifications to the customer via SMS and/or push.
 * This is the P0 SMS Order Notifications feature.
 */
export async function POST(
    request: Request,
    routeContext: { params: Promise<{ orderId: string }> }
) {
    const auth = await getAuthenticatedUser();
    if (!auth.ok) {
        return auth.response;
    }

    const context = await getAuthorizedRestaurantContext(auth.user.id);
    if (!context.ok) {
        return context.response;
    }

    const { orderId } = await routeContext.params;
    const orderIdParsed = OrderIdSchema.safeParse(orderId);
    if (!orderIdParsed.success) {
        return apiError('Invalid order id', 400, 'INVALID_ORDER_ID', orderIdParsed.error.flatten());
    }

    const explicitIdempotencyKey = request.headers.get('x-idempotency-key');
    if (explicitIdempotencyKey && !isIdempotencyKeyValid(explicitIdempotencyKey)) {
        return apiError('Invalid idempotency key', 400, 'INVALID_IDEMPOTENCY_KEY');
    }
    const idempotencyKey = resolveIdempotencyKey(explicitIdempotencyKey);

    const parsed = await parseJsonBody(request, NotifyStatusSchema);
    if (!parsed.success) {
        return parsed.response;
    }

    const db = context.supabase as any;

    // Fetch the order with customer details
    const { data: order, error: orderError } = await db
        .from('orders')
        .select(
            `
            id,
            order_number,
            status,
            customer_phone,
            customer_name,
            restaurant_id,
            table_sessions (
                id,
                guests (
                    id,
                    phone,
                    user_id
                )
            )
        `
        )
        .eq('id', orderIdParsed.data)
        .eq('restaurant_id', context.restaurantId)
        .maybeSingle();

    if (orderError) {
        return apiError('Failed to fetch order', 500, 'ORDER_FETCH_FAILED', orderError.message);
    }

    if (!order) {
        return apiError('Order not found', 404, 'ORDER_NOT_FOUND');
    }

    // Determine the phone number to notify
    let phoneToNotify = order.customer_phone;

    // If no direct customer phone, check table session guests
    if (!phoneToNotify && order.table_sessions?.guests?.phone) {
        phoneToNotify = order.table_sessions.guests.phone;
    }

    if (!phoneToNotify) {
        return apiError(
            'No customer phone number available for notification',
            400,
            'NO_CUSTOMER_PHONE'
        );
    }

    const notifyMethods = parsed.data.notify_methods ?? ['sms'];
    const results: { method: string; success: boolean; error?: string }[] = [];

    // Send SMS notification
    if (notifyMethods.includes('sms')) {
        const smsResult = await sendOrderStatusSms({
            toPhone: phoneToNotify,
            orderNumber: order.order_number,
            status: parsed.data.status,
            etaMinutes: parsed.data.eta_minutes,
        });

        results.push({
            method: 'sms',
            success: smsResult.success,
            error: smsResult.error,
        });

        // Log to notification_logs if available
        try {
            await db.from('notification_logs').insert({
                restaurant_id: context.restaurantId,
                order_id: order.id,
                type: 'order_status_sms',
                recipient: phoneToNotify,
                status: smsResult.success ? 'sent' : 'failed',
                provider: smsResult.provider,
                error_message: smsResult.error ?? null,
                metadata: {
                    order_status: parsed.data.status,
                    idempotency_key: idempotencyKey,
                },
            });
        } catch {
            // Non-critical: don't fail if logging fails
        }
    }

    // Send Push notification (if push token exists)
    if (notifyMethods.includes('push')) {
        try {
            // Check for push tokens for this customer
            const { data: pushTokens } = await db
                .from('push_tokens')
                .select('token')
                .eq('phone', phoneToNotify)
                .eq('is_active', true);

            if (pushTokens && pushTokens.length > 0) {
                // Import push notification service
                const { sendBatchPushNotifications } = await import('@/lib/notifications/push');

                // Send to all registered devices
                const pushResults = await sendBatchPushNotifications(
                    pushTokens.map((t: { token: string }) => ({
                        token: t.token,
                        title: `Order #${order.order_number} Update`,
                        body: `Your order status is now: ${parsed.data.status}`,
                        data: {
                            order_id: order.id,
                            order_number: order.order_number,
                            status: parsed.data.status,
                            type: 'order_status_update',
                        },
                    }))
                );

                const anySuccess = pushResults.some(r => r.success);
                const errors = pushResults
                    .filter(r => !r.success)
                    .map(r => r.error)
                    .filter(Boolean);

                results.push({
                    method: 'push',
                    success: anySuccess,
                    error: errors.length > 0 ? errors.join('; ') : undefined,
                });
            } else {
                results.push({
                    method: 'push',
                    success: false,
                    error: 'No push tokens registered for this customer',
                });
            }
        } catch (pushError) {
            results.push({
                method: 'push',
                success: false,
                error: pushError instanceof Error ? pushError.message : 'Push notification failed',
            });
        }
    }

    // Update order status if provided
    if (parsed.data.status && order.status !== parsed.data.status) {
        await db
            .from('orders')
            .update({
                status: parsed.data.status,
                updated_at: new Date().toISOString(),
            })
            .eq('id', order.id);
    }

    // Write audit log
    await writeAuditLog(context.supabase, {
        restaurant_id: context.restaurantId,
        user_id: auth.user.id,
        action: 'order_status_notification_sent',
        entity_type: 'order',
        entity_id: order.id,
        new_value: {
            status: parsed.data.status,
            notify_methods: notifyMethods,
            results,
        },
        metadata: {
            customer_phone: phoneToNotify.slice(-4).padStart(phoneToNotify.length, '*'), // Masked
            idempotency_key: idempotencyKey,
        },
    });

    const allSuccess = results.every(r => r.success);

    return apiSuccess(
        {
            order_id: order.id,
            order_number: order.order_number,
            notifications: results,
            all_success: allSuccess,
            idempotency_key: idempotencyKey,
        },
        allSuccess ? 200 : 207 // 207 Multi-Status if partial failure
    );
}

// Helper function to parse JSON body with Zod validation
async function parseJsonBody<T extends z.ZodTypeAny>(
    request: Request,
    schema: T
): Promise<{ success: true; data: z.infer<T> } | { success: false; response: Response }> {
    try {
        const body = await request.json();
        const parsed = schema.safeParse(body);
        if (!parsed.success) {
            return {
                success: false,
                response: apiError(
                    'Invalid request body',
                    400,
                    'VALIDATION_ERROR',
                    parsed.error.flatten()
                ),
            };
        }
        return { success: true, data: parsed.data };
    } catch {
        return {
            success: false,
            response: apiError('Invalid JSON body', 400, 'INVALID_JSON'),
        };
    }
}

import { z } from 'zod';
import { apiError, apiSuccess } from '@/lib/api/response';
import {
    getAuthenticatedUser,
    getAuthorizedRestaurantContext,
    getDeviceContext,
} from '@/lib/api/authz';
import { parseJsonBody } from '@/lib/api/validation';
import { writeAuditLog } from '@/lib/api/audit';
import { resolveIdempotencyKey } from '@/lib/api/idempotency';
import type { Json } from '@/types/database';
import { redisRateLimiters } from '@/lib/security';

const SplitMethodSchema = z.enum(['even', 'items', 'custom']);

const SplitRequestLineSchema = z.object({
    guest_name: z.string().trim().max(80).optional(),
    item_ids: z.array(z.string().uuid()).max(250).optional(),
    amount: z.coerce.number().min(0).max(100000000).optional(),
    metadata: z.record(z.string(), z.unknown()).optional(),
});

const UpsertOrderSplitSchema = z.object({
    method: SplitMethodSchema,
    splits: z.array(SplitRequestLineSchema).min(2).max(20),
});

type SplitMethod = z.infer<typeof SplitMethodSchema>;
type SplitRequest = z.infer<typeof UpsertOrderSplitSchema>;

function toCents(amount: number): number {
    return Math.round(amount * 100);
}

function fromCents(cents: number): number {
    return Number((cents / 100).toFixed(2));
}

function buildEvenAmounts(totalPrice: number, splitCount: number): number[] {
    const totalCents = toCents(totalPrice);
    const base = Math.floor(totalCents / splitCount);
    const remainder = totalCents - base * splitCount;

    const cents = Array.from({ length: splitCount }, (_, idx) =>
        idx < remainder ? base + 1 : base
    );
    return cents.map(fromCents);
}

export async function GET(_request: Request, context: { params: Promise<{ orderId: string }> }) {
    const auth = await getAuthenticatedUser();
    let restaurantId: string;
    let db: any;

    if (auth.ok) {
        const restaurantContext = await getAuthorizedRestaurantContext(auth.user.id);
        if (!restaurantContext.ok) {
            return restaurantContext.response;
        }
        restaurantId = restaurantContext.restaurantId;
        db = restaurantContext.supabase;
    } else {
        const deviceContext = await getDeviceContext(_request);
        if (!deviceContext.ok) {
            return auth.response;
        }
        restaurantId = deviceContext.restaurantId;
        db = deviceContext.admin;
    }

    const { orderId } = await context.params;
    const dbAny = db as any;

    const { data: order, error: orderError } = await db
        .from('orders')
        .select('id, total_price, status')
        .eq('restaurant_id', restaurantId)
        .eq('id', orderId)
        .maybeSingle();

    if (orderError) {
        return apiError('Failed to load order', 500, 'ORDER_FETCH_FAILED', orderError.message);
    }
    if (!order) {
        return apiError('Order not found', 404, 'ORDER_NOT_FOUND');
    }

    const { data: splits, error: splitsError } = await dbAny
        .from('order_check_splits')
        .select('*')
        .eq('restaurant_id', restaurantId)
        .eq('order_id', orderId)
        .order('split_index', { ascending: true });

    if (splitsError) {
        return apiError(
            'Failed to load check splits',
            500,
            'ORDER_SPLITS_FETCH_FAILED',
            splitsError.message
        );
    }

    const splitRows = (splits ?? []) as Array<Record<string, unknown>>;
    const splitIds = splitRows.map(row => String(row.id)).filter(Boolean);

    let splitItems: Array<Record<string, unknown>> = [];
    let splitPayments: Array<Record<string, unknown>> = [];
    let orderItems: Array<Record<string, unknown>> = [];

    const { data: orderItemsData, error: orderItemsError } = await dbAny
        .from('order_items')
        .select('id, name, quantity, price, notes, created_at')
        .eq('order_id', orderId)
        .order('created_at', { ascending: true });

    if (orderItemsError) {
        return apiError(
            'Failed to load order items',
            500,
            'ORDER_ITEMS_FETCH_FAILED',
            orderItemsError.message
        );
    }

    orderItems = (orderItemsData ?? []) as Array<Record<string, unknown>>;

    if (splitIds.length > 0) {
        const [
            { data: splitItemsData, error: splitItemsError },
            { data: splitPaymentsData, error: splitPaymentsError },
        ] = await Promise.all([
            dbAny
                .from('order_check_split_items')
                .select('*')
                .eq('restaurant_id', restaurantId)
                .eq('order_id', orderId),
            dbAny
                .from('payments')
                .select('id, split_id, amount, tip_amount, method, status, created_at')
                .eq('restaurant_id', restaurantId)
                .in('split_id', splitIds),
        ]);

        if (splitItemsError) {
            return apiError(
                'Failed to load split items',
                500,
                'ORDER_SPLIT_ITEMS_FETCH_FAILED',
                splitItemsError.message
            );
        }
        if (splitPaymentsError) {
            return apiError(
                'Failed to load split payments',
                500,
                'ORDER_SPLIT_PAYMENTS_FETCH_FAILED',
                splitPaymentsError.message
            );
        }

        splitItems = (splitItemsData ?? []) as Array<Record<string, unknown>>;
        splitPayments = (splitPaymentsData ?? []) as Array<Record<string, unknown>>;
    }

    const inferredMethod: SplitMethod =
        splitItems.length > 0
            ? 'items'
            : splitRows.some(
                    row => row.requested_amount !== null && row.requested_amount !== undefined
                )
              ? 'custom'
              : 'even';

    return apiSuccess({
        order: {
            id: order.id,
            total_price: Number(order.total_price ?? 0),
            status: order.status,
        },
        method: inferredMethod,
        order_items: orderItems,
        splits: splitRows,
        split_items: splitItems,
        split_payments: splitPayments,
    });
}

type ComputedSplit = {
    split_index: number;
    split_label: string | null;
    requested_amount: number | null;
    computed_amount: number;
    item_ids: string[];
    metadata: Json;
};

export async function POST(request: Request, context: { params: Promise<{ orderId: string }> }) {
    // Apply rate limiting for order split (mutation endpoint)
    const rateLimitResponse = await redisRateLimiters.mutation(request as any);
    if (rateLimitResponse) {
        return rateLimitResponse;
    }

    const auth = await getAuthenticatedUser();
    let actorUserId: string | null = null;
    let restaurantId: string;
    let db: any;

    if (auth.ok) {
        const restaurantContext = await getAuthorizedRestaurantContext(auth.user.id);
        if (!restaurantContext.ok) {
            return restaurantContext.response;
        }
        actorUserId = auth.user.id;
        restaurantId = restaurantContext.restaurantId;
        db = restaurantContext.supabase;
    } else {
        const deviceContext = await getDeviceContext(request);
        if (!deviceContext.ok) {
            return auth.response;
        }
        restaurantId = deviceContext.restaurantId;
        db = deviceContext.admin;
    }

    // Extract idempotency key from headers for retry safety
    const explicitIdempotencyKey = request.headers.get('x-idempotency-key');
    const idempotencyKey = resolveIdempotencyKey(explicitIdempotencyKey);

    const parsed = await parseJsonBody(request, UpsertOrderSplitSchema);
    if (!parsed.success) {
        return parsed.response;
    }

    const payload = parsed.data;
    const { orderId } = await context.params;
    const dbAny = db as any;

    const { data: order, error: orderError } = await db
        .from('orders')
        .select('id, total_price, status')
        .eq('restaurant_id', restaurantId)
        .eq('id', orderId)
        .maybeSingle();

    if (orderError) {
        return apiError('Failed to load order', 500, 'ORDER_FETCH_FAILED', orderError.message);
    }
    if (!order) {
        return apiError('Order not found', 404, 'ORDER_NOT_FOUND');
    }
    if (order.status === 'cancelled' || order.status === 'completed') {
        return apiError(
            'Order cannot be split in current status',
            409,
            'ORDER_SPLIT_INVALID_STATUS'
        );
    }

    const totalPrice = Number(order.total_price ?? 0);
    const computed = await computeSplitPlan(dbAny, restaurantId, orderId, totalPrice, payload);
    if (!computed.ok) {
        return computed.response;
    }

    const { error: deleteItemsError } = await dbAny
        .from('order_check_split_items')
        .delete()
        .eq('restaurant_id', restaurantId)
        .eq('order_id', orderId);

    if (deleteItemsError) {
        return apiError(
            'Failed to reset existing split items',
            500,
            'ORDER_SPLIT_RESET_FAILED',
            deleteItemsError.message
        );
    }

    const { error: deleteSplitsError } = await dbAny
        .from('order_check_splits')
        .delete()
        .eq('restaurant_id', restaurantId)
        .eq('order_id', orderId);

    if (deleteSplitsError) {
        return apiError(
            'Failed to reset existing splits',
            500,
            'ORDER_SPLIT_RESET_FAILED',
            deleteSplitsError.message
        );
    }

    const splitRowsToInsert = computed.plan.map(split => ({
        restaurant_id: restaurantId,
        order_id: orderId,
        split_index: split.split_index,
        split_label: split.split_label,
        requested_amount: split.requested_amount,
        computed_amount: split.computed_amount,
        status: 'open',
        metadata: split.metadata,
        created_by: actorUserId,
    }));

    const { data: insertedSplits, error: insertSplitsError } = await dbAny
        .from('order_check_splits')
        .insert(splitRowsToInsert)
        .select('*')
        .order('split_index', { ascending: true });

    if (insertSplitsError) {
        return apiError(
            'Failed to create check splits',
            500,
            'ORDER_SPLIT_CREATE_FAILED',
            insertSplitsError.message
        );
    }

    const splitIdByIndex = new Map<number, string>();
    for (const row of (insertedSplits ?? []) as Array<Record<string, unknown>>) {
        const splitIndex = Number(row.split_index);
        const splitId = String(row.id ?? '');
        if (Number.isFinite(splitIndex) && splitId.length > 0) {
            splitIdByIndex.set(splitIndex, splitId);
        }
    }

    const splitItemRows = computed.plan.flatMap(split =>
        split.item_ids.map(orderItemId => ({
            restaurant_id: restaurantId,
            order_id: orderId,
            split_id: splitIdByIndex.get(split.split_index),
            order_item_id: orderItemId,
            quantity: 1,
            line_amount: computed.itemAmountById.get(orderItemId) ?? 0,
        }))
    );

    let insertedSplitItems: Array<Record<string, unknown>> = [];
    if (splitItemRows.length > 0) {
        const { data: insertItemsData, error: insertItemsError } = await dbAny
            .from('order_check_split_items')
            .insert(splitItemRows)
            .select('*');

        if (insertItemsError) {
            return apiError(
                'Failed to create split item mapping',
                500,
                'ORDER_SPLIT_ITEMS_CREATE_FAILED',
                insertItemsError.message
            );
        }

        insertedSplitItems = (insertItemsData ?? []) as Array<Record<string, unknown>>;
    }

    await writeAuditLog(db, {
        restaurant_id: restaurantId,
        user_id: actorUserId,
        action: 'order_split_configured',
        entity_type: 'order',
        entity_id: orderId,
        metadata: {
            method: payload.method,
            split_count: payload.splits.length,
            source: 'merchant_dashboard',
            idempotency_key: idempotencyKey,
        },
        new_value: {
            method: payload.method,
            splits: splitRowsToInsert,
        } as Json,
    });

    return apiSuccess(
        {
            order_id: orderId,
            method: payload.method,
            splits: insertedSplits ?? [],
            split_items: insertedSplitItems,
        },
        201
    );
}

async function computeSplitPlan(
    dbAny: any,
    restaurantId: string,
    orderId: string,
    totalPrice: number,
    payload: SplitRequest
): Promise<
    | { ok: true; plan: ComputedSplit[]; itemAmountById: Map<string, number> }
    | { ok: false; response: ReturnType<typeof apiError> }
> {
    const plan: ComputedSplit[] = [];
    const itemAmountById = new Map<string, number>();
    const splitCount = payload.splits.length;

    if (payload.method === 'even') {
        const amounts = buildEvenAmounts(totalPrice, splitCount);
        for (let index = 0; index < splitCount; index += 1) {
            const input = payload.splits[index];
            plan.push({
                split_index: index,
                split_label: input.guest_name?.trim() || `Guest ${index + 1}`,
                requested_amount: null,
                computed_amount: amounts[index],
                item_ids: [],
                metadata: (input.metadata ?? {}) as Json,
            });
        }
        return { ok: true, plan, itemAmountById };
    }

    if (payload.method === 'custom') {
        const amounts = payload.splits.map((split, index) => {
            if (
                typeof split.amount !== 'number' ||
                !Number.isFinite(split.amount) ||
                split.amount <= 0
            ) {
                return { index, amount: null };
            }
            return { index, amount: Number(split.amount.toFixed(2)) };
        });

        if (amounts.some(entry => entry.amount === null)) {
            return {
                ok: false,
                response: apiError(
                    'Custom split requires an amount for each guest',
                    400,
                    'ORDER_SPLIT_INVALID_CUSTOM_AMOUNTS'
                ),
            };
        }

        const sum = amounts.reduce((acc, entry) => acc + (entry.amount ?? 0), 0);
        if (Math.abs(sum - totalPrice) > 0.01) {
            return {
                ok: false,
                response: apiError(
                    'Custom split amounts must match order total',
                    400,
                    'ORDER_SPLIT_TOTAL_MISMATCH',
                    {
                        expected_total: Number(totalPrice.toFixed(2)),
                        provided_total: Number(sum.toFixed(2)),
                    }
                ),
            };
        }

        for (const entry of amounts) {
            const input = payload.splits[entry.index];
            const amount = entry.amount ?? 0;
            plan.push({
                split_index: entry.index,
                split_label: input.guest_name?.trim() || `Guest ${entry.index + 1}`,
                requested_amount: amount,
                computed_amount: amount,
                item_ids: [],
                metadata: (input.metadata ?? {}) as Json,
            });
        }
        return { ok: true, plan, itemAmountById };
    }

    const { data: orderItems, error: orderItemsError } = await dbAny
        .from('order_items')
        .select('id, quantity, price')
        .eq('order_id', orderId)
        .order('created_at', { ascending: true });

    if (orderItemsError) {
        return {
            ok: false,
            response: apiError(
                'Failed to load order items for split',
                500,
                'ORDER_ITEMS_FETCH_FAILED',
                orderItemsError.message
            ),
        };
    }

    const rows = (orderItems ?? []) as Array<Record<string, unknown>>;
    if (rows.length === 0) {
        return {
            ok: false,
            response: apiError(
                'Item-based split requires relational order items',
                409,
                'ORDER_SPLIT_ITEMS_NOT_AVAILABLE'
            ),
        };
    }

    const knownOrderItemIds = new Set<string>();
    for (const row of rows) {
        const id = String(row.id ?? '');
        const quantity = Number(row.quantity ?? 1);
        const unitPrice = Number(row.price ?? 0);
        const lineAmount = Number((quantity * unitPrice).toFixed(2));
        if (id.length > 0) {
            knownOrderItemIds.add(id);
            itemAmountById.set(id, lineAmount);
        }
    }

    const seen = new Set<string>();
    for (let index = 0; index < splitCount; index += 1) {
        const input = payload.splits[index];
        const itemIds = input.item_ids ?? [];

        if (itemIds.length === 0) {
            return {
                ok: false,
                response: apiError(
                    'Each split must include at least one order item',
                    400,
                    'ORDER_SPLIT_MISSING_ITEMS'
                ),
            };
        }

        const deduped = [...new Set(itemIds)];
        for (const itemId of deduped) {
            if (!knownOrderItemIds.has(itemId)) {
                return {
                    ok: false,
                    response: apiError(
                        'Split references unknown order item',
                        400,
                        'ORDER_SPLIT_UNKNOWN_ITEM',
                        { order_item_id: itemId }
                    ),
                };
            }
            if (seen.has(itemId)) {
                return {
                    ok: false,
                    response: apiError(
                        'Each order item can only belong to one split',
                        400,
                        'ORDER_SPLIT_DUPLICATE_ITEM',
                        { order_item_id: itemId }
                    ),
                };
            }
            seen.add(itemId);
        }

        const computedAmount = deduped.reduce(
            (acc, itemId) => acc + (itemAmountById.get(itemId) ?? 0),
            0
        );
        plan.push({
            split_index: index,
            split_label: input.guest_name?.trim() || `Guest ${index + 1}`,
            requested_amount: null,
            computed_amount: Number(computedAmount.toFixed(2)),
            item_ids: deduped,
            metadata: (input.metadata ?? {}) as Json,
        });
    }

    if (seen.size !== knownOrderItemIds.size) {
        return {
            ok: false,
            response: apiError(
                'Item split must allocate all order items',
                400,
                'ORDER_SPLIT_INCOMPLETE_ITEMS',
                { allocated_items: seen.size, total_items: knownOrderItemIds.size }
            ),
        };
    }

    const allocatedTotal = Number(
        plan.reduce((acc, split) => acc + split.computed_amount, 0).toFixed(2)
    );
    if (Math.abs(allocatedTotal - totalPrice) > 0.01) {
        return {
            ok: false,
            response: apiError(
                'Allocated split total does not match order total',
                400,
                'ORDER_SPLIT_TOTAL_MISMATCH',
                { expected_total: Number(totalPrice.toFixed(2)), allocated_total: allocatedTotal }
            ),
        };
    }

    return { ok: true, plan, itemAmountById };
}

import { NextRequest } from 'next/server';
import { z } from 'zod';
import { createClient } from '@/lib/supabase/server';
import { apiError, apiSuccess } from '@/lib/api/response';
import { trackApiMetric } from '@/lib/api/metrics';
import { enforcePilotAccess } from '@/lib/api/pilotGate';
import { sendOrderStatusSms } from '@/lib/notifications/sms';
import { createGebetaEvent } from '@/lib/events/contracts';
import { publishEvent } from '@/lib/events/runtime';
import { redisRateLimiters } from '@/lib/security';

const UpdateOrderStatusSchema = z.object({
    status: z.enum([
        'pending',
        'acknowledged',
        'preparing',
        'ready',
        'served',
        'completed',
        'cancelled',
    ]),
    type: z.enum(['kitchen', 'bar', 'general']).optional(),
});

const ALLOWED_TRANSITIONS: Record<string, string[]> = {
    pending: ['acknowledged', 'preparing', 'ready', 'cancelled'], // KDS can fast-track any order
    acknowledged: ['preparing', 'ready', 'cancelled'],
    preparing: ['ready', 'cancelled'],
    ready: ['served', 'completed', 'cancelled'],
    served: ['completed'],
    completed: [],
    cancelled: [],
};

function canTransition(current: string | null, next: string) {
    if (!current) return false;
    return (ALLOWED_TRANSITIONS[current] || []).includes(next);
}

export async function PATCH(
    request: NextRequest,
    context: { params: Promise<{ orderId: string }> }
) {
    // Apply rate limiting for order status updates (mutation endpoint)
    const rateLimitResponse = await redisRateLimiters.mutation(request);
    if (rateLimitResponse) {
        return rateLimitResponse;
    }

    const startedAt = Date.now();
    let responseStatus = 500;
    let restaurantIdForMetrics: string | null = null;

    try {
        const { orderId } = await context.params;
        const body = await request.json();
        const parsed = UpdateOrderStatusSchema.safeParse(body);

        if (!parsed.success) {
            responseStatus = 400;
            return apiError(
                'Invalid request payload',
                400,
                'INVALID_PAYLOAD',
                parsed.error.flatten()
            );
        }

        const supabase = await createClient();

        // Parallelize: auth check + order fetch at the same time
        const [
            {
                data: { user },
                error: userError,
            },
            { data: order, error: orderError },
        ] = await Promise.all([
            supabase.auth.getUser(),
            supabase
                .from('orders')
                .select('id, restaurant_id, status')
                .eq('id', orderId)
                .maybeSingle(),
        ]);

        if (userError || !user) {
            responseStatus = 401;
            return apiError('Unauthorized', 401, 'UNAUTHORIZED');
        }

        if (orderError) {
            responseStatus = 500;
            return apiError('Failed to load order', 500, 'ORDER_FETCH_FAILED', orderError.message);
        }
        if (!order) {
            responseStatus = 404;
            return apiError('Order not found', 404, 'ORDER_NOT_FOUND');
        }

        restaurantIdForMetrics = order.restaurant_id;

        const pilotGateResponse = enforcePilotAccess(order.restaurant_id, request.method);
        if (pilotGateResponse) {
            responseStatus = pilotGateResponse.status;
            return pilotGateResponse;
        }

        // Staff auth check — must be sequential (needs restaurant_id from order)
        const { data: staff, error: staffError } = await supabase
            .from('restaurant_staff')
            .select('id')
            .eq('restaurant_id', order.restaurant_id)
            .eq('user_id', user.id)
            .eq('is_active', true)
            .maybeSingle();

        if (staffError) {
            responseStatus = 500;
            return apiError(
                'Failed to verify staff access',
                500,
                'STAFF_ACCESS_CHECK_FAILED',
                staffError.message
            );
        }
        if (!staff) {
            responseStatus = 403;
            return apiError('Forbidden', 403, 'FORBIDDEN');
        }

        if (!canTransition(order.status, parsed.data.status)) {
            responseStatus = 409;
            return apiError(
                `Invalid status transition from "${order.status}" to "${parsed.data.status}"`,
                409,
                'INVALID_TRANSITION'
            );
        }

        const now = new Date().toISOString();
        const updatePayload: Record<string, string> = {
            status: parsed.data.status,
            updated_at: now,
        };
        if (parsed.data.status === 'acknowledged') updatePayload.acknowledged_at = now;
        if (parsed.data.status === 'ready' || parsed.data.status === 'completed')
            updatePayload.completed_at = now;
        if (['acknowledged', 'preparing', 'ready'].includes(parsed.data.status)) {
            updatePayload.kitchen_status = parsed.data.status;
        }

        const { data: updatedOrder, error: updateError } = await supabase
            .from('orders')
            .update(updatePayload)
            .eq('id', order.id)
            .select('*')
            .single();

        if (updateError || !updatedOrder) {
            responseStatus = 500;
            return apiError(
                'Failed to update order status',
                500,
                'ORDER_UPDATE_FAILED',
                updateError?.message
            );
        }

        // ✅ Respond immediately — fire-and-forget audit + event + metrics writes
        responseStatus = 200;
        const response = apiSuccess(updatedOrder);

        const smsPromise = (async () => {
            if (!updatedOrder?.customer_phone) return;
            const { data: restaurantSettings } = await supabase
                .from('restaurants')
                .select('settings')
                .eq('id', order.restaurant_id)
                .maybeSingle();
            const notificationsSettings = (
                restaurantSettings?.settings as Record<string, unknown> | null
            )?.notifications as Record<string, unknown> | undefined;
            const smsEnabled = Boolean(notificationsSettings?.sms_enabled);
            if (!smsEnabled) return;

            await sendOrderStatusSms({
                toPhone: updatedOrder.customer_phone,
                orderNumber: updatedOrder.order_number ?? updatedOrder.id,
                status: parsed.data.status,
            });
        })();

        // These do NOT block the response
        const durationMs = Date.now() - startedAt;
        Promise.all([
            supabase.from('audit_logs').insert({
                restaurant_id: order.restaurant_id,
                user_id: user.id,
                action: 'order_status_updated',
                entity_type: 'order',
                entity_id: order.id,
                old_value: { status: order.status },
                new_value: { status: parsed.data.status },
                metadata: { source: 'merchant_dashboard' },
            }),
            (supabase as any).from('order_events').insert({
                restaurant_id: order.restaurant_id,
                order_id: order.id,
                event_type: 'status_changed',
                from_status: order.status,
                to_status: parsed.data.status,
                actor_user_id: user.id,
                metadata: { source: 'merchant_dashboard' },
            }),
            ...(parsed.data.status === 'completed' || parsed.data.status === 'served'
                ? [
                      publishEvent(
                          createGebetaEvent('order.completed', {
                              restaurant_id: order.restaurant_id,
                              order_id: order.id,
                              previous_status: order.status,
                              status: parsed.data.status,
                              source: 'merchant_dashboard',
                          })
                      ),
                  ]
                : []),
            trackApiMetric(supabase, {
                restaurantId: restaurantIdForMetrics,
                endpoint: '/api/orders/:id/status',
                method: 'PATCH',
                statusCode: responseStatus,
                durationMs,
            }),
            smsPromise,
        ]).catch(err => {
            console.warn('[PATCH /api/orders/:id/status] background write failed:', err);
        });

        return response;
    } catch (error) {
        responseStatus = 500;
        return apiError(
            'Internal server error',
            500,
            'INTERNAL_ERROR',
            error instanceof Error ? error.message : 'Unknown error'
        );
    }
}

import { z } from 'zod';
import { apiError, apiSuccess } from '@/lib/api/response';
import { getAuthenticatedUser } from '@/lib/api/authz';
import { parseJsonBody } from '@/lib/api/validation';
import { writeAuditLog } from '@/lib/api/audit';
import { enforcePilotAccess } from '@/lib/api/pilotGate';

const BulkStatusSchema = z.object({
    order_ids: z.array(z.string().uuid()).min(1).max(50),
    status: z.enum(['acknowledged', 'preparing', 'ready', 'served', 'completed', 'cancelled']),
});

const ALLOWED_TRANSITIONS: Record<string, string[]> = {
    pending: ['acknowledged', 'cancelled'],
    acknowledged: ['preparing', 'cancelled'],
    preparing: ['ready', 'cancelled'],
    ready: ['served', 'cancelled'],
    served: ['completed'],
    completed: [],
    cancelled: [],
};

function canTransition(current: string | null, next: string) {
    if (!current) {
        return false;
    }
    return (ALLOWED_TRANSITIONS[current] || []).includes(next);
}

export async function POST(request: Request) {
    const auth = await getAuthenticatedUser();
    if (!auth.ok) {
        return auth.response;
    }

    const parsed = await parseJsonBody(request, BulkStatusSchema);
    if (!parsed.success) {
        return parsed.response;
    }

    const supabase = auth.supabase;
    const { data: orders, error: ordersError } = await supabase
        .from('orders')
        .select('id, status, restaurant_id')
        .in('id', parsed.data.order_ids);

    if (ordersError) {
        return apiError('Failed to load orders', 500, 'ORDERS_FETCH_FAILED', ordersError.message);
    }

    if (!orders || orders.length === 0) {
        return apiError('No matching orders found', 404, 'ORDERS_NOT_FOUND');
    }

    const restaurantIds = new Set(orders.map(o => o.restaurant_id));
    if (restaurantIds.size > 1) {
        return apiError(
            'Bulk update requires orders from a single restaurant',
            409,
            'CROSS_RESTAURANT_BULK_NOT_ALLOWED'
        );
    }

    const restaurantId = orders[0].restaurant_id;
    const pilotGateResponse = enforcePilotAccess(restaurantId, request.method);
    if (pilotGateResponse) {
        return pilotGateResponse;
    }

    const invalid = orders.filter(order => !canTransition(order.status, parsed.data.status));
    if (invalid.length > 0) {
        return apiError(
            'One or more orders have invalid status transitions',
            409,
            'INVALID_BULK_TRANSITION',
            invalid.map(item => ({ id: item.id, current_status: item.status }))
        );
    }

    const now = new Date().toISOString();
    const updatePayload: Record<string, string> = {
        status: parsed.data.status,
        updated_at: now,
    };
    if (parsed.data.status === 'acknowledged') {
        updatePayload.acknowledged_at = now;
    }
    if (parsed.data.status === 'ready' || parsed.data.status === 'completed') {
        updatePayload.completed_at = now;
    }

    const { data: updated, error: updateError } = await supabase
        .from('orders')
        .update(updatePayload)
        .in('id', parsed.data.order_ids)
        .select('id, status, restaurant_id');

    if (updateError) {
        return apiError('Failed to update orders', 500, 'BULK_UPDATE_FAILED', updateError.message);
    }

    const eventRows = orders.map(order => ({
        restaurant_id: order.restaurant_id,
        order_id: order.id,
        event_type: 'bulk_status_changed',
        from_status: order.status,
        to_status: parsed.data.status,
        actor_user_id: auth.user.id,
        metadata: { source: 'merchant_dashboard' },
    }));

    const { error: eventError } = await (supabase as any).from('order_events').insert(eventRows);
    if (eventError) {
        console.warn(
            '[POST /api/orders/bulk-status] order_events insert failed:',
            eventError.message
        );
    }

    for (const order of orders) {
        await writeAuditLog(supabase, {
            restaurant_id: order.restaurant_id,
            user_id: auth.user.id,
            action: 'orders_bulk_status_updated',
            entity_type: 'order',
            entity_id: order.id,
            old_value: { status: order.status },
            new_value: { status: parsed.data.status },
            metadata: { source: 'merchant_dashboard' },
        });
    }

    return apiSuccess({
        updated_count: updated?.length ?? 0,
        status: parsed.data.status,
        order_ids: parsed.data.order_ids,
    });
}

/**
 * @openapi
 * /api/orders:
 *   get:
 *     summary: List orders
 *     description: Retrieve a paginated list of orders for the authenticated user's restaurant
 *     tags:
 *       - Orders
 *     security:
 *       - bearerAuth: []
 *     parameters:
 *       - in: query
 *         name: status
