const OrdersQuerySchema = z.object({
    status: z.string().optional(),
    search: z.string().optional(),
    limit: z.coerce.number().int().positive().max(200).optional().default(50),
    offset: z.coerce.number().int().nonnegative().optional().default(0),
});

const OnlineOrderGuestContextSchema = z.object({
    slug: z.string().min(1),
    is_online_order: z.literal(true),
    // For online orders, table/sig/exp are not real QR values
    table: z.string().optional(),
    sig: z.string().optional(),
    exp: z.union([z.string(), z.number()]).optional(),
});

const DineInGuestContextSchema = z.object({
    slug: z.string().min(1),
    table: z.string().min(1),
    sig: z.string().min(1),
    exp: z.union([z.string(), z.number()]),
    is_online_order: z.literal(false).optional(),
});

const GuestContextInputSchema = z.union([OnlineOrderGuestContextSchema, DineInGuestContextSchema]);

const CreateOrderRequestSchema = CreateOrderSchema.omit({
    idempotency_key: true,
    restaurant_id: true,
    table_number: true,
}).extend({
    guest_context: GuestContextInputSchema,
    order_type: z.enum(['dine_in', 'online', 'delivery', 'pickup']).optional().default('dine_in'),
    delivery_address: z.string().max(500).optional(),
    customer_name: z.string().max(100).optional(),
    customer_phone: z.string().max(30).optional(),
    discount_id: z.string().uuid().optional(),
    idempotency_key: z.string().uuid().optional(),
    campaign_attribution: z
        .object({
            campaign_delivery_id: z.string().uuid(),
            campaign_id: z.string().uuid().optional(),
        })
        .optional(),
});

async function resolveRestaurantIdForUser(userId: string) {
    const supabase = await createClient();
    const { data: staffEntry, error: staffError } = await supabase
        .from('restaurant_staff')
        .select('restaurant_id')
        .eq('user_id', userId)
        .eq('is_active', true)
        .order('created_at', { ascending: false })
        .limit(1)
        .maybeSingle();

    if (staffError) {
        return { error: staffError.message };
    }

    if (staffEntry?.restaurant_id) {
        return { restaurantId: staffEntry.restaurant_id };
    }

    const { data: agencyUser, error: agencyError } = await supabase
        .from('agency_users')
        .select('restaurant_ids')
        .eq('user_id', userId)
        .maybeSingle();

    if (agencyError) {
        return { error: agencyError.message };
    }

    return { restaurantId: agencyUser?.restaurant_ids?.[0] ?? null };
}

export async function GET(request: NextRequest) {
    const startedAt = Date.now();
    let responseStatus = 500;
    let restaurantIdForMetrics: string | null = null;
    let supabaseForMetrics: Awaited<ReturnType<typeof createClient>> | null = null;

    try {
        const supabase = await createClient();
        supabaseForMetrics = supabase;
        const {
            data: { user },
            error: userError,
        } = await supabase.auth.getUser();

        if (userError || !user) {
            responseStatus = 401;
            return apiError('Unauthorized', 401, 'UNAUTHORIZED');
        }

        const { restaurantId, error: restaurantError } = await resolveRestaurantIdForUser(user.id);
        if (restaurantError) {
            responseStatus = 500;
            return apiError(
                'Failed to resolve restaurant context',
                500,
                'RESTAURANT_RESOLVE_FAILED',
                restaurantError
            );
        }
        if (!restaurantId) {
            responseStatus = 404;
            return apiError('No restaurant found for user', 404, 'RESTAURANT_NOT_FOUND');
        }
        restaurantIdForMetrics = restaurantId;

        const pilotGateResponse = enforcePilotAccess(restaurantId, request.method);
        if (pilotGateResponse) {
            responseStatus = pilotGateResponse.status;
            return pilotGateResponse;
        }

        const parsed = OrdersQuerySchema.safeParse({
            status: request.nextUrl.searchParams.get('status') ?? undefined,
            search: request.nextUrl.searchParams.get('search') ?? undefined,
            limit: request.nextUrl.searchParams.get('limit') ?? undefined,
            offset: request.nextUrl.searchParams.get('offset') ?? undefined,
        });
        if (!parsed.success) {
            responseStatus = 400;
            return apiError('Invalid query params', 400, 'INVALID_QUERY', parsed.error.flatten());
        }

        let query = supabase
            .from('orders')
            .select('*', { count: 'exact' })
            .eq('restaurant_id', restaurantId)
            .order('created_at', { ascending: false })
            .range(parsed.data.offset, parsed.data.offset + parsed.data.limit - 1);

        if (parsed.data.status && parsed.data.status !== 'all') {
            query = query.eq('status', parsed.data.status);
        }

        if (parsed.data.search) {
            const search = parsed.data.search.trim();
            if (search.length > 0) {
                query = query.or(
                    `table_number.ilike.%${search}%,order_number.ilike.%${search}%,customer_name.ilike.%${search}%`
                );
            }
        }

        const { data, error, count } = await query;

        if (error) {
            responseStatus = 500;
            return apiError('Failed to load orders', 500, 'ORDERS_FETCH_FAILED', error.message);
        }

        responseStatus = 200;
        return apiSuccess({
            orders: data?.map(o => ({ ...o, total_price: Number(o.total_price ?? 0) / 100 })) ?? [],
            total: count ?? 0,
        });
    } catch (error) {
        responseStatus = 500;
        return apiError(
            'Internal server error',
            500,
            'INTERNAL_ERROR',
            error instanceof Error ? error.message : 'Unknown error'
        );
    } finally {
        if (supabaseForMetrics) {
            const durationMs = Date.now() - startedAt;
            await trackApiMetric(supabaseForMetrics, {
                restaurantId: restaurantIdForMetrics,
                endpoint: '/api/orders',
                method: 'GET',
                statusCode: responseStatus,
                durationMs,
            });
        }
    }
}

export async function POST(request: NextRequest) {
    // Apply rate limiting for order creation
    const rateLimitResponse = await redisRateLimiters.orderCreate(request);
    if (rateLimitResponse) {
        return rateLimitResponse;
    }

    try {
        const body = await request.json();
        const parsed = CreateOrderRequestSchema.safeParse(body);

        if (!parsed.success) {
            return NextResponse.json(
                { error: 'Invalid request payload', details: parsed.error.flatten() },
                { status: 400 }
            );
        }

        const supabase = await createClient();
        const isOnlineOrder =
            parsed.data.order_type === 'online' ||
            parsed.data.order_type === 'delivery' ||
            parsed.data.order_type === 'pickup' ||
            (parsed.data.guest_context as { is_online_order?: boolean }).is_online_order === true;

        let restaurantId: string;
        let tableNumber: string;

        if (isOnlineOrder) {
            // ── Online / Delivery / Pickup: resolve restaurant by slug only ──
            const slug = parsed.data.guest_context.slug;
            const { data: restaurant, error: restaurantError } = await supabase
                .from('restaurants')
                .select('id, is_active')
                .eq('slug', slug)
                .maybeSingle();

            if (restaurantError) {
                return NextResponse.json(
                    { error: 'Failed to resolve restaurant' },
                    { status: 500 }
                );
            }
            if (!restaurant || restaurant.is_active === false) {
                return NextResponse.json(
                    { error: 'Restaurant not found or inactive' },
                    { status: 404 }
                );
            }
            restaurantId = restaurant.id;
            // Represent the order type as the table label for legacy display
            tableNumber =
                parsed.data.order_type === 'delivery'
                    ? 'Delivery'
                    : parsed.data.order_type === 'pickup'
                      ? 'Pickup'
                      : 'Online Order';
        } else {
            // ── Dine-in: full QR validation via resolveGuestContext ──
            const guestContext = await resolveGuestContext(supabase, parsed.data.guest_context);
            if (!guestContext.valid) {
                return NextResponse.json(
                    { error: guestContext.reason },
                    { status: guestContext.status }
                );
            }
            restaurantId = guestContext.data.restaurantId;
            tableNumber = guestContext.data.tableNumber;
        }

        const ip = request.headers.get('x-forwarded-for')?.split(',')[0]?.trim() || 'unknown';
        const fingerprint = generateGuestFingerprint(ip, request.headers.get('user-agent'));

        const rateLimit = await checkRateLimit(supabase, fingerprint);
        if (!rateLimit.allowed) {
            return NextResponse.json(
                {
                    error: 'Rate limit exceeded. Please wait before placing another order.',
                    remainingOrders: rateLimit.remainingOrders ?? 0,
                },
                { status: 429 }
            );
        }

        const explicitIdempotencyKey = request.headers.get('x-idempotency-key');
        if (explicitIdempotencyKey && !isIdempotencyKeyValid(explicitIdempotencyKey)) {
            return NextResponse.json({ error: 'Invalid idempotency key' }, { status: 400 });
        }

        const idempotencyKey =
            explicitIdempotencyKey?.trim() ||
            parsed.data.idempotency_key ||
            generateIdempotencyKey();
        let discountRuntime;
        try {
            discountRuntime = parsed.data.discount_id
                ? await prepareOrderDiscount({
                      supabase: createServiceRoleClient() as any,
                      restaurantId,
                      discountId: parsed.data.discount_id,
                      items: parsed.data.items.map(item => ({
                          id: item.id,
                          price: item.price,
                          quantity: item.quantity,
                      })),
                      excludeManagerApproval: true,
                  })
                : {
                      discount: null,
                      calculation: {
                          subtotal: parsed.data.total_price,
                          discountAmount: 0,
                          total: parsed.data.total_price,
                          applied: false,
                      },
                  };
        } catch (error) {
            return NextResponse.json(
                { error: error instanceof Error ? error.message : 'Failed to validate discount' },
                { status: 400 }
            );
        }

        const result = await createOrder(supabase, {
            restaurant_id: restaurantId,
            table_number: tableNumber,
            items: parsed.data.items,
            total_price: discountRuntime.calculation.total,
            notes: parsed.data.notes,
            idempotency_key: idempotencyKey,
            guest_fingerprint: fingerprint,
            order_type: parsed.data.order_type,
            delivery_address: parsed.data.delivery_address,
            customer_name: parsed.data.customer_name,
            customer_phone: parsed.data.customer_phone,
            discount_id: discountRuntime.discount?.id,
            discount_amount: discountRuntime.calculation.discountAmount,
        });

        if (!result.success) {
            return NextResponse.json({ error: result.error }, { status: 400 });
        }

        let campaignAttributionApplied = false;
        if (parsed.data.campaign_attribution) {
            const attribution = parsed.data.campaign_attribution;
            const { data: delivery, error: deliveryError } = await (supabase as any)
                .from('campaign_deliveries' as any)
                .select('id, campaign_id, conversion_order_id')
                .eq('id', attribution.campaign_delivery_id)
                .maybeSingle();

            if (deliveryError) {
                logger.warn('[POST /api/orders] campaign delivery lookup failed', {
                    error: deliveryError.message,
                });
            } else if (delivery) {
                const campaignMatches =
                    !attribution.campaign_id || attribution.campaign_id === delivery.campaign_id;
                if (campaignMatches) {
                    const { data: campaign, error: campaignError } = await (supabase as any)
                        .from('campaigns' as any)
                        .select('id')
                        .eq('id', delivery.campaign_id)
                        .eq('restaurant_id', restaurantId)
                        .maybeSingle();

                    if (campaignError) {
                        logger.warn('[POST /api/orders] campaign validation failed', {
                            error: campaignError.message,
                        });
                    } else if (campaign && !delivery.conversion_order_id) {
                        const { error: updateDeliveryError } = await (supabase as any)
                            .from('campaign_deliveries' as any)
                            .update({
                                status: 'converted',
                                conversion_order_id: result.order.id,
                                clicked_at: new Date().toISOString(),
                            })
                            .eq('id', delivery.id);

                        if (updateDeliveryError) {
                            logger.warn('[POST /api/orders] campaign conversion update failed', {
                                error: updateDeliveryError.message,
                            });
                        } else {
                            campaignAttributionApplied = true;
                        }
                    }
                }
            }
        }

        const { error: auditError } = await supabase.from('audit_logs').insert({
            restaurant_id: restaurantId,
            action: 'order_created_guest',
            entity_type: 'order',
            entity_id: result.order.id,
            metadata: {
                table_number: tableNumber,
                item_count: parsed.data.items.length,
                source: isOnlineOrder ? 'online_ordering' : 'guest_web',
                order_type: parsed.data.order_type,
                slug: parsed.data.guest_context.slug,
                campaign_attribution: parsed.data.campaign_attribution ?? null,
                campaign_attribution_applied: campaignAttributionApplied,
            },
            new_value: {
                status: result.order.status,
                total_price: discountRuntime.calculation.total,
                discount_amount: discountRuntime.calculation.discountAmount,
            },
        });
        if (auditError) {
            logger.warn('[POST /api/orders] audit insert failed', { error: auditError.message });
        }

        await publishEvent(
            createGebetaEvent('order.created', {
                restaurant_id: restaurantId,
                order_id: result.order.id,
                idempotency_key: idempotencyKey,
                source: isOnlineOrder ? 'online_ordering' : 'guest_web',
                order_type: parsed.data.order_type,
            })
        );

        return NextResponse.json(
            {
                data: {
                    id: result.order.id,
                    order_number: result.order.order_number,
                    status: result.order.status,
                    idempotency_key: idempotencyKey,
                    campaign_attribution_applied: campaignAttributionApplied,
                },
            },
            { status: 201 }
        );
    } catch (error) {
        logger.error('[POST /api/orders] failed', error);
        return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
    }
}

/**
 * Scheduled Reports API Endpoint
 * TASK-REPORT-002: Scheduled Reports
 *
 * GET /api/reports/scheduled - List scheduled reports
 * POST /api/reports/scheduled - Create a scheduled report
 */

import { NextRequest, NextResponse } from 'next/server';
import { createServerClient } from '@supabase/ssr';
import { cookies } from 'next/headers';
import { createScheduledReport, getScheduledReports } from '@/lib/services/scheduledReportsService';

export async function GET(request: NextRequest) {
    try {
        const cookieStore = await cookies();

        const supabase = createServerClient(
            process.env.NEXT_PUBLIC_SUPABASE_URL!,
            process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
            {
                cookies: {
                    getAll() {
                        return cookieStore.getAll();
                    },
                    setAll(cookiesToSet) {
                        try {
                            cookiesToSet.forEach(({ name, value, options }) =>
                                cookieStore.set(name, value, options)
                            );
                        } catch {
                            // Ignore errors
                        }
                    },
                },
            }
        );

        const {
            data: { user },
            error: authError,
        } = await supabase.auth.getUser();

        if (authError || !user) {
            return NextResponse.json(
                { error: { code: 'UNAUTHORIZED', message: 'Authentication required' } },
                { status: 401 }
            );
        }

        const { data: staffEntry, error: staffError } = await (supabase as any)
            .from('restaurant_staff')
            .select('restaurant_id')
            .eq('user_id', user.id)
            .eq('is_active', true)
            .maybeSingle();

        if (staffError || !staffEntry) {
            return NextResponse.json(
                { error: { code: 'FORBIDDEN', message: 'Not a staff member' } },
                { status: 403 }
            );
        }

        const restaurantId = staffEntry.restaurant_id;
        const { searchParams } = new URL(request.url);
        const activeOnly = searchParams.get('activeOnly') === 'true';

        const reports = await getScheduledReports(supabase, restaurantId, { activeOnly });

        return NextResponse.json({
            data: reports,
        });
    } catch (error) {
        console.error('[Scheduled Reports API] Error:', error);
        return NextResponse.json(
            { error: { code: 'INTERNAL_ERROR', message: 'An unexpected error occurred' } },
            { status: 500 }
        );
    }
}

export async function POST(request: NextRequest) {
    try {
        const cookieStore = await cookies();

        const supabase = createServerClient(
            process.env.NEXT_PUBLIC_SUPABASE_URL!,
            process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
            {
                cookies: {
                    getAll() {
                        return cookieStore.getAll();
                    },
                    setAll(cookiesToSet) {
                        try {
                            cookiesToSet.forEach(({ name, value, options }) =>
                                cookieStore.set(name, value, options)
                            );
                        } catch {
                            // Ignore errors
                        }
                    },
                },
            }
        );

        const {
            data: { user },
            error: authError,
        } = await supabase.auth.getUser();

        if (authError || !user) {
            return NextResponse.json(
                { error: { code: 'UNAUTHORIZED', message: 'Authentication required' } },
                { status: 401 }
            );
        }

        const { data: staffEntry, error: staffError } = await (supabase as any)
            .from('restaurant_staff')
            .select('restaurant_id, role')
            .eq('user_id', user.id)
            .eq('is_active', true)
            .maybeSingle();

        if (staffError || !staffEntry) {
            return NextResponse.json(
                { error: { code: 'FORBIDDEN', message: 'Not a staff member' } },
                { status: 403 }
            );
        }

        const restaurantId = staffEntry.restaurant_id;

        // Check permission
        const allowedRoles = ['owner', 'admin', 'manager'];
        if (!allowedRoles.includes(staffEntry.role)) {
            return NextResponse.json(
                { error: { code: 'FORBIDDEN', message: 'Insufficient permissions' } },
                { status: 403 }
            );
        }

        const body = await request.json();

        // Validate required fields
        if (!body.name || !body.report_type || !body.recipient_emails?.length) {
            return NextResponse.json(
                {
                    error: {
                        code: 'VALIDATION_ERROR',
                        message: 'Name, report type, and recipient emails are required',
                    },
                },
                { status: 400 }
            );
        }

        const result = await createScheduledReport(
            supabase,
            restaurantId,
            {
                name: body.name,
                description: body.description,
                report_type: body.report_type,
                frequency: body.frequency ?? 'daily',
                run_at_time: body.run_at_time,
                timezone: body.timezone,
                day_of_week: body.day_of_week,
                day_of_month: body.day_of_month,
                date_range: body.date_range,
                custom_date_range_days: body.custom_date_range_days,
                filters: body.filters,
                format: body.format ?? 'pdf',
                include_charts: body.include_charts,
                include_comparison: body.include_comparison,
                delivery_method: body.delivery_method ?? 'email',
                recipient_emails: body.recipient_emails,
                email_subject: body.email_subject,
                email_body: body.email_body,
            },
            user.id
        );

        if (!result.success) {
            return NextResponse.json(
                { error: { code: 'CREATE_FAILED', message: result.error } },
                { status: 400 }
            );
        }

        // Log to audit
        await (supabase as any).from('audit_logs').insert({
            action: 'create_scheduled_report',
            entity_type: 'scheduled_report',
            entity_id: result.report?.id,
            restaurant_id: restaurantId,
            user_id: user.id,
            metadata: {
                report_name: body.name,
                report_type: body.report_type,
                frequency: body.frequency,
            },
        });

        return NextResponse.json({
            data: result.report,
        });
    } catch (error) {
        console.error('[Scheduled Reports API] Error:', error);
        return NextResponse.json(
            { error: { code: 'INTERNAL_ERROR', message: 'An unexpected error occurred' } },
            { status: 500 }
        );
    }
}

import { apiError, apiSuccess } from '@/lib/api/response';
import { getAuthenticatedUser, getAuthorizedRestaurantContext } from '@/lib/api/authz';

export async function GET() {
    const auth = await getAuthenticatedUser();
    if (!auth.ok) return auth.response;

    const context = await getAuthorizedRestaurantContext(auth.user.id);
    if (!context.ok) return context.response;

    const { data: restaurant, error } = await context.supabase
        .from('restaurants')
        .select('settings')
        .eq('id', context.restaurantId)
        .single();

    if (error) return apiError('Failed to fetch zones', 500);

    const zones = (restaurant?.settings as any)?.zones || [];
    return apiSuccess({ zones });
}

export async function POST(request: Request) {
    const auth = await getAuthenticatedUser();
    if (!auth.ok) return auth.response;

    const context = await getAuthorizedRestaurantContext(auth.user.id);
    if (!context.ok) return context.response;

    try {
        const body = await request.json();
        const zones = body.zones;

        if (!Array.isArray(zones)) {
            return apiError('Invalid zones data. Expected an array of strings.', 400);
        }

        // Get current settings
        const { data: restaurant, error: fetchError } = await context.supabase
            .from('restaurants')
            .select('settings')
            .eq('id', context.restaurantId)
            .single();

        if (fetchError) return apiError('Failed to fetch restaurant settings', 500);

        const currentSettings = (restaurant?.settings as any) || {};
        const newSettings = {
            ...currentSettings,
            zones: Array.from(
                new Set(
                    zones.filter(z => typeof z === 'string' && z.trim() !== '').map(z => z.trim())
                )
            ),
        };

        const { error: updateError } = await context.supabase
            .from('restaurants')
            .update({ settings: newSettings })
            .eq('id', context.restaurantId);

        if (updateError) return apiError('Failed to update zones', 500);

        return apiSuccess({ zones: newSettings.zones });
    } catch {
        return apiError('Invalid request body', 400);
    }
}

import { z } from 'zod';
import { apiError, apiSuccess } from '@/lib/api/response';
import { getAuthenticatedUser, getAuthorizedRestaurantContext } from '@/lib/api/authz';
import { parseJsonBody } from '@/lib/api/validation';

export const dynamic = 'force-dynamic';
import {
    createChapaSubaccount,
    isChapaConfigured,
    listChapaBanks,
    maskSettlementAccountNumber,
} from '@/lib/services/chapaService';

const HOSTED_CHECKOUT_FEE_PERCENTAGE = 0.03;

const PaymentSettingsSchema = z.object({
    settlement_bank_code: z.string().trim().min(1),
    settlement_account_name: z.string().trim().min(1),
    settlement_account_number: z.string().trim().max(30).optional().default(''),
});

type RestaurantPaymentRecord = {
    name: string;
    chapa_settlement_bank_code: string | null;
    chapa_settlement_bank_name: string | null;
    chapa_settlement_account_name: string | null;
    chapa_settlement_account_number_masked: string | null;
    chapa_subaccount_id: string | null;
    chapa_subaccount_status: string | null;
    chapa_subaccount_last_error: string | null;
    chapa_subaccount_provisioned_at: string | null;
    platform_fee_percentage: number | null;
    hosted_checkout_fee_percentage: number | null;
};

const PAYMENT_SETTINGS_SELECT = [
    'name',
    'chapa_settlement_bank_code',
    'chapa_settlement_bank_name',
    'chapa_settlement_account_name',
    'chapa_settlement_account_number_masked',
    'chapa_subaccount_id',
    'chapa_subaccount_status',
    'chapa_subaccount_last_error',
    'chapa_subaccount_provisioned_at',
    'platform_fee_percentage',
    'hosted_checkout_fee_percentage',
].join(', ');

function resolveHostedCheckoutFeePercentage(restaurant: RestaurantPaymentRecord) {
    if (typeof restaurant.hosted_checkout_fee_percentage === 'number') {
        return restaurant.hosted_checkout_fee_percentage;
    }

    if (typeof restaurant.platform_fee_percentage === 'number') {
        return restaurant.platform_fee_percentage;
    }

    return HOSTED_CHECKOUT_FEE_PERCENTAGE;
}

function normalizePayoutStatus(params: {
    subaccountId?: string | null;
    providerStatus?: string | null;
    providerMessage?: string | null;
}) {
    const subaccountId = String(params.subaccountId ?? '').trim();
    const providerStatus = String(params.providerStatus ?? '')
        .trim()
        .toLowerCase();
    const providerMessage = String(params.providerMessage ?? '')
        .trim()
        .toLowerCase();
    const haystack = `${providerStatus} ${providerMessage}`;

    console.log('normalizePayoutStatus called with:', {
        subaccountId,
        providerStatus,
        providerMessage,
        haystack,
    });

    // Check for success indicators in status or message
    const isSuccess =
        providerStatus === 'success' ||
        providerStatus === 'active' ||
        haystack.includes('success') ||
        haystack.includes('created successfully') ||
        haystack.includes('approved') ||
        haystack.includes('verified') ||
        haystack.includes('subaccount created');

    if (isSuccess) {
        console.log('normalizePayoutStatus: returning active (success detected)');
        return 'active';
    }

    // If we have a subaccount ID, the account was created successfully
    if (subaccountId) {
        console.log('normalizePayoutStatus: returning active (subaccount ID present)');
        return 'active';
    }

    // If account already exists - this is actually a success case
    if (haystack.includes('exist') || haystack.includes('already')) {
        console.log('normalizePayoutStatus: returning active (already exists)');
        return 'active';
    }

    // Only return verification_required if there's an actual error message
    if (providerMessage && !isSuccess) {
        console.log('normalizePayoutStatus: returning failed (error message present)');
        return 'failed';
    }

    console.log('normalizePayoutStatus: returning not_configured');
    return 'not_configured';
}

function serializePaymentSettings(restaurant: RestaurantPaymentRecord) {
    const status = String(restaurant.chapa_subaccount_status ?? '').trim() || 'not_configured';

    return {
        provider: 'chapa' as const,
        provider_available: isChapaConfigured(),
        settlement_bank_code: restaurant.chapa_settlement_bank_code ?? '',
        settlement_bank_name: restaurant.chapa_settlement_bank_name ?? '',
        settlement_account_name: restaurant.chapa_settlement_account_name ?? '',
        settlement_account_number_masked: restaurant.chapa_settlement_account_number_masked ?? '',
        settlement_status: status,
        subaccount_id: restaurant.chapa_subaccount_id ?? null,
        last_error: restaurant.chapa_subaccount_last_error ?? null,
        provisioned_at: restaurant.chapa_subaccount_provisioned_at ?? null,
        hosted_checkout_fee_percentage: resolveHostedCheckoutFeePercentage(restaurant),
    };
}

export async function GET() {
    const auth = await getAuthenticatedUser();
    if (!auth.ok) {
        return auth.response;
    }

    const context = await getAuthorizedRestaurantContext(auth.user.id);
    if (!context.ok) {
        return context.response;
    }

    const { data, error } = await context.supabase
        .from('restaurants')
        .select(PAYMENT_SETTINGS_SELECT)
        .eq('id', context.restaurantId)
        .single();

    if (error || !data) {
        return apiError(
            'Failed to fetch payment settings',
            500,
            'PAYMENT_SETTINGS_FETCH_FAILED',
            error?.message ?? 'Restaurant not found'
        );
    }

    return apiSuccess(serializePaymentSettings(data as unknown as RestaurantPaymentRecord));
}

export async function PATCH(request: Request) {
    const auth = await getAuthenticatedUser();
    if (!auth.ok) {
        return auth.response;
    }

    const context = await getAuthorizedRestaurantContext(auth.user.id);
    if (!context.ok) {
        return context.response;
    }

    const parsed = await parseJsonBody(request, PaymentSettingsSchema);
    if (!parsed.success) {
        return parsed.response;
    }

    const { data: restaurant, error: fetchError } = await context.supabase
        .from('restaurants')
        .select(PAYMENT_SETTINGS_SELECT)
        .eq('id', context.restaurantId)
        .single();

    if (fetchError || !restaurant) {
        return apiError(
            'Failed to fetch current payment settings',
            500,
            'PAYMENT_SETTINGS_FETCH_FAILED',
            fetchError?.message ?? 'Restaurant not found'
        );
    }

    const current = restaurant as unknown as RestaurantPaymentRecord;
    const nextBankCode = parsed.data.settlement_bank_code.trim();
    const nextAccountName = parsed.data.settlement_account_name.trim();
    const providedAccountNumber = parsed.data.settlement_account_number.replace(/\s+/g, '').trim();

    const currentBankCode = String(current.chapa_settlement_bank_code ?? '').trim();
    const currentAccountName = String(current.chapa_settlement_account_name ?? '').trim();
    const currentSubaccountId = String(current.chapa_subaccount_id ?? '').trim();

    // Check if account details actually changed
    // Note: providedAccountNumber will be empty if the user didn't change the masked number
    const accountDetailsChanged =
        currentBankCode !== nextBankCode || currentAccountName !== nextAccountName;

    // Only need provisioning if:
    // 1. We don't have a subaccount ID yet, OR
    // 2. Account details changed AND user provided a new account number
    const needsProvisioning =
        currentSubaccountId.length === 0 ||
        (accountDetailsChanged && providedAccountNumber.length > 0) ||
        (!accountDetailsChanged &&
            providedAccountNumber.length > 0 &&
            !providedAccountNumber.includes('*'));

    if (accountDetailsChanged && providedAccountNumber.length === 0) {
        return apiError(
            'Enter the full payout account or wallet number to change the payout destination.',
            400,
            'SETTLEMENT_ACCOUNT_NUMBER_REQUIRED'
        );
    }

    let nextBankName = String(current.chapa_settlement_bank_name ?? '').trim();

    try {
        const supportedBanks = await listChapaBanks();
        const selectedBank = supportedBanks.find(bank => bank.code === nextBankCode);

        if (selectedBank) {
            nextBankName = selectedBank.name;
        } else {
            return apiError(
                "Choose a supported payout destination from Chapa's live directory.",
                400,
                'UNSUPPORTED_SETTLEMENT_BANK'
            );
        }
    } catch {
        nextBankName = nextBankName || '';
    }

    if (!needsProvisioning) {
        const { data: updated, error: updateError } = await context.supabase
            .from('restaurants')
            .update({
                chapa_settlement_bank_code: nextBankCode,
                chapa_settlement_bank_name: nextBankName,
                chapa_settlement_account_name: nextAccountName,
                chapa_subaccount_last_error: null,
                platform_fee_percentage: HOSTED_CHECKOUT_FEE_PERCENTAGE,
                hosted_checkout_fee_percentage: HOSTED_CHECKOUT_FEE_PERCENTAGE,
            })
            .eq('id', context.restaurantId)
            .select(PAYMENT_SETTINGS_SELECT)
            .single();

        if (updateError || !updated) {
            return apiError(
                'Failed to update payment settings',
                500,
                'PAYMENT_SETTINGS_UPDATE_FAILED',
                updateError?.message ?? 'Unknown update error'
            );
        }

        return apiSuccess(serializePaymentSettings(updated as unknown as RestaurantPaymentRecord));
    }

    if (providedAccountNumber.length === 0) {
        return apiError(
            'Enter the full payout account or wallet number to finish payout setup.',
            400,
            'SETTLEMENT_ACCOUNT_NUMBER_REQUIRED'
        );
    }

    if (!isChapaConfigured()) {
        return apiError(
            'Chapa is not configured. Add CHAPA_SECRET_KEY before saving payout accounts.',
            503,
            'CHAPA_NOT_CONFIGURED'
        );
    }

    let nextSubaccountId = currentSubaccountId || null;
    let nextStatus = current.chapa_subaccount_status?.trim() || 'provisioning';
    let nextLastError: string | null = null;
    let nextProvisionedAt = current.chapa_subaccount_provisioned_at ?? null;

    try {
        const subaccount = await createChapaSubaccount({
            business_name: current.name.trim(),
            account_name: nextAccountName,
            bank_code: nextBankCode,
            account_number: providedAccountNumber,
            split_type: 'percentage',
            split_value: HOSTED_CHECKOUT_FEE_PERCENTAGE,
        });

        console.log('Chapa subaccount response:', JSON.stringify(subaccount, null, 2));

        const returnedSubaccountId = subaccount.data?.id?.trim();
        if (returnedSubaccountId) {
            nextSubaccountId = returnedSubaccountId;
            nextProvisionedAt = new Date().toISOString();
        }

        // Check if the response indicates success
        const isSuccess =
            subaccount.status === 'success' ||
            String(subaccount.status).toLowerCase() === 'success' ||
            String(subaccount.message).toLowerCase().includes('success') ||
            String(subaccount.message).toLowerCase().includes('created');

        if (isSuccess) {
            nextStatus = 'active';
            nextProvisionedAt = new Date().toISOString();
            nextLastError = null;
            // If we got a subaccount ID, use it
            if (returnedSubaccountId) {
                nextSubaccountId = returnedSubaccountId;
            }
        } else {
            nextStatus = normalizePayoutStatus({
                subaccountId: returnedSubaccountId,
                providerStatus: subaccount.status,
                providerMessage: subaccount.message,
            });
            nextLastError =
                nextStatus === 'active'
                    ? null
                    : subaccount.message || 'Payout destination is waiting for Chapa review.';
        }
    } catch (error) {
        const message =
            error instanceof Error ? error.message : 'Unknown Chapa subaccount provisioning error';
        nextStatus = normalizePayoutStatus({
            subaccountId: nextSubaccountId,
            providerMessage: message,
        });
        nextLastError = message;
    }

    console.log('Saving to database:', {
        restaurantId: context.restaurantId,
        nextBankCode,
        nextBankName,
        nextAccountName,
        nextSubaccountId,
        nextStatus,
        nextLastError,
        nextProvisionedAt,
    });

    const { data: updated, error: updateError } = await context.supabase
        .from('restaurants')
        .update({
            chapa_settlement_bank_code: nextBankCode,
            chapa_settlement_bank_name: nextBankName,
            chapa_settlement_account_name: nextAccountName,
            chapa_settlement_account_number_masked:
                maskSettlementAccountNumber(providedAccountNumber),
            chapa_subaccount_id: nextSubaccountId,
            chapa_subaccount_status: nextStatus,
            chapa_subaccount_last_error: nextLastError,
            chapa_subaccount_provisioned_at: nextProvisionedAt,
            platform_fee_percentage: HOSTED_CHECKOUT_FEE_PERCENTAGE,
            hosted_checkout_fee_percentage: HOSTED_CHECKOUT_FEE_PERCENTAGE,
        })
        .eq('id', context.restaurantId)
        .select(PAYMENT_SETTINGS_SELECT)
        .single();

    if (updateError || !updated) {
        console.error('Database update error:', updateError);
        return apiError(
            'Failed to update payment settings',
            500,
            'PAYMENT_SETTINGS_UPDATE_FAILED',
            updateError?.message ?? 'Unknown update error'
        );
    }

    const updatedRecord = updated as unknown as RestaurantPaymentRecord;
    console.log('Database updated successfully. New values:', {
        chapa_subaccount_status: updatedRecord.chapa_subaccount_status,
        chapa_settlement_bank_code: updatedRecord.chapa_settlement_bank_code,
        chapa_settlement_account_name: updatedRecord.chapa_settlement_account_name,
    });

    return apiSuccess(serializePaymentSettings(updatedRecord));
}

import { randomUUID } from 'crypto';
import { z } from 'zod';
import { apiError, apiSuccess } from '@/lib/api/response';
import { getAuthenticatedUser, getAuthorizedRestaurantContext } from '@/lib/api/authz';
import { parseJsonBody } from '@/lib/api/validation';
import { writeAuditLog } from '@/lib/api/audit';
import { resend, EMAIL_FROM } from '@/lib/email/client';
import { StaffInviteEmail } from '@/lib/email/templates/staff-invite';

const InviteStaffSchema = z.object({
    email: z.string().email().optional().nullable(),
    role: z.enum(['owner', 'admin', 'manager', 'kitchen', 'waiter', 'bar']),
    label: z.string().trim().min(2).max(120).optional().nullable(),
});

export async function POST(request: Request) {
    const auth = await getAuthenticatedUser();
    if (!auth.ok) {
        return auth.response;
    }

    const context = await getAuthorizedRestaurantContext(auth.user.id);
    if (!context.ok) {
        return context.response;
    }

    const parsed = await parseJsonBody(request, InviteStaffSchema);
    if (!parsed.success) {
        return parsed.response;
    }

    const code = randomUUID();
    const expiresAt = new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString();

    const { data, error } = await context.supabase
        .from('staff_invites')
        .insert({
            code,
            email: parsed.data.email ?? null,
            role: parsed.data.role,
            restaurant_id: context.restaurantId,
            created_by: auth.user.id,
            expires_at: expiresAt,
            status: 'pending',
        })
        .select('*')
        .single();

    if (error) {
        return apiError(
            'Failed to create staff invite',
            500,
            'STAFF_INVITE_CREATE_FAILED',
            error.message
        );
    }

    // Fetch restaurant name for the email
    const { data: restaurant } = await context.supabase
        .from('restaurants')
        .select('name')
        .eq('id', context.restaurantId)
        .single();

    const inviteQuery = new URLSearchParams({ code, role: parsed.data.role });
    if (parsed.data.label) {
        inviteQuery.set('label', parsed.data.label);
    }
    const { getAppUrl } = await import('@/lib/config/env');
    const inviteUrl = `${getAppUrl()}/auth/join?${inviteQuery.toString()}`;
    let emailSent = false;

    if (parsed.data.email && resend) {
        console.log('Attempting to send email to:', parsed.data.email);
        try {
            const { data: emailData, error: emailError } = await resend.emails.send({
                from: EMAIL_FROM,
                to: parsed.data.email,
                subject: `Provision access for ${restaurant?.name ?? 'Gebeta'}`,
                html: StaffInviteEmail({
                    inviteUrl,
                    restaurantName: restaurant?.name ?? 'Gebeta',
                    role: parsed.data.role,
                }),
            });

            if (emailError) {
                console.error('Resend API returned error:', emailError);
            } else {
                console.log('Email sent successfully:', emailData);
                emailSent = true;
            }
        } catch (emailError) {
            console.error('Failed to send invite email:', emailError);
            // We don't fail the request if email fails, but we'll flag it in the response
        }
    } else {
        console.log(
            'Skipping email: Email provided?',
            Boolean(parsed.data.email),
            'Resend client ready?',
            Boolean(resend)
        );
    }

    await writeAuditLog(context.supabase, {
        restaurant_id: context.restaurantId,
        user_id: auth.user.id,
        action: 'staff_invite_created',
        entity_type: 'staff_invite',
        entity_id: data.id,
        metadata: {
            role: parsed.data.role,
            has_email: Boolean(parsed.data.email),
            email_sent: emailSent,
            label: parsed.data.label ?? null,
        },
        new_value: {
            status: data.status,
            expires_at: data.expires_at,
        },
    });

    return apiSuccess(
        {
            invite: data,
            invite_url: inviteUrl,
            email_sent: emailSent,
        },
        201
    );
}

import { z } from 'zod';
import { apiError, apiSuccess } from '@/lib/api/response';
import { getAuthenticatedUser, getAuthorizedRestaurantContext } from '@/lib/api/authz';
import { parseJsonBody, parseQuery } from '@/lib/api/validation';
import { writeAuditLog } from '@/lib/api/audit';
import { isIdempotencyKeyValid, resolveIdempotencyKey } from '@/lib/api/idempotency';
import { createServiceRoleClient } from '@/lib/supabase/service-role';

const ScheduleQuerySchema = z.object({
    start_date: z
        .string()
        .regex(/^\d{4}-\d{2}-\d{2}$/)
        .optional(),
    end_date: z
        .string()
        .regex(/^\d{4}-\d{2}-\d{2}$/)
        .optional(),
});

const ShiftCreateSchema = z.object({
    staff_id: z.string().uuid(),
    role: z.enum(['owner', 'admin', 'manager', 'kitchen', 'waiter', 'bar']).optional(),
    shift_date: z.string().regex(/^\d{4}-\d{2}-\d{2}$/),
    start_time: z.string().regex(/^\d{2}:\d{2}$/),
    end_time: z.string().regex(/^\d{2}:\d{2}$/),
    station: z.string().trim().max(80).optional().nullable(),
    notes: z.string().trim().max(400).optional().nullable(),
});

function normalizeWindow(input: { start_date?: string; end_date?: string }) {
    const now = new Date();
    const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());

    const start = input.start_date ? new Date(`${input.start_date}T00:00:00`) : today;
    const end = input.end_date
        ? new Date(`${input.end_date}T00:00:00`)
        : new Date(today.getTime() + 6 * 24 * 60 * 60 * 1000);

    const daySpan = Math.round((end.getTime() - start.getTime()) / (24 * 60 * 60 * 1000));
    return {
        startIso: start.toISOString().slice(0, 10),
        endIso: end.toISOString().slice(0, 10),
        daySpan,
    };
}

function overlaps(aStart: string, aEnd: string, bStart: string, bEnd: string) {
    return aStart < bEnd && bStart < aEnd;
}

export async function GET(request: Request) {
    try {
        const auth = await getAuthenticatedUser();
        if (!auth.ok) {
            return auth.response;
        }

        const context = await getAuthorizedRestaurantContext(auth.user.id, { phase: 'p1' });
        if (!context.ok) {
            return context.response;
        }

        const query = parseQuery(
            Object.fromEntries(new URL(request.url).searchParams.entries()),
            ScheduleQuerySchema
        );
        if (!query.success) {
            return query.response;
        }

        const { startIso, endIso, daySpan } = normalizeWindow(query.data);
        if (daySpan < 0 || daySpan > 31) {
            return apiError(
                'Invalid schedule window. Maximum span is 31 days.',
                400,
                'INVALID_SCHEDULE_WINDOW'
            );
        }

        console.log(
            `[Schedule API] Fetching for restaurant ${context.restaurantId} from ${startIso} to ${endIso}`
        );

        const adminClient = createServiceRoleClient();

        // Use Promise.allSettled to debug which query fails if any
        const results = await Promise.allSettled([
            adminClient
                .from('shifts')
                .select(
                    'id, staff_id, role, shift_date, start_time, end_time, station, status, notes, created_at, updated_at'
                )
                .eq('restaurant_id', context.restaurantId)
                .gte('shift_date', startIso)
                .lte('shift_date', endIso)
                .order('shift_date', { ascending: true })
                .order('start_time', { ascending: true }),
            adminClient
                .from('restaurant_staff_with_users')
                .select(
                    'id, user_id, role, is_active, name, full_name, first_name, last_name, email'
                )
                .eq('restaurant_id', context.restaurantId)
                .eq('is_active', true)
                .order('created_at', { ascending: true }),
        ]);

        const shiftsRes = results[0];
        const staffRes = results[1];

        if (shiftsRes.status === 'rejected') {
            console.error('[Schedule API] Shifts query failed:', shiftsRes.reason);
            throw new Error('Shifts query failed');
        }
        if (staffRes.status === 'rejected') {
            console.error('[Schedule API] Staff query failed:', staffRes.reason);
            throw new Error('Staff query failed');
        }

        if (shiftsRes.value.error) {
            console.error('[Schedule API] Shifts DB error:', shiftsRes.value.error);
            return apiError(
                'Failed to fetch schedule',
                500,
                'SCHEDULE_FETCH_FAILED',
                shiftsRes.value.error.message
            );
        }
        if (staffRes.value.error) {
            console.error('[Schedule API] Staff DB error:', staffRes.value.error);
            // Fallback: If view query fails, try basic staff table?
            // For now, return error to see what's wrong.
            return apiError(
                'Failed to fetch staff',
                500,
                'STAFF_FETCH_FAILED',
                staffRes.value.error.message
            );
        }

        const staffData = staffRes.value.data ?? [];

        // Fix names: specific logic for "Owner" name replacement
        // If the name is "Owner" but the role is NOT owner, try to use email part or "Staff Member"
        const processedStaff = staffData.map(s => {
            let displayName = s.full_name || s.name || s.first_name || s.last_name;

            // If name is effectively "Owner" but they are not the actual owner role,
            // OR even if they are owner but we want a better name (user requested removing "Owner" as name).
            // Let's rely on email if name is generic "Owner".
            if (!displayName || displayName === 'Owner') {
                if (s.email) {
                    displayName = s.email.split('@')[0]; // Use 'makeemoneyonly' from 'makeemoneyonly@gmail.com'
                } else {
                    displayName = 'User';
                }
            }
            return {
                ...s,
                // We overwrite the raw fields or just ensure the UI uses a computed one?
                // The UI might use `name` or `first_name`. Let's populate specific fields.
                name: displayName,
                first_name: displayName.split(' ')[0],
                last_name: displayName.split(' ').slice(1).join(' ') || '',
            };
        });

        return apiSuccess({
            window: {
                start_date: startIso,
                end_date: endIso,
            },
            shifts: shiftsRes.value.data ?? [],
            staff: processedStaff,
        });
    } catch (e: any) {
        console.error('[Schedule API] Unexpected error:', e);
        return apiError('Internal Server Error', 500, 'INTERNAL_ERROR', e.message);
    }
}

export async function POST(request: Request) {
    const auth = await getAuthenticatedUser();
    if (!auth.ok) {
        return auth.response;
    }

    const context = await getAuthorizedRestaurantContext(auth.user.id, { phase: 'p1' });
    if (!context.ok) {
        return context.response;
    }

    const explicitIdempotencyKey = request.headers.get('x-idempotency-key');
    if (explicitIdempotencyKey && !isIdempotencyKeyValid(explicitIdempotencyKey)) {
        return apiError('Invalid idempotency key', 400, 'INVALID_IDEMPOTENCY_KEY');
    }
    const idempotencyKey = resolveIdempotencyKey(explicitIdempotencyKey);

    const parsed = await parseJsonBody(request, ShiftCreateSchema);
    if (!parsed.success) {
        return parsed.response;
    }

    if (parsed.data.end_time <= parsed.data.start_time) {
        return apiError('end_time must be after start_time', 400, 'INVALID_SHIFT_TIME_RANGE');
    }

    const { data: staffMember, error: staffError } = await context.supabase
        .from('restaurant_staff')
        .select('id, role, is_active')
        .eq('id', parsed.data.staff_id)
        .eq('restaurant_id', context.restaurantId)
        .maybeSingle();

    if (staffError) {
        return apiError(
            'Failed to load staff member',
            500,
            'STAFF_FETCH_FAILED',
            staffError.message
        );
    }
    if (!staffMember || staffMember.is_active === false) {
        return apiError('Staff member not found or inactive', 404, 'STAFF_NOT_FOUND');
    }

    const { data: existingShifts, error: existingError } = await context.supabase
        .from('shifts')
        .select('id, start_time, end_time, status')
        .eq('restaurant_id', context.restaurantId)
        .eq('staff_id', parsed.data.staff_id)
        .eq('shift_date', parsed.data.shift_date)
        .in('status', ['scheduled', 'in_progress']);

    if (existingError) {
        return apiError(
            'Failed to validate schedule overlap',
            500,
            'SCHEDULE_OVERLAP_CHECK_FAILED',
            existingError.message
        );
    }

    const overlap = (existingShifts ?? []).find(shift =>
        overlaps(parsed.data.start_time, parsed.data.end_time, shift.start_time, shift.end_time)
    );
    if (overlap) {
        return apiError(
            'Shift overlaps with an existing active shift for this staff member',
            409,
            'SHIFT_OVERLAP_CONFLICT'
        );
    }

    const row = {
        restaurant_id: context.restaurantId,
        staff_id: parsed.data.staff_id,
        role: parsed.data.role ?? staffMember.role,
        shift_date: parsed.data.shift_date,
        start_time: parsed.data.start_time,
        end_time: parsed.data.end_time,
        station: parsed.data.station ?? null,
        notes: parsed.data.notes ?? null,
        status: 'scheduled',
        created_by: auth.user.id,
    };

    const { data: inserted, error: insertError } = await context.supabase
        .from('shifts')
        .insert(row)
        .select('*')
        .single();

    if (insertError) {
        return apiError('Failed to create shift', 500, 'SHIFT_CREATE_FAILED', insertError.message);
    }

    await writeAuditLog(context.supabase, {
        restaurant_id: context.restaurantId,
        user_id: auth.user.id,
        action: 'shift_created',
        entity_type: 'shift',
        entity_id: inserted.id,
        metadata: {
            source: 'merchant_dashboard',
            idempotency_key: idempotencyKey,
        },
        new_value: inserted as any,
    });

    return apiSuccess({ shift: inserted, idempotency_key: idempotencyKey }, 201);
}

import { z } from 'zod';
import { apiError, apiSuccess } from '@/lib/api/response';
import { getAuthenticatedUser, getAuthorizedRestaurantContext } from '@/lib/api/authz';
import { parseJsonBody } from '@/lib/api/validation';
import { writeAuditLog } from '@/lib/api/audit';
import { isIdempotencyKeyValid, resolveIdempotencyKey } from '@/lib/api/idempotency';

const ClockActionSchema = z.object({
    staff_id: z.string().uuid(),
    action: z.enum(['in', 'out']),
    shift_id: z.string().uuid().optional(),
    occurred_at: z.string().datetime().optional(),
    source: z.enum(['dashboard', 'mobile', 'kiosk', 'api']).optional(),
    note: z.string().trim().max(240).optional(),
});

export async function POST(request: Request) {
    const auth = await getAuthenticatedUser();
    if (!auth.ok) {
        return auth.response;
    }

    const context = await getAuthorizedRestaurantContext(auth.user.id, { phase: 'p1' });
    if (!context.ok) {
        return context.response;
    }

    const explicitIdempotencyKey = request.headers.get('x-idempotency-key');
    if (explicitIdempotencyKey && !isIdempotencyKeyValid(explicitIdempotencyKey)) {
        return apiError('Invalid idempotency key', 400, 'INVALID_IDEMPOTENCY_KEY');
    }
    const idempotencyKey = resolveIdempotencyKey(explicitIdempotencyKey);

    const parsed = await parseJsonBody(request, ClockActionSchema);
    if (!parsed.success) {
        return parsed.response;
    }

    const occurredAt = parsed.data.occurred_at ?? new Date().toISOString();

    const { data: staffMember, error: staffError } = await context.supabase
        .from('restaurant_staff')
        .select('id, is_active')
        .eq('id', parsed.data.staff_id)
        .eq('restaurant_id', context.restaurantId)
        .maybeSingle();

    if (staffError) {
        return apiError(
            'Failed to load staff member',
            500,
            'STAFF_FETCH_FAILED',
            staffError.message
        );
    }
    if (!staffMember || staffMember.is_active === false) {
        return apiError('Staff member not found or inactive', 404, 'STAFF_NOT_FOUND');
    }

    const { data: openEntry, error: openEntryError } = await context.supabase
        .from('time_entries')
        .select('id, shift_id, staff_id, clock_in_at, clock_out_at')
        .eq('restaurant_id', context.restaurantId)
        .eq('staff_id', parsed.data.staff_id)
        .is('clock_out_at', null)
        .order('clock_in_at', { ascending: false })
        .limit(1)
        .maybeSingle();

    if (openEntryError) {
        return apiError(
            'Failed to load open time entry',
            500,
            'TIME_ENTRY_FETCH_FAILED',
            openEntryError.message
        );
    }

    if (parsed.data.action === 'in') {
        if (openEntry) {
            return apiError('Staff member is already clocked in', 409, 'CLOCK_ALREADY_OPEN');
        }

        const { data: inserted, error: insertError } = await context.supabase
            .from('time_entries')
            .insert({
                restaurant_id: context.restaurantId,
                staff_id: parsed.data.staff_id,
                shift_id: parsed.data.shift_id || null,
                clock_in_at: occurredAt,
            })
            .select('*')
            .single();

        if (insertError) {
            return apiError('Failed to clock in', 500, 'CLOCK_IN_FAILED', insertError.message);
        }

        if (parsed.data.shift_id) {
            await context.supabase
                .from('shifts')
                .update({ status: 'in_progress' })
                .eq('id', parsed.data.shift_id)
                .eq('restaurant_id', context.restaurantId);
        }

        await writeAuditLog(context.supabase, {
            restaurant_id: context.restaurantId,
            user_id: auth.user.id,
            action: 'staff_clock_in',
            entity_type: 'time_entry',
            entity_id: inserted.id,
            metadata: {
                source: parsed.data.source ?? 'dashboard',
                idempotency_key: idempotencyKey,
            },
            new_value: inserted as any,
        });

        return apiSuccess(
            {
                entry: inserted,
                action: 'in',
                idempotency_key: idempotencyKey,
            },
            201
        );
    }

    if (!openEntry) {
        return apiError(
            'No open time entry found for staff member',
            409,
            'CLOCK_OUT_WITHOUT_OPEN_ENTRY'
        );
    }

    const { data: updated, error: updateError } = await context.supabase
        .from('time_entries')
        .update({
            clock_out_at: occurredAt,
            status: 'closed',
        })
        .eq('id', openEntry.id)
        .eq('restaurant_id', context.restaurantId)
        .select('*')
        .single();

    if (updateError) {
        return apiError('Failed to clock out', 500, 'CLOCK_OUT_FAILED', updateError.message);
    }

    if (openEntry.shift_id) {
        const { data: stillOpenForShift } = await context.supabase
            .from('time_entries')
            .select('id')
            .eq('restaurant_id', context.restaurantId)
            .eq('shift_id', openEntry.shift_id)
            .eq('status', 'open')
            .limit(1);

        if (!stillOpenForShift || stillOpenForShift.length === 0) {
            await context.supabase
                .from('shifts')
                .update({ status: 'completed' })
                .eq('id', openEntry.shift_id)
                .eq('restaurant_id', context.restaurantId)
                .neq('status', 'cancelled');
        }
    }

    await writeAuditLog(context.supabase, {
        restaurant_id: context.restaurantId,
        user_id: auth.user.id,
        action: 'staff_clock_out',
        entity_type: 'time_entry',
        entity_id: updated.id,
        old_value: openEntry as any,
        new_value: updated as any,
        metadata: {
            source: parsed.data.source ?? 'dashboard',
            idempotency_key: idempotencyKey,
        },
    });

    return apiSuccess({
        entry: updated,
        action: 'out',
        idempotency_key: idempotencyKey,
    });
}

import { z } from 'zod';
import { apiError, apiSuccess } from '@/lib/api/response';
import { getAuthenticatedUser, getAuthorizedRestaurantContext } from '@/lib/api/authz';
import { parseJsonBody } from '@/lib/api/validation';
import { writeAuditLog } from '@/lib/api/audit';

const CreateSupportTicketSchema = z.object({
    subject: z.string().trim().min(3).max(140),
    description: z.string().trim().min(5).max(5000),
    priority: z.enum(['low', 'medium', 'high', 'critical']).optional().default('medium'),
    diagnostics_json: z.record(z.string(), z.unknown()).optional(),
});

export async function GET(request: Request) {
    const auth = await getAuthenticatedUser();
    if (!auth.ok) {
        return auth.response;
    }

    const context = await getAuthorizedRestaurantContext(auth.user.id);
    if (!context.ok) {
        return context.response;
    }

    const url = new URL(request.url);
    const limitRaw = Number.parseInt(url.searchParams.get('limit') ?? '20', 10);
    const limit = Number.isFinite(limitRaw) ? Math.max(1, Math.min(limitRaw, 100)) : 20;

    const { data, error } = await context.supabase
        .from('support_tickets')
        .select('id, subject, description, priority, status, source, created_at, updated_at')
        .eq('restaurant_id', context.restaurantId)
        .order('created_at', { ascending: false })
        .limit(limit);

    if (error) {
        return apiError(
            'Failed to fetch support tickets',
            500,
            'SUPPORT_TICKETS_FETCH_FAILED',
            error.message
        );
    }

    return apiSuccess({ tickets: data ?? [] });
}

export async function POST(request: Request) {
    const auth = await getAuthenticatedUser();
    if (!auth.ok) {
        return auth.response;
    }

    const context = await getAuthorizedRestaurantContext(auth.user.id);
    if (!context.ok) {
        return context.response;
    }

    const parsed = await parseJsonBody(request, CreateSupportTicketSchema);
    if (!parsed.success) {
        return parsed.response;
    }

    const { data, error } = await context.supabase
        .from('support_tickets')
        .insert({
            restaurant_id: context.restaurantId,
            source: 'merchant_dashboard',
            subject: parsed.data.subject,
            description: parsed.data.description,
            priority: parsed.data.priority,
            status: 'open',
            diagnostics_json: (parsed.data.diagnostics_json ?? {}) as any,
            created_by: auth.user.id,
        })
        .select('*')
        .single();

    if (error) {
        return apiError(
            'Failed to create support ticket',
            500,
            'SUPPORT_TICKET_CREATE_FAILED',
            error.message
        );
    }

    await writeAuditLog(context.supabase, {
        restaurant_id: context.restaurantId,
        user_id: auth.user.id,
        action: 'support_ticket_created',
        entity_type: 'support_ticket',
        entity_id: data.id,
        metadata: {
            priority: data.priority,
            source: data.source,
        },
        new_value: {
            status: data.status,
            subject: data.subject,
        },
    });

    return apiSuccess(data, 201);
}

