        'server',
        'bartender',
        'host',
        'busser',
        'kitchen',
        'manager',
        'cook',
        'barista',
    ]),
    percentage: z.number().int().min(0).max(10000),
});

const CreateTipPoolWithSharesSchema = z.object({
    tip_pool: CreateTipPoolSchema,
    shares: z.array(TipPoolShareSchema).min(1),
});

export async function GET() {
    const auth = await getAuthenticatedUser();
    if (!auth.ok) {
        return auth.response;
    }

    const context = await getAuthorizedRestaurantContext(auth.user.id, { phase: 'p1' });
    if (!context.ok) {
        return context.response;
    }

    try {
        const db = context.supabase as any;

        // Get tip pools with their shares
        const { data: pools, error: poolsError } = await db
            .from('tip_pools')
            .select('*')
            .eq('restaurant_id', context.restaurantId)
            .order('created_at', { ascending: false });

        if (poolsError) {
            return apiError(
                'Failed to load tip pools',
                500,
                'TIP_POOL_FETCH_FAILED',
                poolsError.message
            );
        }

        if (!pools || pools.length === 0) {
            return apiSuccess({ tip_pools: [], shares: {} });
        }

        const poolIds = pools.map((p: any) => p.id);

        // Get shares for all pools
        const { data: shares, error: sharesError } = await db
            .from('tip_pool_shares')
            .select('*')
            .in('tip_pool_id', poolIds)
            .order('role', { ascending: true });

        if (sharesError) {
            return apiError(
                'Failed to load tip pool shares',
                500,
                'TIP_POOL_SHARES_FETCH_FAILED',
                sharesError.message
            );
        }

        // Group shares by pool
        const sharesByPool: Record<string, any[]> = {};
        (shares ?? []).forEach((share: any) => {
            if (!sharesByPool[share.tip_pool_id]) {
                sharesByPool[share.tip_pool_id] = [];
            }
            sharesByPool[share.tip_pool_id].push(share);
        });

        return apiSuccess({
            tip_pools: pools ?? [],
            shares: sharesByPool,
        });
    } catch (error) {
        return apiError(
            'Failed to load tip pools',
            500,
            'TIP_POOL_FETCH_FAILED',
            error instanceof Error ? error.message : 'Unknown error'
        );
    }
}

export async function POST(request: Request) {
    const auth = await getAuthenticatedUser();
    if (!auth.ok) {
        return auth.response;
    }

    const context = await getAuthorizedRestaurantContext(auth.user.id, { phase: 'p1' });
    if (!context.ok) {
        return context.response;
    }

    const parsed = await parseJsonBody(request, CreateTipPoolWithSharesSchema);
    if (!parsed.success) {
        return parsed.response;
    }

    const { tip_pool, shares } = parsed.data;

    // Validate shares total doesn't exceed 100%
    const totalPercentage = shares.reduce((sum, s) => sum + s.percentage, 0);
    if (totalPercentage > 10000) {
        return apiError('Total shares cannot exceed 100%', 400, 'TIP_POOL_SHARES_EXCEED_100');
    }

    const db = context.supabase as any;

    // Create the tip pool
    const { data: pool, error: poolError } = await db
        .from('tip_pools')
        .insert({
            restaurant_id: context.restaurantId,
            created_by: auth.user.id,
            ...tip_pool,
        })
        .select('*')
        .single();

    if (poolError || !pool) {
        return apiError(
            'Failed to create tip pool',
            500,
            'TIP_POOL_CREATE_FAILED',
            poolError?.message
        );
    }

    // Create shares
    const sharesData = shares.map(share => ({
        restaurant_id: context.restaurantId,
        tip_pool_id: pool.id,
        role: share.role,
        percentage: share.percentage,
    }));

    const { error: sharesError } = await db.from('tip_pool_shares').insert(sharesData);

    if (sharesError) {
        // Rollback pool creation
        await db.from('tip_pools').delete().eq('id', pool.id);
        return apiError(
            'Failed to create tip pool shares',
            500,
            'TIP_POOL_SHARES_CREATE_FAILED',
            sharesError.message
        );
    }

    await writeAuditLog(context.supabase, {
        restaurant_id: context.restaurantId,
        user_id: auth.user.id,
        action: 'tip_pool_created',
        entity_type: 'tip_pool',
        entity_id: pool.id,
        metadata: { name: pool.name, shares_count: shares.length },
    });

    return apiSuccess({ tip_pool: pool, shares }, 201);
}

import { timingSafeEqual } from 'crypto';
import { z } from 'zod';
import { apiError, apiSuccess } from '@/lib/api/response';
import { createServiceRoleClient } from '@/lib/supabase/service-role';
import { sendOrderStatusSms } from '@/lib/notifications/sms';

const GuestOrderStatusSchema = z.object({
    eventType: z.string(),
    details: z.object({
        orderGuid: z.string().uuid(),
        guestOrderStatus: z.enum(['IN_PREPARATION', 'READY_FOR_PICKUP', 'CLOSED', 'VOIDED']),
        lastUpdated: z.string().datetime().optional(),
    }),
});

function verifySharedSecret(headerValue: string | null, expectedSecret: string): boolean {
    if (!headerValue) return false;

    const expected = Buffer.from(expectedSecret, 'utf8');
    const received = Buffer.from(headerValue, 'utf8');
    if (expected.length !== received.length) return false;

    try {
        return timingSafeEqual(expected, received);
    } catch {
        return expectedSecret === headerValue;
    }
}

function mapGuestOrderStatusToInternalStatus(guestOrderStatus: string) {
    if (guestOrderStatus === 'IN_PREPARATION') return 'preparing';
    if (guestOrderStatus === 'READY_FOR_PICKUP') return 'ready';
    if (guestOrderStatus === 'CLOSED') return 'served';
    return 'cancelled';
}

export async function POST(request: Request) {
    const configuredSecret = process.env.GUEST_ORDER_STATUS_WEBHOOK_SECRET;
    if (configuredSecret) {
        const headerSecret =
            request.headers.get('x-webhook-secret') ??
            request.headers.get('x-guest-webhook-secret');
        if (!verifySharedSecret(headerSecret, configuredSecret)) {
            return apiError('Invalid webhook secret', 401, 'INVALID_WEBHOOK_SECRET');
        }
    }

    const body = await request.json().catch(() => null);
    const parsed = GuestOrderStatusSchema.safeParse(body);
    if (!parsed.success) {
        return apiError('Invalid webhook payload', 400, 'INVALID_PAYLOAD', parsed.error.flatten());
    }

    if (parsed.data.eventType !== 'guestOrderStatusUpdated') {
        return apiError('Unsupported eventType', 400, 'UNSUPPORTED_EVENT_TYPE');
    }

    const admin = createServiceRoleClient();
    const orderId = parsed.data.details.orderGuid;
    const guestOrderStatus = parsed.data.details.guestOrderStatus;
    const mappedStatus = mapGuestOrderStatusToInternalStatus(guestOrderStatus);

    const { data: existingOrder, error: orderFetchError } = await admin
        .from('orders')
        .select('id, restaurant_id, status, customer_phone, order_number')
        .eq('id', orderId)
        .maybeSingle();

    if (orderFetchError) {
        return apiError(
            'Failed to resolve order',
            500,
            'ORDER_LOOKUP_FAILED',
            orderFetchError.message
        );
    }
    if (!existingOrder) {
        return apiError('Order not found', 404, 'ORDER_NOT_FOUND');
    }

    if (existingOrder.status === mappedStatus) {
        return apiSuccess({
            accepted: true,
            updated: false,
            order_id: existingOrder.id,
            status: existingOrder.status,
        });
    }

    const { error: updateError } = await admin
        .from('orders')
        .update({
            status: mappedStatus,
            updated_at: new Date().toISOString(),
        })
        .eq('id', existingOrder.id);

    if (updateError) {
        return apiError('Failed to update order', 500, 'ORDER_UPDATE_FAILED', updateError.message);
    }

    const { data: restaurantSettings } = await admin
        .from('restaurants')
        .select('settings')
        .eq('id', existingOrder.restaurant_id)
        .maybeSingle();
    const notificationsSettings = (restaurantSettings?.settings as Record<string, any> | null)
        ?.notifications;
    const smsEnabled = Boolean(notificationsSettings?.sms_enabled);

    const smsPromise =
        smsEnabled && existingOrder.customer_phone
            ? sendOrderStatusSms({
                  toPhone: existingOrder.customer_phone,
                  orderNumber: existingOrder.order_number ?? existingOrder.id,
                  status: mappedStatus,
              })
            : Promise.resolve({ success: false, provider: 'log' as const, skipped: true });

    await Promise.all([
        admin.from('order_events').insert({
            restaurant_id: existingOrder.restaurant_id,
            order_id: existingOrder.id,
            event_type: 'status_changed',
            from_status: existingOrder.status,
            to_status: mappedStatus,
            actor_user_id: null,
            metadata: {
                source: 'guest_order_status_webhook',
                guest_order_status: guestOrderStatus,
                webhook_last_updated: parsed.data.details.lastUpdated ?? null,
            },
        }),
        admin.from('audit_logs').insert({
            restaurant_id: existingOrder.restaurant_id,
            action: 'guest_order_status_webhook_received',
            entity_type: 'order',
            entity_id: existingOrder.id,
            metadata: {
                guest_order_status: guestOrderStatus,
                mapped_status: mappedStatus,
            },
            old_value: { status: existingOrder.status },
            new_value: { status: mappedStatus },
        }),
        smsPromise,
    ]);

    return apiSuccess({
        accepted: true,
        updated: true,
        order_id: existingOrder.id,
        previous_status: existingOrder.status,
        status: mappedStatus,
    });
}

'use server';

import { createClient } from '@/lib/supabase/server';
import { createAuditedServiceRoleClient } from '@/lib/supabase/service-role';
import { verifyOrigin } from '@/lib/security/csrf';

// Role-based redirect map
const ROLE_REDIRECTS: Record<string, string> = {
    kitchen: '/kds',
    waiter: '/waiter',
    runner: '/waiter',
    bar: '/bar',
    manager: '/merchant',
    admin: '/merchant',
    owner: '/merchant',
};

interface ProvisionResult {
    success?: boolean;
    error?: string;
    redirectTo: string;
}

export async function provisionDevice(data: {
    code: string;
    password: string; // Used to create the auth user
    deviceName: string;
}): Promise<ProvisionResult> {
    // CSRF Protection - verify origin before processing
    await verifyOrigin();

    const supabase = await createClient();
    // HIGH-010: Use audited service role client for device provisioning
    const adminClient = createAuditedServiceRoleClient('device-provisioning');

    try {
        // 1. Verify Invite Code
        const { data: invite, error: inviteError } = await adminClient
            .from('staff_invites')
            .select('*')
            .eq('code', data.code) // Query by the Invite Code (token), not the ID
            // In a real production app, we'd use a separate secure token, but ID is okay for MVP if UUID
            .single();

        if (inviteError || !invite) {
            return { error: 'Invalid or expired provisioning code', redirectTo: '/auth/login' };
        }

        if (invite.status === 'accepted') {
            return { error: 'Link already used', redirectTo: '/auth/login' };
        }

        // 2. Check if User Exists (by email in invite)
        // If invite has an email, try to find user. If not, we might create a "Device User"
        // For this MVP, we assume invite has Email.
        const email =
            invite.email ??
            `device-${String(invite.role)}-${String(invite.id).slice(0, 8)}@provisioned.gebeta.local`;

        // 3. Create Auth User (or Sign In if we had password, but here we arc Creating)
        // We use Admin API to creating user without email confirmation for device setup speed
        const { data: authUser, error: createError } = await adminClient.auth.admin.createUser({
            email: email,
            password: data.password,
            email_confirm: true,
            user_metadata: {
                full_name: data.deviceName,
                is_device: true,
                provisioned_from_invite: true,
                provisioned_role: invite.role,
            },
        });

        if (createError) {
            if (/already exists/i.test(createError.message ?? '')) {
                return {
                    error: 'This access identity already exists. Please use the login screen.',
                    redirectTo: '/auth/login',
                };
            }
            return { error: `Setup Failed: ${createError.message}`, redirectTo: '/auth/login' };
        }

        if (!authUser.user) {
            return { error: 'Failed to create device identity', redirectTo: '/auth/login' };
        }

        // 4. Link to Restaurant (Insert into restaurant_staff)
        const { error: linkError } = await adminClient.from('restaurant_staff').insert({
            restaurant_id: invite.restaurant_id,
            user_id: authUser.user.id,
            role: invite.role,
            is_active: true,
        });

        if (linkError) {
            // Rollback user creation? For now, just error.
            return { error: 'Failed to link device to restaurant', redirectTo: '/auth/login' };
        }

        // 5. Mark Invite Accepted
        await adminClient.from('staff_invites').update({ status: 'accepted' }).eq('id', invite.id);

        // 6. Define Redirect
        const target = ROLE_REDIRECTS[invite.role] || '/merchant/onboarding/staff';

        // 7. Auto-Login the Session (We can't do this easily from Server Action for a NEW user created via Admin API)
        // Workaround: We return success, Client side uses `signInWithPassword` immediately?
        // OR: We use `signInWithPassword` here to get a session, and set cookies?

        // Let's try to sign in to set the cookie on this response
        const { error: signInError } = await supabase.auth.signInWithPassword({
            email: email,
            password: data.password,
        });

        if (signInError) {
            return {
                error: 'Setup complete, but auto-login failed. Please log in manually.',
                redirectTo: '/auth/login',
            };
        }

        return { success: true, redirectTo: `${target}?restaurantId=${invite.restaurant_id}` };
    } catch (e: any) {
        console.error('Provisioning Error:', e);
        return { error: e.message || 'Server provisioning failed', redirectTo: '/auth/login' };
    }
}

'use client';

import { Suspense, useEffect, useState } from 'react';
import { useSearchParams } from 'next/navigation';
import { Button } from '@/components/ui/Button';
import { Input } from '@/components/ui/Input';
import { Loader2, Tablet } from 'lucide-react';
import { toast } from 'react-hot-toast';
import { provisionDevice } from './actions';

function DeviceProvisioningContent() {
    const searchParams = useSearchParams();
    const [loading, setLoading] = useState(false);

    const code = searchParams.get('code');
    const role = (searchParams.get('role') ?? '').toLowerCase();
    const inviteLabel = searchParams.get('label');
    const targetModule =
        role === 'kitchen' || role === 'bar'
            ? '/kds/display'
            : role === 'waiter'
              ? '/pos/mobile'
              : '/merchant';

    // Form State
    const [password, setPassword] = useState('');
    const [deviceName, setDeviceName] = useState(inviteLabel ?? '');

    useEffect(() => {
        if (!code) {
            toast.error('Invalid setup link');
            return;
        }
        // Ideally fetch invite details here purely for display
        // For now, we'll infer role from params if available or fetch via server action check
    }, [code]);

    const handleSetup = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);

        try {
            if (!code) throw new Error('No setup code found');

            const result = await provisionDevice({
                code,
                password,
                deviceName: deviceName || `Device-${Math.floor(Math.random() * 1000)}`,
            });

            if (result.error) {
                toast.error(result.error);
            } else {
                toast.success('Device Provisioned Successfully!');
                window.location.replace(result.redirectTo);
            }
        } catch (err: any) {
            toast.error(err.message || 'Setup failed');
        } finally {
            setLoading(false);
        }
    };

    if (!code) {
        return (
            <div className="flex min-h-screen flex-col items-center justify-center p-4">
                <div className="space-y-4 text-center">
                    <h1 className="text-2xl font-bold text-red-600">Invalid Link</h1>
                    <p className="text-gray-500">This setup link is missing a code.</p>
                </div>
            </div>
        );
    }

    return (
        <div className="flex min-h-screen flex-col items-center justify-center bg-gray-50 p-4">
            <div className="w-full max-w-md space-y-8 rounded-xl border border-gray-100 bg-white p-8 shadow-xl">
                {/* Header */}
                <div className="space-y-2 text-center">
                    <div className="mx-auto mb-6 flex h-16 w-16 items-center justify-center rounded-xl bg-blue-50">
                        <Tablet className="h-8 w-8 text-blue-600" />
                    </div>
                    <h1 className="text-2xl font-bold tracking-tight text-gray-900">
                        Device Provisioning
                    </h1>
                    <p className="text-sm text-gray-500">
                        Configure this access key and install the assigned module.
                    </p>
                    <p className="text-xs font-semibold text-blue-700">Target: {targetModule}</p>
                </div>

                <form onSubmit={handleSetup} className="space-y-6">
                    <div className="space-y-4">
                        {/* Device Name Input */}
                        <div>
                            <label className="mb-1 block text-sm font-medium text-gray-700">
                                Device Name
                            </label>
                            <Input
                                type="text"
                                placeholder="e.g. Kitchen Display 1, Waiter Phone"
                                value={deviceName}
                                onChange={e => setDeviceName(e.target.value)}
                                required
                                className="h-12"
                            />
                        </div>

                        {/* Password / Access Code */}
                        <div>
                            <label className="mb-1 block text-sm font-medium text-gray-700">
                                Create Access PIN / Password
                            </label>
                            <Input
                                type="password"
                                placeholder="********"
                                value={password}
                                onChange={e => setPassword(e.target.value)}
                                required
                                minLength={6}
                                className="h-12"
                            />
                            <p className="mt-1 text-xs text-gray-500">
                                This will be used to unlock this device session.
                            </p>
                        </div>
                    </div>

                    <Button
                        type="submit"
                        disabled={loading}
                        className="h-12 w-full bg-blue-600 text-base font-semibold hover:bg-blue-700"
                    >
                        {loading ? (
                            <>
                                <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                                Provisioning...
                            </>
                        ) : (
                            'Install & Connect'
                        )}
                    </Button>
                </form>

                <p className="text-center text-xs text-gray-400">
                    This device will be linked to your restaurant securely.
                </p>
            </div>
        </div>
    );
}

export default function DeviceProvisioningPage() {
    return (
        <Suspense
            fallback={
                <div className="flex h-screen items-center justify-center">
                    <Loader2 className="h-8 w-8 animate-spin text-gray-400" />
                </div>
            }
        >
            <DeviceProvisioningContent />
        </Suspense>
    );
}

