'use client';

import { useCallback, useEffect, useState } from 'react';
import { toast } from 'react-hot-toast';
import { ChannelHealthBoard } from '@/components/merchant/ChannelHealthBoard';
import { DeliveryPartnerHub } from '@/components/merchant/DeliveryPartnerHub';
import {
    OnlineOrderingSettingsPanel,
    type OnlineOrderingSettings,
} from '@/components/merchant/OnlineOrderingSettingsPanel';
import { usePageLoadGuard } from '@/hooks/usePageLoadGuard';
import { useRole } from '@/hooks/useRole';

interface ChannelsPageClientProps {
    initialData?: any;
}

type ChannelSummary = {
    totals: {
        delivery_partners: number;
        connected_partners: number;
        degraded_partners: number;
        external_orders_24h: number;
        external_orders_total: number;
        unacked_orders: number;
    };
    statuses: Record<string, number>;
    partners: Array<{
        id: string;
        provider: string;
        status: string;
        updated_at: string;
        last_sync_at: string | null;
    }>;
};

type ExternalOrder = {
    id: string;
    provider: string;
    provider_order_id: string;
    source_channel: string;
    normalized_status: string;
    total_amount: number;
    currency: string;
    payload_json: Record<string, unknown>;
    acked_at: string | null;
    created_at: string;
    updated_at: string;
};

const defaultSettings: OnlineOrderingSettings = {
    enabled: true,
    accepts_scheduled_orders: true,
    auto_accept_orders: false,
    prep_time_minutes: 30,
    max_daily_orders: 300,
    service_hours: { start: '08:00', end: '22:00' },
    order_throttling_enabled: false,
    throttle_limit_per_15m: 40,
};

export function ChannelsPageClient(_props: ChannelsPageClientProps) {
    const { loading, markLoaded } = usePageLoadGuard('channels');
    const [error, setError] = useState<string | null>(null);

    const [summary, setSummary] = useState<ChannelSummary | null>(null);
    const [orders, setOrders] = useState<ExternalOrder[]>([]);
    const [settings, setSettings] = useState<OnlineOrderingSettings>(defaultSettings);
    const [settingsSaving, setSettingsSaving] = useState(false);

    const { restaurantId: _restaurantId } = useRole(null);
    const [restaurantSlug, setRestaurantSlug] = useState<string | null>(null);

    const [settingsError, setSettingsError] = useState<string | null>(null);
    const [connecting, setConnecting] = useState(false);
    const [acknowledgingId, setAcknowledgingId] = useState<string | null>(null);
    const [refreshToken, setRefreshToken] = useState(0);

    // Mark as loaded on mount
    useEffect(() => {
        markLoaded();
    }, [markLoaded]);

    const loadAll = useCallback(async () => {
        try {
            setError(null);
            setSettingsError(null);

            const [summaryRes, settingsRes, ordersRes] = await Promise.all([
                fetch('/api/channels/summary', { method: 'GET', cache: 'no-store' }),
                fetch('/api/channels/online-ordering/settings', {
                    method: 'GET',
                    cache: 'no-store',
                }),
                fetch('/api/channels/delivery/orders?limit=100', {
                    method: 'GET',
                    cache: 'no-store',
                }),
            ]);

            const [summaryPayload, settingsPayload, ordersPayload] = await Promise.all([
                summaryRes.json(),
                settingsRes.json(),
                ordersRes.json(),
            ]);

            if (!summaryRes.ok) {
                throw new Error(summaryPayload?.error ?? 'Failed to load channel summary.');
            }
            if (!settingsRes.ok) {
                throw new Error(
                    settingsPayload?.error ?? 'Failed to load online ordering settings.'
                );
            }
            if (!ordersRes.ok) {
                console.warn(ordersPayload?.error ?? 'Failed to load delivery orders.');
            } else {
                setOrders((ordersPayload?.data?.orders ?? []) as ExternalOrder[]);
            }

            setSummary((summaryPayload?.data ?? null) as ChannelSummary | null);
            const settingsData = settingsPayload?.data ?? {};
            if (settingsData.slug) {
                setRestaurantSlug(settingsData.slug);
            }
            delete settingsData.slug;
            setSettings({ ...defaultSettings, ...settingsData });
        } catch (loadError) {
            console.error(loadError);
            setError(
                loadError instanceof Error ? loadError.message : 'Failed to load channels data.'
            );
            setSummary(null);
            setOrders([]);
        } finally {
            markLoaded();
        }
    }, [markLoaded]);

    useEffect(() => {
        void loadAll();
    }, [loadAll, refreshToken]);

    const saveSettings = async () => {
        try {
            setSettingsSaving(true);
            setSettingsError(null);
            const response = await fetch('/api/channels/online-ordering/settings', {
                method: 'PATCH',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(settings),
            });
            const payload = await response.json();
            if (!response.ok) {
                throw new Error(payload?.error ?? 'Failed to save online ordering settings.');
            }
            setSettings({ ...defaultSettings, ...(payload?.data ?? {}) });
            toast.success('Online ordering settings updated.');
        } catch (saveError) {
            const message =
                saveError instanceof Error
                    ? saveError.message
                    : 'Failed to save online ordering settings.';
            setSettingsError(message);
            toast.error(message);
        } finally {
            setSettingsSaving(false);
        }
    };

    const connectPartner = async (
        provider: 'beu' | 'deliver_addis' | 'zmall' | 'esoora' | 'custom_local',
        displayName?: string
    ) => {
        try {
            setConnecting(true);
            const response = await fetch('/api/channels/delivery/connect', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    provider,
                    ...(displayName ? { display_name: displayName } : {}),
                }),
            });
            const payload = await response.json();
            if (!response.ok) {
                throw new Error(payload?.error ?? 'Failed to connect delivery partner.');
            }
            toast.success('Delivery partner connected.');
            setRefreshToken(value => value + 1);
        } catch (connectError) {
            toast.error(
                connectError instanceof Error
                    ? connectError.message
                    : 'Failed to connect delivery partner.'
            );
        } finally {
            setConnecting(false);
        }
    };

    const acknowledgeOrder = async (externalOrderId: string) => {
        try {
            setAcknowledgingId(externalOrderId);
            const response = await fetch(`/api/channels/delivery/orders/${externalOrderId}/ack`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({}),
            });
            const payload = await response.json();
            if (!response.ok) {
                throw new Error(payload?.error ?? 'Failed to acknowledge order.');
            }
            toast.success('External order acknowledged.');
            setRefreshToken(value => value + 1);
        } catch (ackError) {
            toast.error(
                ackError instanceof Error ? ackError.message : 'Failed to acknowledge order.'
            );
        } finally {
            setAcknowledgingId(null);
        }
    };

    return (
        <div className="min-h-screen space-y-6 pb-20">
            <div>
                <h1 className="mb-2 text-4xl font-bold tracking-tight text-black">Channels</h1>
                <p className="font-medium text-gray-500">
                    Online ordering settings and delivery integration operations.
                </p>
            </div>

            {error && (
                <div className="rounded-xl border border-amber-200 bg-amber-50 p-4 text-sm font-semibold text-amber-800">
                    {error}
                </div>
            )}

            <ChannelHealthBoard loading={loading} summary={summary} error={null} />

            <OnlineOrderingSettingsPanel
                loading={loading}
                saving={settingsSaving}
                error={settingsError}
                settings={settings}
                restaurantSlug={restaurantSlug}
                onChange={setSettings}
                onSave={saveSettings}
            />

            <DeliveryPartnerHub
                loading={loading}
                partners={summary?.partners ?? []}
                orders={orders}
                connecting={connecting}
                acknowledgingId={acknowledgingId}
                onConnect={connectPartner}
                onAcknowledge={acknowledgeOrder}
            />
        </div>
    );
}

'use client';

import React, { useCallback, useEffect, useMemo, useState } from 'react';
import { Users, Crown, Repeat, Wallet } from 'lucide-react';
import { toast } from 'react-hot-toast';
import { cn } from '@/lib/utils';
import {
    CampaignBuilder,
    type CampaignRow,
    type SegmentOption,
} from '@/components/merchant/CampaignBuilder';
import { GuestDirectory, type GuestDirectoryRow } from '@/components/merchant/GuestDirectory';
import { GuestProfileDrawer } from '@/components/merchant/GuestProfileDrawer';
import {
    LoyaltyProgramBuilder,
    type LoyaltyProgramRow,
} from '@/components/merchant/LoyaltyProgramBuilder';
import { MetricCard } from '@/components/merchant/MetricCard';
import { useAppLocale } from '@/hooks/useAppLocale';
import { formatETBCurrency } from '@/lib/format/et';
import { getP2Copy } from '@/lib/i18n/p2';
import { usePageLoadGuard } from '@/hooks/usePageLoadGuard';

interface GuestsPageClientProps {
    initialData?: any;
}

type Segment = 'all' | 'vip' | 'returning' | 'new';

type GuestDetail = {
    id: string;
    name: string | null;
    language: string;
    tags: string[];
    is_vip: boolean;
    notes: string | null;
    visit_count: number;
    lifetime_value: number;
    first_seen_at: string;
    last_seen_at: string;
};

type GuestVisit = {
    id: string;
    channel: string;
    visited_at: string;
    spend: number;
    order_id: string | null;
    metadata: Record<string, unknown>;
};

export function GuestsPageClient(_props: GuestsPageClientProps) {
    const locale = useAppLocale();
    const copy = getP2Copy(locale);
    const [guests, setGuests] = useState<GuestDirectoryRow[]>([]);
    const { loading, markLoaded } = usePageLoadGuard('guests');
    const [error, setError] = useState<string | null>(null);
    const [query, setQuery] = useState('');
    const [segment, setSegment] = useState<Segment>('all');
    const [tagFilter, setTagFilter] = useState('');
    const [selectedGuestId, setSelectedGuestId] = useState<string | null>(null);
    const [selectedGuest, setSelectedGuest] = useState<GuestDetail | null>(null);
    const [guestVisits, setGuestVisits] = useState<GuestVisit[]>([]);
    const [drawerLoading, setDrawerLoading] = useState(false);
    const [drawerSaving, setDrawerSaving] = useState(false);
    const [refreshToken, setRefreshToken] = useState(0);

    const [growthLoading, setGrowthLoading] = useState(true);
    const [growthError, setGrowthError] = useState<string | null>(null);
    const [loyaltyPrograms, setLoyaltyPrograms] = useState<LoyaltyProgramRow[]>([]);
    const [campaigns, setCampaigns] = useState<CampaignRow[]>([]);
    const [segments, setSegments] = useState<SegmentOption[]>([]);
    const [creatingLoyalty, setCreatingLoyalty] = useState(false);
    const [creatingCampaign, setCreatingCampaign] = useState(false);
    const [launchingCampaignId, setLaunchingCampaignId] = useState<string | null>(null);
    const [activeGrowthTab, setActiveGrowthTab] = useState<'loyalty' | 'campaigns'>(
        'loyalty'
    );

    // Mark as loaded on mount
    useEffect(() => {
        markLoaded();
    }, [markLoaded]);

    const fetchGuests = useCallback(async () => {
        try {
            setError(null);
            const params = new URLSearchParams();
            if (query.trim().length > 0) params.set('query', query.trim());
            if (segment !== 'all') params.set('segment', segment);
            if (tagFilter.trim().length > 0) params.set('tag', tagFilter.trim());
            params.set('limit', '100');

            const response = await fetch(`/api/guests?${params.toString()}`, {
                method: 'GET',
                cache: 'no-store',
            });
            const payload = await response.json();
            if (!response.ok) {
                throw new Error(payload?.error ?? 'Failed to load guests.');
            }
            setGuests((payload?.data?.guests ?? []) as GuestDirectoryRow[]);
        } catch (fetchError) {
            console.error(fetchError);
            setGuests([]);
            setError(fetchError instanceof Error ? fetchError.message : 'Failed to load guests.');
        } finally {
            markLoaded();
        }
    }, [query, segment, tagFilter, markLoaded]);

    const fetchGrowthData = useCallback(async () => {
        try {
            setGrowthLoading(true);
            const [programsRes, cardsRes, campaignsRes] = await Promise.all([
                fetch('/api/loyalty/programs', { method: 'GET', cache: 'no-store' }),
                fetch('/api/gift-cards', { method: 'GET', cache: 'no-store' }),
                fetch('/api/campaigns', { method: 'GET', cache: 'no-store' }),
            ]);

            const [programsPayload, cardsPayload, campaignsPayload] = await Promise.all([
                programsRes.json(),
                cardsRes.json(),
                campaignsRes.json(),
            ]);

            if (!programsRes.ok) {
                throw new Error(programsPayload?.error ?? 'Failed to load loyalty programs.');
            }
            if (!cardsRes.ok) {
                throw new Error(cardsPayload?.error ?? 'Failed to load gift cards.');
            }
            if (!campaignsRes.ok) {
                throw new Error(campaignsPayload?.error ?? 'Failed to load campaigns.');
            }

            setLoyaltyPrograms((programsPayload?.data?.programs ?? []) as LoyaltyProgramRow[]);
            setCampaigns((campaignsPayload?.data?.campaigns ?? []) as CampaignRow[]);
            setSegments(
                ((campaignsPayload?.data?.segments ?? []) as SegmentOption[]).map(item => ({
                    id: item.id,
                    name: item.name,
                }))
            );
        } catch (growthFetchError) {
            console.error(growthFetchError);
            setGrowthError(
                growthFetchError instanceof Error
                    ? growthFetchError.message
                    : 'Failed to load growth operations data.'
            );
        } finally {
            setGrowthLoading(false);
        }
    }, []);

    const fetchGuestDrawerData = useCallback(async (guestId: string) => {
        try {
            setDrawerLoading(true);
            const [guestRes, visitsRes] = await Promise.all([
                fetch(`/api/guests/${guestId}`, { method: 'GET', cache: 'no-store' }),
                fetch(`/api/guests/${guestId}/visits?limit=20`, {
                    method: 'GET',
                    cache: 'no-store',
                }),
            ]);

            const [guestPayload, visitsPayload] = await Promise.all([
                guestRes.json(),
                visitsRes.json(),
            ]);

            if (!guestRes.ok) {
                throw new Error(guestPayload?.error ?? 'Failed to load guest profile.');
            }
            if (!visitsRes.ok) {
                throw new Error(visitsPayload?.error ?? 'Failed to load guest visits.');
            }

            setSelectedGuest((guestPayload?.data ?? null) as GuestDetail | null);
            setGuestVisits((visitsPayload?.data?.visits ?? []) as GuestVisit[]);
        } catch (drawerError) {
            console.error(drawerError);
            toast.error(
                drawerError instanceof Error ? drawerError.message : 'Failed to load guest details.'
            );
            setSelectedGuest(null);
            setGuestVisits([]);
        } finally {
            setDrawerLoading(false);
        }
    }, []);

    useEffect(() => {
        const timer = window.setTimeout(() => {
            void fetchGuests();
        }, 250);
        return () => window.clearTimeout(timer);
    }, [fetchGuests, refreshToken]);

    useEffect(() => {
        void fetchGrowthData();
    }, [fetchGrowthData, refreshToken]);

    useEffect(() => {
        if (!selectedGuestId) return;
        void fetchGuestDrawerData(selectedGuestId);
    }, [selectedGuestId, fetchGuestDrawerData, refreshToken]);

    const openGuest = async (guestId: string) => {
        setSelectedGuestId(guestId);
    };

    const closeDrawer = () => {
        setSelectedGuestId(null);
        setSelectedGuest(null);
        setGuestVisits([]);
    };

    const handleGuestSave = async (payload: {
        guestId: string;
        name?: string;
        language?: 'en' | 'am';
        tags?: string[];
        is_vip?: boolean;
        notes?: string | null;
    }) => {
        try {
            setDrawerSaving(true);
            const response = await fetch(`/api/guests/${payload.guestId}`, {
                method: 'PATCH',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    ...(payload.name !== undefined ? { name: payload.name } : {}),
                    ...(payload.language !== undefined ? { language: payload.language } : {}),
                    ...(payload.tags !== undefined ? { tags: payload.tags } : {}),
                    ...(payload.is_vip !== undefined ? { is_vip: payload.is_vip } : {}),
                    ...(payload.notes !== undefined ? { notes: payload.notes } : {}),
                }),
            });

            const result = await response.json();
            if (!response.ok) {
                throw new Error(result?.error ?? 'Failed to save guest profile.');
            }

            toast.success('Guest profile updated.');
            setRefreshToken(value => value + 1);
        } catch (saveError) {
            toast.error(
                saveError instanceof Error ? saveError.message : 'Failed to save guest profile.'
            );
        } finally {
            setDrawerSaving(false);
        }
    };

    const handleCreateLoyaltyProgram = async (payload: {
        id?: string;
        name: string;
        status: LoyaltyProgramRow['status'];
        points_rule_json?: Record<string, unknown>;
    }) => {
        try {
            setCreatingLoyalty(true);
            const isUpdate = !!payload.id;
            const url = isUpdate ? `/api/loyalty/programs/${payload.id}` : '/api/loyalty/programs';
            const method = isUpdate ? 'PATCH' : 'POST';

            const response = await fetch(url, {
                method,
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(payload),
            });
            const result = await response.json();
            if (!response.ok) {
                throw new Error(
                    result?.error ?? `Failed to ${isUpdate ? 'update' : 'create'} loyalty program.`
                );
            }
            toast.success(`Loyalty program ${isUpdate ? 'updated' : 'created'}.`);
            setRefreshToken(value => value + 1);
        } catch (createError) {
            toast.error(
                createError instanceof Error
                    ? createError.message
                    : `Failed to ${!!payload.id ? 'update' : 'create'} loyalty program.`
            );
        } finally {
            setCreatingLoyalty(false);
        }
    };

    const handleCreateCampaign = async (payload: {
        id?: string;
        name: string;
        channel: CampaignRow['channel'];
        segment_id?: string;
        scheduled_at?: string;
        template_json?: { content: string };
    }) => {
        try {
            setCreatingCampaign(true);
            const isUpdate = !!payload.id;
            const url = isUpdate ? `/api/campaigns/${payload.id}` : '/api/campaigns';
            const method = isUpdate ? 'PATCH' : 'POST';

            const response = await fetch(url, {
                method,
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(payload),
            });
            const result = await response.json();
            if (!response.ok) {
                throw new Error(
                    result?.error ?? `Failed to ${isUpdate ? 'update' : 'create'} campaign.`
                );
            }
            toast.success(`Campaign ${isUpdate ? 'updated' : 'created'}.`);
            setRefreshToken(value => value + 1);
        } catch (createError) {
            toast.error(
                createError instanceof Error
                    ? createError.message
                    : `Failed to ${!!payload.id ? 'update' : 'create'} campaign.`
            );
        } finally {
            setCreatingCampaign(false);
        }
    };

    const handleLaunchCampaign = async (campaignId: string) => {
        try {
            setLaunchingCampaignId(campaignId);
            const response = await fetch(`/api/campaigns/${campaignId}/launch`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({}),
            });
            const result = await response.json();
            if (!response.ok) {
                throw new Error(result?.error ?? 'Failed to launch campaign.');
            }
            toast.success('Campaign launched.');
            setRefreshToken(value => value + 1);
        } catch (launchError) {
            toast.error(
                launchError instanceof Error ? launchError.message : 'Failed to launch campaign.'
            );
        } finally {
            setLaunchingCampaignId(null);
        }
    };

    // Management Handlers
    const handleDeleteLoyalty = async (id: string) => {
        try {
            const res = await fetch(`/api/loyalty/programs/${id}`, { method: 'DELETE' });
            if (!res.ok) {
                const errorData = await res.json();
                throw new Error(errorData.error || 'Failed to delete program');
            }
            toast.success('Program removed');
            setRefreshToken(v => v + 1);
        } catch (error: any) {
            toast.error(error.message || 'Failed to remove program');
        }
    };

    const handleStatusChangeLoyalty = async (id: string, status: LoyaltyProgramRow['status']) => {
        try {
            const res = await fetch(`/api/loyalty/programs/${id}`, {
                method: 'PATCH',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ status }),
            });
            if (!res.ok) {
                const errorData = await res.json();
                throw new Error(errorData.error || 'Failed to update status');
            }
            toast.success(`Program ${status}`);
            setRefreshToken(v => v + 1);
        } catch (error: any) {
            toast.error(error.message || `Failed to ${status} program`);
        }
    };

    const handleDeleteCampaign = async (id: string) => {
        try {
            const res = await fetch(`/api/campaigns/${id}`, { method: 'DELETE' });
            if (!res.ok) {
                const errorData = await res.json();
                throw new Error(errorData.error || 'Failed to delete campaign');
            }
            toast.success('Campaign removed');
            setRefreshToken(v => v + 1);
        } catch (error: any) {
            toast.error(error.message || 'Failed to remove campaign');
        }
    };

    const handleEdit = (type: string, id: string) => {
        toast.success(`Opening edit mode for ${type}...`);
        // Implementation for opening edit modals would go here
    };

    const stats = useMemo(() => {
        const totalGuests = guests.length;
        const vipCount = guests.filter(guest => guest.is_vip).length;
        const returningCount = guests.filter(guest => guest.visit_count >= 2).length;
        const ltvTotal = guests.reduce((sum, guest) => sum + Number(guest.lifetime_value ?? 0), 0);
        return { totalGuests, vipCount, returningCount, ltvTotal };
    }, [guests]);

    return (
        <div className="min-h-screen space-y-8 pb-20">
            <div className="flex items-start justify-between">
                <div>
                    <h1 className="mb-2 text-4xl font-bold tracking-tight text-black">
                        {copy.guests.title}
                    </h1>
                    <p className="font-medium text-gray-500">{copy.guests.subtitle}</p>
                </div>
            </div>

            <div className="grid grid-cols-1 gap-5 md:grid-cols-2 xl:grid-cols-4">
                <MetricCard
                    icon={Users}
                    chip="TOTAL"
                    value={stats.totalGuests}
                    label="Guests in segment"
                    subLabel="Total customer profiles"
                    tone="blue"
                    progress={Math.min(20, Math.max(1, Math.round((stats.totalGuests / 100) * 20)))}
                    targetLabel="Target: 100"
                    currentLabel={`Current: ${stats.totalGuests}`}
                />
                <MetricCard
                    icon={Crown}
                    chip="VIP"
                    value={stats.vipCount}
                    label="VIP guests"
                    subLabel="High value customers"
                    tone="purple"
                    progress={Math.min(
                        20,
                        Math.max(1, Math.round((stats.vipCount / (stats.totalGuests || 1)) * 20))
                    )}
                    targetLabel={`Target: ${Math.round(stats.totalGuests * 0.2)}`}
                    currentLabel={`Current: ${stats.vipCount}`}
                />
                <MetricCard
                    icon={Repeat}
                    chip="RETURNING"
                    value={stats.returningCount}
                    label="Repeat guests"
                    subLabel="Loyal customers"
                    tone="rose"
                    progress={Math.min(
                        20,
                        Math.max(
                            1,
                            Math.round((stats.returningCount / (stats.totalGuests || 1)) * 20)
                        )
                    )}
                    targetLabel={`Target: ${Math.round(stats.totalGuests * 0.4)}`}
                    currentLabel={`Current: ${stats.returningCount}`}
                />
                <MetricCard
                    icon={Wallet}
                    chip="LTV"
                    value={formatETBCurrency(stats.ltvTotal, {
                        locale,
                        compact: true,
                    })}
                    label="Lifetime value"
                    subLabel="Total spend"
                    tone="green"
                    progress={20}
                    targetLabel="Target: -"
                    currentLabel="Lifetime"
                />
            </div>

            <section className="space-y-6">
                <div className="flex flex-col gap-4">
                    <div>
                        <h2 className="text-2xl font-bold tracking-tight text-black">
                            Growth operations
                        </h2>
                        <p className="text-sm font-medium text-gray-500">
                            Manage loyalty, gift cards, and marketing campaigns.
                        </p>
                    </div>

                    <div className="flex w-fit items-center gap-1 rounded-xl bg-gray-100/50 p-1">
                        {[
                            { id: 'loyalty', label: 'Loyalty program', icon: Crown },
                            { id: 'campaigns', label: 'Campaigns', icon: Repeat },
                        ].map(tab => (
                            <button
                                key={tab.id}
                                onClick={() => setActiveGrowthTab(tab.id as any)}
                                className={cn(
                                    'flex items-center gap-2 rounded-xl px-4 py-2 text-sm font-bold transition-all',
                                    activeGrowthTab === tab.id
                                        ? 'bg-white text-gray-900 shadow-sm'
                                        : 'text-gray-500 hover:bg-white/50 hover:text-gray-700'
                                )}
                            >
                                <tab.icon className="h-4 w-4" />
                                {tab.label}
                            </button>
                        ))}
                    </div>
                </div>

                {growthError ? (
                    <p role="alert" className="text-sm font-semibold text-amber-700">
                        {growthError}
                    </p>
                ) : null}

                <div className="min-h-[400px]">
                    {activeGrowthTab === 'loyalty' && (
                        <LoyaltyProgramBuilder
                            programs={loyaltyPrograms}
                            loading={growthLoading}
                            creating={creatingLoyalty}
                            onCreate={handleCreateLoyaltyProgram}
                            onDelete={handleDeleteLoyalty}
                            onStatusChange={handleStatusChangeLoyalty}
                            onEdit={id => handleEdit('loyalty', id)}
                            locale={locale}
                        />
                    )}
                    {activeGrowthTab === 'campaigns' && (
                        <CampaignBuilder
                            campaigns={campaigns}
                            segments={segments}
                            loading={growthLoading}
                            creating={creatingCampaign}
                            launchingId={launchingCampaignId}
                            onCreate={handleCreateCampaign}
                            onLaunch={handleLaunchCampaign}
                            onDelete={handleDeleteCampaign}
                            onEdit={id => handleEdit('campaign', id)}
                        />
                    )}
                </div>
            </section>

            <GuestDirectory
                guests={guests}
                loading={loading}
                error={error}
                query={query}
                onQueryChange={setQuery}
                segment={segment}
                onSegmentChange={setSegment}
                tagFilter={tagFilter}
                onTagFilterChange={setTagFilter}
                onOpenGuest={openGuest}
            />

            <GuestProfileDrawer
                open={selectedGuestId !== null}
                guest={selectedGuest}
                visits={guestVisits}
                loading={drawerLoading}
                saving={drawerSaving}
                onClose={closeDrawer}
                onSave={handleGuestSave}
            />
        </div>
    );
}

'use client';

import { useMemo, useState } from 'react';
import {
    Star,
    Loader2,
    Plus,
    Crown,
    Edit2,
    Pause,
    Play,
    Trash2,
    Repeat,
    Power,
    PlayCircle,
    PauseCircle,
} from 'lucide-react';
import { formatLocalizedDate } from '@/lib/format/et';
import type { AppLocale } from '@/lib/i18n/locale';
import { cn } from '@/lib/utils';

export type LoyaltyProgramRow = {
    id: string;
    name: string;
    status: 'draft' | 'active' | 'paused' | 'archived';
    created_at: string;
    points_rule_json?: {
        points_per_currency_unit: number;
        currency_unit: number;
    };
};

interface LoyaltyProgramBuilderProps {
    programs: LoyaltyProgramRow[];
    loading: boolean;
    creating: boolean;
    locale: AppLocale;
    onCreate: (payload: {
        name: string;
        status: LoyaltyProgramRow['status'];
        points_rule_json?: Record<string, unknown>;
    }) => Promise<void>;
    onStatusChange?: (id: string, status: LoyaltyProgramRow['status']) => Promise<void>;
    onDelete?: (id: string) => Promise<void>;
    onEdit?: (id: string) => void;
}

export function LoyaltyProgramBuilder({
    programs,
    loading,
    creating: isOperationLoading,
    locale,
    onCreate,
    onStatusChange,
    onDelete,
    onEdit,
}: LoyaltyProgramBuilderProps) {
    const [name, setName] = useState('');
    const [status, setStatus] = useState<LoyaltyProgramRow['status']>('draft');
    const [spendAmount, setSpendAmount] = useState('100');
    const [earnPoints, setEarnPoints] = useState('10');
    const [editingId, setEditingId] = useState<string | null>(null);

    const activeCount = useMemo(
        () => programs.filter(program => program.status === 'active').length,
        [programs]
    );

    const handleEditInternal = (id: string) => {
        const program = programs.find(p => p.id === id);
        if (!program) return;

        setEditingId(id);
        setName(program.name);
        setStatus(program.status);
        setSpendAmount(program.points_rule_json?.currency_unit?.toString() ?? '100');
        setEarnPoints(program.points_rule_json?.points_per_currency_unit?.toString() ?? '10');

        // Scroll to form on mobile or for focus
        window.scrollTo({ top: 0, behavior: 'smooth' });
    };

    const cancelEdit = () => {
        setEditingId(null);
        setName('');
        setStatus('draft');
        setSpendAmount('100');
        setEarnPoints('10');
    };

    const submit = async () => {
        const trimmed = name.trim();
        if (trimmed.length < 2) return;

        const spend = Number(spendAmount);
        const earn = Number(earnPoints);
        if (!Number.isFinite(spend) || spend <= 0) return;
        if (!Number.isFinite(earn) || earn < 0) return;

        await onCreate({
            ...(editingId ? { id: editingId } : {}), // Add ID if updating
            name: trimmed,
            status,
            points_rule_json: {
                points_per_currency_unit: earn,
                currency_unit: spend,
            },
        } as any);

        if (editingId) {
            setEditingId(null);
        }
        setName('');
        setStatus('draft');
        setSpendAmount('100');
        setEarnPoints('10');
    };

    return (
        <div className="grid min-h-[500px] grid-cols-1 gap-6 lg:grid-cols-12">
            {/* Left: Creation/Edit Form */}
            <div className="flex flex-col rounded-2xl bg-white p-6 shadow-xl shadow-gray-200/50 lg:col-span-4">
                <div className="mb-6 flex items-center justify-between">
                    <div>
                        <h3 className="text-xl leading-tight font-bold text-gray-900">
                            {editingId ? 'Edit program' : 'Create program'}
                        </h3>
                        <p className="mt-1 text-sm font-medium text-gray-500">
                            {editingId
                                ? 'Modify your existing loyalty rule.'
                                : 'Configure a new loyalty rule for your guests.'}
                        </p>
                    </div>
                    {editingId && (
                        <button
                            onClick={cancelEdit}
                            className="text-xs font-bold text-gray-400 underline underline-offset-4 transition-all hover:text-gray-900"
                        >
                            Cancel
                        </button>
                    )}
                </div>

                <div className="flex-1 space-y-5 rounded-4xl border border-gray-100 bg-gray-50/40 p-5">
                    <div className="space-y-1.5">
                        <label className="ml-1 text-xs font-bold tracking-tight text-gray-400">
                            Program name
                        </label>
                        <input
                            value={name}
                            onChange={event => setName(event.target.value)}
                            placeholder="e.g. VIP Rewards"
                            className="h-12 w-full rounded-xl border border-gray-200 bg-white px-4 text-sm font-semibold transition-all outline-none placeholder:text-gray-300 focus:border-gray-400 focus:ring-4 focus:ring-gray-100/50"
                        />
                    </div>

                    <div className="space-y-1.5">
                        <label className="ml-1 text-xs font-bold tracking-tight text-gray-400">
                            Points calculation
                        </label>
                        <div className="mt-3 flex items-center gap-3">
                            <div className="relative flex-1">
                                <input
                                    value={spendAmount}
                                    onChange={event => setSpendAmount(event.target.value)}
                                    className="h-12 w-full rounded-xl border border-gray-200 bg-white px-4 text-center text-sm font-bold transition-all outline-none focus:border-gray-400"
                                />
                                <div className="absolute -top-2 left-4 bg-gray-50 px-1.5 text-[9px] font-bold tracking-wider text-gray-400 uppercase">
                                    Spend (ETB)
                                </div>
                            </div>
                            <div className="shrink-0 text-gray-300">
                                <Plus className="h-4 w-4 rotate-45" />
                            </div>
                            <div className="relative flex-1">
                                <input
                                    value={earnPoints}
                                    onChange={event => setEarnPoints(event.target.value)}
                                    className="h-12 w-full rounded-xl border border-gray-200 bg-white px-4 text-center text-sm font-bold text-emerald-600 transition-all outline-none focus:border-emerald-400"
                                />
                                <div className="absolute -top-2 left-4 bg-gray-50 px-1.5 text-[9px] font-bold tracking-wider text-gray-400 uppercase">
                                    Earn (Pts)
                                </div>
                            </div>
                        </div>
                        <p className="text-center text-[10px] font-medium text-gray-400">
                            Guest spends{' '}
                            <span className="font-bold text-gray-900">{spendAmount} ETB</span> and
                            earns{' '}
                            <span className="font-bold text-emerald-600">{earnPoints} pts</span>.
                        </p>
                    </div>

                    <div className="space-y-1.5">
                        <label className="ml-1 text-xs font-bold tracking-tight text-gray-400">
                            Status
                        </label>
                        <select
                            value={status}
                            onChange={event =>
                                setStatus(event.target.value as LoyaltyProgramRow['status'])
                            }
                            className="h-12 w-full cursor-pointer appearance-none rounded-xl border border-gray-200 bg-white px-4 text-sm font-bold transition-all outline-none focus:border-gray-400"
                        >
                            <option value="draft">Draft</option>
                            <option value="active">Active (Live)</option>
                            {editingId && <option value="paused">Paused</option>}
                        </select>
                    </div>

                    <div className="mt-auto">
                        <button
                            type="button"
                            onClick={submit}
                            disabled={isOperationLoading || name.trim().length < 2}
                            className={cn(
                                'flex h-12 w-full items-center justify-center gap-2 rounded-xl text-sm font-bold text-black shadow-xl transition-all active:scale-[0.98] disabled:opacity-50',
                                editingId
                                    ? 'bg-gray-900 shadow-gray-900/10'
                                    : 'bg-brand-accent shadow-crimson-900/10'
                            )}
                        >
                            {isOperationLoading ? (
                                <Loader2 className="h-5 w-5 animate-spin text-white/70" />
                            ) : editingId ? (
                                <Edit2 className="h-5 w-5" />
                            ) : (
                                <Plus className="h-5 w-5" />
                            )}
                            {editingId ? 'Update program' : 'Create program'}
                        </button>
                        <p className="mt-3 text-center text-[11px] font-medium text-gray-400">
                            {editingId
                                ? 'Changes take effect immediately for all guests.'
                                : 'Programs can be modified or paused later.'}
                        </p>
                    </div>
                </div>
            </div>

            {/* Right: Management List */}
            <div className="flex flex-col overflow-hidden rounded-2xl bg-white p-6 shadow-xl shadow-gray-200/50 lg:col-span-8">
                <div className="mb-6 flex items-center justify-between">
                    <div>
                        <h3 className="text-xl leading-tight font-bold text-gray-900">
                            Active programs
                        </h3>
                        <p className="mt-1 text-sm font-medium text-gray-500">
                            Currently running {activeCount} active loyalty campaigns.
                        </p>
                    </div>
                    {activeCount > 0 && (
                        <div className="flex items-center gap-1.5 rounded-full border border-emerald-100 bg-emerald-50 px-3 py-1 text-[10px] font-bold text-emerald-700">
                            <div className="h-1.5 w-1.5 animate-pulse rounded-full bg-emerald-500" />
                            {activeCount} active
                        </div>
                    )}
                </div>

                <div className="flex-1 overflow-hidden">
                    {loading ? (
                        <div className="space-y-3">
                            {[1, 2, 3, 4].map(i => (
                                <div
                                    key={i}
                                    className="h-16 w-full animate-pulse rounded-xl bg-gray-50"
                                />
                            ))}
                        </div>
                    ) : programs.length === 0 ? (
                        <div className="flex h-full flex-col items-center justify-center rounded-4xl border border-dashed border-gray-200 bg-gray-50/30 py-20">
                            <div className="mb-3 flex h-12 w-12 items-center justify-center rounded-xl bg-gray-100">
                                <Crown className="h-6 w-6 text-gray-300" />
                            </div>
                            <p className="text-sm font-bold text-gray-500">No programs yet</p>
                            <p className="mt-1 text-xs font-medium text-gray-400">
                                Start by creating your first loyalty program.
                            </p>
                        </div>
                    ) : (
                        <div className="no-scrollbar h-[400px] space-y-3 overflow-y-auto pr-2 pb-4">
                            {programs.map(program => {
                                const pts = program.points_rule_json?.points_per_currency_unit ?? 1;
                                const cur = program.points_rule_json?.currency_unit ?? 1;
                                return (
                                    <div
                                        key={program.id}
                                        className="group flex items-center justify-between rounded-xl border-none bg-white p-4 shadow-sm transition-all hover:shadow-md"
                                    >
                                        <div className="flex items-center gap-4">
                                            <div
                                                className={cn(
                                                    'rounded-1.5xl flex h-11 w-11 items-center justify-center shadow-sm transition-all',
                                                    program.status === 'active'
                                                        ? 'bg-emerald-50 text-emerald-600'
                                                        : 'bg-gray-100 text-gray-400'
                                                )}
                                            >
                                                <Crown className="h-5 w-5" />
                                            </div>
                                            <div>
                                                <p className="text-md leading-tight font-bold text-gray-900">
                                                    {program.name}
                                                </p>
                                                <div className="mt-1 flex items-center gap-2">
                                                    <p className="text-xs font-medium text-gray-400">
                                                        Created{' '}
                                                        {formatLocalizedDate(
                                                            program.created_at,
                                                            locale
                                                        )}
                                                    </p>
                                                    <div className="h-1 w-1 rounded-full bg-gray-200" />
                                                    <p className="text-xs font-bold text-gray-500">
                                                        {pts} pts / {cur} ETB
                                                    </p>
                                                </div>
                                            </div>
                                        </div>
                                        <div className="flex items-center gap-3">
                                            <span
                                                className={cn(
                                                    'rounded-xl border px-2.5 py-1 text-[10px] font-bold capitalize transition-all',
                                                    program.status === 'active'
                                                        ? 'border-emerald-100 bg-emerald-50 text-emerald-700'
                                                        : program.status === 'paused'
                                                          ? 'border-amber-100 bg-amber-50 text-amber-700'
                                                          : 'border-gray-200 bg-gray-100 text-gray-600'
                                                )}
                                            >
                                                {program.status}
                                            </span>

                                            <div className="ml-4 flex items-center gap-1">
                                                <button
                                                    onClick={() => handleEditInternal(program.id)}
                                                    className="flex h-9 w-9 items-center justify-center rounded-xl bg-gray-50 text-gray-400 shadow-sm transition-all hover:bg-gray-100 hover:text-gray-900 active:scale-[0.92] active:bg-gray-200"
                                                    title="Edit program"
                                                >
                                                    <Edit2 className="h-4 w-4" />
                                                </button>
                                                {onStatusChange && (
                                                    <button
                                                        onClick={() =>
                                                            void onStatusChange(
                                                                program.id,
                                                                program.status === 'active'
                                                                    ? 'paused'
                                                                    : 'active'
                                                            )
                                                        }
                                                        className="flex h-9 w-9 items-center justify-center rounded-xl bg-gray-50 text-gray-400 shadow-sm transition-all hover:bg-gray-100 hover:text-gray-900 active:scale-[0.92] active:bg-gray-200"
                                                        title={
                                                            program.status === 'active'
                                                                ? 'Pause program'
                                                                : 'Activate program'
                                                        }
                                                    >
                                                        {program.status === 'active' ? (
                                                            <Pause className="h-4 w-4" />
                                                        ) : (
                                                            <Play className="h-4 w-4" />
                                                        )}
                                                    </button>
                                                )}
                                                {onDelete && (
                                                    <button
                                                        onClick={() => void onDelete(program.id)}
                                                        className="flex h-9 w-9 items-center justify-center rounded-xl bg-gray-50 text-gray-400 shadow-sm transition-all hover:bg-red-50 hover:text-red-600 active:scale-[0.92] active:bg-red-100"
                                                        title="Delete program"
                                                    >
                                                        <Trash2 className="h-4 w-4" />
                                                    </button>
                                                )}
                                            </div>
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}

