    CategoryWithItems,
    MenuItemSummary,
} from '@/lib/services/dashboardDataService';

interface MenuPageClientProps {
    initialData: MenuPageData | null;
}

type MenuDiffEntry = {
    label: string;
    type: 'category' | 'item';
};

type ComparableMenuItem = {
    id: string;
    category_id: string;
    name: string;
    price: number | null;
    description: string | null;
    is_available: boolean | null;
};

type ComparableCategory = {
    id: string;
    name: string;
    order_index: number | null;
    items: ComparableMenuItem[];
};

const buildComparableSnapshot = (
    input: CategoryWithItems[] | null | undefined
): ComparableCategory[] => {
    if (!Array.isArray(input)) return [];
    return input.map(category => ({
        id: category.id,
        name: category.name,
        order_index: category.order_index ?? 0,
        items: (category.items ?? []).map(item => ({
            id: item.id,
            category_id: item.category_id,
            name: item.name,
            price: Number(item.price ?? 0),
            description: item.description ?? null,
            is_available: item.is_available ?? true,
        })),
    }));
};

const toSnapshotString = (input: CategoryWithItems[]) =>
    JSON.stringify(buildComparableSnapshot(input));

const computeMenuDiff = (
    baseline: ComparableCategory[],
    current: ComparableCategory[]
): MenuDiffEntry[] => {
    const entries: MenuDiffEntry[] = [];

    const baselineCategories = new Map(baseline.map(category => [category.id, category]));
    const currentCategories = new Map(current.map(category => [category.id, category]));

    for (const category of current) {
        const previous = baselineCategories.get(category.id);
        if (!previous) {
            entries.push({ label: `Added category: ${category.name}`, type: 'category' });
            continue;
        }
        if (
            (previous.name ?? '') !== (category.name ?? '') ||
            (previous.order_index ?? 0) !== (category.order_index ?? 0)
        ) {
            entries.push({ label: `Updated category: ${category.name}`, type: 'category' });
        }
    }

    for (const category of baseline) {
        if (!currentCategories.has(category.id)) {
            entries.push({ label: `Removed category: ${category.name}`, type: 'category' });
        }
    }

    const baselineItems = new Map(
        (baseline ?? []).flatMap(category =>
            (category.items ?? []).map(item => [item.id, item] as const)
        )
    );
    const currentItems = new Map(
        (current ?? []).flatMap(category =>
            (category.items ?? []).map(item => [item.id, item] as const)
        )
    );

    for (const item of currentItems.values()) {
        const previous = baselineItems.get(item.id);
        if (!previous) {
            entries.push({ label: `Added item: ${item.name}`, type: 'item' });
            continue;
        }
        const changed =
            (previous.name ?? '') !== (item.name ?? '') ||
            Number(previous.price ?? 0) !== Number(item.price ?? 0) ||
            (previous.description ?? '') !== (item.description ?? '') ||
            (previous.is_available ?? true) !== (item.is_available ?? true);
        if (changed) {
            entries.push({ label: `Updated item: ${item.name}`, type: 'item' });
        }
    }

    for (const item of baselineItems.values()) {
        if (!currentItems.has(item.id)) {
            entries.push({ label: `Removed item: ${item.name}`, type: 'item' });
        }
    }

    return entries;
};

export function MenuPageClient({ initialData }: MenuPageClientProps) {
    const supabase = createClient();
    const { loading, markLoaded } = usePageLoadGuard('menu');

    const [categories, setCategories] = useState<CategoryWithItems[]>(
        initialData?.categories ?? []
    );
    const [selectedCategoryId, setSelectedCategoryId] = useState<string | null>(null);
    const [editingItem, setEditingItem] = useState<MenuItemSummary | null>(null);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [isCategoryModalOpen, setIsCategoryModalOpen] = useState(false);
    const [categoryMode, setCategoryMode] = useState<'create' | 'edit'>('create');
    const [categoryName, setCategoryName] = useState('');
    const [categoryNameError, setCategoryNameError] = useState<string | null>(null);
    const [categorySubmitting, setCategorySubmitting] = useState(false);
    const [deleteSubmitting, setDeleteSubmitting] = useState(false);
    const [categoryToDelete, setCategoryToDelete] = useState<ComparableCategory | null>(null);

    const [publishedSnapshot, setPublishedSnapshot] = useState<string | null>(null);
    const [previousPublishedSnapshot, setPreviousPublishedSnapshot] = useState<string | null>(null);
    const [hasUnsavedChanges, setHasUnsavedChanges] = useState(false);
    const [isPublishModalOpen, setIsPublishModalOpen] = useState(false);
    const [isPublishing, setIsPublishing] = useState(false);
    const [isRollbacking, setIsRollbacking] = useState(false);

    // Use effect to mark as loaded when initialData is available
    useEffect(() => {
        if (initialData) {
            markLoaded();
        }
    }, [initialData, markLoaded]);

    // Initialize published snapshot from initial data
    useEffect(() => {
        if (initialData?.categories && !publishedSnapshot) {
            const snapshot = toSnapshotString(initialData.categories);
            setPublishedSnapshot(snapshot);
        }
    }, [initialData, publishedSnapshot]);

    const fetchMenu = useCallback(async () => {
        const { data, error } = await supabase
            .from('categories')
            .select(
                `
                id,
                name,
                order_index,
                menu_items (
                    id,
                    name,
                    price,
                    description,
                    is_available,
                    category_id,
                    image_url
                )
            `
            )
            .order('order_index', { ascending: true });

        if (error) {
            console.error(error);
            toast.error('Failed to load menu.');
            return [];
        }

        // Filter out categories with no items if needed, and format items
        const formatted = (data ?? []).map((cat: any) => ({
            id: cat.id,
            name: cat.name,
            order_index: cat.order_index ?? 0,
            items: (cat.menu_items ?? cat.items ?? []).map((item: any) => ({
                id: item.id,
                name: item.name,
                price: item.price,
                description: item.description,
                is_available: item.is_available ?? true,
                category_id: item.category_id,
                image_url: item.image_url,
            })),
        }));

        setCategories(formatted);
        return formatted;
    }, [supabase]);

    useEffect(() => {
        if (!initialData?.categories) {
            fetchMenu();
        }
    }, [initialData, fetchMenu]);

    // Detect unsaved changes
    useEffect(() => {
        if (!publishedSnapshot) return;
        const currentSnapshot = toSnapshotString(categories);
        setHasUnsavedChanges(currentSnapshot !== publishedSnapshot);
    }, [categories, publishedSnapshot]);

    const getSnapshotData = (snapshot: string | null): CategoryWithItems[] => {
        if (!snapshot) return [];
        try {
            const parsed = JSON.parse(snapshot);
            return Array.isArray(parsed) ? parsed : [];
        } catch (e) {
            console.error('Failed to parse menu snapshot:', e);
            return [];
        }
    };

    const diffEntries = computeMenuDiff(
        buildComparableSnapshot(getSnapshotData(publishedSnapshot)),
        buildComparableSnapshot(categories)
    );

    const handleInlineItemSave = async (itemId: string, updates: InlineMenuItemPatch) => {
        setCategories(prev =>
            (prev ?? []).map(cat => ({
                ...cat,
                items: (cat.items ?? []).map(item =>
                    item.id === itemId ? { ...item, ...updates } : item
                ),
            }))
        );

        const { error } = await supabase.from('menu_items').update(updates).eq('id', itemId);

        if (error) {
            console.error(error);
            toast.error('Failed to save item.');
            await fetchMenu();
        }
    };

    const handleBulkAvailabilityUpdate = async (itemIds: string[], isAvailable: boolean) => {
        const previousCategories = [...categories];
        setCategories(prev =>
            (prev ?? []).map(cat => ({
                ...cat,
                items: (cat.items ?? []).map(item =>
                    itemIds.includes(item.id) ? { ...item, is_available: isAvailable } : item
                ),
            }))
        );

        const { error } = await supabase
            .from('menu_items')
            .update({ is_available: isAvailable })
            .in('id', itemIds);

        if (error) {
            console.error(error);
            toast.error('Failed to update items.');
            setCategories(previousCategories);
        } else {
            toast.success(`Updated ${itemIds.length} items.`);
        }
    };

    const handleBulkPriceUpdate = async (updates: BulkPriceUpdate[]) => {
        const previousCategories = [...categories];

        setCategories(prev =>
            (prev ?? []).map(cat => ({
                ...cat,
                items: (cat.items ?? []).map(item => {
                    const update = updates.find(u => u.id === item.id);
                    return update ? { ...item, price: update.price } : item;
                }),
            }))
        );

        const updatesToApply = updates.map(update => ({
            id: update.id,
            price: update.price,
        }));

        const { error } = await supabase.from('menu_items').upsert(
            updatesToApply.map(update => ({
                id: update.id,
                price: update.price,
            })),
            { onConflict: 'id' }
        );

        if (error) {
            console.error(error);
            toast.error('Failed to update prices.');
            setCategories(previousCategories);
        } else {
            toast.success(`Updated prices for ${updates.length} items.`);
        }
    };

    const handleMoveCategory = async (categoryId: string, direction: 'up' | 'down') => {
        const currentIndex = categories.findIndex(c => c.id === categoryId);
        if (currentIndex === -1) return;

        const newIndex = direction === 'up' ? currentIndex - 1 : currentIndex + 1;
        if (newIndex < 0 || newIndex >= categories.length) return;

        const newCategories = [...categories];
        [newCategories[currentIndex], newCategories[newIndex]] = [
            newCategories[newIndex],
            newCategories[currentIndex],
        ];

        setCategories(newCategories);
    };

    const openCreateCategoryModal = () => {
        setCategoryMode('create');
        setCategoryName('');
        setCategoryNameError(null);
        setIsCategoryModalOpen(true);
    };

    const openEditCategoryModal = (category: ComparableCategory) => {
        setCategoryMode('edit');
        setCategoryName(category.name);
        setCategoryNameError(null);
        setSelectedCategoryId(category.id);
        setIsCategoryModalOpen(true);
    };

    const closeCategoryModal = () => {
        setIsCategoryModalOpen(false);
        setCategoryName('');
        setCategoryNameError(null);
        setSelectedCategoryId(null);
    };

    const handleCategorySubmit = async (e: React.FormEvent) => {
        e.preventDefault();

        if (!categoryName.trim()) {
            setCategoryNameError('Category name is required.');
            return;
        }

        setCategorySubmitting(true);

        try {
            if (categoryMode === 'create') {
                const { error } = await supabase
                    .from('categories')
                    .insert({ name: categoryName, restaurant_id: initialData?.restaurant_id });

                if (error) throw error;
                toast.success('Category created.');
            } else {
                const { error } = await supabase
                    .from('categories')
                    .update({ name: categoryName })
                    .eq('id', selectedCategoryId);

                if (error) throw error;
                toast.success('Category updated.');
            }

            closeCategoryModal();
            await fetchMenu();
        } catch (error) {
            console.error(error);
            toast.error(`Failed to ${categoryMode} category.`);
        } finally {
            setCategorySubmitting(false);
        }
    };

    const handleDeleteCategory = async () => {
        if (!categoryToDelete) return;

        setDeleteSubmitting(true);

        try {
            // Delete all items in the category first
            const { error: itemsError } = await supabase
                .from('menu_items')
                .delete()
                .eq('category_id', categoryToDelete.id);

            if (itemsError) throw itemsError;

            // Then delete the category
            const { error: categoryError } = await supabase
                .from('categories')
                .delete()
                .eq('id', categoryToDelete.id);

            if (categoryError) throw categoryError;

            toast.success('Category deleted.');
            setCategoryToDelete(null);
            await fetchMenu();
        } catch (error) {
            console.error(error);
            toast.error('Failed to delete category.');
        } finally {
            setDeleteSubmitting(false);
        }
    };

    const handlePublishMenu = async () => {
        setIsPublishing(true);

        try {
            // Save current state as published
            const currentSnapshot = toSnapshotString(categories);
            setPreviousPublishedSnapshot(publishedSnapshot);
            setPublishedSnapshot(currentSnapshot);
            setHasUnsavedChanges(false);
            setIsPublishModalOpen(false);
            toast.success('Menu published.');
        } catch (error) {
            console.error(error);
            toast.error('Failed to publish menu.');
        } finally {
            setIsPublishing(false);
        }
    };

    const handleRollbackLatestPublish = async () => {
        if (!previousPublishedSnapshot) return;

        setIsRollbacking(true);

        try {
            // Restore to previous published state
            const previousPublished = getSnapshotData(previousPublishedSnapshot);
            if (previousPublished.length === 0) {
                throw new Error('Invalid or empty rollback snapshot.');
            }

            setCategories(previousPublished);

            // Update database to match
            await Promise.all(
                previousPublished.map(async (category, index) => {
                    await supabase
                        .from('categories')
                        .update({
                            name: category.name,
                            order_index: index,
                        })
                        .eq('id', category.id);

                    await Promise.all(
                        (category.items ?? []).map(async item => {
                            await supabase
                                .from('menu_items')
                                .update({
                                    name: item.name,
                                    price: item.price,
                                    description: item.description,
                                    is_available: item.is_available,
                                    category_id: item.category_id,
                                })
                                .eq('id', item.id);
                        })
                    );
                })
            );

            setPublishedSnapshot(previousPublishedSnapshot);
            setPreviousPublishedSnapshot(null);
            await fetchMenu();
            toast.success('Rolled back to previous published menu.');
        } catch (error) {
            console.error(error);
            toast.error('Rollback failed. Please try again.');
        } finally {
            setIsRollbacking(false);
        }
    };

    useEffect(() => {
        if (!hasUnsavedChanges) return;

        const handler = (event: BeforeUnloadEvent) => {
            event.preventDefault();
            event.returnValue = '';
        };

        window.addEventListener('beforeunload', handler);
        return () => window.removeEventListener('beforeunload', handler);
    }, [hasUnsavedChanges]);

    if (loading) {
        return (
            <div className="min-h-screen space-y-10 bg-white pb-20">
                <div className="flex items-start justify-between">
                    <div className="space-y-2">
                        <Skeleton className="h-10 w-32 rounded-xl" />
                        <Skeleton className="h-4 w-48 rounded-lg" />
                    </div>
                    {/* Header Actions Skeleton */}
                    <div className="flex gap-3">
                        <Skeleton className="h-12 w-24 rounded-xl" />
                        <Skeleton className="h-12 w-36 rounded-xl" />
                    </div>
                </div>
                <div className="space-y-12">
                    {[1, 2].map(category => (
                        <div key={category} className="space-y-6">
                            <div className="flex items-center justify-between pb-4">
                                <Skeleton className="h-8 w-40 rounded-lg" />
                                <div className="flex gap-2">
                                    <Skeleton className="h-9 w-9 rounded-lg" />
                                    <Skeleton className="h-9 w-9 rounded-lg" />
                                </div>
                            </div>
                            <div className="grid grid-cols-1 gap-6 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4">
                                {[1, 2, 3, 4].map(item => (
                                    <div
                                        key={item}
                                        className="flex h-72 flex-col gap-4 rounded-[2rem] bg-white p-4 shadow-sm"
                                    >
                                        <Skeleton className="h-40 w-full rounded-[1.5rem]" />
                                        <div className="space-y-2">
                                            <Skeleton className="h-5 w-3/4 rounded-lg" />
                                            <Skeleton className="h-4 w-1/2 rounded-lg" />
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        );
    }

    return (
        <div className="min-h-screen space-y-10 bg-white pb-20">
            {/* Header */}
            <div className="flex items-start justify-between">
                <div>
                    <h1 className="mb-2 text-4xl font-bold tracking-tight text-black">Menu</h1>
                    <div className="flex items-center gap-3">
                        <p className="font-medium text-gray-500">
                            Manage your categories and items.
                        </p>
                        {hasUnsavedChanges && (
                            <span className="rounded-lg bg-amber-100 px-2 py-1 text-xs font-bold tracking-wide text-amber-700 uppercase">
                                Draft Changes
                            </span>
                        )}
                    </div>
                </div>
                <div className="flex gap-3">
                    <button className="flex h-12 items-center gap-2 rounded-xl bg-white px-5 text-sm font-bold text-black shadow-sm transition-shadow hover:shadow-md">
                        Reorder
                    </button>
                    <button
                        onClick={() => setIsPublishModalOpen(true)}
                        disabled={!hasUnsavedChanges || isPublishing}
                        className="flex h-12 items-center gap-2 rounded-xl bg-emerald-600 px-5 text-sm font-bold text-white shadow-lg shadow-emerald-900/10 transition-colors hover:bg-emerald-700 disabled:opacity-50"
                    >
                        {isPublishing ? 'Publishing...' : 'Publish'}
                    </button>
                    <button
                        onClick={handleRollbackLatestPublish}
                        disabled={!previousPublishedSnapshot || isRollbacking}
                        className="flex h-12 items-center gap-2 rounded-xl bg-white px-5 text-sm font-bold text-black shadow-sm transition-shadow hover:shadow-md disabled:opacity-50"
                    >
                        {isRollbacking ? 'Rolling back...' : 'Rollback'}
                    </button>
                    <button
                        onClick={openCreateCategoryModal}
                        className="bg-brand-accent flex h-12 items-center gap-2 rounded-xl px-5 text-sm font-bold text-black shadow-lg shadow-black/10 transition-colors hover:brightness-105"
                    >
                        <Plus className="h-4 w-4" />
                        Add Category
                    </button>
                </div>
            </div>

            {/* Menu List */}
            <div className="space-y-12">
                {categories.map(category => (
                    <div key={category.id} className="space-y-6">
                        {/* Category Header */}
                        <div className="flex items-center justify-between pb-4">
                            <div className="flex items-baseline gap-4">
                                <h2 className="text-2xl font-bold tracking-tight text-gray-900">
                                    {category.name}
                                </h2>
                                <span className="rounded-full bg-gray-50 px-3 py-1 text-sm font-bold text-gray-400">
                                    {(category.items ?? []).length} items
                                </span>
                            </div>
                            <div className="flex gap-2">
                                <button
                                    onClick={() => handleMoveCategory(category.id, 'up')}
                                    disabled={categories[0]?.id === category.id}
                                    className="flex h-9 w-9 items-center justify-center rounded-lg text-gray-400 transition-all hover:bg-gray-50 hover:text-black disabled:opacity-40"
                                    aria-label={`Move ${category.name} up`}
                                >
                                    <ArrowUp className="h-4 w-4" />
                                </button>
                                <button
                                    onClick={() => handleMoveCategory(category.id, 'down')}
                                    disabled={categories[categories.length - 1]?.id === category.id}
                                    className="flex h-9 w-9 items-center justify-center rounded-lg text-gray-400 transition-all hover:bg-gray-50 hover:text-black disabled:opacity-40"
                                    aria-label={`Move ${category.name} down`}
                                >
                                    <ArrowDown className="h-4 w-4" />
                                </button>
                                <button
                                    onClick={() => openEditCategoryModal(category)}
                                    className="flex h-9 w-9 items-center justify-center rounded-lg text-gray-400 transition-all hover:bg-gray-50 hover:text-black"
                                    aria-label={`Edit ${category.name}`}
                                >
                                    <Edit2 className="h-4 w-4" />
                                </button>
                                <button
                                    onClick={() => setCategoryToDelete(category)}
                                    className="flex h-9 w-9 items-center justify-center rounded-lg text-gray-400 transition-all hover:bg-red-50 hover:text-red-500"
                                    aria-label={`Delete ${category.name}`}
                                >
                                    <Trash2 className="h-4 w-4" />
                                </button>
                            </div>
                        </div>

                        {/* Items Grid */}
                        <MenuGridEditor
                            category={category}
                            readOnly={false}
                            onAddItem={selected => {
                                setSelectedCategoryId(selected.id);
                                setEditingItem(null);
                                setIsModalOpen(true);
                            }}
                            onOpenAdvancedEdit={(selected, item) => {
                                setSelectedCategoryId(selected.id);
                                setEditingItem(item);
                                setIsModalOpen(true);
                            }}
                            onSaveInline={(item, patch) => handleInlineItemSave(item.id, patch)}
                            onBulkAvailabilityUpdate={handleBulkAvailabilityUpdate}
                            onBulkPriceUpdate={handleBulkPriceUpdate}
                        />
                    </div>
                ))}

                {categories.length === 0 && !loading && (
                    <div className="flex flex-col items-center justify-center rounded-[2.5rem] bg-gray-50 py-20 text-center shadow-inner">
                        <div className="mb-6 flex h-20 w-20 items-center justify-center rounded-full bg-white shadow-sm">
                            <UtensilsCrossed className="h-8 w-8 text-gray-400" />
                        </div>
                        <h3 className="mb-2 text-xl font-bold text-gray-900">No categories yet</h3>
                        <p className="mb-8 max-w-sm font-medium text-gray-500">
                            Start building your menu by adding your first category.
                        </p>
                        <button
                            onClick={openCreateCategoryModal}
                            className="bg-brand-accent h-12 rounded-xl px-8 font-bold text-black shadow-lg shadow-black/10 transition-colors hover:brightness-105"
                        >
                            Create Category
                        </button>
                    </div>
                )}
            </div>

            <MenuItemModal
                isOpen={isModalOpen}
                onClose={() => {
                    setIsModalOpen(false);
                    setEditingItem(null);
                    setSelectedCategoryId(null);
                }}
                category={selectedCategoryId}
                categoryName={categories.find(c => c.id === selectedCategoryId)?.name}
                itemToEdit={editingItem}
                onSuccess={() => {
                    fetchMenu();
                    setIsModalOpen(false);
                }}
            />

            {isCategoryModalOpen && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 p-4 backdrop-blur-sm">
                    <div className="w-full max-w-md rounded-2xl bg-white p-6 shadow-xl">
                        <h3 className="text-xl font-bold text-gray-900">
                            {categoryMode === 'edit' ? 'Edit category' : 'Create category'}
                        </h3>
                        <p className="mt-1 text-sm text-gray-500">
                            {categoryMode === 'edit'
                                ? 'Update the category name.'
                                : 'Add a new menu category for your items.'}
                        </p>

                        <form onSubmit={handleCategorySubmit} className="mt-6 space-y-4">
                            <div className="space-y-2">
                                <label
                                    htmlFor="category-name"
                                    className="text-sm font-medium text-gray-700"
                                >
                                    Category name
                                </label>
                                <input
                                    id="category-name"
                                    value={categoryName}
                                    onChange={event => {
                                        setCategoryName(event.target.value);
                                        if (categoryNameError) setCategoryNameError(null);
                                    }}
                                    placeholder="e.g. Starters"
                                    className="w-full rounded-xl border border-gray-200 px-3 py-2 text-sm outline-none focus:border-gray-400"
                                    maxLength={100}
                                    disabled={categorySubmitting}
                                    autoFocus
                                />
                                {categoryNameError && (
                                    <p className="text-xs text-red-600">{categoryNameError}</p>
                                )}
                            </div>

                            <div className="flex items-center justify-end gap-3 pt-2">
                                <button
                                    type="button"
                                    onClick={() => closeCategoryModal()}
                                    disabled={categorySubmitting}
                                    className="h-10 rounded-xl bg-white px-4 text-sm font-semibold text-gray-700 shadow-sm transition-shadow hover:shadow-md disabled:opacity-50"
                                >
                                    Cancel
                                </button>
                                <button
                                    type="submit"
                                    disabled={categorySubmitting}
                                    className="bg-brand-accent inline-flex h-10 min-w-28 items-center justify-center gap-2 rounded-xl px-4 text-sm font-semibold text-black hover:brightness-105 disabled:opacity-50"
                                >
                                    {categorySubmitting && (
                                        <Loader2 className="h-4 w-4 animate-spin" />
                                    )}
                                    {categoryMode === 'edit' ? 'Save' : 'Create'}
                                </button>
                            </div>
                        </form>
                    </div>
                </div>
            )}

            {categoryToDelete && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 p-4 backdrop-blur-sm">
                    <div className="w-full max-w-md rounded-2xl bg-white p-6 shadow-xl">
                        <h3 className="text-xl font-bold text-gray-900">Delete category</h3>
                        <p className="mt-2 text-sm text-gray-600">
                            Delete{' '}
                            <span className="font-semibold text-gray-900">
                                {categoryToDelete.name}
                            </span>{' '}
                            and its{' '}
                            <span className="font-semibold text-gray-900">
                                {(categoryToDelete.items ?? []).length}
                            </span>{' '}
                            item(s)?
                        </p>
                        <p className="mt-1 text-sm text-red-600">This action cannot be undone.</p>

                        <div className="mt-6 flex items-center justify-end gap-3">
                            <button
                                type="button"
                                onClick={() => setCategoryToDelete(null)}
                                disabled={deleteSubmitting}
                                className="h-10 rounded-xl border border-gray-200 px-4 text-sm font-semibold text-gray-700 hover:bg-gray-50 disabled:opacity-50"
                            >
                                Cancel
                            </button>
                            <button
                                type="button"
                                onClick={handleDeleteCategory}
                                disabled={deleteSubmitting}
                                className="inline-flex h-10 min-w-28 items-center justify-center gap-2 rounded-xl bg-red-600 px-4 text-sm font-semibold text-white hover:bg-red-700 disabled:opacity-50"
                            >
                                {deleteSubmitting && <Loader2 className="h-4 w-4 animate-spin" />}
                                Delete
                            </button>
                        </div>
                    </div>
                </div>
            )}

            {isPublishModalOpen && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 p-4 backdrop-blur-sm">
                    <div className="w-full max-w-xl rounded-2xl bg-white p-6 shadow-xl">
                        <h3 className="text-xl font-bold text-gray-900">Publish menu changes</h3>
                        <p className="mt-1 text-sm text-gray-600">
                            Review draft differences before publishing this menu version.
                        </p>

                        <div className="mt-4 rounded-xl border border-gray-200 p-4">
                            <p className="mb-2 text-xs font-semibold tracking-wide text-gray-500 uppercase">
                                Change preview ({diffEntries.length})
                            </p>
                            <div className="max-h-56 space-y-1 overflow-y-auto">
                                {diffEntries.length === 0 && (
                                    <p className="text-sm text-gray-500">
                                        No visible diffs detected.
                                    </p>
                                )}
                                {diffEntries.map((entry, index) => (
                                    <p
                                        key={`${entry.label}-${index}`}
                                        className="text-sm text-gray-700"
                                    >
                                        {entry.label}
                                    </p>
                                ))}
                            </div>
                        </div>

                        <div className="mt-6 flex items-center justify-end gap-3">
                            <button
                                type="button"
                                onClick={() => setIsPublishModalOpen(false)}
                                disabled={isPublishing}
                                className="h-10 rounded-xl border border-gray-200 px-4 text-sm font-semibold text-gray-700 hover:bg-gray-50 disabled:opacity-50"
                            >
                                Cancel
                            </button>
                            <button
                                type="button"
                                onClick={handlePublishMenu}
                                disabled={isPublishing || !hasUnsavedChanges}
                                className="inline-flex h-10 items-center gap-2 rounded-xl bg-emerald-600 px-4 text-sm font-semibold text-white hover:bg-emerald-700 disabled:opacity-50"
                            >
                                {isPublishing && <Loader2 className="h-4 w-4 animate-spin" />}
                                Publish
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

'use client';

/**
 * Merchant Dashboard Client Component
 *
 * This component receives initial data from a Server Component,
 * eliminating the loading flash on initial render.
 *
 * Architecture Pattern:
 * - Server Component fetches initial data (no loading state)
 * - Client Component handles interactivity (filters, refresh, realtime)
 * - Supabase Realtime merges live updates with server data
 *
 * Performance Benefits:
 * - No loading skeleton on initial page load
 * - Instant render with server-provided data
 * - Realtime updates for live metrics
 */

import { type ComponentType, useCallback, useEffect, useMemo, useState, useRef } from 'react';
import { formatETBCurrency } from '@/lib/format/et';
import {
    Bell,
    CalendarCheck,
    CheckCircle,
    ChevronDown,
    Clock,
    ListOrdered,
    MoreHorizontal,
    PauseCircle,
    PlayCircle,
    Timer,
    Users,
    UtensilsCrossed,
    Wallet,
} from 'lucide-react';

import { MetricCard } from '@/components/merchant/MetricCard';
import { RevenueChart } from '@/components/merchant/RevenueChart';

import { AlertRuleBuilderDrawer } from '@/components/merchant/command-center/AlertRuleBuilderDrawer';
import {
    AttentionItem,
    CommandCenterRange,
    CommandCenterMetrics,
} from '@/components/merchant/command-center/types';
import { isAbortError } from '@/hooks/useSafeFetch';
import { useMerchantActivity } from '@/hooks/useMerchantActivity';
import type { CommandCenterData } from '@/lib/services/dashboardDataService';

const STALE_AFTER_MS = 90_000;

const EMPTY_METRICS: CommandCenterMetrics = {
    orders_in_flight: 0,
    avg_ticket_time_minutes: 0,
    active_tables: 0,
    open_requests: 0,
    payment_success_rate: 0,
    gross_sales_today: 0,
    gross_sales_previous: 0,
    total_orders_today: 0,
    avg_order_value_etb: 0,
    unique_tables_today: 0,
};

function nextOrderStatus(status: string) {
    switch (status) {
        case 'pending':
            return 'acknowledged';
        case 'acknowledged':
            return 'preparing';
        case 'preparing':
            return 'ready';
        case 'ready':
            return 'served';
        case 'served':
            return 'completed';
        default:
            return null;
    }
}

interface MerchantDashboardClientProps {
    initialData: CommandCenterData | null;
}

export function MerchantDashboardClient({ initialData }: MerchantDashboardClientProps) {
    const [range, setRange] = useState<CommandCenterRange>('today');

    // Initialize state with server data - NO loading flash!
    const [commandCenter, setCommandCenter] = useState<CommandCenterData | null>(
        initialData ?? null
    );

    const [refreshing, setRefreshing] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [timeTick, setTimeTick] = useState(Date.now());
    const [filterOpen, setFilterOpen] = useState(false);
    const [alertRuleDrawerOpen, setAlertRuleDrawerOpen] = useState(false);

    const { restaurantName } = useMerchantActivity();

    // Ref for abort controller
    const abortControllerRef = useRef<AbortController | null>(null);

    const fetchCommandCenter = useCallback(
        async (isManualRefresh = false, signal?: AbortSignal) => {
            if (isManualRefresh) {
                setRefreshing(true);
            }

            try {
                const response = await fetch(`/api/merchant/command-center?range=${range}`, {
                    method: 'GET',
                    cache: 'no-store',
                    signal,
                });
                if (!response.ok) {
                    throw new Error(`Command center request failed (${response.status})`);
                }

                const payload = await response.json();
                setCommandCenter(payload?.data ?? null);
                setError(null);
            } catch (fetchError) {
                // Silently ignore abort errors
                if (isAbortError(fetchError)) {
                    return;
                }
                setError(fetchError instanceof Error ? fetchError.message : 'Unknown error');
            } finally {
                setRefreshing(false);
            }
        },
        [range]
    );

    // Fetch when range changes
    useEffect(() => {
        // Abort any pending requests
        if (abortControllerRef.current) {
            abortControllerRef.current.abort();
        }

        // Create new AbortController
        abortControllerRef.current = new AbortController();
        const signal = abortControllerRef.current.signal;

        fetchCommandCenter(false, signal);

        return () => {
            abortControllerRef.current?.abort();
        };
    }, [fetchCommandCenter]);

    // Time tick for staleness detection
    useEffect(() => {
        const intervalId = window.setInterval(() => setTimeTick(Date.now()), 30_000);
        return () => window.clearInterval(intervalId);
    }, []);

    // Event listeners for refresh and alert rules
    useEffect(() => {
        const onRefresh = () => {
            fetchCommandCenter(true);
        };
        const onOpenAlertRules = () => {
            setAlertRuleDrawerOpen(true);
        };
        window.addEventListener('merchant:command-center-refresh', onRefresh);
        window.addEventListener('merchant:open-alert-rules', onOpenAlertRules);
        return () => {
            window.removeEventListener('merchant:command-center-refresh', onRefresh);
            window.removeEventListener('merchant:open-alert-rules', onOpenAlertRules);
        };
    }, [fetchCommandCenter]);

    const metrics = commandCenter?.metrics ?? EMPTY_METRICS;
    const queue = useMemo(() => commandCenter?.attention_queue ?? [], [commandCenter]);
    const generatedAt = commandCenter?.sync_status.generated_at;
    const isStale = useMemo(() => {
        if (!generatedAt) return true;
        return timeTick - new Date(generatedAt).getTime() > STALE_AFTER_MS;
    }, [generatedAt, timeTick]);

    const queueForPreset = queue;

    const activeOrders = queueForPreset
        .filter(item => item.type === 'order')
        .slice(0, 4)
        .map(item => {
            const statusLower = item.status.toLowerCase();
            const isReady = ['ready', 'served', 'completed'].includes(statusLower);
            const isHold = statusLower === 'acknowledged';

            return {
                id: item.id,
                title: `${item.label}${item.table_number ? ` (Table ${item.table_number})` : ''}`,
                status: item.status,
                statusColor: isReady
                    ? 'text-green-500'
                    : isHold
                      ? 'text-blue-500'
                      : 'text-orange-500',
                time: item.created_at
                    ? `${Math.max(0, Math.round((Date.now() - new Date(item.created_at).getTime()) / 60000))}m`
                    : '0m',
                icon: isReady ? CheckCircle : isHold ? PauseCircle : PlayCircle,
                iconBg: isReady
                    ? 'bg-green-50 text-green-500'
                    : isHold
                      ? 'bg-orange-50 text-orange-500'
                      : 'bg-blue-50 text-blue-500',
            };
        });

    const activeServiceRequests = queueForPreset
        .filter(item => item.type === 'service_request')
        .slice(0, 4)
        .map(item => {
            return {
                id: item.id,
                title: `${item.label}${item.table_number ? ` (Table ${item.table_number})` : ''}`,
                status: item.status,
                statusColor: item.status === 'completed' ? 'text-green-500' : 'text-blue-500',
                time: item.created_at
                    ? `${Math.max(0, Math.round((Date.now() - new Date(item.created_at).getTime()) / 60000))}m`
                    : '0m',
                icon: item.status === 'completed' ? CheckCircle : Users,
                iconBg:
                    item.status === 'completed'
                        ? 'bg-green-50 text-green-500'
                        : 'bg-blue-50 text-blue-500',
            };
        });

    return (
        <div className="space-y-8 pb-10">
            <div className="flex items-start justify-between">
                <div>
                    <h1 className="mb-2 text-4xl font-bold tracking-tight text-black">
                        Hello, {restaurantName}
                    </h1>
                    <p className="font-medium text-gray-500">
                        Here's your daily performance summary.
                    </p>
                </div>

                <div className="flex items-center gap-2">
                    <span className="rounded-xl bg-gray-50 px-3 py-2 text-sm font-bold text-black">
                        {new Date().toLocaleDateString('en-US', {
                            day: '2-digit',
                            month: 'short',
                            year: 'numeric',
                        })}
                    </span>
                    <button className="bg-brand-accent flex h-10 w-10 items-center justify-center rounded-xl text-black shadow-lg shadow-black/10 transition-colors hover:brightness-105">
                        <CalendarCheck className="h-5 w-5" />
                    </button>
                </div>
            </div>

            <div className="flex flex-wrap items-center justify-between gap-3">
                <div className="flex items-center gap-2">
                    <span
                        className={`rounded-full px-3 py-1 text-xs font-bold ${error ? 'bg-rose-100 text-rose-700' : isStale ? 'bg-amber-100 text-amber-700' : 'bg-emerald-100 text-emerald-700'}`}
                    >
                        {error ? 'SYNC FAILED' : isStale ? 'STALE DATA' : 'IN SYNC'}
                    </span>
                    <span className="text-xs font-semibold text-gray-500">
                        Last sync:{' '}
                        {generatedAt
                            ? new Date(generatedAt).toLocaleTimeString([], {
                                  hour: '2-digit',
                                  minute: '2-digit',
                              })
                            : 'never'}
                    </span>
                </div>
                <div className="flex items-center gap-2">
                    <button
                        onClick={() => setAlertRuleDrawerOpen(true)}
                        className="h-10 rounded-xl bg-white px-3 text-sm font-bold text-gray-700 shadow-sm transition-shadow hover:shadow-md"
                    >
                        Alert Rules
                    </button>
                    <button
                        onClick={() => fetchCommandCenter(true)}
                        className="bg-brand-accent h-10 rounded-xl px-4 text-sm font-bold text-black hover:brightness-105"
                        disabled={refreshing}
                    >
                        {refreshing ? 'Refreshing...' : 'Refresh'}
                    </button>
                </div>
            </div>

            <div className="grid grid-cols-1 gap-5 md:grid-cols-2 xl:grid-cols-4">
                <MetricCard
                    icon={ListOrdered}
                    chip="Live"
                    value={metrics.orders_in_flight}
                    label="Orders In Flight"
                    subLabel={`${metrics.total_orders_today} total in range`}
                    tone="blue"
                    progress={Math.min(20, Math.max(1, metrics.orders_in_flight))}
                    targetLabel="Target: 20"
                    currentLabel={`Current: ${metrics.orders_in_flight}`}
                />
                <MetricCard
                    icon={Timer}
                    chip="Live"
                    value={`${metrics.avg_ticket_time_minutes}m`}
                    label="Avg Ticket Time"
                    subLabel="Open to served/completed"
                    tone="rose"
                    progress={Math.min(
                        20,
                        Math.max(1, Math.round(20 - metrics.avg_ticket_time_minutes / 3))
                    )}
                    targetLabel="Target: 40m"
                    currentLabel={`Current: ${metrics.avg_ticket_time_minutes}m`}
                />
                <MetricCard
                    icon={Users}
                    chip={`${metrics.unique_tables_today}`}
                    value={metrics.active_tables}
                    label="Active Tables"
                    subLabel="Current service load"
                    tone="purple"
                    progress={Math.min(20, Math.max(1, metrics.active_tables))}
                    targetLabel="Target: 20"
                    currentLabel={`Current: ${metrics.active_tables}`}
                />
                <MetricCard
                    icon={Wallet}
                    chip={`${metrics.payment_success_rate}%`}
                    value={metrics.open_requests}
                    label="Open Requests"
                    subLabel={`Payment success ${metrics.payment_success_rate}%`}
                    tone="green"
                    progress={Math.min(20, Math.max(1, metrics.open_requests))}
                    targetLabel="Target: 5"
                    currentLabel={`Current: ${metrics.open_requests}`}
                />
            </div>

            {/* Income Tracker */}
            <div className="rounded-4xl bg-white p-8 shadow-sm">
                <div className="mb-8 flex items-start justify-between">
                    <div className="max-w-xl">
                        <h2 className="mb-2 text-3xl font-bold tracking-tight text-slate-900">
                            Income Tracker
                        </h2>
                        <p className="text-sm font-medium text-gray-500">
                            Real-time analysis of your daily revenue streams.
                        </p>
                    </div>
                    <div className="relative">
                        <button
                            onClick={() => setFilterOpen(value => !value)}
                            className="inline-flex h-10 items-center gap-2 rounded-xl bg-gray-50 px-4 text-sm font-bold text-gray-700 capitalize transition-colors hover:bg-gray-100"
                        >
                            {range}
                            <ChevronDown
                                className={`h-4 w-4 transition-transform ${filterOpen ? 'rotate-180' : ''}`}
                            />
                        </button>
                        {filterOpen && (
                            <div className="absolute right-0 z-20 mt-2 w-32 rounded-xl bg-white p-1 shadow-xl ring-1 ring-black/5">
                                {(['today', 'week', 'month'] as CommandCenterRange[]).map(
                                    option => (
                                        <button
                                            key={option}
                                            onClick={() => {
                                                setRange(option);
                                                setFilterOpen(false);
                                            }}
                                            className={`w-full rounded-lg px-3 py-2 text-left text-sm font-semibold capitalize ${range === option ? 'bg-gray-100 text-gray-900' : 'text-gray-600 hover:bg-gray-50'}`}
                                        >
                                            {option}
                                        </button>
                                    )
                                )}
                            </div>
                        )}
                    </div>
                </div>
                <div className="flex h-full flex-col items-center gap-12 xl:flex-row">
                    <div className="flex h-full w-full flex-1 flex-col justify-center pl-[35px]">
                        <span className="block text-[3.5rem] leading-none font-bold tracking-tighter text-slate-900">
                            {Math.floor(metrics.gross_sales_today).toLocaleString()}
                            <span className="ml-2 text-xl font-medium text-slate-400">ETB</span>
                        </span>
                        <p className="mt-2 text-lg leading-relaxed font-medium text-wrap text-slate-500">
                            {(() => {
                                const diff = Math.floor(
                                    metrics.gross_sales_today - (metrics.gross_sales_previous ?? 0)
                                );
                                const type =
                                    range === 'today'
                                        ? 'yesterday'
                                        : range === 'week'
                                          ? 'last week'
                                          : 'last month';
                                return (
                                    <>
                                        You made{' '}
                                        <span
                                            className={
                                                diff >= 0 ? 'text-emerald-500' : 'text-rose-500'
                                            }
                                        >
                                            {Math.abs(diff).toLocaleString()} ETB
                                        </span>{' '}
                                        {diff >= 0 ? 'more' : 'less'} than {type}
                                    </>
                                );
                            })()}
                        </p>
                    </div>
                    <div className="h-full min-h-[350px] w-full flex-[4] overflow-hidden">
                        <RevenueChart data={commandCenter?.chart_data ?? []} />
                    </div>
                </div>
            </div>

            <div className="grid grid-cols-1 items-start gap-6 xl:grid-cols-2">
                {/* Active Orders Panel */}
                <div className="flex h-full flex-col rounded-4xl bg-white p-8 shadow-sm">
                    <div className="mb-6 flex items-center justify-between">
                        <div className="flex items-center gap-3">
                            <h2 className="text-2xl font-bold tracking-tight text-slate-900">
                                Active Orders
                            </h2>
                            <span className="bg-brand-accent rounded-full px-3 py-1 text-xs font-bold text-black shadow-sm">
                                {metrics.orders_in_flight} Pending
                            </span>
                        </div>
                    </div>
                    {activeOrders.length === 0 ? (
                        <div className="flex flex-1 flex-col items-center justify-center rounded-2xl border-2 border-dashed border-gray-100 bg-gray-50/50 py-12 text-center">
                            <div className="mb-4 flex h-14 w-14 items-center justify-center rounded-full bg-white shadow-sm ring-1 ring-gray-100">
                                <ListOrdered className="h-6 w-6 text-gray-400" />
                            </div>
                            <p className="text-sm font-bold text-gray-700">No active orders</p>
                            <p className="mt-1 text-xs font-medium text-gray-500">
                                New incoming orders will appear here automatically.
                            </p>
                        </div>
                    ) : (
                        <div className="flex flex-col gap-3">
                            {activeOrders.map(order => (
                                <div
                                    key={order.id}
                                    className="group flex cursor-pointer items-center justify-between rounded-xl border border-gray-100 bg-gray-50 p-4 transition-all hover:border-gray-200 hover:bg-white hover:shadow-md"
                                >
                                    <div className="flex flex-1 items-center gap-4">
                                        <div
                                            className={`flex h-12 w-12 items-center justify-center rounded-xl bg-white shadow-sm ring-1 ring-gray-100 ${order.statusColor}`}
                                        >
                                            <order.icon className="h-6 w-6" />
                                        </div>
                                        <div>
                                            <h4 className="mb-1 text-sm font-bold text-slate-900">
                                                {order.title}
                                            </h4>
                                            <div className="flex items-center gap-2">
                                                <Clock className="h-3.5 w-3.5 text-gray-400" />
                                                <span className="text-xs font-semibold text-gray-500">
                                                    {order.time} ago
                                                </span>
                                            </div>
                                        </div>
                                    </div>
                                    <div className="flex items-center gap-4">
                                        <div className="flex items-center gap-2 rounded-lg bg-white px-3 py-1.5 shadow-sm ring-1 ring-gray-100">
                                            <div
                                                className={`h-2 w-2 rounded-full ${order.statusColor.replace('text-', 'bg-')}`}
                                            />
                                            <span
                                                className={`text-xs font-bold ${order.statusColor}`}
                                            >
                                                {order.status}
                                            </span>
                                        </div>
                                        <button className="flex h-8 w-8 items-center justify-center rounded-full text-gray-400 transition-colors hover:bg-gray-100 hover:text-slate-900">
                                            <MoreHorizontal className="h-5 w-5" />
                                        </button>
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>

                {/* Service Requests Panel */}
                <div className="flex h-full flex-col rounded-4xl bg-white p-8 shadow-sm">
                    <div className="mb-6 flex items-center justify-between">
                        <div className="flex items-center gap-3">
                            <h2 className="text-2xl font-bold tracking-tight text-slate-900">
                                Service Requests
                            </h2>
                            <span className="rounded-full bg-blue-500 px-3 py-1 text-xs font-bold text-white shadow-sm">
                                {metrics.open_requests} Open
                            </span>
                        </div>
                    </div>
                    {activeServiceRequests.length === 0 ? (
                        <div className="flex flex-1 flex-col items-center justify-center rounded-2xl border-2 border-dashed border-gray-100 bg-gray-50/50 py-12 text-center">
                            <div className="mb-4 flex h-14 w-14 items-center justify-center rounded-full bg-white shadow-sm ring-1 ring-gray-100">
                                <UtensilsCrossed className="h-6 w-6 text-gray-400" />
                            </div>
                            <p className="text-sm font-bold text-gray-700">No pending requests</p>
                            <p className="mt-1 text-xs font-medium text-gray-500">
                                Service requests from tables will show up here.
                            </p>
                        </div>
                    ) : (
                        <div className="flex flex-col gap-3">
                            {activeServiceRequests.map(request => (
                                <div
                                    key={request.id}
                                    className="group flex cursor-pointer items-center justify-between rounded-xl border border-gray-100 bg-gray-50 p-4 transition-all hover:border-gray-200 hover:bg-white hover:shadow-md"
                                >
                                    <div className="flex flex-1 items-center gap-4">
                                        <div
                                            className={`flex h-12 w-12 items-center justify-center rounded-xl bg-white shadow-sm ring-1 ring-gray-100 ${request.statusColor}`}
                                        >
                                            <request.icon className="h-6 w-6" />
                                        </div>
                                        <div>
                                            <h4 className="mb-1 text-sm font-bold text-slate-900">
                                                {request.title}
                                            </h4>
                                            <div className="flex items-center gap-2">
                                                <Clock className="h-3.5 w-3.5 text-gray-400" />
                                                <span className="text-xs font-semibold text-gray-500">
                                                    {request.time} ago
                                                </span>
                                            </div>
                                        </div>
                                    </div>
                                    <div className="flex items-center gap-4">
                                        <div className="flex items-center gap-2 rounded-lg bg-white px-3 py-1.5 shadow-sm ring-1 ring-gray-100">
                                            <div
                                                className={`h-2 w-2 rounded-full ${request.statusColor.replace('text-', 'bg-')}`}
                                            />
                                            <span
                                                className={`text-xs font-bold ${request.statusColor}`}
                                            >
                                                {request.status}
                                            </span>
                                        </div>
                                        <button className="flex h-8 w-8 items-center justify-center rounded-full text-gray-400 transition-colors hover:bg-gray-100 hover:text-slate-900">
                                            <MoreHorizontal className="h-5 w-5" />
                                        </button>
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            </div>

            <AlertRuleBuilderDrawer
                open={alertRuleDrawerOpen}
                onClose={() => setAlertRuleDrawerOpen(false)}
            />
        </div>
    );
}

'use client';

import React, { useState } from 'react';
import { Tablet, Copy, X } from 'lucide-react';
import { toast } from 'react-hot-toast';
import { cn } from '@/lib/utils';
import {
    getPaymentOptionsForSurface,
    type HardwareDeviceMetadata,
    type HardwareDeviceType,
    type SupportedPaymentMethod,
