                                            cash and Chapa.
                                        </p>
                                    </div>
                                </div>
                            )}
                            <div className="pt-2">
                                <label className="mb-2 block text-xs font-bold tracking-wider text-gray-400 uppercase">
                                    Zone Restriction
                                </label>
                                <div className="flex flex-wrap gap-2">
                                    {availableZones.length > 0 ? (
