'use client';

import React, { useState } from 'react';
import { createClient } from '@/lib/supabase';
import { useRouter } from 'next/navigation';
import { Button } from '@/components/ui/Button';
import { Card } from '@/components/ui/Card';
import { Eye, EyeOff, Lock, Mail } from 'lucide-react';

export const LoginForm = () => {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [showPassword, setShowPassword] = useState(false);

    // We instantiate the client here
    const supabase = createClient();
    const router = useRouter();

    const handleLogin = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setError(null);

        try {
            const { data, error } = await supabase.auth.signInWithPassword({
                email,
                password,
            });

            if (error) throw error;
            if (!data.user) throw new Error('No user returned');

            // Fetch role to determine redirection
            // Since we can't use the hook easily inside this async handler for immediate one-off logic,
            // we query manually similar to the hook logic.

            const { data: staffData, error: roleError } = await supabase
                .from('restaurant_staff')
                .select('role')
                .eq('user_id', data.user.id)
                .maybeSingle();

            if (roleError) {
                console.error('Role fetch error:', roleError);
                // Fallback or just go to dashboard and let the guard handle it
                router.push('/merchant');
                return;
            }

            const role = staffData?.role;

            if (role === 'kitchen' || role === 'bar') {
                router.push('/kds/display');
            } else if (role === 'waiter') {
                router.push('/pos/mobile');
            } else {
                router.push('/merchant');
            }
        } catch (err: any) {
            setError(err.message || 'Failed to sign in');
        } finally {
            setLoading(false);
        }
    };

    return (
        <Card className="bg-surface-0/80 border-surface-200 w-full max-w-md border p-8 shadow-2xl backdrop-blur-xl">
            <div className="mb-8 text-center">
                <h1 className="text-black mb-2 text-3xl font-bold">Gebeta</h1>
                <p className="text-text-secondary">Restaurant Operations Platform</p>
            </div>

            <form onSubmit={handleLogin} className="space-y-4">
                <div className="space-y-2">
                    <label className="text-text-primary text-sm font-medium">Email</label>
                    <div className="relative">
                        <Mail className="text-text-tertiary absolute top-3 left-3 h-5 w-5" />
                        <input
                            type="email"
                            required
                            value={email}
                            onChange={e => setEmail(e.target.value)}
                            className="border-surface-200 bg-surface-50 text-text-primary focus:border-brand-accent focus:ring-brand-accent w-full rounded-lg border py-2.5 pr-4 pl-10 transition-all outline-none focus:ring-1"
                            placeholder="name@restaurant.com"
                        />
                    </div>
                </div>

                <div className="space-y-2">
                    <label className="text-text-primary text-sm font-medium">Password</label>
                    <div className="relative">
                        <Lock className="text-text-tertiary absolute top-3 left-3 h-5 w-5" />
                        <input
                            type={showPassword ? 'text' : 'password'}
                            required
                            value={password}
                            onChange={e => setPassword(e.target.value)}
                            className="border-surface-200 bg-surface-50 text-text-primary focus:border-brand-accent focus:ring-brand-accent w-full rounded-lg border py-2.5 pr-12 pl-10 transition-all outline-none focus:ring-1"
                            placeholder="••••••••"
                        />
                        <button
                            type="button"
                            onClick={() => setShowPassword(!showPassword)}
                            className="text-text-tertiary hover:text-text-primary absolute top-3 right-3"
                        >
                            {showPassword ? (
                                <EyeOff className="h-5 w-5" />
                            ) : (
                                <Eye className="h-5 w-5" />
                            )}
                        </button>
                    </div>
                </div>

                {error && (
                    <div className="rounded-lg border border-red-100 bg-red-50 p-3 text-sm font-medium text-red-600">
                        {error}
                    </div>
                )}

                <Button
                    type="submit"
                    className="bg-brand-accent hover:bg-brand-accent-hover shadow-brand-accent/20 h-12 w-full text-lg font-bold text-black shadow-lg"
                    isLoading={loading}
                >
                    Sign In
                </Button>
            </form>

            <div className="mt-6 text-center">
                <a
                    href="#"
                    className="text-text-tertiary hover:text-black text-sm transition-colors"
                >
                    Forgot your password?
                </a>
            </div>
        </Card>
    );
};

import React from 'react';
import { Clock, CheckCircle, ChevronRight, AlertCircle } from 'lucide-react';
import { differenceInMinutes } from 'date-fns';
import { cn } from '@/lib/utils';

type TicketItem = {
    id: string;
    quantity: number;
    name: string;
    modifiers?: any[];
    notes?: string;
    status: 'pending' | 'cooking' | 'ready';
    category?: string;
};

type TicketCardProps = {
    id: string;
    ticketNumber: string;
    tableNumber: string;
    createdAt: Date;
    status: 'new' | 'active' | 'completed';
    items: TicketItem[];
    onStatusChange: (status: 'new' | 'active' | 'completed') => void;
    variant?: 'light' | 'dark'; // Added for future flexibility if needed
};

export const TicketCard = ({
    ticketNumber,
    tableNumber,
    createdAt,
    status,
    items,
    onStatusChange,
}: TicketCardProps) => {
    const elapsedMinutes = differenceInMinutes(new Date(), createdAt);

    // Urgency Logic
    let urgencyColor = 'bg-blue-500';
    let urgencyBg = 'bg-blue-50';
    let urgencyText = 'text-blue-600';
    let borderColor = 'border-gray-200';

    if (elapsedMinutes > 15) {
        urgencyColor = 'bg-orange-500';
        urgencyBg = 'bg-orange-50';
        urgencyText = 'text-orange-600';
        borderColor = 'border-orange-200';
    }
    if (elapsedMinutes > 30) {
        urgencyColor = 'bg-red-500';
        urgencyBg = 'bg-red-50';
        urgencyText = 'text-red-600';
        borderColor = 'border-red-200';
    }

    if (status === 'completed') {
        urgencyColor = 'bg-green-500';
        urgencyBg = 'bg-green-50';
        urgencyText = 'text-green-600';
        borderColor = 'border-green-200';
    }

    return (
        <div
            className={cn(
                'flex max-h-full flex-col overflow-hidden rounded-xl border bg-white shadow-sm transition-all duration-300 hover:shadow-md',
                status === 'active'
                    ? `border-l-4 ${borderColor} border-l-${urgencyColor} ring-1 ring-black/5`
                    : 'border-gray-200'
            )}
        >
            {/* Header */}
            <div
                className={cn(
                    'flex flex-col gap-2 border-b p-4',
                    status === 'new' ? 'bg-gray-50/50' : 'bg-white',
                    borderColor
                )}
            >
                <div className="flex items-start justify-between">
                    <div className="flex flex-col">
                        <span className="text-xs font-bold tracking-wider text-gray-500 uppercase">
                            Table
                        </span>
                        <span className="text-2xl leading-none font-black text-gray-900">
                            {tableNumber.replace('T-', '')}
                        </span>
                    </div>
                    <div className="flex flex-col items-end">
                        <span className="text-xs font-bold tracking-wider text-gray-500 uppercase">
                            Ticket
                        </span>
                        <span className="text-xl font-bold text-gray-900 tabular-nums">
                            #{ticketNumber.slice(-4)}
                        </span>
                    </div>
                </div>

                <div className="mt-2 flex items-center justify-between">
                    <div
                        className={cn(
                            'flex items-center gap-1.5 rounded-lg px-2.5 py-1 text-xs font-bold',
                            urgencyBg,
                            urgencyText
                        )}
                    >
                        <Clock className="h-3.5 w-3.5" />
                        <span>{elapsedMinutes}m ago</span>
                    </div>
                    {status === 'new' && (
                        <div className="bg-brand-accent/10 text-black animate-pulse rounded-lg px-2 py-1 text-xs font-bold tracking-wide uppercase">
                            New
                        </div>
                    )}
                </div>
            </div>

            {/* Items List */}
            <div className="flex-1 overflow-y-auto bg-gray-50/30 p-2">
                <div className="space-y-1">
                    {items.map((item, idx) => (
                        <div
                            key={`${item.id}-${idx}`}
                            className="group flex gap-3 rounded-xl border border-gray-100 bg-white p-3 shadow-sm"
                        >
                            <div className="flex h-6 w-6 items-center justify-center rounded-md border border-gray-200 bg-gray-100 text-xs font-bold text-gray-900">
                                {item.quantity}x
                            </div>
                            <div className="min-w-0 flex-1">
                                <p className="group-hover:text-black text-sm leading-tight font-bold text-gray-900 transition-colors">
                                    {item.name}
                                </p>
                                {item.modifiers && item.modifiers.length > 0 && (
                                    <div className="mt-1 flex flex-wrap gap-1">
                                        {item.modifiers.map((mod: any, i: number) => (
                                            <span
                                                key={i}
                                                className="rounded border border-gray-200 bg-gray-100 px-1.5 py-0.5 text-[10px] text-gray-600"
                                            >
                                                {mod.name || mod}
                                            </span>
                                        ))}
                                    </div>
                                )}
                                {item.notes && (
                                    <div className="mt-1.5 flex items-start gap-1.5 rounded-lg border border-amber-100 bg-amber-50 p-1.5 text-[11px] font-medium text-amber-600">
                                        <AlertCircle className="mt-0.5 h-3 w-3 shrink-0" />
                                        <span>{item.notes}</span>
                                    </div>
                                )}
                            </div>
                        </div>
                    ))}
                </div>
            </div>

            {/* Footer Actions */}
            <div className="border-t border-gray-100 bg-white p-3">
                {status === 'new' && (
                    <button
                        onClick={() => onStatusChange('active')}
                        className="flex w-full items-center justify-center gap-2 rounded-xl bg-blue-600 py-3 font-bold text-white shadow-lg shadow-blue-900/10 transition-all hover:bg-blue-700 active:scale-[0.98]"
                    >
                        <span>Start Preparing</span>
                        <ChevronRight className="h-4 w-4" />
                    </button>
                )}

                {status === 'active' && (
                    <button
                        onClick={() => onStatusChange('completed')}
                        className="flex w-full items-center justify-center gap-2 rounded-xl border-2 border-green-500 bg-white py-3 font-bold text-green-600 transition-all hover:bg-green-50 active:scale-[0.98]"
                    >
                        <CheckCircle className="h-5 w-5" />
                        <span>Mark Ready</span>
                    </button>
                )}
            </div>
        </div>
    );
};

'use client';

import React, { useState, useEffect } from 'react';
import { Card } from '@/components/ui/Card';
import { Button } from '@/components/ui/Button';
import { X, Upload, Image as ImageIcon } from 'lucide-react';
import { createClient } from '@/lib/supabase';
import { toast } from 'react-hot-toast';

interface MenuItemModalProps {
    isOpen: boolean;
    onClose: () => void;
    category: string | null;
    categoryName?: string;
    itemToEdit?: {
        id: string;
        name: string;
        name_am?: string | null;
        price: number | null;
        description?: string | null;
        image_url?: string | null;
        category_id: string;
    } | null;
    onSuccess: () => void;
}

export function MenuItemModal({
    isOpen,
    onClose,
    category,
    categoryName,
    itemToEdit,
    onSuccess,
}: MenuItemModalProps) {
    const [loading, setLoading] = useState(false);
    const [uploading, setUploading] = useState(false);
    const [formError, setFormError] = useState<string | null>(null);

    // Form State
    const [name, setName] = useState('');
    const [nameAm, setNameAm] = useState('');
    const [price, setPrice] = useState('');
    const [description, setDescription] = useState('');
    const [imageUrl, setImageUrl] = useState('');

    const supabase = createClient();

    // Reset or populate fields when opening
    useEffect(() => {
        if (isOpen) {
            if (itemToEdit) {
                setName(itemToEdit.name);
                setNameAm(itemToEdit.name_am || '');
                setPrice((itemToEdit.price ?? 0).toString());
                setDescription(itemToEdit.description || '');
                setImageUrl(itemToEdit.image_url || '');
            } else {
                setName('');
                setNameAm('');
                setPrice('');
                setDescription('');
                setImageUrl('');
            }
            setFormError(null);
        }
    }, [isOpen, itemToEdit]);

    const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        try {
            setUploading(true);
            if (!e.target.files || e.target.files.length === 0) return;

            const file = e.target.files[0];
            const fileExt = file.name.split('.').pop();
            const fileName = `${Math.random().toString(36).substring(2)}.${fileExt}`;
            const filePath = `${fileName}`;

            // 1. Upload
            const { error: uploadError } = await supabase.storage
                .from('menu-items')
                .upload(filePath, file);

            if (uploadError) {
                // If bucket doesn't exist, this fails.
                // We should ideally create bucket or handle it.
                // Assuming "menu-items" bucket exists public.
                throw uploadError;
            }

            // 2. Get Public URL
            const { data } = supabase.storage.from('menu-items').getPublicUrl(filePath);

            setImageUrl(data.publicUrl);
        } catch (error: any) {
            toast.error(error?.message || 'Failed to upload image.');
        } finally {
            setUploading(false);
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!category && !itemToEdit) {
