'use client';

import { useEffect, useCallback, useMemo, useRef, useState } from 'react';
import { createClient } from '@/lib/supabase/client';
import type { RealtimeChannel } from '@supabase/supabase-js';

/**
 * HIGH-015: Reconnection configuration
 */
const RECONNECT_CONFIG = {
    /** Maximum number of reconnection attempts */
    maxRetries: 5,
    /** Base delay in milliseconds for exponential backoff */
    baseDelayMs: 1000,
    /** Maximum delay in milliseconds */
    maxDelayMs: 30000,
    /** Jitter factor to prevent thundering herd (0-1) */
    jitterFactor: 0.3,
};

/**
 * MED-003: Message deduplication configuration
 */
const DEDUP_CONFIG = {
    /** Time window in milliseconds for deduplication (5 seconds) */
    dedupWindowMs: 5000,
    /** Maximum number of message IDs to track */
    maxTrackedMessages: 1000,
};

/**
 * Calculate exponential backoff delay with jitter
 */
function calculateReconnectDelay(retryCount: number): number {
    const delay = Math.min(
        RECONNECT_CONFIG.baseDelayMs * Math.pow(2, retryCount),
        RECONNECT_CONFIG.maxDelayMs
    );
    // Add jitter
    const jitter = delay * RECONNECT_CONFIG.jitterFactor * Math.random();
    return delay + jitter;
}

/**
 * MED-003: Generate a unique message ID from realtime payload
 * Uses table, event type, and record ID to create a deterministic identifier
 */
function generateMessageId(
    table: string,
    eventType: 'INSERT' | 'UPDATE' | 'DELETE',
    recordId: string
): string {
    return `${table}:${eventType}:${recordId}`;
}

/**
 * MED-003: Message deduplication tracker
 * Tracks processed message IDs within a time window to prevent duplicate processing
 */
class MessageDeduplicator {
    private processedMessages: Map<string, number> = new Map();
    private cleanupInterval: ReturnType<typeof setInterval> | null = null;

    constructor() {
        // Periodically clean up old entries
        this.cleanupInterval = setInterval(() => this.cleanup(), DEDUP_CONFIG.dedupWindowMs);
    }

    /**
     * Check if a message has already been processed
     * Returns true if the message is a duplicate (should be skipped)
     */
    isDuplicate(messageId: string): boolean {
        const now = Date.now();
        const lastProcessed = this.processedMessages.get(messageId);

        if (lastProcessed !== undefined) {
            // Check if within deduplication window
            if (now - lastProcessed < DEDUP_CONFIG.dedupWindowMs) {
                return true; // Duplicate detected
            }
        }

        // Mark as processed
        this.processedMessages.set(messageId, now);

        // Enforce max tracked messages limit
        if (this.processedMessages.size > DEDUP_CONFIG.maxTrackedMessages) {
            this.cleanup();
        }

        return false;
    }

    /**
     * Clean up old entries outside the deduplication window
     */
    private cleanup(): void {
        const now = Date.now();
        const cutoff = now - DEDUP_CONFIG.dedupWindowMs;

        for (const [id, timestamp] of this.processedMessages.entries()) {
            if (timestamp < cutoff) {
                this.processedMessages.delete(id);
            }
        }
    }

    /**
     * Clear all tracked messages
     */
    clear(): void {
        this.processedMessages.clear();
    }

    /**
     * Destroy the deduplicator and clean up resources
     */
    destroy(): void {
        if (this.cleanupInterval) {
            clearInterval(this.cleanupInterval);
            this.cleanupInterval = null;
        }
        this.processedMessages.clear();
    }
}

type OrderStatus = 'pending' | 'confirmed' | 'preparing' | 'ready' | 'completed';
type ExternalOrderStatus =
    | 'pending'
    | 'confirmed'
    | 'preparing'
    | 'ready'
    | 'delivered'
    | 'cancelled';

interface KDSOrder {
    id: string;
    order_type: 'dine-in' | 'delivery' | 'pickup';
    source: string;
    status: OrderStatus | ExternalOrderStatus;
    created_at: string;
    restaurant_id?: string;
}

interface RealtimePayload {
    eventType: 'INSERT' | 'UPDATE' | 'DELETE';
    new: Record<string, unknown>;
    old: Record<string, unknown>;
    schema: string;
    table: string;
    commit_timestamp: string;
}

interface UseKDSRealtimeOptions {
    restaurantId: string;
    onNewOrder?: (order: KDSOrder) => void;
    onOrderUpdate?: (order: KDSOrder) => void;
    onOrderDelete?: (orderId: string) => void;
    enabled?: boolean;
}

/**
 * Hook for real-time KDS order updates via Supabase Realtime
 *
 * Subscribes to both `orders` and `external_orders` tables for
 * comprehensive omnichannel order tracking.
 */
export function useKDSRealtime({
    restaurantId,
    onNewOrder,
    onOrderUpdate,
    onOrderDelete,
    enabled = true,
}: UseKDSRealtimeOptions) {
    const channelRef = useRef<RealtimeChannel | null>(null);
    const supabase = useMemo(() => createClient(), []);
    const mountedRef = useRef(false);
    const [isConnected, setIsConnected] = useState(false);

    // HIGH-015: Reconnection state
    const retryCountRef = useRef(0);
    const reconnectTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
    const [reconnectionStatus, setReconnectionStatus] = useState<
        'idle' | 'reconnecting' | 'failed'
    >('idle');

    // MED-003: Message deduplicator instance
    const deduplicatorRef = useRef<MessageDeduplicator | null>(null);

    // Initialize deduplicator on mount
    useEffect(() => {
        deduplicatorRef.current = new MessageDeduplicator();
        return () => {
            deduplicatorRef.current?.destroy();
            deduplicatorRef.current = null;
        };
    }, []);

    const handleOrdersChange = useCallback(
        (payload: RealtimePayload) => {
            if (!mountedRef.current) return;

            // MED-003: Check for duplicate messages
            const recordId = (payload.new?.id || payload.old?.id) as string;
            if (recordId && deduplicatorRef.current) {
                const messageId = generateMessageId(payload.table, payload.eventType, recordId);
                if (deduplicatorRef.current.isDuplicate(messageId)) {
                    console.log(`[KDS Realtime] Skipping duplicate message: ${messageId}`);
                    return;
                }
            }

            const order = payload.new;

            // Filter by restaurant_id
            if (order.restaurant_id !== restaurantId) {
                return;
            }

            switch (payload.eventType) {
                case 'INSERT':
                    onNewOrder?.({
                        id: order.id as string,
                        order_type: 'dine-in',
                        source: 'dine-in',
                        status: order.status as OrderStatus,
                        created_at: order.created_at as string,
                    });
                    break;
                case 'UPDATE':
                    onOrderUpdate?.({
                        id: order.id as string,
                        order_type: 'dine-in',
                        source: 'dine-in',
                        status: order.status as OrderStatus,
                        created_at: order.created_at as string,
                    });
                    break;
                case 'DELETE':
                    onOrderDelete?.(payload.old.id as string);
                    break;
            }
        },
        [restaurantId, onNewOrder, onOrderUpdate, onOrderDelete]
    );

    const handleExternalOrdersChange = useCallback(
        (payload: RealtimePayload) => {
            if (!mountedRef.current) return;

            // MED-003: Check for duplicate messages
            const recordId = (payload.new?.id || payload.old?.id) as string;
            if (recordId && deduplicatorRef.current) {
                const messageId = generateMessageId(payload.table, payload.eventType, recordId);
                if (deduplicatorRef.current.isDuplicate(messageId)) {
                    console.log(`[KDS Realtime] Skipping duplicate message: ${messageId}`);
                    return;
                }
            }

            const order = payload.new;

            // Filter by restaurant_id
            if (order.restaurant_id !== restaurantId) {
                return;
            }

            const provider = order.provider as string;
            const payloadJson = order.payload_json as Record<string, unknown> | null;
            const fulfillmentType = payloadJson?.fulfillment_type as string;

            switch (payload.eventType) {
                case 'INSERT':
                    onNewOrder?.({
                        id: order.id as string,
                        order_type: fulfillmentType === 'pickup' ? 'pickup' : 'delivery',
                        source: provider,
                        status: order.normalized_status as ExternalOrderStatus,
                        created_at: order.created_at as string,
                    });
                    break;
                case 'UPDATE':
                    onOrderUpdate?.({
                        id: order.id as string,
                        order_type: fulfillmentType === 'pickup' ? 'pickup' : 'delivery',
                        source: provider,
                        status: order.normalized_status as ExternalOrderStatus,
                        created_at: order.created_at as string,
                    });
                    break;
                case 'DELETE':
                    onOrderDelete?.(payload.old.id as string);
                    break;
            }
        },
        [restaurantId, onNewOrder, onOrderUpdate, onOrderDelete]
    );

    /**
     * HIGH-015: Attempt to reconnect with exponential backoff
     */
    const attemptReconnect = useCallback(() => {
        if (!mountedRef.current) return;

        const currentRetry = retryCountRef.current;

        if (currentRetry >= RECONNECT_CONFIG.maxRetries) {
            console.error(
                `[KDS Realtime] Max reconnection attempts (${RECONNECT_CONFIG.maxRetries}) reached`
            );
            setReconnectionStatus('failed');
            return;
        }

        const delay = calculateReconnectDelay(currentRetry);
        console.log(
            `[KDS Realtime] Scheduling reconnect attempt ${currentRetry + 1}/${RECONNECT_CONFIG.maxRetries} in ${Math.round(delay)}ms`
        );

        setReconnectionStatus('reconnecting');

        reconnectTimeoutRef.current = setTimeout(() => {
            if (!mountedRef.current) return;

            retryCountRef.current++;

            // Unsubscribe existing channel if any
            if (channelRef.current) {
                channelRef.current.unsubscribe();
                channelRef.current = null;
            }

            // Trigger reconnection by setting up a new subscription
            setupChannel();
        }, delay);
    }, []);

    /**
     * HIGH-015: Setup channel with reconnection handling
     */
    const setupChannel = useCallback(() => {
        if (!mountedRef.current || !restaurantId) return;

        const channel = supabase
            .channel(`kds-orders-${restaurantId}`)
            .on(
                'postgres_changes',
                {
                    event: '*',
                    schema: 'public',
                    table: 'orders',
                    filter: `restaurant_id=eq.${restaurantId}`,
                },
                payload => {
                    handleOrdersChange(payload as unknown as RealtimePayload);
                }
            )
            .on(
                'postgres_changes',
                {
                    event: '*',
                    schema: 'public',
                    table: 'external_orders',
                    filter: `restaurant_id=eq.${restaurantId}`,
                },
                payload => {
                    handleExternalOrdersChange(payload as unknown as RealtimePayload);
                }
            )
            .subscribe(status => {
                console.log(`[KDS Realtime] Subscription status: ${status}`);
                if (!mountedRef.current) return;

                if (status === 'SUBSCRIBED') {
                    setIsConnected(true);
                    setReconnectionStatus('idle');
                    retryCountRef.current = 0; // Reset retry count on successful connection
                    return;
                }

                if (status === 'CHANNEL_ERROR' || status === 'CLOSED' || status === 'TIMED_OUT') {
                    setIsConnected(false);
                    // HIGH-015: Attempt reconnection with exponential backoff
                    attemptReconnect();
                }
            });

        channelRef.current = channel;
    }, [restaurantId, supabase, handleOrdersChange, handleExternalOrdersChange, attemptReconnect]);

    useEffect(() => {
        if (!enabled || !restaurantId) return;

        mountedRef.current = true;
        retryCountRef.current = 0;
        setReconnectionStatus('idle');

        // Initial channel setup
        setupChannel();

        // HIGH-015: Cleanup function
        return () => {
            mountedRef.current = false;

            // Clear any pending reconnect timeout
            if (reconnectTimeoutRef.current) {
                clearTimeout(reconnectTimeoutRef.current);
                reconnectTimeoutRef.current = null;
            }

            if (channelRef.current) {
                channelRef.current.unsubscribe();
                channelRef.current = null;
            }
            setIsConnected(false);
            setReconnectionStatus('idle');
        };
    }, [enabled, restaurantId, setupChannel]);

    return {
        isConnected,
        reconnectionStatus,
    };
}

/**
 * Hook for real-time driver status updates
 */
interface DriverStatusUpdate {
    orderId: string;
    status: 'pending' | 'assigned' | 'arrived';
    driverName?: string;
    driverPhone?: string;
    etaMinutes?: number;
}

interface UseDriverStatusRealtimeOptions {
    restaurantId: string;
    onDriverStatusUpdate?: (update: DriverStatusUpdate) => void;
    enabled?: boolean;
}

export function useDriverStatusRealtime({
    restaurantId,
    onDriverStatusUpdate,
    enabled = true,
}: UseDriverStatusRealtimeOptions) {
    const supabase = createClient();
    const mountedRef = useRef(false);

    useEffect(() => {
        if (!enabled || !restaurantId) return;

        mountedRef.current = true;

        const channel = supabase
            .channel(`driver-status-${restaurantId}`)
            .on(
                'postgres_changes',
                {
                    event: 'UPDATE',
                    schema: 'public',
                    table: 'external_orders',
                    filter: `restaurant_id=eq.${restaurantId}`,
                },
                payload => {
                    if (!mountedRef.current) return;

                    const order = payload.new as Record<string, unknown>;
                    const payloadJson = order.payload_json as Record<string, unknown> | null;
                    const driverInfo = payloadJson?.driver_info as Record<string, unknown> | null;

                    if (driverInfo) {
                        onDriverStatusUpdate?.({
                            orderId: order.id as string,
                            status: driverInfo.status as 'pending' | 'assigned' | 'arrived',
                            driverName: driverInfo.name as string | undefined,
                            driverPhone: driverInfo.phone as string | undefined,
                            etaMinutes: driverInfo.eta_minutes as number | undefined,
                        });
                    }
                }
            )
            .subscribe();

        return () => {
            mountedRef.current = false;
            channel.unsubscribe();
        };
    }, [enabled, restaurantId, supabase, onDriverStatusUpdate]);
}

'use client';

import { useEffect, useState } from 'react';

export type ActivityType = 'order' | 'kitchen' | 'staff' | 'request';

export interface ActivityItem {
    id: string;
    type: ActivityType;
    user: string;
    action: string;
    target: string;
    time: string;
    timestamp: Date;
    avatar?: string;
    message?: string;
    hasMessage?: boolean;
    hasFile?: boolean;
    fileName?: string;
    fileSize?: string;
}

export function useMerchantActivity() {
    const [activities, setActivities] = useState<ActivityItem[]>([]);
    const [loading, setLoading] = useState(true);

    // Initialize from sessionStorage instantly to prevent "Hello, Restaurant" flash
    const [restaurantName, setRestaurantName] = useState<string>(() => {
        if (typeof window !== 'undefined') {
            return sessionStorage.getItem('gebeta_restaurant_name') ?? 'Restaurant';
        }
        return 'Restaurant';
    });
    const [restaurantHandle, setRestaurantHandle] = useState<string>(() => {
        if (typeof window !== 'undefined') {
            return sessionStorage.getItem('gebeta_restaurant_handle') ?? '@restaurant_admin';
        }
        return '@restaurant_admin';
    });

    useEffect(() => {
        let mounted = true;

        async function fetchData() {
            try {
                if (!mounted) return;
                setLoading(true);

                console.log('[Hook] Fetching merchant activity...');
                const response = await fetch('/api/merchant/activity');

                console.log('[Hook] Response status:', response.status);

                if (!response.ok) {
                    if (response.status === 401 || response.status === 404) {
                        // Silent fail for unauthorized/guest users so it doesn't pollute console
                        if (mounted) setLoading(false);
                        return;
                    }
                    console.error('[Hook] API Error. Status:', response.status);
                    return;
                }

                const data = await response.json();
                console.log('[Hook] Received data:', {
                    orderCount: data.orders?.length || 0,
                    requestCount: data.requests?.length || 0,
                    restaurant: data.restaurant,
                });

                if (!mounted) return;

                // Set restaurant info
                if (data.restaurant) {
                    const name = data.restaurant.name as string;
                    const handle = `@${data.restaurant.slug as string}_admin`;
                    setRestaurantName(name);
                    setRestaurantHandle(handle);
                    // Persist so minimize/restore doesn't flash "Restaurant"
                    sessionStorage.setItem('gebeta_restaurant_name', name);
                    sessionStorage.setItem('gebeta_restaurant_handle', handle);
                }

                // Transform orders to activities
                const orderActivities: ActivityItem[] = (data.orders || []).map((order: any) => ({
                    id: `order-${order.id}`,
                    type: 'order' as ActivityType,
                    user: `Order ${order.order_number?.startsWith('ORD-') ? order.order_number.split('-').slice(1).join('-') : `#${order.order_number}`}`,
                    action: 'placed for',
                    target: `Table ${order.table_number}`,
                    time: new Date(order.created_at).toLocaleTimeString([], {
                        hour: 'numeric',
                        minute: '2-digit',
                    }),
                    timestamp: new Date(order.created_at),
                    hasMessage: !!order.notes,
                    message: order.notes ? `Note: '${order.notes}'` : undefined,
                    avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=Order${order.id}`,
                }));

                // Transform requests to activities
                const requestActivities: ActivityItem[] = (data.requests || []).map((req: any) => ({
                    id: `req-${req.id}`,
                    type: 'request' as ActivityType,
                    user: `Table ${req.table_number}`,
                    action: 'requested',
                    target:
                        req.request_type === 'waiter'
                            ? 'Waiter Assistance'
                            : req.request_type === 'bill'
                              ? 'Bill'
                              : req.request_type,
                    time: new Date(req.created_at).toLocaleTimeString([], {
                        hour: 'numeric',
                        minute: '2-digit',
                    }),
                    timestamp: new Date(req.created_at),
                    hasMessage: false,
                    avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=Req${req.id}`,
                }));

                // Combine and sort
                const combined = [...orderActivities, ...requestActivities].sort(
                    (a, b) => b.timestamp.getTime() - a.timestamp.getTime()
                );

                setActivities(combined);
            } catch (error) {
                console.error('Error fetching merchant activity:', error);
            } finally {
                if (mounted) setLoading(false);
            }
        }

        fetchData();

        return () => {
            mounted = false;
        };
    }, []);

    const broadcastMessage = async (message: string) => {
        const newActivity: ActivityItem = {
            id: `broadcast-${Date.now()}`,
            type: 'staff',
            user: 'You',
            action: 'broadcasted',
            target: 'to All Staff',
            time: new Date().toLocaleTimeString([], { hour: 'numeric', minute: '2-digit' }),
            timestamp: new Date(),
            hasMessage: true,
            message: message,
            avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=${restaurantName}`,
        };
        setActivities(prev => [newActivity, ...prev]);
        return true;
    };

    const refresh = async () => {
        setLoading(true);
        try {
            const response = await fetch('/api/merchant/activity');
            if (!response.ok) return;
            const data = await response.json();

            // Re-process the data (same logic as above)
            const orderActivities: ActivityItem[] = (data.orders || []).map((order: any) => ({
                id: `order-${order.id}`,
                type: 'order' as ActivityType,
                user: `Order ${order.order_number?.startsWith('ORD-') ? order.order_number.split('-').slice(1).join('-') : `#${order.order_number}`}`,
                action: 'placed for',
                target: `Table ${order.table_number}`,
                time: new Date(order.created_at).toLocaleTimeString([], {
                    hour: 'numeric',
                    minute: '2-digit',
                }),
                timestamp: new Date(order.created_at),
                hasMessage: !!order.notes,
                message: order.notes ? `Note: '${order.notes}'` : undefined,
                avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=Order${order.id}`,
            }));

            const requestActivities: ActivityItem[] = (data.requests || []).map((req: any) => ({
                id: `req-${req.id}`,
                type: 'request' as ActivityType,
                user: `Table ${req.table_number}`,
                action: 'requested',
                target:
                    req.request_type === 'waiter'
                        ? 'Waiter Assistance'
                        : req.request_type === 'bill'
                          ? 'Bill'
                          : req.request_type,
                time: new Date(req.created_at).toLocaleTimeString([], {
                    hour: 'numeric',
                    minute: '2-digit',
                }),
                timestamp: new Date(req.created_at),
                hasMessage: false,
                avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=Req${req.id}`,
            }));

            const combined = [...orderActivities, ...requestActivities].sort(
                (a, b) => b.timestamp.getTime() - a.timestamp.getTime()
            );

            setActivities(combined);
        } catch (error) {
            console.error('Error refreshing activity:', error);
        } finally {
            setLoading(false);
        }
    };

    return {
        activities,
        loading,
        restaurantName,
        restaurantHandle,
        broadcastMessage,
        refresh,
    };
}

import { getSupabaseClient } from '@/lib/supabase/client';
import { useEffect, useMemo, useState } from 'react';
import { UserRole } from '@/types/models';
import { useRouter } from 'next/navigation';
import type { User } from '@supabase/supabase-js';

export function useRole(restaurantId: string | null) {
    const [role, setRole] = useState<UserRole | null>(null);
    const [loading, setLoading] = useState(true);
    const [user, setUser] = useState<User | null>(null);
    const [resolvedRestaurantId, setResolvedRestaurantId] = useState<string | null>(restaurantId);
    const router = useRouter();
    const supabase = useMemo(() => getSupabaseClient(), []);

    useEffect(() => {
        let cancelled = false;

        async function fetchRole(currentUser?: User | null) {
            if (!cancelled) {
                setLoading(true);
            }

            try {
                let activeUser = currentUser ?? null;
                if (!activeUser) {
                    const {
                        data: { user: authUser },
                        error: userError,
                    } = await supabase.auth.getUser();
                    if (userError || !authUser) {
                        if (cancelled) return;
                        setRole(null);
                        setUser(null);
                        setResolvedRestaurantId(null);
                        setLoading(false);
                        return;
                    }
                    activeUser = authUser;
                }

                if (!activeUser) {
                    if (cancelled) return;
                    setRole(null);
                    setUser(null);
                    setResolvedRestaurantId(null);
                    setLoading(false);
                    return;
                }

                if (cancelled) return;
                setUser(activeUser);

                // 2. Get Role (treat NULL is_active as active for compatibility with old rows)
                const baseQuery = supabase
                    .from('restaurant_staff')
                    .select('role, restaurant_id, is_active')
                    .eq('user_id', activeUser.id);

                const { data: roleFromRpc, error: rpcError } = await (supabase.rpc as any)(
                    'get_my_staff_role',
                    {
                        p_restaurant_id: restaurantId,
                    }
                );

                if (
                    !rpcError &&
                    roleFromRpc &&
                    (Array.isArray(roleFromRpc) ? roleFromRpc.length > 0 : roleFromRpc)
                ) {
                    const match = Array.isArray(roleFromRpc) ? roleFromRpc[0] : roleFromRpc;
                    if (cancelled) return;
                    setRole(match.role as UserRole);
                    setResolvedRestaurantId(match.restaurant_id);
                    return;
                }

                const { data, error } = restaurantId
                    ? await baseQuery.eq('restaurant_id', restaurantId).maybeSingle()
                    : await baseQuery
                          .order('created_at', { ascending: false })
                          .limit(1)
                          .maybeSingle();

                if (error) {
                    if (cancelled) return;
                    console.warn('Error fetching role:', error.message);
                    setRole(null);
                } else if (data && data.is_active !== false) {
                    if (cancelled) return;
                    setRole(data.role as UserRole);
                    setResolvedRestaurantId(data.restaurant_id);
                } else {
                    if (cancelled) return;
                    setRole(null);
                    setResolvedRestaurantId(restaurantId);
                }
            } catch (err) {
                if (cancelled) return;
                console.error('Error in useRole:', err);
                setRole(null);
            } finally {
                if (cancelled) return;
                setLoading(false);
            }
        }

        fetchRole();

        const {
            data: { subscription },
        } = supabase.auth.onAuthStateChange((_event, session) => {
            void fetchRole(session?.user ?? null);
        });

        return () => {
            cancelled = true;
            subscription.unsubscribe();
        };
    }, [restaurantId, supabase]);

    const requireRole = (allowedRoles: UserRole[], redirectUrl = '/login') => {
        if (loading) return; // Don't redirect while loading
        if (!role || !allowedRoles.includes(role)) {
            router.push(redirectUrl);
        }
    };

    return { role, loading, user, restaurantId: resolvedRestaurantId, requireRole };
}

/**
 * Session Refresh Hook
 *
 * Manages client-side session refresh for Supabase authentication.
 * Handles session expiry gracefully and provides automatic refresh logic.
 *
 * @module useSessionRefresh
 */

'use client';

import { useEffect, useCallback, useRef } from 'react';
import { getSupabaseClient } from '@/lib/supabase/client';

/**
 * Configuration options for session refresh behavior
 */
interface SessionRefreshConfig {
    /** Interval in milliseconds to check session status (default: 60000 = 1 minute) */
    checkIntervalMs?: number;
    /** Threshold in seconds before expiry to trigger refresh (default: 300 = 5 minutes) */
    refreshThresholdSeconds?: number;
    /** Callback when session is refreshed successfully */
    onRefresh?: (session: { userId: string; expiresAt: number }) => void;
    /** Callback when session expires and cannot be refreshed */
    onExpired?: () => void;
    /** Callback when refresh fails */
    onError?: (error: Error) => void;
}

interface SessionInfo {
    userId: string;
    expiresAt: number;
    isValid: boolean;
    timeUntilExpiry: number;
}

const DEFAULT_CHECK_INTERVAL = 60_000; // 1 minute
const DEFAULT_REFRESH_THRESHOLD = 300; // 5 minutes before expiry

/**
 * Hook for managing Supabase session refresh logic on the client side.
 *
 * This hook:
 * - Periodically checks session expiry status
 * - Automatically refreshes tokens before they expire
 * - Handles session expiry gracefully with callbacks
 * - Provides manual refresh functionality
 *
 * @param config - Configuration options for session refresh behavior
 * @returns Object with session info and refresh functions
 *
 * @example
 * ```tsx
 * function AuthenticatedComponent() {
 *   const { sessionInfo, refreshSession, isRefreshing } = useSessionRefresh({
 *     onExpired: () => router.push('/auth/login'),
 *     onError: (err) => toast.error('Session refresh failed'),
 *   });
 *
 *   if (!sessionInfo?.isValid) {
 *     return <SessionExpiredMessage />;
 *   }
 *
 *   return <ProtectedContent />;
 * }
 * ```
 */
export function useSessionRefresh(config: SessionRefreshConfig = {}) {
    const {
        checkIntervalMs = DEFAULT_CHECK_INTERVAL,
        refreshThresholdSeconds = DEFAULT_REFRESH_THRESHOLD,
        onRefresh,
        onExpired,
        onError,
    } = config;

    const supabase = getSupabaseClient();
    const isRefreshingRef = useRef(false);
    const checkIntervalRef = useRef<NodeJS.Timeout | null>(null);

    /**
     * Get current session information
     */
    const getSessionInfo = useCallback(async (): Promise<SessionInfo | null> => {
        try {
            const {
                data: { session },
                error,
            } = await supabase.auth.getSession();

            if (error || !session) {
                return null;
            }

            const now = Math.floor(Date.now() / 1000);
            const expiresAt = session.expires_at ?? 0;
            const timeUntilExpiry = expiresAt - now;
            const isValid = timeUntilExpiry > 0;

            return {
                userId: session.user.id,
                expiresAt,
                isValid,
                timeUntilExpiry,
            };
        } catch (error) {
            console.error('[SessionRefresh] Error getting session info:', error);
            return null;
        }
    }, [supabase]);

    /**
     * Refresh the session manually
     */
    const refreshSession = useCallback(async (): Promise<boolean> => {
        if (isRefreshingRef.current) {
            return false;
        }

        isRefreshingRef.current = true;

        try {
            const {
                data: { session },
                error,
            } = await supabase.auth.refreshSession();

            if (error) {
                console.error('[SessionRefresh] Refresh failed:', error);
                onError?.(new Error(error.message));
                return false;
            }

            if (session) {
                onRefresh?.({
                    userId: session.user.id,
                    expiresAt: session.expires_at ?? 0,
                });
                return true;
            }

            return false;
        } catch (error) {
            const err = error instanceof Error ? error : new Error('Unknown refresh error');
            console.error('[SessionRefresh] Refresh error:', err);
            onError?.(err);
            return false;
        } finally {
            isRefreshingRef.current = false;
        }
    }, [supabase, onRefresh, onError]);

    /**
     * Check session and refresh if needed
     */
    const checkAndRefresh = useCallback(async () => {
        const sessionInfo = await getSessionInfo();

        if (!sessionInfo) {
            // No session exists
            onExpired?.();
            return;
        }

        if (!sessionInfo.isValid) {
            // Session has already expired
            console.warn('[SessionRefresh] Session has expired');
            onExpired?.();
            return;
        }

        // Refresh if session is about to expire
        if (sessionInfo.timeUntilExpiry <= refreshThresholdSeconds) {
            console.log(
                '[SessionRefresh] Session expiring soon, refreshing...',
                `Time until expiry: ${sessionInfo.timeUntilExpiry}s`
            );
            await refreshSession();
        }
    }, [getSessionInfo, refreshSession, refreshThresholdSeconds, onExpired]);

    /**
     * Set up auth state listener for immediate expiry detection
     */
    useEffect(() => {
        const {
            data: { subscription },
        } = supabase.auth.onAuthStateChange((event, session) => {
            if (event === 'TOKEN_REFRESHED') {
                if (session) {
                    onRefresh?.({
                        userId: session.user.id,
                        expiresAt: session.expires_at ?? 0,
                    });
                }
            } else if (event === 'SIGNED_OUT') {
                onExpired?.();
            }
        });

        return () => {
            subscription.unsubscribe();
        };
    }, [supabase, onRefresh, onExpired]);

    /**
     * Set up periodic session check
     */
    useEffect(() => {
        // Initial check
        checkAndRefresh();

        // Set up interval
        checkIntervalRef.current = setInterval(checkAndRefresh, checkIntervalMs);

        return () => {
            if (checkIntervalRef.current) {
                clearInterval(checkIntervalRef.current);
            }
        };
    }, [checkAndRefresh, checkIntervalMs]);

    return {
        /** Get current session information */
        getSessionInfo,
        /** Manually refresh the session */
        refreshSession,
        /** Check session and refresh if needed */
        checkAndRefresh,
        /** Whether a refresh is currently in progress */
        get isRefreshing() {
            return isRefreshingRef.current;
        },
    };
}

/**
 * Hook for components that need to protect content based on session state.
 *
 * @param options - Configuration options
 * @returns Session state and loading status
 *
 * @example
 * ```tsx
 * function ProtectedPage() {
 *   const { isAuthenticated, isLoading, userId } = useSessionState({
 *     redirectTo: '/auth/login',
 *   });
 *
 *   if (isLoading) return <LoadingSpinner />;
 *   if (!isAuthenticated) return null; // Will redirect
 *
 *   return <Dashboard userId={userId} />;
 * }
 * ```
 */
export function useSessionState(options: { redirectTo?: string } = {}) {
    void options; // Options reserved for future use (e.g., redirect behavior)
    const supabase = getSupabaseClient();

    const checkSession = useCallback(async () => {
        const {
            data: { session },
            error,
        } = await supabase.auth.getSession();

        if (error || !session) {
            return { isAuthenticated: false, userId: null };
        }

        return {
            isAuthenticated: true,
            userId: session.user.id,
            expiresAt: session.expires_at ?? 0,
        };
    }, [supabase]);

    return {
        checkSession,
    };
}

export default useSessionRefresh;

