/**
 * MED-006: Split Realtime Channels by Function
 *
 * Provides separate realtime channels for different data types:
 * - Orders channel: For dine-in order updates
 * - External orders channel: For delivery/pickup orders
 * - Tables channel: For table status updates
 * - KDS items channel: For kitchen display item updates
 *
 * Benefits:
 * - Reduced unnecessary traffic by subscribing only to needed channels
 * - Better error isolation - one channel failure doesn't affect others
 * - Independent reconnection logic per channel
 * - More granular connection status tracking
 */

'use client';

import { useEffect, useCallback, useMemo, useRef, useState } from 'react';
import { createClient } from '@/lib/supabase/client';
import type { RealtimeChannel } from '@supabase/supabase-js';

/**
 * Reconnection configuration
 */
const RECONNECT_CONFIG = {
    maxRetries: 5,
    baseDelayMs: 1000,
    maxDelayMs: 30000,
    jitterFactor: 0.3,
};

/**
 * Message deduplication configuration
 */
const DEDUP_CONFIG = {
    dedupWindowMs: 5000,
    maxTrackedMessages: 1000,
};

/**
 * Calculate exponential backoff delay with jitter
 */
function calculateReconnectDelay(retryCount: number): number {
    const delay = Math.min(
        RECONNECT_CONFIG.baseDelayMs * Math.pow(2, retryCount),
        RECONNECT_CONFIG.maxDelayMs
    );
    const jitter = delay * RECONNECT_CONFIG.jitterFactor * Math.random();
    return delay + jitter;
}

/**
 * Generate a unique message ID from realtime payload
 */
function generateMessageId(
    table: string,
    eventType: 'INSERT' | 'UPDATE' | 'DELETE',
    recordId: string
): string {
    return `${table}:${eventType}:${recordId}`;
}

/**
 * Message deduplication tracker
 */
class MessageDeduplicator {
    private processedMessages: Map<string, number> = new Map();
    private cleanupInterval: ReturnType<typeof setInterval> | null = null;

    constructor() {
        this.cleanupInterval = setInterval(() => this.cleanup(), DEDUP_CONFIG.dedupWindowMs);
    }

    isDuplicate(messageId: string): boolean {
        const now = Date.now();
        const lastProcessed = this.processedMessages.get(messageId);

        if (lastProcessed !== undefined && now - lastProcessed < DEDUP_CONFIG.dedupWindowMs) {
            return true;
        }

        this.processedMessages.set(messageId, now);

        if (this.processedMessages.size > DEDUP_CONFIG.maxTrackedMessages) {
            this.cleanup();
        }

        return false;
    }

    private cleanup(): void {
        const now = Date.now();
        const cutoff = now - DEDUP_CONFIG.dedupWindowMs;

        for (const [id, timestamp] of this.processedMessages.entries()) {
            if (timestamp < cutoff) {
                this.processedMessages.delete(id);
            }
        }
    }

    destroy(): void {
        if (this.cleanupInterval) {
            clearInterval(this.cleanupInterval);
            this.cleanupInterval = null;
        }
        this.processedMessages.clear();
    }
}

/**
 * Channel types for split subscriptions
 */
export type ChannelType = 'orders' | 'external_orders' | 'tables' | 'kds_items';

/**
 * Connection status per channel
 */
export type ChannelConnectionStatus = {
    [K in ChannelType]: 'disconnected' | 'connecting' | 'connected' | 'error';
};

/**
 * Realtime payload interface
 */
interface RealtimePayload {
    eventType: 'INSERT' | 'UPDATE' | 'DELETE';
    new: Record<string, unknown>;
    old: Record<string, unknown>;
    schema: string;
    table: string;
    commit_timestamp: string;
}

/**
 * Options for split realtime channels
 */
interface UseSplitRealtimeChannelsOptions {
    restaurantId: string;
    channels: ChannelType[];
    onOrderChange?: (payload: RealtimePayload) => void;
    onExternalOrderChange?: (payload: RealtimePayload) => void;
    onTableChange?: (payload: RealtimePayload) => void;
    onKDSItemChange?: (payload: RealtimePayload) => void;
    enabled?: boolean;
}

/**
 * Hook for split realtime channels by function
 *
 * MED-006: Provides separate channels for different data types
 */
export function useSplitRealtimeChannels({
    restaurantId,
    channels,
    onOrderChange,
    onExternalOrderChange,
    onTableChange,
    onKDSItemChange,
    enabled = true,
}: UseSplitRealtimeChannelsOptions) {
    const supabase = useMemo(() => createClient(), []);
    const mountedRef = useRef(false);

    // Track channels separately
    const channelsRef = useRef<Map<ChannelType, RealtimeChannel>>(new Map());
    const retryCountRef = useRef<Map<ChannelType, number>>(new Map());
    const reconnectTimeoutsRef = useRef<Map<ChannelType, ReturnType<typeof setTimeout>>>(new Map());

    // Deduplicator for all channels
    const deduplicatorRef = useRef<MessageDeduplicator | null>(null);

    // Connection status per channel
    const [connectionStatus, setConnectionStatus] = useState<ChannelConnectionStatus>(() => ({
        orders: 'disconnected',
        external_orders: 'disconnected',
        tables: 'disconnected',
        kds_items: 'disconnected',
    }));

    // Initialize deduplicator
    useEffect(() => {
        deduplicatorRef.current = new MessageDeduplicator();
        return () => {
            deduplicatorRef.current?.destroy();
            deduplicatorRef.current = null;
        };
    }, []);

    /**
     * Check for duplicate messages
     */
    const checkDuplicate = useCallback((payload: RealtimePayload): boolean => {
        const recordId = (payload.new?.id || payload.old?.id) as string;
        if (recordId && deduplicatorRef.current) {
            const messageId = generateMessageId(payload.table, payload.eventType, recordId);
            return deduplicatorRef.current.isDuplicate(messageId);
        }
        return false;
    }, []);

    /**
     * Update connection status for a channel
     */
    const updateStatus = useCallback(
        (
            channelType: ChannelType,
            status: 'disconnected' | 'connecting' | 'connected' | 'error'
        ) => {
            setConnectionStatus(prev => ({
                ...prev,
                [channelType]: status,
            }));
        },
        []
    );

    // Store attemptReconnect in ref for use in setupChannel's subscribe callback
    const attemptReconnectRef = useRef<((channelType: ChannelType) => void) | null>(null);

    /**
     * Attempt to reconnect a specific channel
     */
    const attemptReconnect = useCallback(
        (channelType: ChannelType) => {
            if (!mountedRef.current) return;

            const currentRetry = retryCountRef.current.get(channelType) ?? 0;

            if (currentRetry >= RECONNECT_CONFIG.maxRetries) {
                console.error(`[Realtime] ${channelType}: Max reconnection attempts reached`);
                updateStatus(channelType, 'error');
                return;
            }

            const delay = calculateReconnectDelay(currentRetry);
            console.warn(
                `[Realtime] ${channelType}: Scheduling reconnect attempt ${currentRetry + 1} in ${Math.round(delay)}ms`
            );

            const timeout = setTimeout(() => {
                if (!mountedRef.current) return;

                retryCountRef.current.set(channelType, currentRetry + 1);

                // Unsubscribe existing channel
                const existingChannel = channelsRef.current.get(channelType);
                if (existingChannel) {
                    existingChannel.unsubscribe();
                    channelsRef.current.delete(channelType);
                }

                // Reconnect
                setupChannelRef.current?.(channelType);
            }, delay);

            reconnectTimeoutsRef.current.set(channelType, timeout);
        },
        [updateStatus]
    );

    // Store attemptReconnect in ref
    useEffect(() => {
        attemptReconnectRef.current = attemptReconnect;
    }, [attemptReconnect]);

    // Store setupChannel in ref for use in attemptReconnect
    const setupChannelRef = useRef<((channelType: ChannelType) => void) | null>(null);

    /**
     * Setup a single channel
     */
    const setupChannel = useCallback(
        (channelType: ChannelType) => {
            if (!mountedRef.current || !restaurantId) return;

            updateStatus(channelType, 'connecting');

            const channelName = `${channelType}-${restaurantId}`;

            let channel: RealtimeChannel;

            switch (channelType) {
                case 'orders':
                    channel = supabase.channel(channelName).on(
                        'postgres_changes',
                        {
                            event: '*',
                            schema: 'public',
                            table: 'orders',
                            filter: `restaurant_id=eq.${restaurantId}`,
                        },
                        payload => {
                            if (!mountedRef.current) return;
                            const typedPayload = payload as unknown as RealtimePayload;
                            if (checkDuplicate(typedPayload)) {
                                console.warn(`[Realtime] Skipping duplicate orders message`);
                                return;
                            }
                            onOrderChange?.(typedPayload);
                        }
                    );
                    break;

                case 'external_orders':
                    channel = supabase.channel(channelName).on(
                        'postgres_changes',
                        {
                            event: '*',
                            schema: 'public',
                            table: 'external_orders',
                            filter: `restaurant_id=eq.${restaurantId}`,
                        },
                        payload => {
                            if (!mountedRef.current) return;
                            const typedPayload = payload as unknown as RealtimePayload;
                            if (checkDuplicate(typedPayload)) {
                                console.warn(
                                    `[Realtime] Skipping duplicate external_orders message`
                                );
                                return;
                            }
                            onExternalOrderChange?.(typedPayload);
                        }
                    );
                    break;

                case 'tables':
                    channel = supabase.channel(channelName).on(
                        'postgres_changes',
                        {
                            event: '*',
                            schema: 'public',
                            table: 'tables',
                            filter: `restaurant_id=eq.${restaurantId}`,
                        },
                        payload => {
                            if (!mountedRef.current) return;
                            const typedPayload = payload as unknown as RealtimePayload;
                            if (checkDuplicate(typedPayload)) {
                                console.warn(`[Realtime] Skipping duplicate tables message`);
                                return;
                            }
                            onTableChange?.(typedPayload);
                        }
                    );
                    break;

                case 'kds_items':
                    channel = supabase.channel(channelName).on(
                        'postgres_changes',
                        {
                            event: '*',
                            schema: 'public',
                            table: 'kds_order_items',
                            filter: `restaurant_id=eq.${restaurantId}`,
                        },
                        payload => {
                            if (!mountedRef.current) return;
                            const typedPayload = payload as unknown as RealtimePayload;
                            if (checkDuplicate(typedPayload)) {
                                console.warn(`[Realtime] Skipping duplicate kds_items message`);
                                return;
                            }
                            onKDSItemChange?.(typedPayload);
                        }
                    );
                    break;

                default:
                    console.error(`[Realtime] Unknown channel type: ${channelType}`);
                    return;
            }

            // Subscribe with status handling
            channel.subscribe(status => {
                console.warn(`[Realtime] ${channelType} subscription status: ${status}`);
                if (!mountedRef.current) return;

                if (status === 'SUBSCRIBED') {
                    updateStatus(channelType, 'connected');
                    retryCountRef.current.set(channelType, 0);
                } else if (
                    status === 'CHANNEL_ERROR' ||
                    status === 'CLOSED' ||
                    status === 'TIMED_OUT'
                ) {
                    updateStatus(channelType, 'error');
                    attemptReconnectRef.current?.(channelType);
                }
            });

            channelsRef.current.set(channelType, channel);
        },
        [
            restaurantId,
            supabase,
            updateStatus,
            checkDuplicate,
            onOrderChange,
            onExternalOrderChange,
            onTableChange,
            onKDSItemChange,
        ]
    );

    // Store setupChannel in ref for use in attemptReconnect
    // Using empty deps as setupChannel should be stable within the component lifecycle
    useEffect(() => {
        setupChannelRef.current = setupChannel;
    }, []);

    /**
     * Setup all requested channels
     */
    useEffect(() => {
        if (!enabled || !restaurantId) return;

        mountedRef.current = true;

        // Setup each requested channel
        for (const channelType of channels) {
            retryCountRef.current.set(channelType, 0);
            setupChannel(channelType);
        }

        return () => {
            mountedRef.current = false;

            // Clear all reconnect timeouts
            for (const [, timeout] of reconnectTimeoutsRef.current) {
                clearTimeout(timeout);
            }
            reconnectTimeoutsRef.current.clear();

            // Unsubscribe all channels
            for (const [, channel] of channelsRef.current) {
                channel.unsubscribe();
            }
            channelsRef.current.clear();

            // Reset status
            setConnectionStatus({
                orders: 'disconnected',
                external_orders: 'disconnected',
                tables: 'disconnected',
                kds_items: 'disconnected',
            });
        };
    }, [enabled, restaurantId, channels, setupChannel]);

    /**
     * Check if all requested channels are connected
     */
    const isAllConnected = useMemo(() => {
        return channels.every(ch => connectionStatus[ch] === 'connected');
    }, [channels, connectionStatus]);

    /**
     * Check if any channel has an error
     */
    const hasError = useMemo(() => {
        return channels.some(ch => connectionStatus[ch] === 'error');
    }, [channels, connectionStatus]);

    return {
        connectionStatus,
        isAllConnected,
        hasError,
    };
}

/**
 * Simplified hook for orders-only realtime
 */
export function useOrdersRealtime(options: {
    restaurantId: string;
    onOrderChange?: (payload: RealtimePayload) => void;
    enabled?: boolean;
}) {
    return useSplitRealtimeChannels({
        restaurantId: options.restaurantId,
        channels: ['orders'],
        onOrderChange: options.onOrderChange,
        enabled: options.enabled,
    });
}

/**
 * Simplified hook for KDS realtime (orders + external_orders + kds_items)
 */
export function useKDSChannels(options: {
    restaurantId: string;
    onOrderChange?: (payload: RealtimePayload) => void;
    onExternalOrderChange?: (payload: RealtimePayload) => void;
    onKDSItemChange?: (payload: RealtimePayload) => void;
    enabled?: boolean;
}) {
    return useSplitRealtimeChannels({
        restaurantId: options.restaurantId,
        channels: ['orders', 'external_orders', 'kds_items'],
        onOrderChange: options.onOrderChange,
        onExternalOrderChange: options.onExternalOrderChange,
        onKDSItemChange: options.onKDSItemChange,
        enabled: options.enabled,
    });
}

export default useSplitRealtimeChannels;

import { useState, useCallback, useEffect } from 'react';
import { toast } from 'react-hot-toast';

export type StaffRole = 'owner' | 'admin' | 'manager' | 'kitchen' | 'waiter' | 'bar' | 'runner';

export type StaffMember = {
    id: string;
    user_id: string;
    role: string;
    is_active: boolean | null;
    created_at: string | null;
    name?: string | null;
    full_name?: string | null;
    first_name?: string | null;
    last_name?: string | null;
    email?: string | null;
    pin_code?: string | null;
    assigned_zones?: string[];
};

export const ROLE_BADGE: Record<string, string> = {
    owner: 'bg-black text-white border-black',
    admin: 'bg-gray-900 text-white border-gray-900',
    manager: 'bg-gray-100 text-gray-900 border-gray-200',
    waiter: 'bg-white text-gray-600 border border-gray-100',
    bar: 'bg-white text-gray-600 border border-gray-100',
    kitchen: 'bg-white text-gray-600 border border-gray-100',
    runner: 'bg-white text-gray-400 border border-gray-100',
};

export function useStaff(initialData?: StaffMember[]) {
    const [staff, setStaff] = useState<StaffMember[]>(initialData ?? []);
    const [loading, setLoading] = useState(!initialData);
    const [error, setError] = useState<string | null>(null);
    const [activeUpdatingId, setActiveUpdatingId] = useState<string | null>(null);
    const [inviteLoading, setInviteLoading] = useState(false);
    const [inviteUrl, setInviteUrl] = useState<string | null>(null);

    const fetchStaff = useCallback(async () => {
        try {
            // Only set loading to true if we don't have data yet
            if (staff.length === 0) {
                setLoading(true);
            }
            setError(null);
            const response = await fetch('/api/staff', { method: 'GET' });

            if (!response.ok) {
                let errorMessage = 'Failed to fetch staff.';
                try {
                    const errorPayload = await response.json();
                    errorMessage = errorPayload?.error ?? errorMessage;
                } catch {
                    // unexpected non-json error
                    errorMessage = `Error ${response.status}: ${response.statusText}`;
                }
                throw new Error(errorMessage);
            }

            const payload = await response.json();
            const freshStaff = (payload?.data?.staff ?? []) as StaffMember[];
            setStaff(freshStaff);
        } catch (fetchError) {
            console.error(fetchError);
            setError(fetchError instanceof Error ? fetchError.message : 'Failed to fetch staff.');
        } finally {
            setLoading(false);
        }
    }, [staff.length]);

    // Initial load
    useEffect(() => {
        void fetchStaff();
    }, [fetchStaff]);

    const handleInvite = async (payload: {
        email: string | null;
        role: StaffRole;
        label?: string | null;
    }) => {
        try {
            setInviteLoading(true);
            const response = await fetch('/api/staff/invite', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(payload),
            });
            const result = await response.json();
            if (!response.ok) {
                throw new Error(result?.error ?? 'Failed to create invite.');
            }
            setInviteUrl(result?.data?.invite_url ?? null);
            toast.success('Provisioning link created.');
            return true;
        } catch (inviteError) {
            toast.error(
                inviteError instanceof Error
                    ? inviteError.message
                    : 'Failed to create provisioning link.'
            );
            return false;
        } finally {
            setInviteLoading(false);
        }
    };

    const handleRoleUpdate = async (staffId: string, role: StaffRole) => {
        try {
            const response = await fetch(`/api/staff/${staffId}/role`, {
                method: 'PATCH',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ role }),
            });
            const payload = await response.json();
            if (!response.ok) {
                throw new Error(payload?.error ?? 'Failed to update role.');
            }

            setStaff(previous =>
                previous.map(member => (member.id === staffId ? { ...member, role } : member))
            );
            toast.success('Role updated.');
            return true;
        } catch (roleError) {
            toast.error(roleError instanceof Error ? roleError.message : 'Failed to update role.');
            return false;
        }
    };

    const handleActiveToggle = async (member: StaffMember) => {
        try {
            const nextValue = member.is_active === false;
            setActiveUpdatingId(member.id);
            const response = await fetch(`/api/staff/${member.id}/active`, {
                method: 'PATCH',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ is_active: nextValue }),
            });
            const payload = await response.json();
            if (!response.ok) {
                throw new Error(payload?.error ?? 'Failed to update active status.');
            }

            setStaff(previous =>
                previous.map(staffMember =>
                    staffMember.id === member.id
                        ? { ...staffMember, is_active: nextValue }
                        : staffMember
                )
            );
            toast.success(nextValue ? 'Staff activated.' : 'Staff deactivated.');
            return true;
        } catch (activeError) {
            toast.error(
                activeError instanceof Error
                    ? activeError.message
                    : 'Failed to update active status.'
            );
            return false;
        } finally {
            setActiveUpdatingId(null);
        }
    };

    const handleAddPinStaff = async (payload: {
        name: string;
        role: StaffRole;
        pin_code: string;
        assigned_zones?: string[];
    }) => {
        try {
            setLoading(true);
            const response = await fetch('/api/staff/add-pin', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(payload),
            });
            const result = await response.json();
            if (!response.ok) {
                throw new Error(result?.error ?? 'Failed to add staff member.');
            }

            setStaff(prev => [...prev, result.data.staff]);
            toast.success('Staff member added.');
            return true;
        } catch (err: any) {
            toast.error(err.message || 'Failed to add staff member.');
            return false;
        } finally {
            setLoading(false);
        }
    };

    const handleDeleteStaff = async (staffId: string): Promise<boolean> => {
        // Optimistic remove
        setStaff(prev => prev.filter(s => s.id !== staffId));
        try {
            const response = await fetch(`/api/staff/${staffId}`, { method: 'DELETE' });
            const result = await response.json();
            if (!response.ok) {
                throw new Error(result?.error ?? 'Failed to remove staff member.');
            }
            toast.success('Staff member removed.');
            return true;
        } catch (err: any) {
            toast.error(err.message || 'Failed to remove staff member.');
            void fetchStaff();
            return false;
        }
    };

    return {
        staff,
        loading,
        error,
        activeUpdatingId,
        inviteLoading,
        inviteUrl,
        setInviteUrl,
        fetchStaff,
        handleInvite,
        handleRoleUpdate,
        handleActiveToggle,
        handleAddPinStaff,
        handleDeleteStaff,
    };
}

/**
 * Tests for Rate Limiting Utility
 *
 * Tests Redis-backed rate limiting with in-memory fallback.
 * Covers sliding window algorithm, fallback behavior, and edge cases.
 */

import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { NextRequest } from 'next/server';
import {
    RATE_LIMITS,
    checkRateLimit,
    rateLimitMiddleware,
    withRateLimit,
    type RateLimitConfig,
    type RateLimitResult,
} from '../rate-limit';

// Mock the logger
vi.mock('../logger', () => ({
    logger: {
        warn: vi.fn(),
        error: vi.fn(),
        info: vi.fn(),
        debug: vi.fn(),
    },
}));

// Mock Redis to test fallback behavior
const mockRedis = {
    pipeline: vi.fn(() => ({
        zremrangebyscore: vi.fn().mockReturnThis(),
        zcard: vi.fn().mockReturnThis(),
        exec: vi.fn().mockResolvedValue([null, 0]),
    })),
    zadd: vi.fn().mockResolvedValue(1),
    expire: vi.fn().mockResolvedValue(1),
};

vi.mock('@upstash/redis', () => ({
    Redis: vi.fn(() => mockRedis),
}));

describe('Rate Limiting', () => {
    beforeEach(() => {
        vi.clearAllMocks();
        // Reset environment for each test
        process.env.UPSTASH_REDIS_REST_URL = '';
        process.env.UPSTASH_REDIS_REST_TOKEN = '';
    });

    afterEach(() => {
        vi.restoreAllMocks();
    });

    describe('RATE_LIMITS configuration', () => {
        it('should have correct mutation limits', () => {
            expect(RATE_LIMITS.mutations.limit).toBe(10);
            expect(RATE_LIMITS.mutations.windowSeconds).toBe(60);
            expect(RATE_LIMITS.mutations.keyPrefix).toBe('rl:mut');
        });

        it('should have correct auth limits (stricter)', () => {
            expect(RATE_LIMITS.auth.limit).toBe(5);
            expect(RATE_LIMITS.auth.windowSeconds).toBe(60);
            expect(RATE_LIMITS.auth.keyPrefix).toBe('rl:auth');
        });

        it('should have correct read limits (more generous)', () => {
            expect(RATE_LIMITS.reads.limit).toBe(60);
            expect(RATE_LIMITS.reads.windowSeconds).toBe(60);
            expect(RATE_LIMITS.reads.keyPrefix).toBe('rl:read');
        });
    });

    describe('checkRateLimit', () => {
        it('should return success when under limit', async () => {
            const request = new NextRequest('http://localhost:3000/api/orders', {
                method: 'POST',
                headers: {
                    'x-forwarded-for': '192.168.1.1',
                },
            });

            const config: RateLimitConfig = {
                limit: 5,
                windowSeconds: 60,
                keyPrefix: 'test',
            };

            const result = await checkRateLimit(request, config);

            expect(result.success).toBe(true);
            expect(result.limit).toBe(5);
            expect(result.remaining).toBeGreaterThanOrEqual(0);
            expect(result.reset).toBeGreaterThan(0);
        });

        it('should use x-real-ip header when x-forwarded-for is not present', async () => {
            const request = new NextRequest('http://localhost:3000/api/orders', {
                method: 'POST',
                headers: {
                    'x-real-ip': '10.0.0.1',
                },
            });

            const config: RateLimitConfig = {
                limit: 5,
                windowSeconds: 60,
                keyPrefix: 'test',
            };

            const result = await checkRateLimit(request, config);

            expect(result.success).toBe(true);
        });

        it('should fallback to 127.0.0.1 when no IP headers are present', async () => {
            const request = new NextRequest('http://localhost:3000/api/orders', {
                method: 'POST',
            });

            const config: RateLimitConfig = {
                limit: 5,
                windowSeconds: 60,
                keyPrefix: 'test',
            };

            const result = await checkRateLimit(request, config);

            expect(result.success).toBe(true);
        });

        it('should handle multiple requests and track count', async () => {
            const request = new NextRequest('http://localhost:3000/api/orders', {
                method: 'POST',
                headers: {
                    'x-forwarded-for': '192.168.1.2',
                },
            });

            const config: RateLimitConfig = {
                limit: 3,
                windowSeconds: 60,
                keyPrefix: 'test-multi',
            };

            // First request
            const result1 = await checkRateLimit(request, config);
            expect(result1.success).toBe(true);
            expect(result1.remaining).toBe(2);

            // Second request
            const result2 = await checkRateLimit(request, config);
            expect(result2.success).toBe(true);
            expect(result2.remaining).toBe(1);

            // Third request
            const result3 = await checkRateLimit(request, config);
            expect(result3.success).toBe(true);
            expect(result3.remaining).toBe(0);

            // Fourth request should be rate limited
            const result4 = await checkRateLimit(request, config);
            expect(result4.success).toBe(false);
            expect(result4.remaining).toBe(0);
        });
    });

    describe('rateLimitMiddleware', () => {
        it('should return null for GET requests (no rate limiting)', async () => {
            const request = new NextRequest('http://localhost:3000/api/orders', {
                method: 'GET',
                headers: {
                    'x-forwarded-for': '192.168.1.3',
                },
            });

            const result = await rateLimitMiddleware(request);

            expect(result).toBeNull();
        });

        it('should return null for non-API paths', async () => {
            const request = new NextRequest('http://localhost:3000/orders', {
                method: 'POST',
                headers: {
                    'x-forwarded-for': '192.168.1.4',
                },
            });

            const result = await rateLimitMiddleware(request);

            expect(result).toBeNull();
        });

        it('should apply rate limiting to POST requests to API endpoints', async () => {
            const request = new NextRequest('http://localhost:3000/api/orders', {
                method: 'POST',
                headers: {
                    'x-forwarded-for': '192.168.1.5',
                },
            });

            const result = await rateLimitMiddleware(request);

            // Should return null (continue) for first request
            expect(result).toBeNull();
        });

        it('should return 429 response when rate limit exceeded', async () => {
            const ip = '192.168.1.6';
            const request = new NextRequest('http://localhost:3000/api/orders', {
                method: 'POST',
                headers: {
                    'x-forwarded-for': ip,
                },
            });

            // Make multiple requests to exceed the limit
            // Default mutation limit is 10, so we need 11 requests
            for (let i = 0; i < 11; i++) {
                const result = await rateLimitMiddleware(request);

                if (i < 10) {
                    expect(result).toBeNull();
                } else {
                    expect(result).not.toBeNull();
                    expect(result?.status).toBe(429);

                    const body = await result?.json();
                    expect(body.error.code).toBe('RATE_LIMIT_EXCEEDED');
                    expect(result?.headers.get('X-RateLimit-Limit')).toBe('10');
                    expect(result?.headers.get('X-RateLimit-Remaining')).toBe('0');
                    expect(result?.headers.get('Retry-After')).toBeDefined();
                }
            }
        });

        it('should apply stricter rate limiting to auth endpoints', async () => {
            const ip = '192.168.1.7';
            const request = new NextRequest('http://localhost:3000/api/auth/login', {
                method: 'POST',
                headers: {
                    'x-forwarded-for': ip,
                },
            });

            // Auth limit is 5, so 6th request should be rate limited
            for (let i = 0; i < 6; i++) {
                const result = await rateLimitMiddleware(request);

                if (i < 5) {
