                },
            });

            const config: RateLimitConfig = {
                limit: 5,
                windowSeconds: 60,
                keyPrefix: 'test-ipv6',
            };

            const result = await checkRateLimit(request, config);

            expect(result.success).toBe(true);
        });

        it('should handle multiple IPs in x-forwarded-for (use first)', async () => {
            const request = new NextRequest('http://localhost:3000/api/orders', {
                method: 'POST',
                headers: {
                    'x-forwarded-for': '192.168.1.12, 10.0.0.1, 172.16.0.1',
                },
            });

            const config: RateLimitConfig = {
                limit: 5,
                windowSeconds: 60,
                keyPrefix: 'test-multi-ip',
            };

            const result = await checkRateLimit(request, config);

            expect(result.success).toBe(true);
        });

        it('should handle different paths separately', async () => {
            const config: RateLimitConfig = {
                limit: 2,
                windowSeconds: 60,
                keyPrefix: 'test-paths',
            };

            // Request to /api/orders
            const request1 = new NextRequest('http://localhost:3000/api/orders', {
                method: 'POST',
                headers: {
                    'x-forwarded-for': '192.168.1.13',
                },
            });

            // Request to /api/payments
            const request2 = new NextRequest('http://localhost:3000/api/payments', {
                method: 'POST',
                headers: {
                    'x-forwarded-for': '192.168.1.13',
                },
            });

            // Both should succeed as they're different paths
            const result1 = await checkRateLimit(request1, config);
            const result2 = await checkRateLimit(request2, config);

            expect(result1.success).toBe(true);
            expect(result2.success).toBe(true);
        });

        it('should handle concurrent requests correctly', async () => {
            const config: RateLimitConfig = {
                limit: 5,
                windowSeconds: 60,
                keyPrefix: 'test-concurrent',
            };

            const request = new NextRequest('http://localhost:3000/api/orders', {
                method: 'POST',
                headers: {
                    'x-forwarded-for': '192.168.1.14',
                },
            });

            // Make 5 concurrent requests
            const results = await Promise.all([
                checkRateLimit(request, config),
                checkRateLimit(request, config),
                checkRateLimit(request, config),
                checkRateLimit(request, config),
                checkRateLimit(request, config),
            ]);

            // All should succeed (within limit)
            results.forEach(result => {
                expect(result.success).toBe(true);
            });

            // 6th request should fail
            const result = await checkRateLimit(request, config);
            expect(result.success).toBe(false);
        });
    });
});

/**
 * Telegram Alerts Module
 *
 * Provides alerting via Telegram for critical production events.
 * Used for:
 * - Health check failures (via Better Uptime integration)
 * - Payment webhook failures
 * - ERCA submission backlogs
 * - EOD reports
 * - Manual operational alerts
 *
 * @see docs/1. Engineering Foundation/0. ENTERPRISE_MASTER_BLUEPRINT.md - Sprint 7.6
 * @see docs/1. Engineering Foundation/6. ENGINEERING_RUNOOK.md - Monitoring Checklist
 */

/**
 * Alert severity levels
 */
export type AlertLevel = 'critical' | 'warning' | 'info';

/**
 * Alert context for additional debugging information
 */
export interface AlertContext {
    restaurantId?: string;
    restaurantName?: string;
    orderId?: string;
    paymentId?: string;
    userId?: string;
    deviceType?: 'pos' | 'kds' | 'guest' | 'dashboard';
    error?: string;
    stack?: string;
    metadata?: Record<string, unknown>;
    [key: string]: unknown;
}

/**
 * Telegram message payload
 */
interface TelegramMessage {
    chat_id: string;
    text: string;
    parse_mode?: 'HTML' | 'Markdown' | 'MarkdownV2';
    disable_notification?: boolean;
}

/**
 * Telegram API response
 */
interface TelegramResponse {
    ok: boolean;
    result?: unknown;
    description?: string;
    error_code?: number;
}

/**
 * Get severity emoji for alert level
 */
function getSeverityEmoji(level: AlertLevel): string {
    switch (level) {
        case 'critical':
            return '🚨';
        case 'warning':
            return '⚠️';
        case 'info':
            return 'ℹ️';
        default:
            return '📢';
    }
}

/**
 * Get severity prefix for alert level
 */
function getSeverityPrefix(level: AlertLevel): string {
    switch (level) {
        case 'critical':
            return 'CRITICAL';
        case 'warning':
            return 'WARNING';
        case 'info':
            return 'INFO';
        default:
            return 'ALERT';
    }
}

/**
 * Format alert message for Telegram (HTML format)
 */
function formatMessage(level: AlertLevel, message: string, context?: AlertContext): string {
    const emoji = getSeverityEmoji(level);
    const prefix = getSeverityPrefix(level);
    const timestamp = new Date().toISOString();

    const lines: string[] = [
        `${emoji} <b>[${prefix}]</b>`,
        '',
        `<b>${escapeHtml(message)}</b>`,
        '',
        `<i>Time: ${timestamp}</i>`,
    ];

    // Add environment if available
    if (process.env.NODE_ENV && process.env.NODE_ENV !== 'development') {
        lines.push(`<i>Environment: ${process.env.NODE_ENV}</i>`);
    }

    // Add context
    if (context) {
        lines.push('');
        lines.push('<b>Context:</b>');

        if (context.restaurantId) {
            const restaurantInfo = context.restaurantName
                ? `${context.restaurantName} (${context.restaurantId})`
                : context.restaurantId;
            lines.push(`• Restaurant: ${escapeHtml(restaurantInfo)}`);
        }

        if (context.orderId) {
            lines.push(`• Order: <code>${escapeHtml(context.orderId)}</code>`);
        }

        if (context.paymentId) {
            lines.push(`• Payment: <code>${escapeHtml(context.paymentId)}</code>`);
        }

        if (context.userId) {
            lines.push(`• User: <code>${escapeHtml(context.userId)}</code>`);
        }

        if (context.deviceType) {
            lines.push(`• Device: ${context.deviceType.toUpperCase()}`);
        }

        if (context.error) {
            lines.push(`• Error: <pre>${escapeHtml(context.error)}</pre>`);
        }

        if (context.metadata && Object.keys(context.metadata).length > 0) {
            lines.push('• Additional:');
            for (const [key, value] of Object.entries(context.metadata)) {
                lines.push(`  - ${key}: ${escapeHtml(String(value))}`);
            }
        }
    }

    // Add stack trace if available (truncate to avoid Telegram limits)
    if (context?.stack) {
        lines.push('');
        lines.push('<b>Stack Trace:</b>');
        const truncatedStack =
            context.stack.length > 500 ? context.stack.slice(0, 500) + '...' : context.stack;
        lines.push(`<pre>${escapeHtml(truncatedStack)}</pre>`);
    }

    return lines.join('\n');
}

/**
 * Escape HTML special characters for Telegram
 */
function escapeHtml(text: string): string {
    return text.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

/**
 * Send an alert via Telegram
 *
 * @param level - Alert severity (critical, warning, info)
 * @param message - Human-readable alert message
 * @param context - Additional context for debugging
 * @returns Promise<boolean> - true if sent successfully
 *
 * @example
 * // Critical alert for POS down
 * await sendAlert('critical', 'POS offline at Saba Grill', {
 *   restaurantId: 'rest-123',
 *   restaurantName: 'Saba Grill',
 *   deviceType: 'pos',
 *   error: 'Connection timeout after 30s'
 * });
 *
 * @example
 * // Warning for payment webhook issue
 * await sendAlert('warning', 'Chapa webhook verification failed', {
 *   restaurantId: 'rest-456',
 *   paymentId: 'pay-789',
 *   error: 'Invalid HMAC signature'
 * });
 *
 * @example
 * // Info for EOD report
 * await sendAlert('info', 'EOD report sent for Saba Grill', {
 *   restaurantId: 'rest-123',
 *   metadata: { totalOrders: 47, revenue: 15750 }
 * });
 */
export async function sendAlert(
    level: AlertLevel,
    message: string,
    context?: AlertContext
): Promise<boolean> {
    const botToken = process.env.TELEGRAM_BOT_TOKEN;
    const chatId = process.env.TELEGRAM_ALERT_CHAT_ID;

    // If not configured, log to console in development
    if (!botToken || !chatId) {
        if (process.env.NODE_ENV === 'development') {
            console.log(
                `[TELEGRAM ALERT - ${level.toUpperCase()}] ${message}`,
                context ? JSON.stringify(context, null, 2) : ''
            );
        }
        return false;
    }

    // Format message
    const formattedMessage = formatMessage(level, message, context);

    // Prepare Telegram API request
    const payload: TelegramMessage = {
        chat_id: chatId,
        text: formattedMessage,
        parse_mode: 'HTML',
        // Don't notify for info-level alerts during off-hours
        disable_notification: level === 'info',
    };

    try {
        const response = await fetch(`https://api.telegram.org/bot${botToken}/sendMessage`, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
            },
            body: JSON.stringify(payload),
        });

        const result = (await response.json()) as TelegramResponse;

        if (!result.ok) {
            console.error('Telegram alert failed:', {
                error_code: result.error_code,
                description: result.description,
            });
            return false;
        }

        return true;
    } catch (error) {
        console.error('Failed to send Telegram alert:', error);
        return false;
    }
}

/**
 * Send a critical alert
 * Used for: POS down, payments failing, orders not reaching KDS
 * Expected response time: 10 minutes
 */
export async function sendCriticalAlert(message: string, context?: AlertContext): Promise<boolean> {
    return sendAlert('critical', message, context);
}

/**
 * Send a warning alert
 * Used for: Slow API responses, ERCA backlog, EOD reports not sending
 * Expected response time: 1 hour
 */
export async function sendWarningAlert(message: string, context?: AlertContext): Promise<boolean> {
    return sendAlert('warning', message, context);
}

/**
 * Send an info alert
 * Used for: EOD reports, non-urgent notifications
 */
export async function sendInfoAlert(message: string, context?: AlertContext): Promise<boolean> {
    return sendAlert('info', message, context);
}

/**
 * Send EOD (End of Day) report for a restaurant
 *
 * @param restaurantId - Restaurant identifier
 * @param restaurantName - Human-readable name
 * @param data - EOD summary data
 */
export async function sendEodReport(
    restaurantId: string,
    restaurantName: string,
    data: {
        totalOrders: number;
        totalRevenue: number;
        totalGuests: number;
        topItems: Array<{ name: string; quantity: number }>;
        paymentBreakdown: Record<string, number>;
    }
): Promise<boolean> {
    const lines: string[] = [
        `📊 <b>EOD Report - ${escapeHtml(restaurantName)}</b>`,
        '',
        `<i>${new Date().toLocaleDateString('en-ET', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}</i>`,
        '',
        `<b>Orders:</b> ${data.totalOrders}`,
        `<b>Guests:</b> ${data.totalGuests}`,
        `<b>Revenue:</b> ETB ${data.totalRevenue.toLocaleString()}`,
        '',
        '<b>Payment Methods:</b>',
    ];

    for (const [method, amount] of Object.entries(data.paymentBreakdown)) {
        lines.push(`• ${method}: ETB ${amount.toLocaleString()}`);
    }

    if (data.topItems.length > 0) {
        lines.push('');
        lines.push('<b>Top Items:</b>');
        for (const item of data.topItems.slice(0, 5)) {
            lines.push(`• ${escapeHtml(item.name)}: ${item.quantity}x`);
        }
    }

    const botToken = process.env.TELEGRAM_BOT_TOKEN;
    const chatId = process.env.TELEGRAM_ALERT_CHAT_ID;

    // Fallback to console in development
    if (!botToken || !chatId) {
        if (process.env.NODE_ENV === 'development') {
            console.log('[EOD REPORT]', lines.join('\n'));
        }
        return false;
    }

    try {
        const response = await fetch(`https://api.telegram.org/bot${botToken}/sendMessage`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                chat_id: chatId,
                text: lines.join('\n'),
                parse_mode: 'HTML',
            }),
        });

        const result = (await response.json()) as TelegramResponse;
        return result.ok;
    } catch (error) {
        console.error('Failed to send EOD report:', error);
        return false;
    }
}

/**
 * Check if Telegram alerts are configured
 */
export function isTelegramConfigured(): boolean {
    return !!(process.env.TELEGRAM_BOT_TOKEN && process.env.TELEGRAM_ALERT_CHAT_ID);
}

/**
 * Test Telegram configuration by sending a test message
 *
 * @returns Promise<boolean> - true if test message sent successfully
 */
export async function testTelegramConnection(): Promise<boolean> {
    if (!isTelegramConfigured()) {
        console.warn('Telegram alerts not configured');
        return false;
    }

    return sendInfoAlert('Telegram alert configuration test - connection successful', {
        metadata: {
            environment: process.env.NODE_ENV || 'unknown',
            timestamp: new Date().toISOString(),
        },
    });
}

import type { SupabaseClient } from '@supabase/supabase-js';
import type { Database, Json } from '@/types/database';

type TrackApiMetricParams = {
    restaurantId?: string | null;
    endpoint: string;
    method: string;
    statusCode: number;
    durationMs: number;
};

export const API_METRIC_ACTION = 'api_metric_recorded';
export const API_METRIC_ENTITY_TYPE = 'api_endpoint';

export async function trackApiMetric(
    supabase: SupabaseClient<Database>,
    params: TrackApiMetricParams
) {
    const isError = params.statusCode >= 400;

    const metadata: Json = {
        endpoint: params.endpoint,
        method: params.method.toUpperCase(),
        status_code: params.statusCode,
        duration_ms: params.durationMs,
        is_error: isError,
        source: 'api_observability',
    };

    try {
        if (typeof (supabase as any).from !== 'function') {
            return { error: null };
        }

        const query = supabase.from('audit_logs') as any;
        if (typeof query.insert !== 'function') {
            return { error: null };
        }

        const { error } = await query.insert({
            restaurant_id: params.restaurantId ?? null,
            action: API_METRIC_ACTION,
            entity_type: API_METRIC_ENTITY_TYPE,
            metadata,
            new_value: {
                endpoint: params.endpoint,
                status_code: params.statusCode,
                duration_ms: params.durationMs,
                is_error: isError,
            } as Json,
        });

        return { error };
    } catch {
        return { error: null };
    }
}

/**
 * Request Size Limits
 *
 * LOW-010: Add request size limits to prevent abuse
 * Limits request body size for API routes to prevent DoS attacks
 */

import { NextRequest, NextResponse } from 'next/server';

/**
 * Default size limits for different content types (in bytes)
 */
export const DEFAULT_SIZE_LIMITS = {
    // Default limit for JSON requests (100KB)
    json: 100 * 1024,
    // Default limit for form data (10MB - for file uploads)
    formData: 10 * 1024 * 1024,
    // Default limit for text/plain (1MB)
    text: 1024 * 1024,
    // Default limit for unknown content types (10KB)
    default: 10 * 1024,
};

/**
 * Size limits configuration per route pattern
 */
export const ROUTE_SIZE_LIMITS: Record<string, Partial<typeof DEFAULT_SIZE_LIMITS>> = {
    // Menu items with images can be larger
    '/api/menu': {
        json: 500 * 1024, // 500KB
        formData: 20 * 1024 * 1024, // 20MB
    },
    // Orders should be smaller
    '/api/orders': {
        json: 50 * 1024, // 50KB
    },
    // Payments should be minimal
    '/api/payments': {
        json: 10 * 1024, // 10KB
    },
    // Webhooks can vary
    '/api/webhooks': {
        json: 500 * 1024, // 500KB
    },
    // Guest orders
    '/api/guest': {
        json: 50 * 1024, // 50KB
    },
    // Delivery aggregator orders
    '/api/delivery': {
        json: 100 * 1024, // 100KB
    },
};

/**
 * Get the size limit for a request
 */
export function getSizeLimit(pathname: string, contentType: string): number {
    // Find matching route pattern
    let routeLimits: Partial<typeof DEFAULT_SIZE_LIMITS> = {};

    for (const [pattern, limits] of Object.entries(ROUTE_SIZE_LIMITS)) {
        if (pathname.startsWith(pattern)) {
            routeLimits = limits;
            break;
        }
    }

    // Determine content type category
    if (contentType.includes('application/json')) {
        return routeLimits.json ?? DEFAULT_SIZE_LIMITS.json;
    }

    if (contentType.includes('multipart/form-data')) {
        return routeLimits.formData ?? DEFAULT_SIZE_LIMITS.formData;
    }

    if (contentType.includes('text/plain')) {
        return routeLimits.text ?? DEFAULT_SIZE_LIMITS.text;
    }

    return routeLimits.default ?? DEFAULT_SIZE_LIMITS.default;
}

/**
 * Check if request body exceeds size limit
 *
 * @param request - The Next.js request object
 * @param customLimit - Optional custom limit in bytes
 * @returns Object with isValid flag and error message if invalid
 */
export async function checkRequestSize(
    request: NextRequest,
    customLimit?: number
): Promise<{ isValid: boolean; error?: string; size?: number }> {
    const contentType = request.headers.get('content-type') || '';
    const contentLength = request.headers.get('content-length');

    // If Content-Length header is present, check it first
    if (contentLength) {
        const size = parseInt(contentLength, 10);
        const limit = customLimit ?? getSizeLimit(request.nextUrl.pathname, contentType);

        if (size > limit) {
            return {
                isValid: false,
                error: `Request body too large. Maximum allowed: ${formatBytes(limit)}`,
                size,
            };
        }

        return { isValid: true, size };
    }

    // For chunked transfer encoding, we need to read the body
    // This is more expensive but necessary for streaming requests
    try {
        const clone = request.clone();
        const body = await clone.text();
        const size = Buffer.byteLength(body, 'utf8');
        const limit = customLimit ?? getSizeLimit(request.nextUrl.pathname, contentType);

        if (size > limit) {
            return {
                isValid: false,
                error: `Request body too large. Maximum allowed: ${formatBytes(limit)}`,
                size,
            };
        }

        return { isValid: true, size };
    } catch (error) {
        // If we can't read the body, allow the request to proceed
        // The route handler will handle any actual issues
        return { isValid: true };
    }
}

/**
 * Middleware to enforce request size limits
 *
 * @param request - The Next.js request object
 * @param options - Configuration options
 * @returns NextResponse if request should be rejected, null otherwise
 */
export async function requestSizeMiddleware(
    request: NextRequest,
    options?: {
        customLimits?: Partial<typeof DEFAULT_SIZE_LIMITS>;
        routes?: Record<string, Partial<typeof DEFAULT_SIZE_LIMITS>>;
    }
): Promise<NextResponse | null> {
    // Only check requests with a body
    const method = request.method.toUpperCase();
    if (!['POST', 'PUT', 'PATCH'].includes(method)) {
        return null;
    }

    const contentType = request.headers.get('content-type') || '';

    // Determine limit
    let limit: number;
    if (options?.customLimits) {
        const mergedLimits = { ...DEFAULT_SIZE_LIMITS, ...options.customLimits };
        if (contentType.includes('application/json')) {
            limit = mergedLimits.json;
        } else if (contentType.includes('multipart/form-data')) {
            limit = mergedLimits.formData;
        } else if (contentType.includes('text/plain')) {
            limit = mergedLimits.text;
        } else {
            limit = mergedLimits.default;
        }
    } else {
        limit = getSizeLimit(request.nextUrl.pathname, contentType);
    }

    // Check route-specific limits
    if (options?.routes) {
        for (const [pattern, routeLimits] of Object.entries(options.routes)) {
            if (request.nextUrl.pathname.startsWith(pattern)) {
                if (contentType.includes('application/json') && routeLimits.json) {
                    limit = routeLimits.json;
                } else if (contentType.includes('multipart/form-data') && routeLimits.formData) {
                    limit = routeLimits.formData;
                }
                break;
            }
        }
    }

    const result = await checkRequestSize(request, limit);

    if (!result.isValid) {
        return NextResponse.json(
            {
                error: {
                    code: 'REQUEST_TOO_LARGE',
                    message: result.error,
                },
            },
            { status: 413 }
        );
    }

    return null;
}

/**
 * Format bytes to human-readable string
 */
function formatBytes(bytes: number): string {
    if (bytes < 1024) {
        return `${bytes} bytes`;
    }

    if (bytes < 1024 * 1024) {
        return `${(bytes / 1024).toFixed(1)} KB`;
    }

    return `${(bytes / (1024 * 1024)).toFixed(1)} MB`;
}

/**
 * Higher-order function to wrap API handlers with size limits
 *
 * @param handler - The original API route handler
 * @param options - Size limit options
 * @returns Wrapped handler with size checking
 */
export function withRequestSizeLimit(
    handler: (request: NextRequest, context: unknown) => Promise<NextResponse>,
    options?: {
        limit?: number;
        limits?: Partial<typeof DEFAULT_SIZE_LIMITS>;
    }
): (request: NextRequest, context: unknown) => Promise<NextResponse> {
    return async (request: NextRequest, context: unknown) => {
        const method = request.method.toUpperCase();

        if (['POST', 'PUT', 'PATCH'].includes(method)) {
            const contentType = request.headers.get('content-type') || '';
            let limit = options?.limit;

            if (!limit && options?.limits) {
                if (contentType.includes('application/json')) {
                    limit = options.limits.json ?? DEFAULT_SIZE_LIMITS.json;
                } else if (contentType.includes('multipart/form-data')) {
                    limit = options.limits.formData ?? DEFAULT_SIZE_LIMITS.formData;
                } else if (contentType.includes('text/plain')) {
                    limit = options.limits.text ?? DEFAULT_SIZE_LIMITS.text;
                } else {
                    limit = options.limits.default ?? DEFAULT_SIZE_LIMITS.default;
                }
            }

            const result = await checkRequestSize(request, limit);

            if (!result.isValid) {
                return NextResponse.json(
                    {
                        error: {
                            code: 'REQUEST_TOO_LARGE',
                            message: result.error,
                        },
                    },
                    { status: 413 }
                );
            }
        }

        return handler(request, context);
    };
}

/**
 * Export types for external use
 */
export type SizeLimits = typeof DEFAULT_SIZE_LIMITS;

/**
 * Request Tracing Utilities
 *
 * MED-026: Implements request ID propagation for distributed tracing.
 * Provides middleware and utilities for tracking requests across services.
 *
 * @module lib/api/tracing
 */

import { NextRequest, NextResponse } from 'next/server';
import { logger } from '../logger';

/**
 * Header names for tracing
 */
export const TRACING_HEADERS = {
    /** Request ID header */
    requestId: 'x-request-id',
    /** Trace ID header (for distributed tracing) */
    traceId: 'x-trace-id',
    /** Span ID header */
    spanId: 'x-span-id',
    /** Parent span ID header */
    parentSpanId: 'x-parent-span-id',
    /** Baggage header for context propagation */
    baggage: 'x-baggage',
    /** Origin service header */
    origin: 'x-origin-service',
} as const;

/**
 * Trace context interface
 */
export interface TraceContext {
    /** Unique request ID */
    requestId: string;
    /** Distributed trace ID (shared across services) */
    traceId: string;
    /** Current span ID */
    spanId: string;
    /** Parent span ID (if this is a child span) */
    parentSpanId?: string;
    /** Origin service name */
    origin?: string;
    /** Baggage items (key-value pairs for context propagation) */
    baggage?: Record<string, string>;
    /** Start time of the request */
    startTime: number;
}

/**
 * Generate a unique ID for tracing
 */
function generateTraceId(): string {
    // Generate a 32-character hex string (16 bytes)
    return crypto.randomUUID().replace(/-/g, '');
}

/**
 * Generate a span ID
 */
function generateSpanId(): string {
    // Generate a 16-character hex string (8 bytes)
    return crypto.randomUUID().replace(/-/g, '').slice(0, 16);
}

/**
 * Parse baggage header
 */
function parseBaggage(header: string | null): Record<string, string> {
    if (!header) return {};

    const baggage: Record<string, string> = {};
    const items = header.split(',');

    for (const item of items) {
        const [key, value] = item.trim().split('=');
        if (key && value) {
            baggage[decodeURIComponent(key)] = decodeURIComponent(value);
        }
    }

    return baggage;
}

/**
 * Format baggage for header
 */
export function formatBaggage(baggage: Record<string, string>): string {
    return Object.entries(baggage)
        .map(([key, value]) => `${encodeURIComponent(key)}=${encodeURIComponent(value)}`)
        .join(',');
}

/**
 * Extract trace context from request headers
 */
export function extractTraceContext(request: NextRequest): TraceContext {
    const requestId = request.headers.get(TRACING_HEADERS.requestId) || crypto.randomUUID();
    const traceId = request.headers.get(TRACING_HEADERS.traceId) || generateTraceId();
    const spanId = generateSpanId();
    const parentSpanId = request.headers.get(TRACING_HEADERS.spanId) || undefined;
    const origin = request.headers.get(TRACING_HEADERS.origin) || undefined;
    const baggage = parseBaggage(request.headers.get(TRACING_HEADERS.baggage));

    return {
        requestId,
        traceId,
        spanId,
        parentSpanId,
        origin,
        baggage: Object.keys(baggage).length > 0 ? baggage : undefined,
        startTime: Date.now(),
    };
}

/**
 * Create trace headers for outgoing requests
 */
export function createTraceHeaders(context: TraceContext): Record<string, string> {
    const headers: Record<string, string> = {
        [TRACING_HEADERS.requestId]: context.requestId,
        [TRACING_HEADERS.traceId]: context.traceId,
        [TRACING_HEADERS.spanId]: generateSpanId(), // New span ID for outgoing request
        [TRACING_HEADERS.parentSpanId]: context.spanId, // Current span becomes parent
    };

    if (context.origin) {
        headers[TRACING_HEADERS.origin] = context.origin;
    }

    if (context.baggage) {
        headers[TRACING_HEADERS.baggage] = formatBaggage(context.baggage);
    }

    return headers;
}

/**
 * Add trace headers to a response
 */
export function addTraceHeaders(response: NextResponse, context: TraceContext): void {
    response.headers.set(TRACING_HEADERS.requestId, context.requestId);
    response.headers.set(TRACING_HEADERS.traceId, context.traceId);
    response.headers.set(TRACING_HEADERS.spanId, context.spanId);
}

/**
 * Trace context storage - Edge Runtime compatible
 * Note: AsyncLocalStorage is not available in Edge Runtime,
 * so we use a simple module-level variable for middleware context.
 */
let currentTraceContext: TraceContext | undefined;

/**
 * Get the current trace context
 */
export function getCurrentTraceContext(): TraceContext | undefined {
    return currentTraceContext;
}

/**
 * Run a function within a trace context
 */
export function withTraceContext<T>(context: TraceContext, fn: () => T): T {
    const previousContext = currentTraceContext;
    currentTraceContext = context;
    try {
        return fn();
    } finally {
        currentTraceContext = previousContext;
    }
}

/**
 * Create a child span for a sub-operation
 */
export function createChildSpan(operationName: string): TraceContext {
    const parent = getCurrentTraceContext();

    if (parent) {
        return {
            requestId: parent.requestId,
            traceId: parent.traceId,
            spanId: generateSpanId(),
            parentSpanId: parent.spanId,
            origin: parent.origin,
            baggage: parent.baggage,
            startTime: Date.now(),
        };
    }

    // No parent context, create a new one
    return {
        requestId: crypto.randomUUID(),
        traceId: generateTraceId(),
        spanId: generateSpanId(),
        startTime: Date.now(),
    };
}

/**
 * Log with trace context
 */
export function logWithContext(
    level: 'debug' | 'info' | 'warn' | 'error',
    message: string,
    context?: Record<string, unknown>
): void {
    const traceContext = getCurrentTraceContext();
    const logContext = {
        ...context,
        ...(traceContext && {
            requestId: traceContext.requestId,
            traceId: traceContext.traceId,
            spanId: traceContext.spanId,
        }),
    };

    switch (level) {
        case 'debug':
            logger.debug(message, logContext);
            break;
        case 'info':
            logger.info(message, logContext);
            break;
        case 'warn':
            logger.warn(message, logContext);
            break;
        case 'error':
            logger.error(message, undefined, logContext);
            break;
    }
}

/**
 * Trace middleware for Next.js
 * Extracts or creates trace context and adds to response headers
 */
export function tracingMiddleware(request: NextRequest): {
    context: TraceContext;
    addHeaders: (response: NextResponse) => void;
} {
    const context = extractTraceContext(request);

    // Log incoming request with trace context
    logger.info(`Incoming request: ${request.method} ${request.nextUrl.pathname}`, {
        requestId: context.requestId,
        traceId: context.traceId,
        method: request.method,
        path: request.nextUrl.pathname,
        origin: context.origin,
    });

    return {
        context,
        addHeaders: (response: NextResponse) => {
            addTraceHeaders(response, context);

            // Add timing header
            const duration = Date.now() - context.startTime;
            response.headers.set('x-response-time', `${duration}ms`);
        },
    };
}

/**
 * Span timing utility for performance tracking
 */
export class SpanTimer {
    private startTime: number;
    private context: TraceContext;
    private operationName: string;

    constructor(operationName: string, context?: TraceContext) {
        this.operationName = operationName;
        this.context = context ||
            getCurrentTraceContext() || {
                requestId: crypto.randomUUID(),
                traceId: generateTraceId(),
                spanId: generateSpanId(),
                startTime: Date.now(),
            };
        this.startTime = Date.now();
    }

    /**
     * End the span and log the duration
     */
    end(metadata?: Record<string, unknown>): number {
        const duration = Date.now() - this.startTime;

        logger.debug(`Span completed: ${this.operationName}`, {
            requestId: this.context.requestId,
            traceId: this.context.traceId,
            spanId: this.context.spanId,
            operation: this.operationName,
            durationMs: duration,
            ...metadata,
        });

        return duration;
    }

    /**
     * Get current duration without ending
     */
    getDuration(): number {
        return Date.now() - this.startTime;
    }

    /**
     * Get the trace context
     */
    getContext(): TraceContext {
        return this.context;
    }
}

/**
 * Decorator for tracing async functions
 */
export function traced<T extends (...args: unknown[]) => Promise<unknown>>(
    operationName: string
): (
    target: unknown,
    propertyKey: string,
    descriptor: TypedPropertyDescriptor<T>
) => TypedPropertyDescriptor<T> {
    return function (
        target: unknown,
        propertyKey: string,
        descriptor: TypedPropertyDescriptor<T>
    ): TypedPropertyDescriptor<T> {
        const originalMethod = descriptor.value;

        if (!originalMethod) {
            return descriptor;
        }

        descriptor.value = async function (this: unknown, ...args: Parameters<T>) {
            const timer = new SpanTimer(operationName);
            try {
                const result = await originalMethod.apply(this, args);
                timer.end({ status: 'success' });
                return result;
            } catch (error) {
                timer.end({
                    status: 'error',
                    error: error instanceof Error ? error.message : 'Unknown error',
                });
                throw error;
            }
        } as T;

        return descriptor;
    };
}

/**
 * Fetch wrapper with automatic trace propagation
 */
export async function tracedFetch(url: string, options: RequestInit = {}): Promise<Response> {
    const context = getCurrentTraceContext();
    const traceHeaders = context ? createTraceHeaders(context) : {};

    const timer = new SpanTimer(`fetch:${new URL(url).pathname}`);

    try {
        const response = await fetch(url, {
            ...options,
            headers: {
                ...options.headers,
                ...traceHeaders,
            },
        });

        timer.end({
            status: response.ok ? 'success' : 'error',
            statusCode: response.status,
        });

        return response;
    } catch (error) {
        timer.end({
            status: 'error',
            error: error instanceof Error ? error.message : 'Unknown error',
        });
        throw error;
    }
}

/**
 * MED-005: Agency Audit Logging
 *
 * Provides comprehensive audit logging for agency-level operations:
 * - Cross-restaurant access by agency users
 * - Agency admin actions (create restaurant, manage staff, etc.)
 * - Security-sensitive operations (role changes, permission updates)
 *
 * This ensures accountability and traceability for multi-tenant operations.
