import { createHash, createHmac, randomUUID } from 'crypto';

type PrintMode = 'off' | 'fallback' | 'always';
type PrinterProvider = 'log' | 'webhook';

export interface KdsPrintPolicy {
    mode: PrintMode;
    provider: PrinterProvider;
    webhook_url: string | null;
    copies: number;
    timeout_ms: number;
    max_attempts: number;
    base_backoff_ms: number;
}

export interface KdsPrintPayload {
    restaurantId: string;
    orderId: string;
    orderNumber: string;
    tableNumber?: string | null;
    firedAt: string;
    reason: string;
    items: Array<{
        name: string;
        quantity: number;
        station?: string | null;
        notes?: string | null;
        status?: string | null;
    }>;
}

export const DEFAULT_KDS_PRINT_POLICY: KdsPrintPolicy = {
    mode: 'off',
    provider: 'log',
    webhook_url: null,
    copies: 1,
    timeout_ms: 4000,
    max_attempts: 4,
    base_backoff_ms: 400,
};

export function normalizeKdsPrintPolicy(input: unknown): KdsPrintPolicy {
    const raw = (input ?? {}) as Record<string, unknown>;
    const mode =
        raw.mode === 'fallback' || raw.mode === 'always' || raw.mode === 'off'
            ? raw.mode
            : DEFAULT_KDS_PRINT_POLICY.mode;
    const provider =
        raw.provider === 'webhook' || raw.provider === 'log'
            ? raw.provider
            : DEFAULT_KDS_PRINT_POLICY.provider;
    const webhookUrl =
        typeof raw.webhook_url === 'string' && raw.webhook_url.trim().length > 0
            ? raw.webhook_url.trim()
            : null;
    const copiesRaw = Number(raw.copies ?? DEFAULT_KDS_PRINT_POLICY.copies);
    const copies = Number.isFinite(copiesRaw)
        ? Math.max(1, Math.min(5, Math.floor(copiesRaw)))
        : DEFAULT_KDS_PRINT_POLICY.copies;
    const timeoutRaw = Number(raw.timeout_ms ?? DEFAULT_KDS_PRINT_POLICY.timeout_ms);
    const timeout_ms = Number.isFinite(timeoutRaw)
        ? Math.max(1000, Math.min(20000, Math.floor(timeoutRaw)))
        : DEFAULT_KDS_PRINT_POLICY.timeout_ms;
    const attemptsRaw = Number(raw.max_attempts ?? DEFAULT_KDS_PRINT_POLICY.max_attempts);
    const max_attempts = Number.isFinite(attemptsRaw)
        ? Math.max(1, Math.min(8, Math.floor(attemptsRaw)))
        : DEFAULT_KDS_PRINT_POLICY.max_attempts;
    const backoffRaw = Number(raw.base_backoff_ms ?? DEFAULT_KDS_PRINT_POLICY.base_backoff_ms);
    const base_backoff_ms = Number.isFinite(backoffRaw)
        ? Math.max(100, Math.min(5000, Math.floor(backoffRaw)))
        : DEFAULT_KDS_PRINT_POLICY.base_backoff_ms;

    return {
        mode,
        provider,
        webhook_url: webhookUrl,
        copies,
        timeout_ms,
        max_attempts,
        base_backoff_ms,
    };
}

function resolveBridgeSigningSecret(): string | null {
    const explicit = process.env.KDS_PRINTER_WEBHOOK_SECRET;
    if (explicit && explicit.trim().length >= 16) return explicit.trim();

    const fallback = process.env.HMAC_SECRET;
    if (fallback && fallback.trim().length >= 16) return fallback.trim();
    return null;
}

function signBridgeBody(
    body: string,
    timestamp: string,
    nonce: string,
    secret: string
): { signature: string; bodySha256: string } {
    const bodySha256 = createHash('sha256').update(body).digest('hex');
    const canonical = `v1.${timestamp}.${nonce}.${bodySha256}`;
    const signature = createHmac('sha256', secret).update(canonical).digest('hex');
    return { signature, bodySha256 };
}

async function sleep(ms: number) {
    await new Promise(resolve => setTimeout(resolve, ms));
}

function computeBackoffMs(base: number, attempt: number) {
    const exponent = Math.max(0, attempt - 1);
    const expDelay = base * 2 ** exponent;
    const jitter = Math.floor(Math.random() * Math.max(50, base));
    return Math.min(15_000, expDelay + jitter);
}

function shouldRetryStatus(status: number): boolean {
    if (status === 408 || status === 409 || status === 425 || status === 429) return true;
    return status >= 500;
}

type DispatchResult = {
    provider: PrinterProvider;
    dispatched: boolean;
    reason: string;
    attempts: number;
    event_id: string;
    bridge_status?: number;
};

export async function dispatchKdsPrintJob(
    policy: KdsPrintPolicy,
    payload: KdsPrintPayload
): Promise<DispatchResult> {
    const eventId = randomUUID();
    if (policy.mode === 'off') {
        return {
            provider: policy.provider,
            dispatched: false,
            reason: 'print_mode_off',
            attempts: 0,
            event_id: eventId,
        };
    }

    if (policy.provider === 'webhook' && policy.webhook_url) {
        const secret = resolveBridgeSigningSecret();
        if (!secret) {
            throw new Error(
                'KDS_PRINTER_WEBHOOK_SECRET (or HMAC_SECRET) is required for signed printer webhook dispatch'
            );
        }
        const envelope = {
            event: 'kds.ticket.print.v1',
            event_id: eventId,
            occurred_at: new Date().toISOString(),
            idempotency_key: eventId,
            copies: policy.copies,
            payload,
        };
        const body = JSON.stringify(envelope);

        let lastStatus: number | undefined;
        let lastError: string | null = null;

        for (let attempt = 1; attempt <= policy.max_attempts; attempt += 1) {
            const timestamp = new Date().toISOString();
            const nonce = randomUUID();
            const { signature, bodySha256 } = signBridgeBody(body, timestamp, nonce, secret);

            const controller = new AbortController();
            const timeoutHandle = setTimeout(() => controller.abort(), policy.timeout_ms);
            try {
                const response = await fetch(policy.webhook_url, {
                    method: 'POST',
                    headers: {
                        'Content-Type': 'application/json',
                        'x-gebeta-event': 'kds.ticket.print.v1',
                        'x-gebeta-event-id': eventId,
                        'x-gebeta-idempotency-key': eventId,
                        'x-gebeta-signature-version': 'v1',
                        'x-gebeta-signature-timestamp': timestamp,
                        'x-gebeta-signature-nonce': nonce,
                        'x-gebeta-signature-sha256': signature,
                        'x-gebeta-body-sha256': bodySha256,
                        'x-gebeta-attempt': String(attempt),
                    },
                    body,
                    signal: controller.signal,
                });
                clearTimeout(timeoutHandle);

                if (response.ok) {
                    return {
                        provider: 'webhook',
                        dispatched: true,
                        reason: attempt === 1 ? 'sent_to_webhook' : 'sent_to_webhook_after_retry',
                        attempts: attempt,
                        event_id: eventId,
                        bridge_status: response.status,
                    };
                }

                lastStatus = response.status;
                const retryable = shouldRetryStatus(response.status);
                if (!retryable || attempt === policy.max_attempts) {
                    break;
                }
                await sleep(computeBackoffMs(policy.base_backoff_ms, attempt));
            } catch (error: any) {
                clearTimeout(timeoutHandle);
                lastError = String(error?.message ?? 'bridge_request_failed');
                if (attempt === policy.max_attempts) break;
                await sleep(computeBackoffMs(policy.base_backoff_ms, attempt));
            }
        }

        throw new Error(
            `Printer webhook dispatch failed after retries: status=${String(lastStatus ?? 'none')} error=${lastError ?? 'none'}`
        );
    }

    // Log-mode provider acts as a non-hardware fallback in lower environments.
    console.info('[KDS_PRINTER_LOG]', {
        event: 'kds.ticket.print.v1',
        event_id: eventId,
        copies: policy.copies,
        payload,
    });
    return {
        provider: 'log' as const,
        dispatched: true,
        reason: 'logged_print_job',
        attempts: 1,
        event_id: eventId,
    };
}

/**
 * Centralized Logging Utility
 *
 * Addresses: Missing Centralized Error Logging (P2 Audit Finding #11)
 * Provides structured logging with levels and context tracking
 */

export type LogLevel = 'debug' | 'info' | 'warn' | 'error';

export interface LogContext {
    [key: string]: unknown;
}

export interface LogEntry {
    level: LogLevel;
    message: string;
    context?: LogContext;
    timestamp: string;
    requestId?: string;
    source?: string;
}

class Logger {
    private static instance: Logger;
    private source: string = 'app';

    private constructor() {}

    static getInstance(): Logger {
        if (!Logger.instance) {
            Logger.instance = new Logger();
        }
        return Logger.instance;
    }

    /**
     * Create a child logger with a specific source context
     */
    child(source: string): Logger {
        const childLogger = new Logger();
        childLogger.source = source;
        return childLogger;
    }

    /**
     * Generate a unique request ID for tracking
     */
    generateRequestId(): string {
        return `${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
    }

    private formatEntry(
        level: LogLevel,
        message: string,
        context?: LogContext,
        requestId?: string
    ): LogEntry {
        return {
            level,
            message,
            context,
            timestamp: new Date().toISOString(),
            requestId,
            source: this.source,
        };
    }

    private logToConsole(entry: LogEntry): void {
        const prefix = `[${entry.timestamp}] [${entry.level.toUpperCase()}] [${entry.source}]`;
        const requestId = entry.requestId ? ` [${entry.requestId}]` : '';

        const logData = {
            ...entry.context,
            ...(entry.requestId && { requestId: entry.requestId }),
        };

        switch (entry.level) {
            case 'debug':
                if (process.env.NODE_ENV === 'development') {
                    console.debug(prefix + requestId, entry.message, logData);
                }
                break;
            case 'info':
                console.info(prefix + requestId, entry.message, logData);
                break;
            case 'warn':
                console.warn(prefix + requestId, entry.message, logData);
                break;
            case 'error':
                console.error(prefix + requestId, entry.message, logData);
                break;
        }
    }

    /**
     * Log debug message (only in development)
     */
    debug(message: string, context?: LogContext, requestId?: string): void {
        const entry = this.formatEntry('debug', message, context, requestId);
        this.logToConsole(entry);
    }

    /**
     * Log info message
     */
    info(message: string, context?: LogContext, requestId?: string): void {
        const entry = this.formatEntry('info', message, context, requestId);
        this.logToConsole(entry);
    }

    /**
     * Log warning message
     */
    warn(message: string, context?: LogContext, requestId?: string): void {
        const entry = this.formatEntry('warn', message, context, requestId);
        this.logToConsole(entry);
    }

    /**
     * Log error message with optional error object
     */
    error(
        message: string,
        error?: Error | unknown,
        context?: LogContext,
        requestId?: string
    ): void {
        const errorContext: LogContext = {
            ...context,
        };

        if (error instanceof Error) {
            errorContext.error = {
                name: error.name,
                message: error.message,
                stack: error.stack,
            };
        } else if (error !== undefined) {
            errorContext.error = error;
        }

        const entry = this.formatEntry('error', message, errorContext, requestId);
        this.logToConsole(entry);

        // TODO: Send to external error tracking service (Sentry, LogRocket, etc.)
        // if (process.env.NODE_ENV === 'production') {
        //     this.sendToErrorTracking(entry);
        // }
    }

    /**
     * Log API request/response
     */
    logApiRequest(method: string, path: string, context?: LogContext, requestId?: string): void {
        this.info(`API Request: ${method} ${path}`, context, requestId);
    }

    logApiResponse(
        method: string,
        path: string,
        statusCode: number,
        duration: number,
        context?: LogContext,
        requestId?: string
    ): void {
        const level = statusCode >= 400 ? 'error' : statusCode >= 300 ? 'warn' : 'info';
        const message = `API Response: ${method} ${path} - ${statusCode} (${duration}ms)`;

        const entry = this.formatEntry(level, message, context, requestId);
        this.logToConsole(entry);
    }

    /**
     * Log user action for audit trail
     */
    logUserAction(action: string, userId: string, context?: LogContext, requestId?: string): void {
        this.info(`User Action: ${action}`, { userId, ...context }, requestId);
    }

    /**
     * Log performance metric
     */
    logPerformance(metric: string, value: number, unit: string = 'ms', context?: LogContext): void {
        this.info(`Performance: ${metric}`, { value, unit, ...context });
    }
}

