/**
 * Get queue statistics
 *
 * @param restaurantId - Optional restaurant ID filter
 * @returns Queue statistics
 */
export async function getQueueStats(restaurantId?: string): Promise<{
    pending: number;
    processing: number;
    sent: number;
    failed: number;
    cancelled: number;
}> {
    const supabase = createServiceRoleClient();

    let query = (supabase as any)
        .from('notification_queue')
        .select('status', { count: 'exact', head: true });

    if (restaurantId) {
        query = query.eq('restaurant_id', restaurantId);
    }

    const { count: _count, error } = await query;

    if (error) {
        console.error('[queue] Failed to get queue stats:', error);
        return {
            pending: 0,
            processing: 0,
            sent: 0,
            failed: 0,
            cancelled: 0,
        };
    }

    // Get counts by status
    const [pending, processing, sent, failed, cancelled] = await Promise.all([
        (supabase as any)
            .from('notification_queue')
            .select('id', { count: 'exact', head: true })
            .eq('status', 'pending')
            .then((r: any) => r.count || 0),
        (supabase as any)
            .from('notification_queue')
            .select('id', { count: 'exact', head: true })
            .eq('status', 'processing')
            .then((r: any) => r.count || 0),
        (supabase as any)
            .from('notification_queue')
            .select('id', { count: 'exact', head: true })
            .eq('status', 'sent')
            .then((r: any) => r.count || 0),
        (supabase as any)
            .from('notification_queue')
            .select('id', { count: 'exact', head: true })
            .eq('status', 'failed')
            .then((r: any) => r.count || 0),
        (supabase as any)
            .from('notification_queue')
            .select('id', { count: 'exact', head: true })
            .eq('status', 'cancelled')
            .then((r: any) => r.count || 0),
    ]);

    return { pending, processing, sent, failed, cancelled };
}

