/**
 * Notification queue insert type
 */
interface NotificationQueueInsert {
    id?: string;
    restaurant_id: string;
    guest_phone: string;
    guest_id?: string;
    notification_type?: string;
    channel?: string;
    status?: string;
    priority?: number;
