    message_am?: string;
    retry_count?: number;
    max_retries?: number;
    next_retry_at?: string;
    sent_at?: string;
    error_message?: string;
    provider_response?: Record<string, unknown>;
    idempotency_key: string;
    metadata?: Record<string, unknown>;
