    updated_at?: string;
}

/**
 * Notification queue update type
 */
interface NotificationQueueUpdate {
    status?: string;
    priority?: number;
    retry_count?: number;
    max_retries?: number;
    next_retry_at?: string;
    sent_at?: string;
    error_message?: string;
    provider_response?: Record<string, unknown>;
    updated_at?: string;
