import type { PaymentLifecycleEvent } from '@/lib/events/contracts';
import { writeAuditLog } from '@/lib/api/audit';
import { createServiceRoleClient } from '@/lib/supabase/service-role';

export interface PaymentEventProcessingResult {
    ok: boolean;
    outcome: 'processed' | 'already_processed' | 'ignored';
    paymentId: string | null;
    orderId: string | null;
    paymentSessionId?: string | null;
}

export async function processPaymentLifecycleEvent(
    event: PaymentLifecycleEvent
): Promise<PaymentEventProcessingResult> {
    const admin = createServiceRoleClient();
    const { payload } = event;
    const now = new Date().toISOString();
    const adminAny = admin as any;

    const { data: resolvedOrder } = payload.order_id
        ? await admin
              .from('orders')
              .select('id, restaurant_id, status, order_number, total_price, paid_at')
              .eq('id', payload.order_id)
              .maybeSingle()
        : { data: null };

    const { data: resolvedPaymentSession } = payload.payment_session_id
        ? await adminAny
              .from('payment_sessions')
              .select('*')
              .eq('id', payload.payment_session_id)
              .maybeSingle()
        : payload.provider_transaction_id
          ? await adminAny
                .from('payment_sessions')
                .select('*')
                .eq('selected_provider', payload.provider)
                .eq('provider_transaction_id', payload.provider_transaction_id)
                .order('created_at', { ascending: false })
                .limit(1)
                .maybeSingle()
          : { data: null };

    const { data: existingPayment } = await admin
        .from('payments')
        .select('id, status, order_id, restaurant_id, payment_session_id, metadata')
        .eq('provider', payload.provider)
        .eq('provider_reference', payload.provider_transaction_id)
        .order('created_at', { ascending: false })
        .limit(1)
        .maybeSingle();

    const orderId =
        resolvedOrder?.id ??
        resolvedPaymentSession?.order_id ??
        existingPayment?.order_id ??
        payload.order_id ??
        null;
    const restaurantId =
        resolvedOrder?.restaurant_id ??
        resolvedPaymentSession?.restaurant_id ??
        existingPayment?.restaurant_id ??
        payload.restaurant_id;
    const paymentSessionId =
        resolvedPaymentSession?.id ??
        (existingPayment as { payment_session_id?: string | null } | null)?.payment_session_id ??
        payload.payment_session_id ??
        null;
    const monetaryAmount = payload.amount ?? resolvedOrder?.total_price ?? 0;
    const paymentStatus = payload.status === 'completed' ? 'captured' : 'failed';
    const paymentSessionStatus = payload.status === 'completed' ? 'captured' : 'failed';

    if (existingPayment?.status === paymentStatus) {
        return {
            ok: true,
            outcome: 'already_processed',
            paymentId: existingPayment.id,
            orderId,
            paymentSessionId,
        };
    }

    let paymentId = existingPayment?.id ?? payload.payment_id ?? null;

    if (existingPayment?.id) {
        const { error } = await admin
            .from('payments')
            .update({
                status: paymentStatus,
                captured_at: payload.status === 'completed' ? now : null,
                provider_reference: payload.provider_transaction_id,
                metadata: {
                    ...((existingPayment?.metadata as Record<string, unknown> | undefined) ?? {}),
                    webhook_event_id: event.id,
                    webhook_trace_id: event.trace_id,
                    webhook_status: payload.status,
                },
                payment_session_id: paymentSessionId,
            })
            .eq('id', existingPayment.id);

        if (error) {
            throw new Error(error.message);
        }
    } else {
        const { data, error } = await admin
            .from('payments')
            .insert({
                restaurant_id: restaurantId,
                order_id: orderId,
                payment_session_id: paymentSessionId,
                amount: monetaryAmount,
                currency: payload.currency ?? 'ETB',
                method: payload.provider,
                provider: payload.provider,
                provider_reference: payload.provider_transaction_id,
                status: paymentStatus,
                captured_at: payload.status === 'completed' ? now : null,
                metadata: {
                    ...payload.metadata,
                    webhook_event_id: event.id,
                    webhook_trace_id: event.trace_id,
                    webhook_status: payload.status,
                },
            })
            .select('id')
            .single();

        if (error || !data) {
            throw new Error(error?.message ?? 'Failed to create payment record');
        }

        paymentId = data.id;
    }

    if (paymentSessionId) {
        const sessionMetadata = {
            ...(((resolvedPaymentSession?.metadata as Record<string, unknown> | undefined) ??
                {}) as Record<string, unknown>),
            webhook_event_id: event.id,
            webhook_trace_id: event.trace_id,
            webhook_status: payload.status,
            payment_id: paymentId,
        };

        const { error: paymentSessionError } = await adminAny
            .from('payment_sessions')
            .update({
                status: paymentSessionStatus,
                selected_provider: payload.provider,
                provider_transaction_id: payload.provider_transaction_id,
                provider_reference: payload.provider_transaction_id,
                captured_at: payload.status === 'completed' ? now : null,
                metadata: sessionMetadata,
                updated_at: now,
            })
            .eq('id', paymentSessionId);

        if (paymentSessionError) {
            throw new Error(paymentSessionError.message);
        }
    }

    if (orderId) {
        const nextOrderStatus =
            payload.status === 'completed'
                ? // The current operational UI expects paid orders to move into "pending"
                  // so KDS and waiter views continue to work before the larger status-contract migration.
                  'pending'
                : 'cancelled';
        const orderPatch: Record<string, unknown> = {
            status: nextOrderStatus,
            paid_at: payload.status === 'completed' ? now : null,
        };

        if (payload.provider === 'chapa' && payload.status === 'completed') {
            orderPatch.chapa_verified = true;
        }

        const { error } = await admin.from('orders').update(orderPatch).eq('id', orderId);
        if (error) {
            throw new Error(error.message);
        }
    }

    await writeAuditLog(admin, {
        restaurant_id: restaurantId,
        action: payload.status === 'completed' ? 'payment_confirmed' : 'payment_failed',
        entity_type: 'payment',
        entity_id: paymentId,
        metadata: {
            event_id: event.id,
            trace_id: event.trace_id,
            provider: payload.provider,
            provider_transaction_id: payload.provider_transaction_id,
            idempotency_key: payload.idempotency_key,
            order_id: orderId,
            payment_session_id: paymentSessionId,
        },
        new_value: {
            status: paymentStatus,
            order_status: payload.status === 'completed' ? 'pending' : 'cancelled',
        },
    });

    return {
        ok: true,
        outcome: 'processed',
        paymentId,
        orderId,
        paymentSessionId,
    };
}

import { createPaymentAdapterRegistry } from '@/lib/payments/adapters';
import type { PaymentProviderName as BasePaymentProviderName } from '@/lib/payments/types';
import type { Json } from '@/types/database';

export const PAYMENT_SESSION_SURFACES = [
    'guest_qr',
    'online_order',
    'waiter_pos',
    'terminal',
] as const;

export const PAYMENT_SESSION_CHANNELS = ['dine_in', 'pickup', 'delivery', 'online'] as const;

export const PAYMENT_SESSION_INTENTS = [
    'pay_now',
    'pay_later',
    'waiter_close_out',
    'staff_recorded',
    'assisted_digital',
] as const;

export const PAYMENT_SESSION_STATUSES = [
    'created',
    'awaiting_method',
    'pending_provider',
    'authorized',
    'captured',
    'failed',
    'cancelled',
    'expired',
] as const;

export type PaymentSessionSurface = (typeof PAYMENT_SESSION_SURFACES)[number];
export type PaymentSessionChannel = (typeof PAYMENT_SESSION_CHANNELS)[number];
export type PaymentSessionIntent = (typeof PAYMENT_SESSION_INTENTS)[number];
export type PaymentSessionStatus = (typeof PAYMENT_SESSION_STATUSES)[number];
export type PaymentSessionMethod =
    | 'cash'
    | 'chapa'
    | 'card'
    | 'other'
    | 'gift_card'
    | 'bank_transfer';
export type PaymentProviderName = Exclude<BasePaymentProviderName, 'internal'>;

export interface PaymentSessionRecord {
    id: string;
    restaurant_id: string;
    order_id: string | null;
    surface: PaymentSessionSurface;
    channel: PaymentSessionChannel;
    intent_type: PaymentSessionIntent;
    status: PaymentSessionStatus;
    selected_method: string | null;
    selected_provider: string | null;
    amount: number;
    currency: string;
    checkout_url: string | null;
    provider_transaction_id: string | null;
    provider_reference: string | null;
    metadata: Json;
    authorized_at: string | null;
    captured_at: string | null;
    expires_at: string | null;
    created_at: string;
    updated_at: string;
}

type DbLike = {
    from(table: string): any;
};

export function getSurfaceForOrderMode(isOnlineOrder: boolean): PaymentSessionSurface {
    return isOnlineOrder ? 'online_order' : 'guest_qr';
}

export function getDefaultProviderForMethod(_method?: string | null): PaymentProviderName {
    return 'chapa';
}

async function getRestaurantChapaSplitConfig(
    db: DbLike,
    restaurantId: string
): Promise<{
    subaccountId?: string;
    splitValue: number;
    settlementMode: 'subaccount_split' | 'platform_hold';
    merchantPayoutStatus: string;
}> {
    const { data, error } = await db
        .from('restaurants')
        .select(
            'chapa_subaccount_id, chapa_subaccount_status, hosted_checkout_fee_percentage, platform_fee_percentage'
        )
        .eq('id', restaurantId)
        .maybeSingle();

    if (error) {
        throw new Error(error.message);
    }

    const subaccountId = String(data?.chapa_subaccount_id ?? '').trim();
    const merchantPayoutStatus =
        String(data?.chapa_subaccount_status ?? '').trim() || 'not_configured';
    const splitValue =
        typeof data?.hosted_checkout_fee_percentage === 'number'
            ? Number(data.hosted_checkout_fee_percentage)
            : Number(data?.platform_fee_percentage ?? 0.03);
    const canUseSubaccount =
        subaccountId.length > 0 &&
        !['failed', 'verification_required', 'not_configured'].includes(merchantPayoutStatus);

    return {
        ...(canUseSubaccount ? { subaccountId } : {}),
        splitValue,
        settlementMode: canUseSubaccount ? 'subaccount_split' : 'platform_hold',
        merchantPayoutStatus,
    };
}

export async function createPaymentSession(
    db: DbLike,
    input: {
        restaurant_id: string;
        order_id?: string | null;
        surface: PaymentSessionSurface;
        channel: PaymentSessionChannel;
        intent_type: PaymentSessionIntent;
        status?: PaymentSessionStatus;
        selected_method?: string | null;
        selected_provider?: string | null;
        amount: number;
        currency?: string;
        metadata?: Json;
        expires_at?: string | null;
        created_by?: string | null;
    }
): Promise<PaymentSessionRecord> {
    const now = new Date().toISOString();
    const { data, error } = await db
        .from('payment_sessions')
        .insert({
            restaurant_id: input.restaurant_id,
            order_id: input.order_id ?? null,
            surface: input.surface,
            channel: input.channel,
            intent_type: input.intent_type,
            status: input.status ?? 'created',
            selected_method: input.selected_method ?? null,
            selected_provider: input.selected_provider ?? null,
            amount: Number(input.amount.toFixed(2)),
            currency: input.currency ?? 'ETB',
            metadata: (input.metadata ?? {}) as Json,
            expires_at: input.expires_at ?? null,
            created_by: input.created_by ?? null,
            updated_at: now,
        })
        .select('*')
        .single();

    if (error || !data) {
        throw new Error(error?.message ?? 'Failed to create payment session');
    }

    return data as PaymentSessionRecord;
}

export async function updatePaymentSession(
    db: DbLike,
    paymentSessionId: string,
    patch: Record<string, unknown>
): Promise<PaymentSessionRecord> {
    const { data, error } = await db
        .from('payment_sessions')
        .update({
            ...patch,
            updated_at: new Date().toISOString(),
        })
        .eq('id', paymentSessionId)
        .select('*')
        .single();

    if (error || !data) {
        throw new Error(error?.message ?? 'Failed to update payment session');
    }

    return data as PaymentSessionRecord;
}

export async function findLatestPaymentSessionForOrder(
    db: DbLike,
    restaurantId: string,
    orderId: string
): Promise<PaymentSessionRecord | null> {
    const { data, error } = await db
        .from('payment_sessions')
        .select('*')
        .eq('restaurant_id', restaurantId)
        .eq('order_id', orderId)
        .order('created_at', { ascending: false })
        .limit(1)
        .maybeSingle();

    if (error) {
        throw new Error(error.message);
    }

    return (data ?? null) as PaymentSessionRecord | null;
}

export async function initiateHostedPaymentSession(params: {
    db: DbLike;
    paymentSessionId: string;
    restaurantId: string;
    orderId: string;
    amount: number;
    currency?: string;
    email?: string | null;
    metadata?: Record<string, unknown>;
    returnUrl: string;
    callbackUrl?: string;
}): Promise<{
    paymentSession: PaymentSessionRecord;
    paymentId: string;
    checkoutUrl: string;
    provider: PaymentProviderName;
    transactionReference: string;
    attempts: Array<{ provider: string; ok: boolean; error?: string }>;
    fallbackApplied: boolean;
}> {
    const registry = createPaymentAdapterRegistry();
    const splitConfig = await getRestaurantChapaSplitConfig(params.db, params.restaurantId);
    const initiation = await registry.initiateWithFallback({
        preferredProvider: 'chapa',
        input: {
            amount: Number(params.amount.toFixed(2)),
            currency: (params.currency ?? 'ETB').toUpperCase(),
            email: params.email ?? undefined,
            metadata: {
                ...(params.metadata ?? {}),
                settlement_mode: splitConfig.settlementMode,
                merchant_payout_status: splitConfig.merchantPayoutStatus,
            },
            returnUrl: params.returnUrl,
            callbackUrl: params.callbackUrl,
            ...(splitConfig.subaccountId
                ? {
                      subaccountId: splitConfig.subaccountId,
                      splitType: 'percentage' as const,
                      splitValue: splitConfig.splitValue,
                  }
                : {}),
        },
    });
    const resolvedProvider: PaymentProviderName = 'chapa';

    const paymentInsert = await params.db
        .from('payments')
        .insert({
            restaurant_id: params.restaurantId,
            order_id: params.orderId,
            payment_session_id: params.paymentSessionId,
            method: resolvedProvider,
            provider: resolvedProvider,
            provider_reference: initiation.result.transactionReference,
            amount: Number(params.amount.toFixed(2)),
            currency: (params.currency ?? 'ETB').toUpperCase(),
            status: 'pending',
            metadata: {
                ...(params.metadata ?? {}),
                payment_session_id: params.paymentSessionId,
                provider_attempts: initiation.attempts,
                fallback_applied: initiation.fallbackApplied,
            } as Json,
        })
        .select('id')
        .single();

    if (paymentInsert.error || !paymentInsert.data?.id) {
        throw new Error(paymentInsert.error?.message ?? 'Failed to create pending payment');
    }

    const paymentSession = await updatePaymentSession(params.db, params.paymentSessionId, {
        status: 'pending_provider',
        selected_method: resolvedProvider,
        selected_provider: resolvedProvider,
        checkout_url: initiation.result.checkoutUrl,
        provider_transaction_id: initiation.result.transactionReference,
        metadata: {
            ...(params.metadata ?? {}),
            payment_id: paymentInsert.data.id,
            payment_session_id: params.paymentSessionId,
            provider_attempts: initiation.attempts,
            fallback_applied: initiation.fallbackApplied,
        } as Json,
    });

    return {
        paymentSession,
        paymentId: paymentInsert.data.id,
        checkoutUrl: initiation.result.checkoutUrl,
        provider: resolvedProvider,
        transactionReference: initiation.result.transactionReference,
        attempts: initiation.attempts,
        fallbackApplied: initiation.fallbackApplied,
    };
}

export async function ensurePaymentSessionForRecordedPayment(
    db: DbLike,
    input: {
        restaurantId: string;
        orderId?: string | null;
        surface: PaymentSessionSurface;
        channel: PaymentSessionChannel;
        method: PaymentSessionMethod;
        provider?: string | null;
        amount: number;
        status:
            | 'pending'
            | 'authorized'
            | 'captured'
            | 'failed'
            | 'voided'
            | 'partially_refunded'
            | 'refunded';
        metadata?: Json;
    }
): Promise<PaymentSessionRecord> {
    const existing =
        input.orderId != null
            ? await findLatestPaymentSessionForOrder(db, input.restaurantId, input.orderId)
            : null;

    const nextStatus: PaymentSessionStatus =
        input.status === 'captured'
            ? 'captured'
            : input.status === 'authorized'
              ? 'authorized'
              : input.status === 'voided'
                ? 'cancelled'
                : input.status === 'partially_refunded' || input.status === 'refunded'
                  ? 'captured'
                  : input.status === 'failed'
                    ? 'failed'
                    : 'pending_provider';

    if (existing) {
        return updatePaymentSession(db, existing.id, {
            status: nextStatus,
            selected_method: input.method,
            selected_provider:
                input.provider && input.provider !== 'internal'
                    ? input.provider
                    : existing.selected_provider,
            amount: Number(input.amount.toFixed(2)),
            metadata: input.metadata ?? existing.metadata,
            ...(nextStatus === 'authorized' ? { authorized_at: new Date().toISOString() } : {}),
            ...(nextStatus === 'captured' ? { captured_at: new Date().toISOString() } : {}),
        });
    }

    return createPaymentSession(db, {
        restaurant_id: input.restaurantId,
        order_id: input.orderId ?? null,
        surface: input.surface,
        channel: input.channel,
        intent_type: input.method === 'chapa' ? 'assisted_digital' : 'staff_recorded',
        status: nextStatus,
        selected_method: input.method,
        selected_provider: input.provider && input.provider !== 'internal' ? input.provider : null,
        amount: input.amount,
        metadata: input.metadata,
    });
}

/**
 * Telebirr Payment Provider
 *
 * Implements Telebirr QR-based mobile money payment integration for Ethiopia.
 * Telebirr is the leading mobile money service in Ethiopia with 40M+ users.
 *
 * Documentation: https://developer.telebirr.com/
 */

import {
    PaymentInitiateInput,
    PaymentInitiateResponse,
    PaymentProvider,
    PaymentProviderError,
    PaymentProviderHealth,
    PaymentProviderName,
    PaymentVerifyResponse,
} from './types';
import { createHmac, createHash } from 'crypto';

const TELEBIRR_API_URL = 'https://api.telebirr.com/v1';
const TELEBIRR_APP_ID = process.env.TELEBIRR_APP_ID;
const TELEBIRR_APP_KEY = process.env.TELEBIRR_APP_KEY;

/**
 * Telebirr payment request payload
 */
interface TelebirrPaymentRequest {
    appId: string;
    appKey: string;
    amount: string;
    currency: string;
    subject: string;
    body: string;
    outTradeNo: string;
    notifyUrl: string;
    returnUrl: string;
    receiveName: string;
    timeoutExpress: string;
    timestamp: string;
    nonceStr: string;
    sign: string;
}

/**
 * Telebirr payment response
 */
interface TelebirrPaymentResponse {
    code: string;
    msg: string;
    data?: {
        qrCode?: string;
        outTradeNo?: string;
        tradeNo?: string;
    };
}

/**
 * Telebirr verification response
 */
interface TelebirrVerifyResponse {
    code: string;
    msg: string;
    data?: {
        tradeStatus: 'WAIT_BUYER_PAY' | 'TRADE_SUCCESS' | 'TRADE_CLOSED' | 'TRADE_FINISHED';
        outTradeNo: string;
        tradeNo: string;
        totalAmount: string;
        currency: string;
        buyerId?: string;
    };
}

/**
 * Generate Telebirr signature
 * Uses HMAC-SHA256 with app key
 */
function generateSignature(params: Record<string, string>, appKey: string): string {
    // Sort parameters alphabetically
    const sortedKeys = Object.keys(params).sort();

    // Build query string (excluding empty values)
    const queryString = sortedKeys
        .filter(key => params[key] && params[key].length > 0)
        .map(key => `${key}=${params[key]}`)
        .join('&');

    // Append app key
    const stringToSign = `${queryString}&key=${appKey}`;

    // Generate HMAC-SHA256 hash
    return createHmac('sha256', appKey).update(stringToSign).digest('hex').toUpperCase();
}

/**
 * Generate nonce string for request uniqueness
 */
function generateNonceStr(length: number = 32): string {
    const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
    let result = '';
    for (let i = 0; i < length; i++) {
        result += chars.charAt(Math.floor(Math.random() * chars.length));
    }
    return result;
}

/**
 * Generate timestamp in Telebirr format (yyyyMMddHHmmss)
 */
function generateTimestamp(): string {
    const now = new Date();
    return (
        now.getFullYear().toString() +
        (now.getMonth() + 1).toString().padStart(2, '0') +
        now.getDate().toString().padStart(2, '0') +
        now.getHours().toString().padStart(2, '0') +
        now.getMinutes().toString().padStart(2, '0') +
        now.getSeconds().toString().padStart(2, '0')
    );
}

/**
 * Validate Telebirr webhook signature
 */
export function verifyTelebirrWebhookSignature(
    payload: string,
    signature: string,
    appKey: string
): boolean {
    if (!appKey) {
        console.error('[Telebirr] Missing app key for webhook verification');
        return false;
    }

    try {
        // Parse the payload
        const params = JSON.parse(payload) as Record<string, string>;

        // Extract and remove the sign from params
        const { sign: receivedSign, ...paramsWithoutSign } = params;

        if (!receivedSign) {
            console.error('[Telebirr] No signature in webhook payload');
            return false;
        }

        // Recalculate signature
        const calculatedSign = generateSignature(paramsWithoutSign, appKey);

        // Constant-time comparison
        return calculatedSign === receivedSign;
    } catch (error) {
        console.error('[Telebirr] Webhook signature verification failed:', error);
        return false;
    }
}

/**
 * Telebirr Payment Provider Implementation
 */
export class TelebirrProvider implements PaymentProvider {
    name: PaymentProviderName = 'telebirr' as PaymentProviderName;
    private appId: string;
    private appKey: string;
    private appUrl: string;

    constructor(appId?: string, appKey?: string, appUrl?: string) {
        this.appId = appId ?? TELEBIRR_APP_ID ?? '';
        this.appKey = appKey ?? TELEBIRR_APP_KEY ?? '';
        this.appUrl = appUrl ?? process.env.NEXT_PUBLIC_APP_URL ?? 'http://localhost:3000';
    }

    /**
     * Check if Telebirr is configured
     */
    isConfigured(): boolean {
        return this.appId.length > 0 && this.appKey.length > 0;
    }

    /**
     * Initiate a Telebirr payment
     * Returns a QR code URL for the customer to scan
     */
    async initiatePayment(input: PaymentInitiateInput): Promise<PaymentInitiateResponse> {
        const { amount, currency, email, metadata, callbackUrl, returnUrl } = input;

        if (!this.isConfigured()) {
            throw new PaymentProviderError({
                provider: this.name,
                code: 'TELEBIRR_NOT_CONFIGURED',
                message:
                    'Telebirr credentials not configured. Set TELEBIRR_APP_ID and TELEBIRR_APP_KEY',
                statusCode: 500,
            });
        }

        // Generate unique transaction reference
        const outTradeNo = `TB${Date.now()}${Math.floor(Math.random() * 10000)}`;
        const timestamp = generateTimestamp();
        const nonceStr = generateNonceStr();

        // Build request parameters
        const params: Record<string, string> = {
            appId: this.appId,
            amount: Math.ceil(amount).toString(), // Telebirr uses integer amounts
            currency: currency || 'ETB',
            subject: (metadata?.subject as string) || 'Gebeta Order',
            body: (metadata?.body as string) || 'Payment for order',
            outTradeNo,
            notifyUrl: callbackUrl || `${this.appUrl}/api/webhooks/telebirr`,
            returnUrl: returnUrl || `${this.appUrl}/order/status?ref=${outTradeNo}`,
            receiveName: (metadata?.firstName as string) || email?.split('@')[0] || 'Guest',
            timeoutExpress: '30m', // Payment expires in 30 minutes
            timestamp,
            nonceStr,
        };

        // Generate signature
        params.sign = generateSignature(params, this.appKey);

        try {
            const response = await fetch(`${TELEBIRR_API_URL}/payment/precreate`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify(params),
            });

            const data = (await response.json()) as TelebirrPaymentResponse;

            if (data.code !== '10000' || !data.data?.qrCode) {
                throw new PaymentProviderError({
                    provider: this.name,
                    code: 'TELEBIRR_INITIATE_FAILED',
                    message: data.msg || 'Failed to initiate Telebirr payment',
                    statusCode: response.status || 502,
                    causeMessage: data.msg,
                });
            }

            return {
                checkoutUrl: data.data.qrCode, // QR code URL for customer to scan
                transactionReference: outTradeNo,
                provider: this.name,
                raw: data as unknown as Record<string, unknown>,
            };
        } catch (error) {
            if (error instanceof PaymentProviderError) {
                throw error;
            }

            throw new PaymentProviderError({
                provider: this.name,
                code: 'TELEBIRR_REQUEST_FAILED',
                message: 'Failed to communicate with Telebirr API',
                statusCode: 502,
                causeMessage: error instanceof Error ? error.message : 'Unknown error',
            });
        }
    }

    /**
     * Verify a Telebirr payment status
     */
    async verifyPayment(transactionReference: string): Promise<PaymentVerifyResponse> {
        if (!this.isConfigured()) {
            throw new PaymentProviderError({
                provider: this.name,
                code: 'TELEBIRR_NOT_CONFIGURED',
                message: 'Telebirr credentials not configured',
                statusCode: 500,
            });
        }

        const timestamp = generateTimestamp();
        const nonceStr = generateNonceStr();

        const params: Record<string, string> = {
            appId: this.appId,
            outTradeNo: transactionReference,
            timestamp,
            nonceStr,
        };

        params.sign = generateSignature(params, this.appKey);

        try {
            const response = await fetch(`${TELEBIRR_API_URL}/payment/query`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify(params),
            });

            const data = (await response.json()) as TelebirrVerifyResponse;

            if (data.code !== '10000') {
                throw new PaymentProviderError({
                    provider: this.name,
                    code: 'TELEBIRR_VERIFY_FAILED',
                    message: data.msg || 'Failed to verify Telebirr payment',
                    statusCode: response.status || 502,
                });
            }

            // Map Telebirr status to our status
            let status: 'pending' | 'success' | 'failed' | 'cancelled';
            switch (data.data?.tradeStatus) {
                case 'TRADE_SUCCESS':
                case 'TRADE_FINISHED':
                    status = 'success';
                    break;
                case 'TRADE_CLOSED':
                    status = 'cancelled';
                    break;
                case 'WAIT_BUYER_PAY':
                default:
                    status = 'pending';
            }

            return {
                status,
                transactionReference: data.data?.outTradeNo || transactionReference,
                providerReference: data.data?.tradeNo,
                amount: parseFloat(data.data?.totalAmount || '0'),
                currency: data.data?.currency || 'ETB',
                metadata: {
                    buyerId: data.data?.buyerId,
                },
            };
        } catch (error) {
            if (error instanceof PaymentProviderError) {
                throw error;
            }

            throw new PaymentProviderError({
                provider: this.name,
                code: 'TELEBIRR_VERIFY_REQUEST_FAILED',
                message: 'Failed to verify payment with Telebirr',
                statusCode: 502,
                causeMessage: error instanceof Error ? error.message : 'Unknown error',
            });
        }
    }

    /**
     * Check Telebirr API health
     */
    async healthCheck(): Promise<PaymentProviderHealth> {
        const checkedAt = new Date().toISOString();

        if (!this.isConfigured()) {
            return {
                provider: this.name,
                status: 'unavailable',
                checkedAt,
                reason: 'Telebirr credentials not configured',
            };
        }

        try {
            // Simple health check - verify API is reachable
            const response = await fetch(`${TELEBIRR_API_URL}/health`, {
                method: 'GET',
                signal: AbortSignal.timeout(5000), // 5 second timeout
            });

            if (response.ok) {
                return {
                    provider: this.name,
                    status: 'healthy',
                    checkedAt,
                };
            }

            return {
                provider: this.name,
                status: 'degraded',
                checkedAt,
                reason: `API returned status ${response.status}`,
            };
        } catch (error) {
            return {
                provider: this.name,
                status: 'unavailable',
                checkedAt,
                reason: error instanceof Error ? error.message : 'Health check failed',
            };
        }
    }
}

