        this.causeMessage = params.causeMessage;
    }
}

import { createHmac, randomUUID, timingSafeEqual } from 'crypto';
import type { PaymentEventStatus, PaymentLifecycleEventPayload } from '@/lib/events/contracts';
import { createPaymentLifecycleEvent } from '@/lib/events/contracts';
import { enqueueInternalJob, publishEvent } from '@/lib/events/runtime';
import {
    createServiceRoleClient,
    createAuditedServiceRoleClient,
} from '@/lib/supabase/service-role';

type PaymentProvider = 'chapa';

type PaymentContext = {
    restaurant_id: string;
    order_id: string | null;
    payment_id: string | null;
    payment_session_id: string | null;
};

interface ParsedWebhookPayload {
    provider: PaymentProvider;
    provider_transaction_id: string;
    status: PaymentEventStatus;
    amount: number | null;
    currency: string | null;
    metadata: Record<string, unknown>;
    raw_payload: Record<string, unknown>;
}

function safeJsonParse(value: string): Record<string, unknown> {
    try {
        const parsed = JSON.parse(value);
        if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
            return parsed as Record<string, unknown>;
        }
    } catch {
        // Ignore parse failures and let callers handle invalid payloads.
    }

    return {};
}

function getString(record: Record<string, unknown>, ...keys: string[]): string | null {
    for (const key of keys) {
        const value = record[key];
        if (typeof value === 'string' && value.trim().length > 0) {
            return value.trim();
        }
    }

    return null;
}

function getNestedRecord(record: Record<string, unknown>, key: string): Record<string, unknown> {
    const value = record[key];
    if (value && typeof value === 'object' && !Array.isArray(value)) {
        return value as Record<string, unknown>;
    }

    return {};
}

function getAmount(record: Record<string, unknown>, ...keys: string[]): number | null {
    for (const key of keys) {
        const value = record[key];
        if (typeof value === 'number' && Number.isFinite(value)) {
            return value;
        }
        if (typeof value === 'string' && value.trim().length > 0) {
            const parsed = Number(value);
            if (Number.isFinite(parsed)) {
                return parsed;
            }
        }
    }

    return null;
}

function statusFromRaw(rawStatus: string | null): PaymentEventStatus {
    const normalized = rawStatus?.toLowerCase() ?? '';
    if (
        ['success', 'successful', 'completed', 'paid', 'captured', 'pay_success'].includes(
            normalized
        )
    ) {
        return 'completed';
    }

    return 'failed';
}

function compareSignature(
    secret: string,
    providedSignature: string | null,
    rawBody: string
): boolean {
    if (!providedSignature) {
        return false;
    }

    const normalizedProvided = providedSignature.trim();
    const expectedHex = createHmac('sha256', secret).update(rawBody).digest('hex');
    const expectedBase64 = createHmac('sha256', secret).update(rawBody).digest('base64');
    const candidates = [expectedHex, expectedBase64];

    return candidates.some(candidate => {
        const candidateBuffer = Buffer.from(candidate);
        const providedBuffer = Buffer.from(normalizedProvided);

        if (candidateBuffer.length !== providedBuffer.length) {
            return false;
        }

        try {
            return timingSafeEqual(candidateBuffer, providedBuffer);
        } catch {
            return false;
        }
    });
}

export function verifyChapaWebhookSignature(
    rawBody: string,
    providedSignature: string | null
): boolean {
    const secret = process.env.CHAPA_WEBHOOK_SECRET;

    // HIGH-011: Require explicit webhook secret even in development
    // If no secret is configured, fail verification
    if (!secret) {
        console.error(
            '[Chapa Webhook] CHAPA_WEBHOOK_SECRET is not configured. Webhook verification failed.'
        );
        // In development, allow a dedicated test secret to be used
        const testSecret = process.env.CHAPA_WEBHOOK_TEST_SECRET;
        if (testSecret && process.env.NODE_ENV !== 'production') {
            return compareSignature(testSecret, providedSignature, rawBody);
        }
        return false;
    }

    return compareSignature(secret, providedSignature, rawBody);
}

export function parseChapaWebhook(
    rawBody: string,
    searchParams?: URLSearchParams
): ParsedWebhookPayload {
    const body = safeJsonParse(rawBody);
    const data = getNestedRecord(body, 'data');
    const meta = getNestedRecord(data, 'meta');
    const txRef =
        getString(body, 'trx_ref', 'tx_ref') ??
        getString(data, 'trx_ref', 'tx_ref', 'reference') ??
        searchParams?.get('trx_ref') ??
        searchParams?.get('tx_ref');

    if (!txRef) {
        throw new Error('Missing Chapa transaction reference');
    }

    const status = statusFromRaw(
        getString(body, 'status', 'event') ??
            getString(data, 'status') ??
            searchParams?.get('status') ??
            null
    );

    return {
        provider: 'chapa',
        provider_transaction_id: txRef,
        status,
        amount: getAmount(body, 'amount') ?? getAmount(data, 'amount'),
        currency: getString(body, 'currency') ?? getString(data, 'currency'),
        metadata: meta,
        raw_payload: body,
    };
}

async function resolvePaymentContext(
    provider: PaymentProvider,
    providerTransactionId: string,
    metadata: Record<string, unknown>
): Promise<PaymentContext> {
    // HIGH-010: Use audited service role client for sensitive payment operations
    const admin = createAuditedServiceRoleClient('payment-webhooks', {
        metadata: { provider, providerTransactionId },
    });
    const metadataPaymentSessionId =
        typeof metadata.payment_session_id === 'string' &&
        metadata.payment_session_id.trim().length > 0
            ? metadata.payment_session_id
            : null;
    const metadataOrderId =
        typeof metadata.order_id === 'string' && metadata.order_id.trim().length > 0
            ? metadata.order_id
            : null;
    const metadataPaymentId =
        typeof metadata.payment_id === 'string' && metadata.payment_id.trim().length > 0
            ? metadata.payment_id
            : null;
    const metadataRestaurantId =
        typeof metadata.restaurant_id === 'string' && metadata.restaurant_id.trim().length > 0
            ? metadata.restaurant_id
            : null;

    if (metadataPaymentSessionId) {
        const { data } = await admin
            .from('payment_sessions')
            .select('id, restaurant_id, order_id')
            .eq('id', metadataPaymentSessionId)
            .maybeSingle();

        if (data?.restaurant_id) {
            return {
                restaurant_id: data.restaurant_id,
                order_id: data.order_id,
                payment_id: metadataPaymentId,
                payment_session_id: data.id,
            };
        }
    }

    if (metadataPaymentId) {
        const { data } = await admin
            .from('payments')
            .select('id, order_id, restaurant_id, payment_session_id')
            .eq('id', metadataPaymentId)
            .maybeSingle();

        if (data?.restaurant_id) {
            return {
                restaurant_id: data.restaurant_id,
                order_id: data.order_id,
                payment_id: data.id,
                payment_session_id:
                    (data as { payment_session_id?: string | null }).payment_session_id ?? null,
            };
        }
    }

    if (metadataOrderId) {
        const { data } = await admin
            .from('orders')
            .select('id, restaurant_id')
            .eq('id', metadataOrderId)
            .maybeSingle();

        if (data?.restaurant_id) {
            return {
                restaurant_id: data.restaurant_id,
                order_id: data.id,
                payment_id: null,
                payment_session_id: metadataPaymentSessionId,
            };
        }
    }

    const { data: paymentSession } = await admin
        .from('payment_sessions')
        .select('id, order_id, restaurant_id')
        .eq('selected_provider', provider)
        .eq('provider_transaction_id', providerTransactionId)
        .order('created_at', { ascending: false })
        .limit(1)
        .maybeSingle();

    if (paymentSession?.restaurant_id) {
        return {
            restaurant_id: paymentSession.restaurant_id,
            order_id: paymentSession.order_id,
            payment_id: metadataPaymentId,
            payment_session_id: paymentSession.id,
        };
    }

    const { data: payment } = await admin
        .from('payments')
        .select('id, order_id, restaurant_id, payment_session_id')
        .eq('provider', provider)
        .eq('provider_reference', providerTransactionId)
        .order('created_at', { ascending: false })
        .limit(1)
        .maybeSingle();

    if (payment?.restaurant_id) {
        return {
            restaurant_id: payment.restaurant_id,
            order_id: payment.order_id,
            payment_id: payment.id,
            payment_session_id:
                (payment as { payment_session_id?: string | null }).payment_session_id ?? null,
        };
    }

    const { data: order } = await admin
        .from('orders')
        .select('id, restaurant_id')
        .eq('chapa_tx_ref', providerTransactionId)
        .order('created_at', { ascending: false })
        .limit(1)
        .maybeSingle();

    if (order?.restaurant_id) {
        return {
            restaurant_id: order.restaurant_id,
            order_id: order.id,
            payment_id: null,
            payment_session_id: metadataPaymentSessionId,
        };
    }

    if (!metadataRestaurantId) {
        throw new Error(
            `Unable to resolve payment context for ${provider}:${providerTransactionId}`
        );
    }

    return {
        restaurant_id: metadataRestaurantId,
        order_id: metadataOrderId,
        payment_id: metadataPaymentId,
        payment_session_id: metadataPaymentSessionId,
    };
}

export async function publishPaymentWebhookEvent(parsed: ParsedWebhookPayload): Promise<{
    eventId: string;
    jobMessageId?: string;
}> {
    const context = await resolvePaymentContext(
        parsed.provider,
        parsed.provider_transaction_id,
        parsed.metadata
    );
    const payload: PaymentLifecycleEventPayload = {
        restaurant_id: context.restaurant_id,
        order_id: context.order_id,
        payment_id: context.payment_id,
        payment_session_id: context.payment_session_id,
        provider: parsed.provider,
        provider_transaction_id: parsed.provider_transaction_id,
        idempotency_key:
            (typeof parsed.metadata.idempotency_key === 'string' &&
                parsed.metadata.idempotency_key.trim().length > 0 &&
                parsed.metadata.idempotency_key.trim()) ||
            randomUUID(),
        status: parsed.status,
        amount: parsed.amount,
        currency: parsed.currency,
        metadata: parsed.metadata,
        raw_payload: parsed.raw_payload,
    };

    const event = createPaymentLifecycleEvent(parsed.status, payload);
    await publishEvent(event);
    const jobMessageId = await enqueueInternalJob({
        path: '/api/jobs/payments/complete',
        body: event as unknown as Record<string, unknown>,
        deduplicationKey: event.id,
    });

    return {
        eventId: event.id,
        jobMessageId,
    };
}

/**
 * E2E Test Mode Security Validation
 *
 * CRITICAL: This module ensures E2E test bypass can NEVER be enabled in production.
 *
 * Security model:
 * 1. NODE_ENV must NOT be 'production'
 * 2. E2E_TEST_MODE must be 'true'
 * 3. E2E_BYPASS_SECRET must be configured
 *
 * All three conditions must be true for E2E bypass to work.
 * This module validates these constraints at application startup.
 */

/**
 * Validate E2E test configuration at startup.
 * Throws an error if E2E test mode is configured unsafely.
 *
 * Call this function in instrumentation.ts to validate at server startup.
 */
export function validateE2EConfig(): void {
    const nodeEnv = process.env.NODE_ENV;
    const e2eTestMode = process.env.E2E_TEST_MODE;
    const e2eBypassSecret = process.env.E2E_BYPASS_SECRET;

    // CRITICAL: Never allow E2E test mode in production
    if (nodeEnv === 'production') {
        if (e2eTestMode === 'true') {
            throw new Error(
                'CRITICAL SECURITY VIOLATION: E2E_TEST_MODE cannot be enabled in production. ' +
                    'Set E2E_TEST_MODE to anything other than "true" in production.'
            );
        }

        if (e2eBypassSecret) {
            console.warn(
                '[SECURITY WARNING] E2E_BYPASS_SECRET should not be set in production. ' +
                    'Remove this environment variable before deployment.'
            );
        }

        // Production is safe - no E2E bypass possible
        return;
    }

    // Non-production environment (development, test, etc.)
    if (e2eTestMode === 'true') {
        if (!e2eBypassSecret || e2eBypassSecret === '') {
            console.warn(
                '[SECURITY WARNING] E2E_TEST_MODE is enabled but E2E_BYPASS_SECRET is not set. ' +
                    'E2E bypass will not work without a configured secret. ' +
                    'Set E2E_BYPASS_SECRET environment variable.'
            );
        } else {
            console.log(
                '[E2E] E2E test mode is enabled with configured secret. ' +
                    'E2E bypass will be available for testing.'
            );
        }
    }

    // Log for debugging in non-production
    if (nodeEnv === 'development' && e2eTestMode !== 'true') {
        console.log(
            '[E2E] E2E test mode is disabled. ' +
                'Set E2E_TEST_MODE=true and E2E_BYPASS_SECRET=<secret> to enable E2E bypass.'
        );
    }
}

/**
 * Check if E2E bypass is allowed in the current environment.
 * Use this for runtime checks in middleware and server components.
 *
 * @returns true if E2E bypass is permitted, false otherwise
 */
export function isE2EBypassAllowed(): boolean {
    const nodeEnv = process.env.NODE_ENV;
    const e2eTestMode = process.env.E2E_TEST_MODE;

    // Production: Never allow bypass
    if (nodeEnv === 'production') {
        return false;
    }

    // Non-production: Only allow if explicitly enabled
    return e2eTestMode === 'true';
}

/**
 * Validate that E2E bypass secret is properly configured.
 * Use this to ensure the secret matches between environment and request.
 *
 * @param providedSecret - The secret provided in the request
 * @returns true if the secret is valid, false otherwise
 */
export function isValidE2EBypassSecret(providedSecret: string | undefined): boolean {
    // E2E bypass must be allowed first
    if (!isE2EBypassAllowed()) {
        return false;
    }

    const configuredSecret = process.env.E2E_BYPASS_SECRET;

    // Secret must be configured
    if (!configuredSecret || configuredSecret === '') {
        return false;
    }

    // Secret must be provided
    if (!providedSecret || providedSecret === '') {
        return false;
    }

    // Use timing-safe comparison to prevent timing attacks
    // Note: For E2E test secrets, timing attacks are less of a concern
    // but it's good practice to use safe comparison
    // Using dynamic require to avoid issues in edge runtime
    let nodeCrypto: typeof import('crypto') | null = null;
    try {
        // eslint-disable-next-line @typescript-eslint/no-require-imports
        nodeCrypto = require('crypto');
    } catch {
        // Crypto not available (edge runtime), deny access
        return false;
    }

    if (!nodeCrypto) {
        return false;
    }

    const configuredBuffer = Buffer.from(configuredSecret, 'utf-8');
    const providedBuffer = Buffer.from(providedSecret, 'utf-8');

    // Length check first (but don't return early to avoid timing leaks)
    if (configuredBuffer.length !== providedBuffer.length) {
        return false;
    }

    // Timing-safe comparison
    try {
        return nodeCrypto.timingSafeEqual(configuredBuffer, providedBuffer);
    } catch {
        // If comparison fails for any reason, deny access
        return false;
    }
}

/**
 * Log E2E bypass security events.
 * Use this for audit logging and debugging.
 *
 * @param event - The type of event
 * @param details - Additional context
 */
export function logE2ESecurityEvent(
    event: 'bypass_attempt' | 'bypass_success' | 'bypass_rejected' | 'config_warning',
    details: Record<string, unknown> = {}
): void {
    const nodeEnv = process.env.NODE_ENV;
    const timestamp = new Date().toISOString();

    const logEntry = {
        timestamp,
        event,
        environment: nodeEnv,
        ...details,
    };

    if (event === 'bypass_attempt' && nodeEnv === 'production') {
        // Critical: Bypass attempt in production
        console.error('[SECURITY CRITICAL] E2E bypass attempt in production environment:', logEntry);
    } else if (event === 'bypass_rejected') {
        console.warn('[SECURITY] E2E bypass rejected:', logEntry);
    } else if (event === 'bypass_success') {
        console.log('[E2E] E2E bypass successful:', logEntry);
    } else {
        console.log('[E2E]', event, logEntry);
    }
}

