/**
 * Session Store - Redis-backed with Memory Fallback
 *
 * Production-ready session storage that uses Redis when available,
 * with automatic fallback to memory store for development.
 *
 * Addresses COMPREHENSIVE_CODEBASE_AUDIT_REPORT Section 3.1
 */

import { env, hasRedis } from '@/lib/config/env';

/**
 * Session data structure
 */
export interface SessionData {
    userId: string;
    lastActivity: number;
    createdAt: number;
    ipAddress: string;
    userAgent: string;
    role?: string;
    restaurantId?: string;
    metadata?: Record<string, unknown>;
}

/**
 * Session store interface - allows for different backends
 */
export interface SessionStore {
    get(sessionId: string): Promise<SessionData | null>;
    set(sessionId: string, data: SessionData, ttl?: number): Promise<void>;
    delete(sessionId: string): Promise<boolean>;
    exists(sessionId: string): Promise<boolean>;
    updateActivity(sessionId: string): Promise<boolean>;
    getAllSessionIds?(): Promise<string[]>;
    cleanup?(): Promise<number>;
}

/**
 * In-memory session store (for development/fallback)
 */
export class MemorySessionStore implements SessionStore {
    private sessions = new Map<string, { data: SessionData; expiresAt: number }>();
    private readonly defaultTTL: number;

    constructor(defaultTTL: number = 30 * 60) {
        this.defaultTTL = defaultTTL;
        // Start cleanup interval
        setInterval(() => this.cleanup(), 5 * 60 * 1000);
    }

    async get(sessionId: string): Promise<SessionData | null> {
        const entry = this.sessions.get(sessionId);
        if (!entry) return null;

        if (Date.now() > entry.expiresAt) {
            this.sessions.delete(sessionId);
            return null;
        }

        return entry.data;
    }

    async set(sessionId: string, data: SessionData, ttl?: number): Promise<void> {
        const expiresAt = Date.now() + (ttl || this.defaultTTL) * 1000;
        this.sessions.set(sessionId, { data, expiresAt });
    }

    async delete(sessionId: string): Promise<boolean> {
        return this.sessions.delete(sessionId);
    }

    async exists(sessionId: string): Promise<boolean> {
        const entry = this.sessions.get(sessionId);
        if (!entry) return false;

        if (Date.now() > entry.expiresAt) {
            this.sessions.delete(sessionId);
            return false;
        }

        return true;
    }

    async updateActivity(sessionId: string): Promise<boolean> {
        const entry = this.sessions.get(sessionId);
        if (!entry) return false;

        entry.data.lastActivity = Date.now();
        entry.expiresAt = Date.now() + this.defaultTTL * 1000;
        return true;
    }

    async getAllSessionIds(): Promise<string[]> {
        return Array.from(this.sessions.keys());
    }

    async cleanup(): Promise<number> {
        const now = Date.now();
        let cleaned = 0;

        for (const [sessionId, entry] of this.sessions.entries()) {
            if (now > entry.expiresAt) {
                this.sessions.delete(sessionId);
                cleaned++;
            }
        }

        return cleaned;
    }

    // Sync methods for backward compatibility
    getSync(sessionId: string): SessionData | null {
        const entry = this.sessions.get(sessionId);
        if (!entry || Date.now() > entry.expiresAt) {
            return null;
        }
        return entry.data;
    }

    setSync(sessionId: string, data: SessionData, ttl?: number): void {
        const expiresAt = Date.now() + (ttl || this.defaultTTL) * 1000;
        this.sessions.set(sessionId, { data, expiresAt });
    }
}

/**
 * Redis session store (for production)
 */
export class RedisSessionStore implements SessionStore {
    private client: RedisClient;
    private readonly keyPrefix: string;
    private readonly defaultTTL: number;

    constructor(client: RedisClient, keyPrefix: string = 'session:', defaultTTL: number = 30 * 60) {
        this.client = client;
        this.keyPrefix = keyPrefix;
        this.defaultTTL = defaultTTL;
    }

    private getKey(sessionId: string): string {
        return `${this.keyPrefix}${sessionId}`;
    }

    async get(sessionId: string): Promise<SessionData | null> {
        const key = this.getKey(sessionId);
        const data = await this.client.get(key);

        if (!data) return null;

        try {
            return JSON.parse(data) as SessionData;
        } catch {
            await this.client.del(key);
            return null;
        }
    }

    async set(sessionId: string, data: SessionData, ttl?: number): Promise<void> {
        const key = this.getKey(sessionId);
        const value = JSON.stringify(data);
        const expiresInSeconds = ttl || this.defaultTTL;

        await this.client.setex(key, expiresInSeconds, value);
    }

    async delete(sessionId: string): Promise<boolean> {
        const key = this.getKey(sessionId);
        const result = await this.client.del(key);
        return result > 0;
    }

    async exists(sessionId: string): Promise<boolean> {
        const key = this.getKey(sessionId);
        const result = await this.client.exists(key);
        return result === 1;
    }

    async updateActivity(sessionId: string): Promise<boolean> {
        const data = await this.get(sessionId);

        if (!data) return false;

        data.lastActivity = Date.now();
        await this.set(sessionId, data, this.defaultTTL);
        return true;
    }

    async getAllSessionIds(): Promise<string[]> {
        const pattern = `${this.keyPrefix}*`;
        const keys = await this.client.keys(pattern);
        return keys.map(key => key.replace(this.keyPrefix, ''));
    }

    async cleanup(): Promise<number> {
        // Redis handles TTL automatically, but we can clean up expired sessions
        // that might have been set without TTL
        let cleaned = 0;
        const keys = await this.getAllSessionIds();

        for (const sessionId of keys) {
            const data = await this.get(sessionId);
            if (data) {
                const maxLifetime = 8 * 60 * 60 * 1000; // 8 hours
                if (Date.now() - data.createdAt > maxLifetime) {
                    await this.delete(sessionId);
                    cleaned++;
                }
            }
        }

        return cleaned;
    }
}

/**
 * Redis client interface (minimal)
 */
export interface RedisClient {
    get(key: string): Promise<string | null>;
    set(key: string, value: string): Promise<'OK' | null>;
    setex(key: string, seconds: number, value: string): Promise<'OK' | null>;
    del(key: string): Promise<number>;
    exists(key: string): Promise<number>;
    keys(pattern: string): Promise<string[]>;
    quit(): Promise<void>;
}

/**
 * Create Redis client
 */
async function createRedisClient(): Promise<RedisClient | null> {
    const redisUrl = env.REDIS_URL;

    if (!redisUrl) {
        return null;
    }

    try {
        // Dynamic import to avoid bundling issues if Redis isn't needed
        const { Redis } = await import('ioredis');
        const redis = new Redis(redisUrl, {
            maxRetriesPerRequest: 3,
            enableReadyCheck: true,
            lazyConnect: true,
            retryStrategy: (times: number) => {
                if (times > 3) {
                    console.warn('Redis connection retry limit reached');
                    return null;
                }
                return Math.min(times * 100, 3000);
            },
        });

        // Test connection
        await redis.ping();

        console.log('✅ Redis connected for session storage');
        return redis as unknown as RedisClient;
    } catch (error) {
        console.warn('⚠️ Redis connection failed, falling back to memory store:', error);
        return null;
    }
}

// Singleton stores
let memoryStore: MemorySessionStore | null = null;
let redisStore: RedisSessionStore | null = null;
let redisClient: RedisClient | null = null;
let initializationPromise: Promise<void> | null = null;

/**
 * Initialize session store
 * Should be called at application startup
 */
export async function initializeSessionStore(): Promise<void> {
    if (initializationPromise) {
        return initializationPromise;
    }

    initializationPromise = (async () => {
        if (hasRedis()) {
            redisClient = await createRedisClient();

            if (redisClient) {
                redisStore = new RedisSessionStore(redisClient);
                return;
            }
        }

        // Fall back to memory store
        memoryStore = new MemorySessionStore();
        console.log('📝 Using in-memory session store (not recommended for production)');
    })();

    return initializationPromise;
}

/**
 * Get the active session store
 */
export function getSessionStore(): SessionStore {
    if (redisStore) {
        return redisStore;
    }

    if (!memoryStore) {
        memoryStore = new MemorySessionStore();
    }

    return memoryStore;
}

/**
 * Get memory store (for backward compatibility with sync operations)
 */
export function getMemoryStore(): MemorySessionStore {
    if (!memoryStore) {
        memoryStore = new MemorySessionStore();
    }
    return memoryStore;
}

/**
 * Check if using Redis
 */
export function isUsingRedis(): boolean {
    return redisStore !== null;
}

/**
 * Close connections (for graceful shutdown)
 */
export async function closeSessionStore(): Promise<void> {
    if (redisClient) {
        await redisClient.quit();
        redisClient = null;
        redisStore = null;
    }
    memoryStore = null;
    initializationPromise = null;
}

const sessionStoreExports = {
    initializeSessionStore,
    getSessionStore,
    getMemoryStore,
    isUsingRedis,
    closeSessionStore,
    MemorySessionStore,
    RedisSessionStore,
};

export default sessionStoreExports;

/**
 * Campaign Service
 *
 * Unified campaign delivery for:
 * - SMS via Africa's Talking
 * - Email via Resend
 * - WhatsApp via WhatsApp Business API
 * - Telegram via Telegram Bot API
 */

import { sendSms, SmsSendResult } from '@/lib/notifications/sms';
import { resend, EMAIL_FROM } from '@/lib/email/client';
import { createServiceRoleClient } from '@/lib/supabase/service-role';

export type Channel = 'sms' | 'email' | 'whatsapp' | 'telegram';

export interface CampaignRecipient {
    guestId: string;
    phone?: string;
    email?: string;
    whatsapp?: string;
    telegramChatId?: string;
    name?: string;
    isVerified: boolean;
}

export interface CampaignMessage {
    subject?: string;
    body: string;
    htmlBody?: string;
}

export interface CampaignDeliveryResult {
    success: boolean;
    channel: Channel;
    guestId: string;
    messageId?: string;
    error?: string;
    deliveredAt?: Date;
}

/**
 * Send a campaign to a single recipient via the specified channel
 */
export async function sendToRecipient(
    recipient: CampaignRecipient,
    channel: Channel,
    message: CampaignMessage
): Promise<CampaignDeliveryResult> {
    const { guestId, phone, email, whatsapp } = recipient;

    try {
        switch (channel) {
            case 'sms':
                if (!phone || !recipient.isVerified) {
                    return {
                        success: false,
                        channel,
                        guestId,
                        error: 'Phone not available or not verified',
                    };
                }
                return await sendSmsCampaign(phone, message.body, guestId);

            case 'email':
                if (!email || !recipient.isVerified) {
                    return {
                        success: false,
                        channel,
                        guestId,
                        error: 'Email not available or not verified',
                    };
                }
                return await sendEmailCampaign(
                    email,
                    message.subject || 'Message',
                    message.htmlBody || message.body,
                    guestId
                );

            case 'whatsapp':
                if (!whatsapp || !recipient.isVerified) {
                    return {
                        success: false,
                        channel,
                        guestId,
                        error: 'WhatsApp not available or not verified',
                    };
                }
                return await sendWhatsAppCampaign(whatsapp, message.body, guestId);

            case 'telegram':
                if (!recipient.telegramChatId) {
                    return { success: false, channel, guestId, error: 'Telegram not linked' };
                }
                return await sendTelegramCampaign(recipient.telegramChatId, message.body, guestId);

            default:
                return { success: false, channel, guestId, error: `Unknown channel: ${channel}` };
        }
    } catch (error) {
        return {
            success: false,
            channel,
            guestId,
            error: error instanceof Error ? error.message : 'Unknown error',
        };
    }
}

/**
 * Send SMS via Africa's Talking
 */
async function sendSmsCampaign(
    phone: string,
    body: string,
    guestId: string
): Promise<CampaignDeliveryResult> {
    const result = await sendSms(phone, body);

    return {
        success: result.success,
        channel: 'sms',
        guestId,
        error: result.error,
        deliveredAt: result.success ? new Date() : undefined,
    };
}

/**
 * Send Email via Resend
 */
async function sendEmailCampaign(
    toEmail: string,
    subject: string,
    htmlBody: string,
    guestId: string
): Promise<CampaignDeliveryResult> {
    if (!resend) {
        return {
            success: false,
            channel: 'email',
            guestId,
            error: 'Resend not configured',
        };
    }

    try {
        const data = await resend.emails.send({
            from: EMAIL_FROM,
            to: toEmail,
            subject,
            html: htmlBody,
        });

        return {
            success: true,
            channel: 'email',
            guestId,
            messageId: data.data?.id,
            deliveredAt: new Date(),
        };
    } catch (error) {
        return {
            success: false,
            channel: 'email',
            guestId,
            error: error instanceof Error ? error.message : 'Resend error',
        };
    }
}

/**
 * Send WhatsApp (fallback to SMS for now)
 */
async function sendWhatsAppCampaign(
    phone: string,
    body: string,
    guestId: string
): Promise<CampaignDeliveryResult> {
    // TODO: Implement WhatsApp Business API
    // Fall back to SMS for now
    return await sendSmsCampaign(phone, `[WhatsApp]: ${body}`, guestId);
}

/**
 * Send Telegram message
 */
async function sendTelegramCampaign(
    chatId: string,
    body: string,
    guestId: string
): Promise<CampaignDeliveryResult> {
    const botToken = process.env.TELEGRAM_BOT_TOKEN;

    if (!botToken) {
        return {
            success: false,
            channel: 'telegram',
            guestId,
            error: 'Telegram bot token not configured',
        };
    }

    try {
        const response = await fetch(`https://api.telegram.org/bot${botToken}/sendMessage`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                chat_id: chatId,
                text: body,
                parse_mode: 'HTML',
            }),
        });

        const data = await response.json();

        if (data.ok) {
            return {
                success: true,
                channel: 'telegram',
                guestId,
                messageId: String(data.result.message_id),
                deliveredAt: new Date(),
            };
        } else {
            return {
                success: false,
                channel: 'telegram',
                guestId,
                error: data.description || 'Telegram API error',
            };
        }
    } catch (error) {
        return {
            success: false,
            channel: 'telegram',
            guestId,
            error: error instanceof Error ? error.message : 'Network error',
        };
    }
}

/**
 * Get verified recipients for a campaign from a restaurant
 */
export async function getVerifiedRecipients(
    restaurantId: string,
    options?: {
        segmentId?: string;
        hasPhone?: boolean;
        hasEmail?: boolean;
    }
): Promise<CampaignRecipient[]> {
    const supabase = createServiceRoleClient();

    let query = supabase
        .from('guests')
        .select(
            `
      id,
      name,
      phone,
      email,
      whatsapp,
      is_verified,
      metadata->telegram_chat_id as telegramChatId
    `
        )
        .eq('restaurant_id', restaurantId)
        .eq('is_verified', true);

    if (options?.hasPhone) {
        query = query.not('phone', 'is', null);
    }

    if (options?.hasEmail) {
        query = query.not('email', 'is', null);
    }

    const { data: guests, error } = await query;

    if (error) {
        console.error('Error fetching campaign recipients:', error);
        return [];
    }

    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    return (guests || []).map((g: any) => ({
        guestId: g.id,
        phone: g.phone,
        email: g.email,
        whatsapp: g.whatsapp,
        telegramChatId: g.telegramChatId,
        name: g.name,
        isVerified: g.is_verified,
    }));
}

/**
 * Send a marketing campaign to all recipients
 */
export async function sendCampaign(
    campaignId: string,
    restaurantId: string,
    channel: Channel,
    message: CampaignMessage
): Promise<{
    total: number;
    successful: number;
    failed: number;
    results: CampaignDeliveryResult[];
}> {
    const supabase = createServiceRoleClient();

    // Get campaign to track stats
    const { data: campaign } = await supabase
        .from('marketing_campaigns')
        .select('*')
        .eq('id', campaignId)
        .single();

    if (!campaign) {
        throw new Error('Campaign not found');
    }

    // Get recipients
    const recipients = await getVerifiedRecipients(restaurantId, {
        [channel === 'sms' || channel === 'whatsapp' ? 'hasPhone' : 'hasEmail']: true,
    });

    const results: CampaignDeliveryResult[] = [];
    let successful = 0;
    let failed = 0;

    // Send to each recipient
    for (const recipient of recipients) {
        const result = await sendToRecipient(recipient, channel, message);
        results.push(result);

        if (result.success) {
            successful++;

            // Record in campaign_recipients
            await supabase.from('campaign_recipients').upsert({
                campaign_id: campaignId,
                restaurant_id: restaurantId,
                guest_id: recipient.guestId,
                status: 'sent',
                sent_at: new Date(),
            });
        } else {
            failed++;

            await supabase.from('campaign_recipients').upsert({
                campaign_id: campaignId,
                restaurant_id: restaurantId,
                guest_id: recipient.guestId,
                status: 'failed',
                bounce_reason: result.error,
            });
        }
    }

    // Update campaign stats
    const channelKey = channel === 'sms' || channel === 'whatsapp' ? 'sms_sent' : 'emails_sent';

    await supabase
        .from('marketing_campaigns')
        .update({
            [channelKey]: successful,
            total_recipients: recipients.length,
            status: 'sent',
            sent_at: new Date(),
        })
        .eq('id', campaignId);

    return { total: recipients.length, successful, failed, results };
}

/**
 * Verify a guest's contact information
 */
export async function sendVerificationCode(
    guestId: string,
    channel: 'sms' | 'email'
): Promise<{ success: boolean; error?: string }> {
    const supabase = createServiceRoleClient();

    const { data: guest } = await supabase.from('guests').select('*').eq('id', guestId).single();

    if (!guest) {
        return { success: false, error: 'Guest not found' };
    }

    // Generate verification code (6 digits)
    const code = Math.floor(100000 + Math.random() * 900000).toString();

    const metadata = guest.metadata || {};

    // Store code in guest metadata
    await supabase
        .from('guests')
        .update({
            metadata: {
                ...metadata,
                verification_code: code,
                verification_expires: new Date(Date.now() + 10 * 60 * 1000),
            },
        })
        .eq('id', guestId);

    // Send verification code
    const message = `Your Gebeta verification code is: ${code}. This code expires in 10 minutes.`;

    if (channel === 'sms' && guest.phone) {
        const result = await sendSms(guest.phone, message);
        return { success: result.success, error: result.error };
    } else if (channel === 'email' && guest.email) {
        if (!resend) {
            return { success: false, error: 'Email not configured' };
        }

        try {
            await resend.emails.send({
                from: EMAIL_FROM,
                to: guest.email,
                subject: 'Verify your contact info',
                html: `<p>${message}</p>`,
            });
            return { success: true };
        } catch (error) {
            return {
                success: false,
                error: error instanceof Error ? error.message : 'Email error',
            };
        }
    }

    return { success: false, error: 'No contact info available' };
}

/**
 * Verify a guest's contact with code
 */
export async function verifyContact(
    guestId: string,
    code: string
): Promise<{ success: boolean; error?: string; contactType?: string }> {
    const supabase = createServiceRoleClient();

    const { data: guest } = await supabase.from('guests').select('*').eq('id', guestId).single();

    if (!guest) {
        return { success: false, error: 'Guest not found' };
    }

    const metadata = guest.metadata || {};
    const storedCode = metadata.verification_code;
    const expires = metadata.verification_expires;

    // Check code
    if (!storedCode || storedCode !== code) {
        return { success: false, error: 'Invalid verification code' };
    }

    // Check expiry
    if (expires && new Date(expires) < new Date()) {
        return { success: false, error: 'Verification code expired' };
    }

    // Mark as verified
    await supabase
        .from('guests')
        .update({
            is_verified: true,
            metadata: {
                ...metadata,
                verification_code: null,
                verification_expires: null,
                verified_at: new Date(),
            },
        })
        .eq('id', guestId);

    // Determine what was verified
    let contactType = 'unknown';
    if (guest.phone) contactType = 'phone';
    if (guest.email) contactType = contactType === 'phone' ? 'both' : 'email';

    return { success: true, contactType };
}

/**
 * Centralized Menu Management Service
 * TASK-MULTI-001: Push menu changes to all locations from one place
 *
 * Enables multi-location restaurants to manage menus centrally.
 */

import type { SupabaseClient } from '@supabase/supabase-js';
import type { Database } from '@/types/database';

// =========================================================
// Type Definitions
// =========================================================

export type SyncStatus = 'pending' | 'syncing' | 'synced' | 'failed' | 'partial';

export interface MenuLocation {
    id: string;
    restaurant_id: string;
    restaurant_name: string;
    is_primary: boolean;
    sync_enabled: boolean;
    last_sync_at: string | null;
    sync_status: SyncStatus;
    pending_changes: number;
}

export interface MenuChange {
    id: string;
    change_type: 'create' | 'update' | 'delete' | 'price_change' | 'availability_change';
    entity_type: 'category' | 'menu_item' | 'modifier_group' | 'modifier_option';
    entity_id: string;
    location_ids: string[];
    change_data: Record<string, unknown>;
    status: 'pending' | 'applied' | 'failed';
    applied_at: string | null;
    applied_to: string[];
    failed_at: string | null;
    error_message: string | null;
    created_at: string;
    created_by: string;
}

export interface CentralizedMenuConfig {
    id: string;
    primary_restaurant_id: string;
    name: string;
    description: string | null;
    sync_categories: boolean;
    sync_items: boolean;
    sync_modifiers: boolean;
    sync_pricing: boolean;
    sync_availability: boolean;
    auto_sync_enabled: boolean;
    sync_schedule: string | null;
    created_at: string;
    updated_at: string;
}

export interface SyncResult {
    location_id: string;
    location_name: string;
    success: boolean;
    changes_applied: number;
    changes_failed: number;
    errors: string[];
}

