/**
 * Record a menu change for sync
 */
export async function recordMenuChange(
    supabase: SupabaseClient<Database>,
    primaryRestaurantId: string,
    change: {
        change_type: 'create' | 'update' | 'delete' | 'price_change' | 'availability_change';
        entity_type: 'category' | 'menu_item' | 'modifier_group' | 'modifier_option';
        entity_id: string;
        change_data: Record<string, unknown>;
    },
    userId: string
): Promise<void> {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const db = supabase as any;

    try {
        // Get config
        const { data: config } = await db
            .from('centralized_menu_configs')
            .select('id')
            .eq('primary_restaurant_id', primaryRestaurantId)
            .maybeSingle();

        if (!config) {
            return; // No centralized menu configured
        }

        // Get linked locations
        const { data: links } = await db
            .from('menu_location_links')
            .select('restaurant_id')
            .eq('menu_config_id', config.id)
            .eq('sync_enabled', true)
            .neq('restaurant_id', primaryRestaurantId);

        if (!links || links.length === 0) {
            return;
        }

        // Record the change
        await db.from('menu_change_queue').insert({
            menu_config_id: config.id,
            change_type: change.change_type,
            entity_type: change.entity_type,
            entity_id: change.entity_id,
            location_ids: links.map((l: { restaurant_id: string }) => l.restaurant_id),
            change_data: change.change_data,
            status: 'pending',
            created_by: userId,
        });

        // Update pending changes count for each location
        for (const link of links) {
            await db.rpc('increment_pending_changes', {
                p_restaurant_id: link.restaurant_id,
                p_menu_config_id: config.id,
            });
        }
    } catch (error) {
        console.error('[CentralizedMenu] Failed to record change:', error);
    }
}

/**
 * Get pending changes for a location
 */
export async function getPendingChanges(
    supabase: SupabaseClient<Database>,
    primaryRestaurantId: string
): Promise<MenuChange[]> {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const db = supabase as any;

    try {
        const { data: config } = await db
            .from('centralized_menu_configs')
            .select('id')
            .eq('primary_restaurant_id', primaryRestaurantId)
            .maybeSingle();

        if (!config) {
            return [];
        }

        const { data, error } = await db
            .from('menu_change_queue')
            .select('*')
            .eq('menu_config_id', config.id)
            .eq('status', 'pending')
            .order('created_at', { ascending: true });

        if (error) {
            console.error('[CentralizedMenu] Failed to fetch pending changes:', error);
            return [];
        }

        return data ?? [];
    } catch (error) {
        console.error('[CentralizedMenu] Error:', error);
        return [];
    }
}

/**
 * Chapa Payment Service
 *
 * Integrates with Chapa (chapa.co) for hosted checkout, verification,
 * and merchant split-settlement provisioning.
 *
 * Docs: https://developer.chapa.co/docs/accept-payments
 */

const CHAPA_BASE_URL = 'https://api.chapa.co/v1';

export interface ChapaInitializeParams {
    amount: number; // ETB amount
    currency?: string; // defaults to 'ETB'
    email?: string;
    first_name: string;
    last_name?: string;
    phone_number?: string; // 09xxxxxxxx or 07xxxxxxxx format
    tx_ref: string; // unique transaction reference
    callback_url: string; // webhook URL Chapa POSTs to on success
    return_url: string; // where to redirect user after payment
    customization?: {
        title?: string;
        description?: string;
        logo?: string;
    };
    meta?: Record<string, string>;
    subaccounts?: {
        id: string;
        split_type?: 'percentage' | 'flat';
        split_value?: number;
    };
}

export interface ChapaInitializeResponse {
    status: 'success' | 'failed';
    message: string;
    data?: {
        checkout_url: string;
    };
}

export interface ChapaVerifyResponse {
    status: 'success' | 'failed';
    message: string;
    data?: {
        amount: string;
        currency: string;
        status: 'success' | 'failed' | 'pending';
        reference: string;
        tx_ref: string;
        customization?: Record<string, string>;
        meta?: Record<string, string>;
    };
}

export interface ChapaBankRecord {
    id: string;
    name: string;
    code: string;
}

export interface ChapaSubaccountParams {
    business_name: string;
    account_name: string;
    bank_code: string;
    account_number: string;
    split_type: 'percentage' | 'flat';
    split_value: number;
}

export interface ChapaSubaccountResponse {
    status: 'success' | 'failed';
    message: string;
    data?: {
        id?: string;
        [key: string]: unknown;
    };
}

/**
 * Initialize a Chapa payment transaction
 * Returns a checkout_url to redirect the user to
 */
export async function initializeChapaTransaction(
    params: ChapaInitializeParams
): Promise<ChapaInitializeResponse> {
    const secretKey = process.env.CHAPA_SECRET_KEY;

    if (!secretKey) {
        throw new Error('CHAPA_SECRET_KEY is not configured');
    }

    const response = await fetch(`${CHAPA_BASE_URL}/transaction/initialize`, {
        method: 'POST',
        headers: {
            Authorization: `Bearer ${secretKey}`,
            'Content-Type': 'application/json',
        },
        body: JSON.stringify({
            ...params,
            currency: params.currency ?? 'ETB',
        }),
    });

    const data = (await response.json()) as ChapaInitializeResponse;
    return data;
}

/**
 * Fetch the bank list used for merchant settlement account onboarding.
 */
export async function listChapaBanks(): Promise<ChapaBankRecord[]> {
    const secretKey = process.env.CHAPA_SECRET_KEY;

    if (!secretKey) {
        throw new Error('CHAPA_SECRET_KEY is not configured');
    }

    console.log('Fetching banks from Chapa API...');

    const response = await fetch(`${CHAPA_BASE_URL}/banks`, {
        method: 'GET',
        headers: {
            Authorization: `Bearer ${secretKey}`,
        },
        cache: 'no-store',
    });

    const payload = (await response.json()) as {
        status?: string;
        message?: string;
        data?: Array<Record<string, unknown>>;
    };

    console.log('Chapa banks API response:', {
        status: response.status,
        ok: response.ok,
        payloadStatus: payload.status,
        payloadMessage: payload.message,
        dataLength: payload.data?.length ?? 0,
    });

    // Chapa's bank-list docs describe a successful response with the message
    // "Banks retrieved". Do not require status === "success" here because the
    // bank directory response shape differs from payment endpoints.
    if (!response.ok || !Array.isArray(payload.data)) {
        const errorMsg =
            payload.message ?? `Failed to load Chapa banks (status: ${response.status})`;
        console.error('Chapa banks API error:', errorMsg);
        throw new Error(errorMsg);
    }

    const banks = payload.data
        .map(bank => {
            const id = String(bank.id ?? bank.bank_code ?? bank.code ?? '').trim();
            const name = String(bank.name ?? bank.bank_name ?? bank.title ?? '').trim();
            // Chapa split-payment docs require the bank id / bank_code from the
            // get banks endpoint when creating subaccounts.
            const code = String(bank.bank_code ?? bank.id ?? bank.code ?? bank.slug ?? '').trim();

            if (!id || !name) {
                return null;
            }

            return {
                id,
                name,
                code,
            };
        })
        .filter((bank): bank is ChapaBankRecord => bank !== null)
        .sort((left, right) => left.name.localeCompare(right.name));

    console.log(`Parsed ${banks.length} valid banks from Chapa response`);
    return banks;
}

/**
 * Create a restaurant settlement subaccount for split payments.
 */
export async function createChapaSubaccount(
    params: ChapaSubaccountParams
): Promise<ChapaSubaccountResponse> {
    const secretKey = process.env.CHAPA_SECRET_KEY;

    if (!secretKey) {
        throw new Error('CHAPA_SECRET_KEY is not configured');
    }

    console.log('Creating Chapa subaccount with params:', {
        business_name: params.business_name,
        account_name: params.account_name,
        bank_code: params.bank_code,
        split_type: params.split_type,
        split_value: params.split_value,
    });

    const response = await fetch(`${CHAPA_BASE_URL}/subaccount`, {
        method: 'POST',
        headers: {
            Authorization: `Bearer ${secretKey}`,
            'Content-Type': 'application/json',
        },
        body: JSON.stringify(params),
    });

    const data = (await response.json()) as ChapaSubaccountResponse;

    console.log('Chapa subaccount API response:', {
        httpStatus: response.status,
        ok: response.ok,
        status: data.status,
        message: data.message,
        dataId: data.data?.id,
        fullData: data.data,
    });

    return {
        ...data,
        status: data.status ?? (response.ok ? 'success' : 'failed'),
        message:
            data.message ||
            (response.ok ? 'Subaccount created' : 'Failed to create Chapa subaccount'),
    };
}
/**
 * Verify a completed Chapa transaction
 * Always verify server-side before marking order as confirmed
 */
export async function verifyChapaTransaction(txRef: string): Promise<ChapaVerifyResponse> {
    const secretKey = process.env.CHAPA_SECRET_KEY;

    if (!secretKey) {
        throw new Error('CHAPA_SECRET_KEY is not configured');
    }

    const response = await fetch(
        `${CHAPA_BASE_URL}/transaction/verify/${encodeURIComponent(txRef)}`,
        {
            method: 'GET',
            headers: {
                Authorization: `Bearer ${secretKey}`,
            },
        }
    );

    const data = (await response.json()) as ChapaVerifyResponse;
    return data;
}

/**
 * Generate a unique, sortable transaction reference for Chapa
 * Format: gebeta-{restaurant_prefix}-{timestamp}-{random}
 */
export function generateChapaTransactionRef(restaurantSlug: string): string {
    const prefix = restaurantSlug.replace(/[^a-z0-9]/gi, '').slice(0, 8);
    const timestamp = Date.now().toString(36);
    const random = Math.random().toString(36).slice(2, 6);
    return `gebeta-${prefix}-${timestamp}-${random}`;
}

/**
 * Check whether Chapa is properly configured (secret key present)
 */
export function isChapaConfigured(): boolean {
    const key = process.env.CHAPA_SECRET_KEY;
    return !!key && key.length > 10 && !key.startsWith('MOCK');
}

export function maskSettlementAccountNumber(accountNumber: string): string {
    const trimmed = accountNumber.replace(/\s+/g, '');
    if (trimmed.length <= 4) {
        return trimmed;
    }

    return `${'*'.repeat(Math.max(0, trimmed.length - 4))}${trimmed.slice(-4)}`;
}

/**
 * Guest Analytics Service
 *
 * Provides comprehensive guest analytics and insights for restaurant operations.
 * Includes guest segmentation, visit patterns, and lifetime value analysis.
 */

import type { SupabaseClient } from '@supabase/supabase-js';
import type { Database } from '@/types/database';

// ============================================================================
// Types
// ============================================================================

export interface GuestAnalyticsParams {
    restaurantId: string;
    startDate?: string;
    endDate?: string;
}

export interface GuestSegment {
    segment: 'new' | 'returning' | 'vip' | 'at_risk';
    count: number;
    percentOfTotal: number;
    avgSpend: number;
    avgVisits: number;
}

export interface GuestMetrics {
    totalGuests: number;
    newGuests: number;
    returningGuests: number;
    vipGuests: number;
    avgVisitsPerGuest: number;
    avgSpendPerGuest: number;
    avgSpendPerVisit: number;
    totalRevenue: number;
    retentionRate: number;
}

export interface VisitPattern {
    hour: number;
    dayOfWeek: number;
    visitCount: number;
    avgSpend: number;
}

export interface TopGuest {
    id: string;
    name: string;
    visitCount: number;
    totalSpend: number;
    avgSpendPerVisit: number;
    lastVisit: string;
    segment: string;
}

export interface GuestAnalyticsData {
    metrics: GuestMetrics;
    segments: GuestSegment[];
    visitPatterns: VisitPattern[];
    topGuests: TopGuest[];
    trends: GuestTrend[];
    insights: GuestInsight[];
}

export interface GuestTrend {
    date: string;
    newGuests: number;
    returningGuests: number;
    totalVisits: number;
    revenue: number;
}

export interface GuestInsight {
    type: 'warning' | 'info' | 'success';
    title: string;
    description: string;
    metric?: number;
    recommendation?: string;
}

// ============================================================================
// Service Functions
// ============================================================================

/**
 * Generate comprehensive guest analytics
 */
export async function generateGuestAnalytics(
    supabase: SupabaseClient<Database>,
    params: GuestAnalyticsParams
): Promise<{ data: GuestAnalyticsData | null; error: Error | null }> {
    try {
        const { restaurantId, startDate, endDate } = params;

        // Fetch guests with their order history
        const { data: guests, error: guestsError } = await supabase
            .from('guests')
            .select(
                `
                id,
                name,
                is_vip,
                created_at,
                orders:guest_visits (
                    id,
                    total_price:spend,
                    created_at
                )
            `
            )
            .eq('restaurant_id', restaurantId);

        if (guestsError) throw guestsError;

        // Fetch orders for patterns
        const { data: rawOrders, error: ordersError } = await supabase
            .from('guest_visits')
            .select('id, created_at, total_price:spend, guest_id')
            .eq('restaurant_id', restaurantId);

        if (ordersError) throw ordersError;
        const orders = rawOrders || [];

        // Calculate analytics
        const metrics = calculateMetrics(guests || [], orders, startDate, endDate);
        const segments = calculateSegments(guests || [], orders);
        const visitPatterns = calculateVisitPatterns(orders);
        const topGuests = calculateTopGuests(guests || []);
        const trends = calculateTrends(orders, startDate, endDate);
        const insights = generateInsights(metrics, segments, trends);

        return {
            data: {
                metrics,
                segments,
                visitPatterns,
                topGuests,
                trends,
                insights,
            },
            error: null,
        };
    } catch (error) {
        console.error('Error generating guest analytics:', error);
        return { data: null, error: error as Error };
    }
}

/**
 * Get guest retention rate
 */
export async function getGuestRetentionRate(
    supabase: SupabaseClient<Database>,
    restaurantId: string,
    months: number = 3
): Promise<{ data: number | null; error: Error | null }> {
    try {
        const now = new Date();
        const periodStart = new Date(now.getFullYear(), now.getMonth() - months, 1);
        const periodEnd = new Date(now.getFullYear(), now.getMonth(), 0);

        // Get guests who visited in the first period
        const { data: firstPeriodOrders, error: firstError } = await supabase
            .from('guest_visits')
            .select('guest_id')
            .eq('restaurant_id', restaurantId)
            .gte('created_at', periodStart.toISOString())
            .lte('created_at', periodEnd.toISOString())
            .not('guest_id', 'is', null);

        if (firstError) throw firstError;

        const firstPeriodGuests = new Set(firstPeriodOrders?.map(o => o.guest_id) || []);

        // Check how many returned in the next period
        const nextPeriodStart = new Date(now.getFullYear(), now.getMonth(), 1);
        const nextPeriodEnd = now;

        const { data: secondPeriodOrders, error: secondError } = await supabase
            .from('guest_visits')
            .select('guest_id')
            .eq('restaurant_id', restaurantId)
            .gte('created_at', nextPeriodStart.toISOString())
            .lte('created_at', nextPeriodEnd.toISOString())
            .not('guest_id', 'is', null);

        if (secondError) throw secondError;

        const secondPeriodGuests = new Set(secondPeriodOrders?.map(o => o.guest_id) || []);

        // Calculate retention
        let returningGuests = 0;
        for (const guestId of firstPeriodGuests) {
            if (secondPeriodGuests.has(guestId)) {
                returningGuests++;
            }
        }

        const retentionRate =
            firstPeriodGuests.size > 0 ? (returningGuests / firstPeriodGuests.size) * 100 : 0;

        return { data: Math.round(retentionRate * 100) / 100, error: null };
    } catch (error) {
        console.error('Error calculating retention rate:', error);
        return { data: null, error: error as Error };
    }
}

/**
 * Get guest lifetime value distribution
 */
export async function getGuestLifetimeValue(
    supabase: SupabaseClient<Database>,
    restaurantId: string
): Promise<{
    data: { avgLtv: number; medianLtv: number; topDecileLtv: number } | null;
    error: Error | null;
}> {
    try {
        const { data: guests, error } = await supabase
            .from('guests')
            .select(
                `
                id,
                orders:guest_visits (
                    total_price:spend
                )
            `
            )
            .eq('restaurant_id', restaurantId);

        if (error) throw error;

        const ltvValues: number[] = [];

        for (const guest of guests || []) {
            const totalSpend =
                (guest.orders as Array<{ total_price?: number }>)?.reduce((sum, o) => sum + (o.total_price || 0), 0) || 0;
            ltvValues.push(totalSpend);
        }

        ltvValues.sort((a, b) => a - b);

        const avgLtv =
            ltvValues.length > 0 ? ltvValues.reduce((a, b) => a + b, 0) / ltvValues.length : 0;
        const medianLtv = ltvValues.length > 0 ? ltvValues[Math.floor(ltvValues.length / 2)] : 0;
        const topDecileLtv =
            ltvValues.length > 0 ? ltvValues[Math.floor(ltvValues.length * 0.9)] : 0;

        return {
            data: {
                avgLtv: Math.round(avgLtv * 100) / 100,
                medianLtv: Math.round(medianLtv * 100) / 100,
                topDecileLtv: Math.round(topDecileLtv * 100) / 100,
            },
            error: null,
        };
    } catch (error) {
        console.error('Error calculating guest LTV:', error);
        return { data: null, error: error as Error };
    }
}

// ============================================================================
// Helper Functions
// ============================================================================


function calculateMetrics(
    guests: any[],
    orders: any[],
    _startDate?: string,
    _endDate?: string
): GuestMetrics {
    const now = new Date();
    const thirtyDaysAgo = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);

    let newGuests = 0;
    let returningGuests = 0;
    let vipGuests = 0;
    let totalVisits = 0;
    let totalRevenue = 0;
    const guestVisitCounts = new Map<string, number>();
    const guestSpendCounts = new Map<string, number>();

    // Process orders
    for (const order of orders) {
        if (order.guest_id) {
            totalVisits++;
            totalRevenue += order.total_price || 0;
            guestVisitCounts.set(order.guest_id, (guestVisitCounts.get(order.guest_id) || 0) + 1);
            guestSpendCounts.set(
                order.guest_id,
                (guestSpendCounts.get(order.guest_id) || 0) + (order.total_price || 0)
            );
        }
    }

    // Process guests
    for (const guest of guests) {
        const visitCount = guestVisitCounts.get(guest.id) || 0;
        const isNew = new Date(guest.created_at) >= thirtyDaysAgo;

        if (isNew) newGuests++;
        if (visitCount > 1) returningGuests++;
        if (guest.is_vip) vipGuests++;
    }

    const totalGuests = guests.length;
    const avgVisitsPerGuest = totalGuests > 0 ? totalVisits / totalGuests : 0;
    const avgSpendPerGuest = totalGuests > 0 ? totalRevenue / totalGuests : 0;
    const avgSpendPerVisit = totalVisits > 0 ? totalRevenue / totalVisits : 0;

    // Calculate retention rate (guests with 2+ visits / total guests)
    const guestsWithMultipleVisits = Array.from(guestVisitCounts.values()).filter(
        c => c >= 2
    ).length;
    const retentionRate = totalGuests > 0 ? (guestsWithMultipleVisits / totalGuests) * 100 : 0;

    return {
        totalGuests,
        newGuests,
        returningGuests,
        vipGuests,
        avgVisitsPerGuest: Math.round(avgVisitsPerGuest * 100) / 100,
        avgSpendPerGuest: Math.round(avgSpendPerGuest * 100) / 100,
        avgSpendPerVisit: Math.round(avgSpendPerVisit * 100) / 100,
        totalRevenue: Math.round(totalRevenue * 100) / 100,
        retentionRate: Math.round(retentionRate * 100) / 100,
    };
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any
function calculateSegments(guests: any[], orders: any[]): GuestSegment[] {
    const segments: Record<string, { count: number; spend: number; visits: number }> = {
        new: { count: 0, spend: 0, visits: 0 },
        returning: { count: 0, spend: 0, visits: 0 },
        vip: { count: 0, spend: 0, visits: 0 },
        at_risk: { count: 0, spend: 0, visits: 0 },
    };

    const now = new Date();
    const thirtyDaysAgo = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);
    const ninetyDaysAgo = new Date(now.getTime() - 90 * 24 * 60 * 60 * 1000);

    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const guestOrders = new Map<string, any[]>();
    for (const order of orders) {
        if (order.guest_id) {
            if (!guestOrders.has(order.guest_id)) {
                guestOrders.set(order.guest_id, []);
            }
            guestOrders.get(order.guest_id)!.push(order);
        }
    }

    for (const guest of guests) {
        const guestOrderList = guestOrders.get(guest.id) || [];
        const totalSpend = guestOrderList.reduce((sum, o) => sum + (o.total_price || 0), 0);
        const visitCount = guestOrderList.length;
        const lastOrderDate =
            guestOrderList.length > 0
                ? new Date(Math.max(...guestOrderList.map(o => new Date(o.created_at).getTime())))
                : null;

        // Determine segment
        if (guest.is_vip) {
            segments.vip.count++;
            segments.vip.spend += totalSpend;
            segments.vip.visits += visitCount;
        } else if (lastOrderDate && lastOrderDate < ninetyDaysAgo && visitCount > 0) {
            segments.at_risk.count++;
            segments.at_risk.spend += totalSpend;
            segments.at_risk.visits += visitCount;
        } else if (new Date(guest.created_at) >= thirtyDaysAgo) {
            segments.new.count++;
            segments.new.spend += totalSpend;
            segments.new.visits += visitCount;
        } else if (visitCount > 1) {
            segments.returning.count++;
            segments.returning.spend += totalSpend;
            segments.returning.visits += visitCount;
        } else {
            segments.new.count++;
            segments.new.spend += totalSpend;
            segments.new.visits += visitCount;
        }
    }

    const totalGuests = guests.length || 1;

    return Object.entries(segments).map(([segment, data]) => ({
        segment: segment as GuestSegment['segment'],
        count: data.count,
        percentOfTotal: Math.round((data.count / totalGuests) * 10000) / 100,
        avgSpend: data.count > 0 ? Math.round((data.spend / data.count) * 100) / 100 : 0,
        avgVisits: data.count > 0 ? Math.round((data.visits / data.count) * 100) / 100 : 0,
    }));
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any
function calculateVisitPatterns(orders: any[]): VisitPattern[] {
    const patterns = new Map<string, { count: number; spend: number }>();

    for (const order of orders) {
        const date = new Date(order.created_at);
        const hour = date.getHours();
        const dayOfWeek = date.getDay();
        const key = `${hour}-${dayOfWeek}`;

        if (!patterns.has(key)) {
            patterns.set(key, { count: 0, spend: 0 });
        }
        patterns.get(key)!.count++;
        patterns.get(key)!.spend += order.total_price || 0;
    }

    const result: VisitPattern[] = [];

    for (let hour = 0; hour < 24; hour++) {
        for (let dayOfWeek = 0; dayOfWeek < 7; dayOfWeek++) {
            const key = `${hour}-${dayOfWeek}`;
            const data = patterns.get(key) || { count: 0, spend: 0 };
            result.push({
                hour,
                dayOfWeek,
                visitCount: data.count,
                avgSpend: data.count > 0 ? Math.round((data.spend / data.count) * 100) / 100 : 0,
            });
        }
    }

    return result;
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any
function calculateTopGuests(guests: any[]): TopGuest[] {
    const guestData: TopGuest[] = [];

    for (const guest of guests) {
        const orders = (guest.orders as Array<{ total_price?: number; created_at: string }>) || [];
        const visitCount = orders.length;
        const totalSpend = orders.reduce((sum, o) => sum + (o.total_price || 0), 0);
        const lastVisit =
            orders.length > 0
                ? orders.sort(
                      (a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime()
                  )[0].created_at
                : guest.created_at;

        let segment = 'new';
        if (guest.is_vip) segment = 'vip';
        else if (visitCount > 5) segment = 'returning';

        guestData.push({
            id: guest.id,
            name: guest.name || 'Unknown',
            visitCount,
            totalSpend: Math.round(totalSpend * 100) / 100,
            avgSpendPerVisit:
                visitCount > 0 ? Math.round((totalSpend / visitCount) * 100) / 100 : 0,
            lastVisit,
            segment,
        });
    }

    return guestData.sort((a, b) => b.totalSpend - a.totalSpend).slice(0, 10);
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any
function calculateTrends(orders: any[], _startDate?: string, _endDate?: string): GuestTrend[] {
    const trends = new Map<
        string,
        {
            newGuests: Set<string>;
            returningGuests: Set<string>;
            totalVisits: number;
            revenue: number;
        }
    >();

    // Group by date
    for (const order of orders) {
        const date = new Date(order.created_at).toISOString().split('T')[0];
        if (!trends.has(date)) {
            trends.set(date, {
                newGuests: new Set(),
                returningGuests: new Set(),
                totalVisits: 0,
                revenue: 0,
            });
        }
        const data = trends.get(date)!;
        data.totalVisits++;
        data.revenue += order.total_price || 0;
        if (order.guest_id) {
            data.returningGuests.add(order.guest_id);
        }
    }

    return Array.from(trends.entries())
        .map(([date, data]) => ({
            date,
            newGuests: data.newGuests.size,
            returningGuests: data.returningGuests.size,
            totalVisits: data.totalVisits,
            revenue: Math.round(data.revenue * 100) / 100,
        }))
        .sort((a, b) => a.date.localeCompare(b.date));
}

function generateInsights(
    metrics: GuestMetrics,
    _segments: GuestSegment[],
    _trends: GuestTrend[]
): GuestInsight[] {
    const insights: GuestInsight[] = [];

    // Retention insight
    if (metrics.retentionRate < 20) {
        insights.push({
            type: 'warning',
            title: 'Low Guest Retention',
            description: `Only ${metrics.retentionRate}% of guests return for a second visit.`,
            metric: metrics.retentionRate,
            recommendation: 'Consider implementing a loyalty program to encourage repeat visits.',
        });
    } else if (metrics.retentionRate > 40) {
        insights.push({
            type: 'success',
            title: 'Strong Guest Retention',
            description: `${metrics.retentionRate}% of guests return for multiple visits.`,
            metric: metrics.retentionRate,
        });
    }

    // VIP segment insight
    const vipSegment = _segments.find((s: GuestSegment) => s.segment === 'vip');
    if (vipSegment && vipSegment.percentOfTotal < 5) {
        insights.push({
            type: 'info',
            title: 'VIP Opportunity',
            description: `Only ${vipSegment.percentOfTotal}% of guests are VIPs.`,
            metric: vipSegment.percentOfTotal,
            recommendation: 'Identify top spenders and offer VIP status to increase loyalty.',
        });
    }

    // At-risk segment insight
    const atRiskSegment = _segments.find((s: GuestSegment) => s.segment === 'at_risk');
    if (atRiskSegment && atRiskSegment.count > 0) {
        insights.push({
            type: 'warning',
            title: 'At-Risk Guests',
            description: `${atRiskSegment.count} guests haven't visited in 90+ days.`,
            metric: atRiskSegment.count,
            recommendation: 'Send a re-engagement campaign with a special offer.',
        });
    }

    // Average spend insight
    if (metrics.avgSpendPerVisit > 0) {
        insights.push({
            type: 'info',
            title: 'Average Spend Per Visit',
            description: `Guests spend an average of ${metrics.avgSpendPerVisit} ETB per visit.`,
            metric: metrics.avgSpendPerVisit,
        });
    }

    return insights;
}

/**
 * Labor Reports Service
 *
 * Provides comprehensive labor analytics and reporting for restaurant operations.
 * Includes time tracking, labor cost analysis, and scheduling insights.
 *
 * LOW-002: Configurable hourly rates per restaurant and role
 */

import type { SupabaseClient } from '@supabase/supabase-js';
import type { Database } from '@/types/database';

// ============================================================================
// Types
// ============================================================================

/**
 * Hourly rate configuration for labor cost calculations
 * LOW-002: Made configurable per restaurant and role
 */
export interface HourlyRateConfig {
    /** Default hourly rate for the restaurant (in ETB) */
    defaultRate: number;
    /** Role-specific hourly rates (override default) */
    roleRates?: Record<string, number>;
    /** Staff-specific hourly rates (override role and default) */
    staffRates?: Record<string, number>;
}

/**
 * Default hourly rates by role in ETB
 * These are fallback values when restaurant hasn't configured custom rates
 */
export const DEFAULT_ROLE_HOURLY_RATES: Record<string, number> = {
    manager: 75,
    chef: 60,
    cook: 45,
    waiter: 35,
    waitress: 35,
    bartender: 40,
    cashier: 40,
    host: 35,
    hostess: 35,
    dishwasher: 30,
    cleaner: 30,
    delivery: 40,
    default: 50,
};

/**
 * Fetch hourly rate configuration for a restaurant
 * Uses the restaurants table's settings column for labor configuration
 */
export async function getHourlyRateConfig(
    supabase: SupabaseClient<Database>,
    restaurantId: string
): Promise<HourlyRateConfig> {
    try {
        // Try to fetch restaurant-specific rate configuration from restaurants table
        const { data: restaurant, error } = await supabase
            .from('restaurants')
            .select('settings')
            .eq('id', restaurantId)
            .single();

        if (error || !restaurant?.settings) {
            // Return default configuration
            return {
                defaultRate: DEFAULT_ROLE_HOURLY_RATES.default,
                roleRates: DEFAULT_ROLE_HOURLY_RATES,
            };
        }

        // Extract labor settings from restaurant settings JSONB column
        const settings = restaurant.settings as Record<string, unknown>;
        const laborSettings = (settings?.labor as Record<string, unknown>) || {};

        return {
            defaultRate:
                (laborSettings.defaultHourlyRate as number) ?? DEFAULT_ROLE_HOURLY_RATES.default,
            roleRates: {
                ...DEFAULT_ROLE_HOURLY_RATES,
                ...(laborSettings.roleHourlyRates as Record<string, number>),
            },
            staffRates: laborSettings.staffHourlyRates as Record<string, number>,
        };
    } catch {
        // Return default configuration on error
        return {
            defaultRate: DEFAULT_ROLE_HOURLY_RATES.default,
            roleRates: DEFAULT_ROLE_HOURLY_RATES,
        };
    }
}

/**
 * Get hourly rate for a specific staff member
 */
export function getStaffHourlyRate(
    staffId: string,
    role: string,
    config: HourlyRateConfig
): number {
    // 1. Check staff-specific rate (highest priority)
    if (config.staffRates?.[staffId] !== undefined) {
        return config.staffRates[staffId];
    }

    // 2. Check role-specific rate
    const normalizedRole = role.toLowerCase();
    if (config.roleRates?.[normalizedRole] !== undefined) {
        return config.roleRates[normalizedRole];
    }

    // 3. Fall back to default rate
    return config.defaultRate;
}

export interface LaborReportParams {
    restaurantId: string;
    startDate: string;
    endDate: string;
    groupBy?: 'day' | 'week' | 'month';
    /** Optional hourly rate configuration override */
    hourlyRateConfig?: HourlyRateConfig;
}

export interface TimeEntrySummary {
    staffId: string;
    staffName: string;
    role: string;
    totalHours: number;
    regularHours: number;
    overtimeHours: number;
    totalPay: number;
    hourlyRate: number;
    shiftsWorked: number;
    avgHoursPerShift: number;
}

export interface DailyLaborSummary {
