    totalHours: number;
    totalPay: number;
    staffCount: number;
    scheduledHours: number;
    variance: number;
    laborCostPercent: number;
    sales: number;
}

export interface LaborReportData {
    summary: {
        totalHours: number;
        totalPay: number;
        avgHoursPerEmployee: number;
        laborCostPercent: number;
        overtimeHours: number;
        overtimePay: number;
        totalShifts: number;
        avgShiftLength: number;
    };
    byStaff: TimeEntrySummary[];
    byDay: DailyLaborSummary[];
