/**
 * Calculate next run time
 */
function calculateNextRunTime(
    frequency: ReportFrequency,
    runAtTime: string,
    dayOfWeek: number | null,
    dayOfMonth: number | null,
    _timezone: string = 'Africa/Addis_Ababa'
): string {
    const now = new Date();
    const [hours, minutes] = runAtTime.split(':').map(Number);

    const nextRun = new Date(now);
    nextRun.setHours(hours, minutes, 0, 0);

    switch (frequency) {
        case 'daily':
            if (nextRun <= now) {
                nextRun.setDate(nextRun.getDate() + 1);
            }
            break;

        case 'weekly':
            if (dayOfWeek !== null) {
                const currentDay = nextRun.getDay();
                const daysUntilTarget = (dayOfWeek - currentDay + 7) % 7;
                nextRun.setDate(nextRun.getDate() + daysUntilTarget);
                if (nextRun <= now) {
                    nextRun.setDate(nextRun.getDate() + 7);
                }
            }
            break;

        case 'monthly':
            if (dayOfMonth !== null) {
                nextRun.setDate(Math.min(dayOfMonth, getDaysInMonth(nextRun)));
                if (nextRun <= now) {
                    nextRun.setMonth(nextRun.getMonth() + 1);
                    nextRun.setDate(Math.min(dayOfMonth, getDaysInMonth(nextRun)));
                }
            }
            break;

        case 'quarterly':
            // Run on first day of quarter
            const month = now.getMonth();
            const quarterStartMonth = Math.floor(month / 3) * 3;
            nextRun.setMonth(quarterStartMonth, 1);
            if (nextRun <= now) {
                nextRun.setMonth(nextRun.getMonth() + 3);
            }
            break;
    }

    return nextRun.toISOString();
}

function getDaysInMonth(date: Date): number {
    return new Date(date.getFullYear(), date.getMonth() + 1, 0).getDate();
}

function getDateRange(
    dateRange: DateRange,
    customDays: number | null
): { startDate: Date; endDate: Date } {
    const now = new Date();
    const endDate = new Date(now);
    endDate.setHours(23, 59, 59, 999);
    const startDate = new Date(now);
    startDate.setHours(0, 0, 0, 0);

    switch (dateRange) {
        case 'previous_day':
            startDate.setDate(startDate.getDate() - 1);
            endDate.setDate(endDate.getDate() - 1);
            break;

        case 'previous_week':
            startDate.setDate(startDate.getDate() - 7);
            break;

        case 'previous_month':
            startDate.setMonth(startDate.getMonth() - 1);
            break;

        case 'week_to_date':
            startDate.setDate(startDate.getDate() - startDate.getDay());
            break;

        case 'month_to_date':
            startDate.setDate(1);
            break;

        case 'custom':
            if (customDays) {
                startDate.setDate(startDate.getDate() - customDays);
            }
            break;
    }

    return { startDate, endDate };
}

async function generateReportData(
    supabase: SupabaseClient<Database>,
    restaurantId: string,
    reportType: ReportType,
    startDate: Date,
    endDate: Date,
    _filters: Record<string, unknown>
): Promise<Record<string, unknown>> {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const db = supabase as any;

    switch (reportType) {
        case 'sales_summary':
            const { data: orders } = await db
                .from('orders')
                .select('id, total_price, created_at, status')
                .eq('restaurant_id', restaurantId)
                .gte('created_at', startDate.toISOString())
                .lte('created_at', endDate.toISOString());

            return {
                total_sales:
                    orders?.reduce((sum: number, o: { total_price?: number }) => sum + (o.total_price ?? 0), 0) ?? 0,
                order_count: orders?.length ?? 0,
                period_start: startDate,
                period_end: endDate,
            };

        case 'item_performance':
            const { data: orderItems } = await db
                .from('order_items')
                .select('name, quantity, price, menu_item_id')
                .eq('restaurant_id', restaurantId)
                .gte('created_at', startDate.toISOString())
                .lte('created_at', endDate.toISOString());

            return {
                items: orderItems ?? [],
                period_start: startDate,
                period_end: endDate,
            };

        default:
            return { period_start: startDate, period_end: endDate };
    }
}


