/**
 * Typed Supabase query helpers
 *
 * Addresses: Type Safety Gaps with Supabase Queries (Medium Priority Audit Finding #7)
 * Provides centralized, type-safe query functions for common database operations
 */

import type { SupabaseClient } from '@supabase/supabase-js';
import type { Database } from '@/types/database';

// Type aliases for cleaner code
type Tables = Database['public']['Tables'];

/**
 * Fetch reviews for a specific menu item
 *
 * @param supabase - Supabase client instance
 * @param itemId - The item ID to fetch reviews for
 * @returns Array of reviews ordered by created_at desc
 */
export async function fetchReviews(
    supabase: SupabaseClient<Database>,
    itemId: string
): Promise<{ data: Tables['reviews']['Row'][] | null; error: Error | null }> {
    return supabase
        .from('reviews')
        .select('*')
        .eq('item_id', itemId)
        .order('created_at', { ascending: false })
        .returns<Tables['reviews']['Row'][]>();
}

/**
 * Fetch orders for a restaurant within a time range
 *
 * @param supabase - Supabase client instance
 * @param restaurantId - The restaurant ID
 * @param since - ISO timestamp to fetch orders from
 * @returns Array of orders ordered by created_at desc
 */
export async function fetchOrdersSince(
    supabase: SupabaseClient<Database>,
    restaurantId: string,
    since: string
): Promise<{ data: Tables['orders']['Row'][] | null; error: Error | null }> {
    return supabase
        .from('orders')
        .select('*')
        .eq('restaurant_id', restaurantId)
        .gt('created_at', since)
        .order('created_at', { ascending: false })
        .returns<Tables['orders']['Row'][]>();
}

/**
 * Fetch pending service requests for a restaurant
 *
 * @param supabase - Supabase client instance
 * @param restaurantId - The restaurant ID
 * @returns Array of non-completed service requests
 */
export async function fetchPendingServiceRequests(
    supabase: SupabaseClient<Database>,
    restaurantId: string
): Promise<{ data: Tables['service_requests']['Row'][] | null; error: Error | null }> {
    return supabase
        .from('service_requests')
        .select('*')
        .eq('restaurant_id', restaurantId)
        .neq('status', 'completed')
        .order('created_at', { ascending: false })
        .returns<Tables['service_requests']['Row'][]>();
}

/**
 * Fetch menu items by category
 *
 * @param supabase - Supabase client instance
 * @param categoryId - The category ID
 * @returns Array of menu items in the category
 */
export async function fetchItemsByCategory(
    supabase: SupabaseClient<Database>,
    categoryId: string
): Promise<{ data: Tables['menu_items']['Row'][] | null; error: Error | null }> {
    return supabase
        .from('menu_items')
        .select('*')
        .eq('category_id', categoryId)
        .eq('is_available', true)
        .order('name', { ascending: true })
        .returns<Tables['menu_items']['Row'][]>();
}

/**
 * Fetch restaurant with full menu (categories + items)
 *
 * @param supabase - Supabase client instance
 * @param slug - The restaurant slug
 * @returns Restaurant data with nested categories and items
 */
export async function fetchRestaurantWithMenu(
    supabase: SupabaseClient<Database>,
    slug: string
): Promise<{ data: Tables['restaurants']['Row'] | null; error: Error | null }> {
    return supabase
        .from('restaurants')
        .select(
            `
            *,
            categories:categories(
                *,
                items:menu_items(*)
            )
        `
        )
        .eq('slug', slug)
        .single();
}

/**
 * Insert a new order with type safety
 *
 * @param supabase - Supabase client instance
 * @param order - Order data to insert
 * @returns Inserted order data
 */
export async function insertOrder(
    supabase: SupabaseClient<Database>,
    order: Tables['orders']['Insert']
): Promise<{ data: Tables['orders']['Row'] | null; error: Error | null }> {
    const { error } = await supabase.from('orders').insert(order);

    // Return early if there's an error
    if (error) {
        return { data: null, error };
    }

    // Since we don't use .select(), we return the input object as the "Row".
    // This avoids triggering RLS SELECT policies which guests don't have.
    // Ensure `id` was generated prior to calling this function.
    return { data: order as Tables['orders']['Row'], error: null };
}

/**
 * Insert a service request with type safety
 *
 * @param supabase - Supabase client instance
 * @param request - Service request data to insert
 * @returns Inserted service request data
 */
export async function insertServiceRequest(
    supabase: SupabaseClient<Database>,
    request: Tables['service_requests']['Insert']
): Promise<{ data: Tables['service_requests']['Row'] | null; error: Error | null }> {
    return supabase
        .from('service_requests')
        .insert(request)
        .select()
        .single()
        .returns<Tables['service_requests']['Row']>();
}

/**
 * Update order status with type safety
 *
 * @param supabase - Supabase client instance
 * @param orderId - The order ID to update
 * @param status - New status value
 * @returns Updated order data
 */
export async function updateOrderStatus(
    supabase: SupabaseClient<Database>,
    orderId: string,
    status: Tables['orders']['Row']['status']
): Promise<{ data: Tables['orders']['Row'] | null; error: Error | null }> {
    return supabase
        .from('orders')
        .update({ status, updated_at: new Date().toISOString() })
        .eq('id', orderId)
        .select()
        .single()
        .returns<Tables['orders']['Row']>();
}

/**
 * Check for existing order by idempotency key
 *
 * @param supabase - Supabase client instance
 * @param idempotencyKey - The idempotency key to check
 * @returns Existing order if found, null otherwise
 */
export async function getOrderByIdempotencyKey(
    supabase: SupabaseClient<Database>,
    idempotencyKey: string
): Promise<{ data: Pick<Tables['orders']['Row'], 'id' | 'status'> | null; error: Error | null }> {
    return supabase
        .from('orders')
        .select('id, status')
        .eq('idempotency_key', idempotencyKey)
        .maybeSingle()
        .returns<Pick<Tables['orders']['Row'], 'id' | 'status'> | null>();
}

/**
 * Fetch items by IDs for validation
 *
 * @param supabase - Supabase client instance
 * @param itemIds - Array of item IDs to fetch
 * @returns Array of items with validation fields
 */
export async function fetchItemsForValidation(
    supabase: SupabaseClient<Database>,
    itemIds: string[]
): Promise<{
    data: Array<{
        id: string;
        name: string;
        price: number;
        is_available: boolean;
        station: string;
        course: string;
    }> | null;
    error: Error | null;
}> {
    const db = supabase as any;
    return db
        .from('menu_items')
        .select('id, name, price, is_available, station, course')
        .in('id', itemIds);
}

import { createServerClient } from '@supabase/ssr';
import { cookies, headers } from 'next/headers';
import type { Database } from '@/types/database';
import {
    isE2EBypassAllowed,
    isValidE2EBypassSecret,
    logE2ESecurityEvent,
} from '@/lib/security/e2e-validation';

export async function createClient() {
    const cookieStore = await cookies();
    const headersList = await headers();

    // =========================================================
    // CRIT-003: Secure E2E Test Bypass
    // =========================================================
    // SECURITY: Check if E2E bypass is allowed in current environment
    // This is the FIRST check - if not allowed, skip all bypass logic
    // =========================================================

    let isE2EBypass = false;

    if (!isE2EBypassAllowed()) {
        // In production, log any bypass attempts for security monitoring
        const e2eBypassAuth = headersList.get('x-e2e-bypass-auth');
        const e2eBypassSecret = headersList.get('x-e2e-bypass-secret');
        const cookieToken = cookieStore.get('sb-access-token')?.value;

        if (e2eBypassAuth === '1' || e2eBypassSecret || cookieToken?.startsWith('e2e-mock-')) {
            logE2ESecurityEvent('bypass_attempt', {
                source: 'server',
                hasHeaderAuth: !!e2eBypassAuth,
                hasHeaderSecret: !!e2eBypassSecret,
                hasCookieToken: !!cookieToken,
            });
        }
        // Continue to normal Supabase client - E2E bypass is NOT available
    } else {
        // E2E bypass is allowed in this environment (non-production with E2E_TEST_MODE=true)
        const configuredSecret = process.env.E2E_BYPASS_SECRET;

        // SECURITY: Require configured secret - NO default fallback
        if (!configuredSecret || configuredSecret === '') {
            logE2ESecurityEvent('config_warning', {
                source: 'server',
                reason: 'E2E_BYPASS_SECRET not configured',
            });
        } else {
            // Check for header-based bypass (set by Playwright via setExtraHTTPHeaders)
            const e2eBypassAuth = headersList.get('x-e2e-bypass-auth');
            const e2eBypassSecret = headersList.get('x-e2e-bypass-secret');
            const hasValidHeaderBypass =
                e2eBypassAuth === '1' && isValidE2EBypassSecret(e2eBypassSecret ?? undefined);

            // Check for cookie-based bypass (set by middleware on subsequent requests)
            const cookieValue = cookieStore.get('sb-access-token')?.value;
            const expectedCookieValue = `e2e-mock-access-token:${configuredSecret}`;
            const hasValidCookieBypass = cookieValue === expectedCookieValue;

            // E2E bypass is active if either header or cookie bypass is valid
            isE2EBypass = hasValidHeaderBypass || hasValidCookieBypass;

            // Log when E2E bypass is active
            if (isE2EBypass) {
                logE2ESecurityEvent('bypass_success', {
                    source: 'server',
                    method: hasValidHeaderBypass ? 'header' : 'cookie',
                });
            }
        }
    }

    // Get and clean environment variables
    // Vercel can store values with extra quotes and \r\n when set via CLI/API
    // e.g. '"actual-value" \r\n' — we need to strip all of that
    const cleanEnvVar = (val: string | undefined): string => {
        if (!val) return '';
        return val
            .replace(/\r/g, '') // carriage returns
            .replace(/\n/g, '') // newlines
            .replace(/^["']+/, '') // leading quotes (one or more)
            .replace(/["']+$/, '') // trailing quotes (one or more)
            .trim();
    };

    const supabaseUrl = cleanEnvVar(process.env.NEXT_PUBLIC_SUPABASE_URL);
    const supabaseKey = cleanEnvVar(process.env.NEXT_PUBLIC_SUPABASE_PUBLISHABLE_KEY);

    // If environment variables are missing or are placeholder values, return a mock client
    // When real credentials are available (like in .env), use the real Supabase client
    // E2E bypass via cookie is still supported for authenticated sessions in E2E tests
    const isPlaceholderUrl = supabaseUrl?.includes('placeholder') || !supabaseUrl;
    const isPlaceholderKey = supabaseKey === 'placeholder-key' || !supabaseKey;
    const hasRealCredentials = supabaseUrl && supabaseKey && !isPlaceholderUrl && !isPlaceholderKey;

    // Use mock client when:
    // 1. E2E bypass cookie is set (middleware set this from headers)
    // 2. No credentials at all
    // 3. Placeholder values (E2E tests without real backend)
    // NOTE: E2E bypass cookie takes priority over real credentials
    // This ensures E2E tests have predictable mocked data
    if (isE2EBypass || !hasRealCredentials) {
        // Helper to create chainable mock methods.
        // NOTE: data is the list-level result; maybeSingle returns null (no row found)
        // unless overridden by a table-specific mock below.
        const createChainableMock = (data: unknown, singleData: unknown = null) => ({
