/**
 * PowerSync schema definition
 * Defines the local SQLite database schema for offline operation
 */
export const powerSyncSchema = `
    -- Orders table (mirrors backend orders)
    CREATE TABLE IF NOT EXISTS orders (
        id TEXT PRIMARY KEY,
        restaurant_id TEXT NOT NULL,
        order_number INTEGER NOT NULL,
        table_number INTEGER,
        guest_name TEXT,
        guest_phone TEXT,
        status TEXT NOT NULL DEFAULT 'pending',
        order_type TEXT NOT NULL DEFAULT 'dine_in',
        subtotal_santim INTEGER NOT NULL DEFAULT 0,
        discount_santim INTEGER NOT NULL DEFAULT 0,
        vat_santim INTEGER NOT NULL DEFAULT 0,
        total_santim INTEGER NOT NULL DEFAULT 0,
        notes TEXT,
        idempotency_key TEXT UNIQUE NOT NULL,
        guest_fingerprint TEXT,
        created_at TEXT NOT NULL,
        updated_at TEXT NOT NULL,
        synced_at TEXT,
        last_modified TEXT NOT NULL,
        version INTEGER NOT NULL DEFAULT 1
    );

    -- Order items table
    CREATE TABLE IF NOT EXISTS order_items (
        id TEXT PRIMARY KEY,
        order_id TEXT NOT NULL,
        menu_item_id TEXT NOT NULL,
        menu_item_name TEXT NOT NULL,
        menu_item_name_am TEXT,
        quantity INTEGER NOT NULL DEFAULT 1,
        unit_price_santim INTEGER NOT NULL,
        total_price_santim INTEGER NOT NULL,
        modifiers_json TEXT,
        notes TEXT,
        status TEXT NOT NULL DEFAULT 'pending',
        station TEXT,
        fired_at TEXT,
        created_at TEXT NOT NULL,
        synced_at TEXT,
        FOREIGN KEY (order_id) REFERENCES orders(id)
    );

    -- KDS order items for kitchen display
    CREATE TABLE IF NOT EXISTS kds_items (
        id TEXT PRIMARY KEY,
        order_id TEXT NOT NULL,
        order_item_id TEXT NOT NULL,
        station TEXT NOT NULL,
        status TEXT NOT NULL DEFAULT 'queued',
        started_at TEXT,
        ready_at TEXT,
        recalled_at TEXT,
        bumped_at TEXT,
        priority INTEGER NOT NULL DEFAULT 0,
        created_at TEXT NOT NULL,
        synced_at TEXT,
        FOREIGN KEY (order_id) REFERENCES orders(id)
    );

    -- Sync queue for pending operations
    CREATE TABLE IF NOT EXISTS sync_queue (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        operation TEXT NOT NULL,
        table_name TEXT NOT NULL,
        record_id TEXT NOT NULL,
        payload TEXT NOT NULL,
        idempotency_key TEXT UNIQUE NOT NULL,
        status TEXT NOT NULL DEFAULT 'pending',
        attempts INTEGER NOT NULL DEFAULT 0,
        last_error TEXT,
        created_at TEXT NOT NULL,
        processed_at TEXT
    );

    -- Printer jobs for offline printing
    CREATE TABLE IF NOT EXISTS printer_jobs (
        id TEXT PRIMARY KEY,
        order_id TEXT NOT NULL,
        station TEXT NOT NULL,
        payload_json TEXT NOT NULL,
        status TEXT NOT NULL DEFAULT 'pending',
        attempts INTEGER NOT NULL DEFAULT 0,
        last_error TEXT,
        created_at TEXT NOT NULL,
        printed_at TEXT,
        FOREIGN KEY (order_id) REFERENCES orders(id)
    );

    -- Restaurant settings cached locally
    CREATE TABLE IF NOT EXISTS restaurant_settings (
        restaurant_id TEXT PRIMARY KEY,
        settings_json TEXT NOT NULL,
        synced_at TEXT NOT NULL
    );

    -- Indexes for performance
    CREATE INDEX IF NOT EXISTS idx_orders_restaurant ON orders(restaurant_id);
    CREATE INDEX IF NOT EXISTS idx_orders_status ON orders(status);
    CREATE INDEX IF NOT EXISTS idx_orders_idempotency ON orders(idempotency_key);
    CREATE INDEX IF NOT EXISTS idx_order_items_order ON order_items(order_id);
    CREATE INDEX IF NOT EXISTS idx_kds_items_order ON kds_items(order_id);
    CREATE INDEX IF NOT EXISTS idx_kds_items_station ON kds_items(station);
    CREATE INDEX IF NOT EXISTS idx_sync_queue_status ON sync_queue(status);
    CREATE INDEX IF NOT EXISTS idx_printer_jobs_status ON printer_jobs(status);
`;

/**
 * PowerSync configuration options
 */
export interface PowerSyncConfig {
    /** PowerSync Cloud endpoint URL */
    endpoint: string;
    /** Authentication token */
    apiKey: string;
    /** Current restaurant ID for multi-tenant sync */
    restaurantId?: string;
    /** Enable debug logging */
    debug?: boolean;
}

/**
 * Get PowerSync configuration from environment
 */
export function getPowerSyncConfig(): PowerSyncConfig {
    const endpoint = process.env.NEXT_PUBLIC_POWERSYNC_ENDPOINT;
    const apiKey = process.env.POWERSYNC_API_KEY;

    if (!endpoint || !apiKey) {
        console.warn('[PowerSync] Missing configuration - running in offline-only mode');
        return {
            endpoint: '',
            apiKey: '',
            debug: process.env.NODE_ENV === 'development',
        };
    }

    return {
        endpoint,
        apiKey,
        debug: process.env.NODE_ENV === 'development',
    };
}

// Export the PowerSyncDatabase type
export type { PowerSyncDatabase };

/**
 * Singleton PowerSync database instance
 */
let powerSyncDb: PowerSyncDatabase | null = null;

/**
 * Initialize PowerSync database
 * Must be called in a React context (Client Component)
 *
 * Note: When @powersync packages are installed, this will use the actual
 * PowerSync implementation. Until then, it returns null and runs in offline-only mode.
 */
export async function initPowerSync(): Promise<PowerSyncDatabase | null> {
    if (powerSyncDb) {
        return powerSyncDb;
    }

    const config = getPowerSyncConfig();

    if (!config.endpoint || !config.apiKey) {
        console.warn('[PowerSync] Not configured - offline mode only');
        return null;
    }

    // Dynamic import when packages are available
    // Uses @powersync/web for core functionality and @powersync/react for React integration
    try {
        // Use dynamic import to avoid build errors when packages aren't available
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        let webModule: any;
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        let reactModule: any;

        try {
            webModule = await import('@powersync/web');
        } catch {
            webModule = null;
        }

        try {
            reactModule = await import('@powersync/react');
        } catch {
            reactModule = null;
        }

        if (!webModule || !reactModule) {
            console.warn('[PowerSync] Packages not available - running in offline-only mode');
            return null;
        }

        const { PowerSyncDatabase } = webModule;
        const { PowerSyncOpenSQLiteAdapter } = reactModule;

        powerSyncDb = await PowerSyncDatabase.connect({
            schema: powerSyncSchema,
            adapter: new PowerSyncOpenSQLiteAdapter({
                dbFilename: 'gebeta_offline.db',
            }),
        });

        if (config.debug) {
            console.log('[PowerSync] Database initialized successfully');
        }

        return powerSyncDb;
    } catch (error) {
        // Packages not installed yet - run in offline-only mode
        console.warn('[PowerSync] Packages not available - running in offline-only mode:', error);
        return null;
    }
}

/**
 * Get the PowerSync database instance
 */
export function getPowerSync(): PowerSyncDatabase | null {
    return powerSyncDb;
}

/**
 * Close PowerSync connection
 */
export async function closePowerSync(): Promise<void> {
    if (powerSyncDb) {
        await powerSyncDb.close();
        powerSyncDb = null;
    }
}

/**
 * Sync Worker
 *
 * CRIT-05: Offline sync consolidation
 * Handles background sync between local PowerSync and server
 */

import {
    getPendingSyncOperations,
    markSyncOperationCompleted,
    markSyncOperationFailed,
    getSyncQueueStatus,
} from './idempotency';

/**
 * Sync operation row type from the database
 */
interface SyncOperationRow {
    id: number;
    operation: string;
    table_name: string;
    record_id: string;
    payload: string;
    idempotency_key: string;
    attempts: number;
    last_error: string | null;
    created_at: string;
}

/**
 * HIGH-013: API endpoint configuration for sync operations
 * Uses the unified /api/sync endpoint for batch operations
 */
const SYNC_API_ENDPOINT = '/api/sync';

/**
 * Individual table endpoints for direct operations (fallback)
 */
const SYNC_ENDPOINTS: Record<string, string> = {
    orders: '/api/orders',
    order_items: '/api/orders/items',
    kds_order_items: '/api/kds/items',
    tables: '/api/device/tables',
    payments: '/api/payments',
    guests: '/api/guests',
} as const;

/**
 * Exponential backoff configuration
 */
const MAX_RETRIES = 3;
const BASE_DELAY_MS = 1000;
const MAX_DELAY_MS = 30000;

/**
 * Sync worker configuration
 */
export interface SyncWorkerConfig {
    /** Interval in ms for checking pending operations */
    syncIntervalMs: number;
    /** Maximum operations per sync batch */
    batchSize: number;
    /** Enable printer queue processing */
    enablePrinterQueue: boolean;
    /** Callback for sync events */
    onSyncProgress?: (stats: SyncProgress) => void;
    /** Callback for errors */
    onError?: (error: Error) => void;
}

/**
 * Sync progress statistics
 */
export interface SyncProgress {
    pendingOperations: number;
    completedOperations: number;
    failedOperations: number;
    printerJobsProcessed: number;
    printerJobsSucceeded: number;
    printerJobsFailed: number;
    lastSyncAt: string | null;
    isOnline: boolean;
}

const DEFAULT_CONFIG: SyncWorkerConfig = {
    syncIntervalMs: 5000, // 5 seconds
    batchSize: 20,
    enablePrinterQueue: true,
};

/**
 * Create a sync worker
 */
export function createSyncWorker(config: Partial<SyncWorkerConfig> = {}) {
    const cfg = { ...DEFAULT_CONFIG, ...config };

    let isRunning = false;
    let intervalId: ReturnType<typeof setInterval> | null = null;
    let lastSyncAt: string | null = null;

    /**
     * HIGH-013: Calculate exponential backoff delay
     */
    function calculateBackoffDelay(retryCount: number): number {
        const delay = Math.min(BASE_DELAY_MS * Math.pow(2, retryCount), MAX_DELAY_MS);
        // Add jitter to prevent thundering herd
        return delay + Math.random() * 1000;
    }

    /**
     * HIGH-013: Execute batch sync via unified /api/sync endpoint
     * This is more efficient than individual API calls
     */
    async function executeBatchSync(operations: SyncOperationRow[]): Promise<{
        succeeded: number;
        failed: number;
        results: Map<number, { success: boolean; error?: string }>;
    }> {
        const results = new Map<number, { success: boolean; error?: string }>();
        let succeeded = 0;
        let failed = 0;

        if (operations.length === 0) {
            return { succeeded, failed, results };
        }

        // Transform operations to sync API format
        const syncOperations = operations.map(op => {
            let payload;
            try {
                payload = op.payload ? JSON.parse(op.payload) : {};
            } catch {
                payload = {};
            }

            return {
                id: crypto.randomUUID(),
                operation: op.operation.toLowerCase(),
                tableName: op.table_name,
                recordId: op.record_id,
                data: payload,
                version: 1,
                lastModified: new Date().toISOString(),
                idempotencyKey: op.idempotency_key || `sync-${op.id}`,
                restaurantId: payload.restaurant_id || '',
            };
        });

        try {
            const response = await fetch(SYNC_API_ENDPOINT, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({
                    operations: syncOperations,
                    clientId: `sync-worker-${Date.now()}`,
                }),
            });

            if (!response.ok) {
                // Batch failed - fall back to individual operations
                console.warn(
                    '[SyncWorker] Batch sync failed, falling back to individual operations'
                );
                for (const op of operations) {
                    const result = await executeSyncOperation(op);
                    results.set(op.id, result);
                    if (result.success) {
                        succeeded++;
                    } else {
                        failed++;
                    }
                }
                return { succeeded, failed, results };
            }

            const data = await response.json();

            // Process results from batch response
            if (data.data?.results && Array.isArray(data.data.results)) {
                for (let i = 0; i < operations.length; i++) {
                    const op = operations[i];
                    const result = data.data.results[i];
                    if (result) {
                        results.set(op.id, { success: result.success, error: result.error });
                        if (result.success) {
                            succeeded++;
                        } else {
                            failed++;
                        }
                    }
                }
            }

            return { succeeded, failed, results };
        } catch (error) {
            console.error('[SyncWorker] Batch sync error:', error);
            // Fall back to individual operations
            for (const op of operations) {
                const result = await executeSyncOperation(op);
                results.set(op.id, result);
                if (result.success) {
                    succeeded++;
                } else {
                    failed++;
                }
            }
            return { succeeded, failed, results };
        }
    }

    /**
     * HIGH-013: Make actual API call to server for sync operation (fallback)
     */
    async function executeSyncOperation(
        op: SyncOperationRow
    ): Promise<{ success: boolean; error?: string }> {
        const endpoint = SYNC_ENDPOINTS[op.table_name];

        if (!endpoint) {
            console.warn(`[SyncWorker] No endpoint configured for table: ${op.table_name}`);
            return { success: false, error: `Unknown table: ${op.table_name}` };
        }

        const method =
            op.operation === 'INSERT' || op.operation === 'create'
                ? 'POST'
                : op.operation === 'UPDATE' || op.operation === 'update'
                  ? 'PATCH'
                  : 'DELETE';
        const url =
            method === 'DELETE' || method === 'PATCH' ? `${endpoint}/${op.record_id}` : endpoint;

        try {
            const response = await fetch(url, {
                method,
                headers: {
                    'Content-Type': 'application/json',
                    'x-sync-operation-id': String(op.id),
                    'x-idempotency-key': op.idempotency_key || String(op.id),
                },
                body: method !== 'DELETE' ? op.payload : undefined,
            });

            if (!response.ok) {
                const errorData = await response.json().catch(() => ({}));
                return {
                    success: false,
                    error: errorData.error?.message || errorData.error || `HTTP ${response.status}`,
                };
            }

            return { success: true };
        } catch (error) {
            return {
                success: false,
                error: error instanceof Error ? error.message : String(error),
            };
        }
    }

    /**
     * Process pending sync operations with retry logic
     * Uses batch sync for efficiency
     */
    async function processSyncOperations(): Promise<{
        processed: number;
        succeeded: number;
        failed: number;
    }> {
        const operations = await getPendingSyncOperations(cfg.batchSize);

        if (operations.length === 0) {
            return { processed: 0, succeeded: 0, failed: 0 };
        }

        console.log(`[SyncWorker] Processing ${operations.length} operations via batch sync`);

        // Use batch sync for efficiency
        const { succeeded, failed, results } = await executeBatchSync(operations);

        // Mark operations as completed or failed based on results
        for (const op of operations) {
            const result = results.get(op.id);
            if (result?.success) {
                await markSyncOperationCompleted(op.id);
            } else if (result) {
                const retryCount = op.attempts || 0;
                if (retryCount >= MAX_RETRIES) {
                    await markSyncOperationFailed(op.id, result.error || 'Max retries exceeded');
                    cfg.onError?.(new Error(result.error || 'Sync operation failed'));
                }
            }
        }

        return { processed: operations.length, succeeded, failed };
    }

    /**
     * Process pending sync operations individually (legacy method)
     * Used as fallback when batch sync fails
     */
    async function processSyncOperationsIndividually(): Promise<{
        processed: number;
        succeeded: number;
        failed: number;
    }> {
        const operations = await getPendingSyncOperations(cfg.batchSize);

        let processed = 0;
        let succeeded = 0;
        let failed = 0;

        for (const op of operations) {
            processed++;

            const retryCount = op.attempts || 0;

            try {
                console.log(
                    `[SyncWorker] Processing ${op.operation} on ${op.table_name}/${op.record_id} (attempt ${retryCount + 1})`
                );

                // HIGH-013: Execute actual API call
                const result = await executeSyncOperation(op);

                if (result.success) {
                    await markSyncOperationCompleted(op.id);
                    succeeded++;
                    console.log(`[SyncWorker] Successfully synced operation ${op.id}`);
                } else {
                    // Check if we should retry
                    if (retryCount < MAX_RETRIES) {
                        const delay = calculateBackoffDelay(retryCount);
                        console.warn(
                            `[SyncWorker] Operation ${op.id} failed, scheduling retry ${retryCount + 1}/${MAX_RETRIES} in ${delay}ms`
                        );

                        // Schedule retry with exponential backoff
                        setTimeout(async () => {
                            // The operation will be picked up in the next sync cycle
                            // with an incremented retry count
                        }, delay);

                        failed++;
                    } else {
                        console.error(
                            `[SyncWorker] Operation ${op.id} failed after ${MAX_RETRIES} retries: ${result.error}`
                        );
                        await markSyncOperationFailed(
                            op.id,
                            result.error || 'Max retries exceeded'
                        );
                        failed++;
                        cfg.onError?.(new Error(result.error || 'Sync operation failed'));
                    }
                }
            } catch (error) {
                console.error(`[SyncWorker] Unexpected error for operation ${op.id}:`, error);
                await markSyncOperationFailed(op.id, String(error));
                failed++;
                cfg.onError?.(new Error(String(error)));
            }
        }

        return { processed, succeeded, failed };
    }

    /**
     * Process pending print jobs
     */
    async function processPrinterQueue(): Promise<{
        processed: number;
        succeeded: number;
        failed: number;
    }> {
        // This would integrate with the actual printer system
        // For now, just return zeros as we can't print from server
        return { processed: 0, succeeded: 0, failed: 0 };
    }

    /**
     * Get current sync status
     */
    async function getStatus(): Promise<SyncProgress> {
        const queueStats = await getSyncQueueStatus();

        return {
            pendingOperations: queueStats.pending,
            completedOperations: queueStats.completed,
            failedOperations: queueStats.failed,
            printerJobsProcessed: 0,
            printerJobsSucceeded: 0,
            printerJobsFailed: 0,
            lastSyncAt,
            isOnline: typeof navigator !== 'undefined' ? navigator.onLine : true,
        };
    }

    /**
     * Run one sync cycle
     */
    async function syncOnce(): Promise<SyncProgress> {
        if (!navigator.onLine) {
            console.log('[SyncWorker] Offline - skipping sync');
            return getStatus();
        }

        console.log('[SyncWorker] Starting sync cycle');

        const syncResult = await processSyncOperations();

        let _printerResult = { processed: 0, succeeded: 0, failed: 0 };
        if (cfg.enablePrinterQueue) {
            _printerResult = await processPrinterQueue();
        }

        lastSyncAt = new Date().toISOString();

        const status = await getStatus();
        cfg.onSyncProgress?.(status);

        console.log(
            `[SyncWorker] Sync complete: ${syncResult.succeeded} succeeded, ${syncResult.failed} failed`
        );

        return status;
    }

    /**
     * Start the sync worker
     */
    function start() {
        if (isRunning) return;

        isRunning = true;
        intervalId = setInterval(syncOnce, cfg.syncIntervalMs);

        // Run immediately on start
        syncOnce();

        console.log('[SyncWorker] Started');
    }

    /**
     * Stop the sync worker
     */
    function stop() {
        if (!isRunning) return;

        if (intervalId) {
            clearInterval(intervalId);
            intervalId = null;
        }

        isRunning = false;
        console.log('[SyncWorker] Stopped');
    }

    return {
        start,
        stop,
        syncOnce,
        getStatus,
        get isRunning() {
            return isRunning;
        },
    };
}

/**
 * Singleton sync worker instance
 */
let syncWorker: ReturnType<typeof createSyncWorker> | null = null;

/**
 * Get the sync worker instance
 */
export function getSyncWorker() {
    if (!syncWorker) {
        syncWorker = createSyncWorker();
    }
    return syncWorker;
}

/**
 * Start the global sync worker
 */
export function startGlobalSync() {
    const worker = getSyncWorker();
    worker.start();
}

/**
 * Stop the global sync worker
 */
export function stopGlobalSync() {
    const worker = getSyncWorker();
    worker.stop();
}

/**
 * Trigger a manual sync
 */
export async function triggerSync(): Promise<SyncProgress> {
    const worker = getSyncWorker();
    return worker.syncOnce();
}

/**
 * Waitlist Service
 *
 * Service layer for table waitlist management.
 * Handles adding guests to waitlist, position management, notifications, and status updates.
 */

import { createServiceRoleClient } from '@/lib/supabase/service-role';
import { sendSmsWithRetry } from '@/lib/notifications/retry';
import { checkAndRecord, type NotificationType } from '@/lib/notifications/deduplication';
import { logger } from '@/lib/logger';
import type {
    AddWaitlistParams,
    WaitlistEntry,
    WaitlistStatus,
    NotifyResult,
    UpdateWaitlistStatusParams,
    WaitlistStats,
    TableWaitlistRow,
} from './types';
import { WAITLIST_MESSAGES, WAITLIST_CONFIG } from './types';
import { createHash } from 'crypto';

/**
 * Normalize a database row to WaitlistEntry
 */
function normalizeWaitlistEntry(row: TableWaitlistRow): WaitlistEntry {
    return {
        id: row.id,
        restaurant_id: row.restaurant_id,
        guest_name: row.guest_name ?? '',
        guest_phone: row.guest_phone,
        guest_count: row.guest_count,
        status: row.status,
        position: row.position,
        estimated_wait_minutes: row.estimated_wait_minutes,
        notified_at: row.notified_at,
        seated_at: row.seated_at,
        notes: row.notes,
        created_at: row.created_at,
        updated_at: row.updated_at,
    };
}

/**
 * Calculate the next position for a new waitlist entry
 */
// eslint-disable-next-line @typescript-eslint/no-explicit-any
async function getNextPosition(supabase: any, restaurantId: string): Promise<number> {
    const { data, error } = await supabase
        .from('table_waitlist')
        .select('position')
        .eq('restaurant_id', restaurantId)
        .eq('status', 'waiting')
        .order('position', { ascending: false })
        .limit(1)
        .maybeSingle();

    if (error) {
        logger.error('[waitlist] Error getting next position', error);
        throw new Error('Failed to calculate waitlist position');
    }

    return data ? data.position + 1 : 1;
}

/**
 * Estimate wait time based on position
 * Uses average table turnover time to estimate
 */
function estimateWaitTimeByPosition(position: number): number {
    if (position <= 0) return 0;

    // Base wait time: position * average wait per party
    // Adjust for typical party sizes
    const baseWait = position * WAITLIST_CONFIG.DEFAULT_WAIT_PER_PERSON;

    // Cap at reasonable maximum (2 hours)
    return Math.min(baseWait, 120);
}

/**
 * Update positions after a guest is seated or cancelled
 */
// eslint-disable-next-line @typescript-eslint/no-explicit-any
async function recalculatePositions(supabase: any, restaurantId: string): Promise<void> {
    // Get all waiting entries ordered by position
    const { data: entries, error } = await supabase
        .from('table_waitlist')
        .select('id')
        .eq('restaurant_id', restaurantId)
        .eq('status', 'waiting')
        .order('position', { ascending: true });

    if (error) {
        console.error('[waitlist] Error fetching entries for position recalculation:', error);
        return;
    }

    // Update positions sequentially
    for (let i = 0; i < (entries?.length ?? 0); i++) {
        const entry = entries![i];
        await supabase
            .from('table_waitlist')
            .update({ position: i + 1 })
            .eq('id', entry.id);
    }
}

/**
 * Generate idempotency key for waitlist notifications
 */
function generateIdempotencyKey(waitlistId: string, notificationType: string): string {
    return createHash('sha256')
        .update(`waitlist:${waitlistId}:${notificationType}:${Date.now()}`)
        .digest('hex')
        .slice(0, 32);
}

/**
 * Add a guest to the waitlist
 */
export async function addToWaitlist(params: AddWaitlistParams): Promise<WaitlistEntry> {
    const supabase = createServiceRoleClient();
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const db = supabase as any;

    const { restaurantId, guestName, guestPhone, guestCount, notes } = params;

    // Validate guest count
    if (
        guestCount < WAITLIST_CONFIG.MIN_GUEST_COUNT ||
        guestCount > WAITLIST_CONFIG.MAX_GUEST_COUNT
    ) {
        throw new Error(
            `Guest count must be between ${WAITLIST_CONFIG.MIN_GUEST_COUNT} and ${WAITLIST_CONFIG.MAX_GUEST_COUNT}`
        );
    }

    // Get next position
    const position = await getNextPosition(db, restaurantId);

    // Estimate wait time
    const estimatedWaitMinutes = estimateWaitTimeByPosition(position);

    // Insert waitlist entry
    const { data, error } = await db
        .from('table_waitlist')
        .insert({
            restaurant_id: restaurantId,
            guest_name: guestName,
            guest_phone: guestPhone,
            guest_count: guestCount,
            status: 'waiting',
            position,
            estimated_wait_minutes: estimatedWaitMinutes,
            notes: notes ?? null,
        })
        .select('*')
        .single();

    if (error || !data) {
        logger.error('[waitlist] Error adding to waitlist', error);
        throw new Error(error?.message ?? 'Failed to add to waitlist');
    }

    const entry = normalizeWaitlistEntry(data as TableWaitlistRow);

    // Send initial notification (non-blocking)
    sendWaitlistNotification(entry, 'added').catch(err => {
        logger.error('[waitlist] Failed to send initial notification', err);
    });

    return entry;
}

/**
 * Get waitlist entries for a restaurant
 */
export async function getWaitlist(
    restaurantId: string,
    status?: WaitlistStatus
): Promise<WaitlistEntry[]> {
    const supabase = createServiceRoleClient();
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const db = supabase as any;

    let query = db.from('table_waitlist').select('*').eq('restaurant_id', restaurantId);

    if (status) {
        query = query.eq('status', status);
    }

    const { data, error } = await query.order('position', { ascending: true });

    if (error) {
        logger.error('[waitlist] Error fetching waitlist', error);
        throw new Error('Failed to fetch waitlist');
    }

    return ((data ?? []) as TableWaitlistRow[]).map(normalizeWaitlistEntry);
}

/**
 * Get a single waitlist entry by ID
 */
export async function getWaitlistEntry(waitlistId: string): Promise<WaitlistEntry | null> {
    const supabase = createServiceRoleClient();
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const db = supabase as any;

    const { data, error } = await db
        .from('table_waitlist')
        .select('*')
        .eq('id', waitlistId)
        .maybeSingle();

    if (error) {
        logger.error('[waitlist] Error fetching waitlist entry', error);
        throw new Error('Failed to fetch waitlist entry');
    }

    if (!data) {
        return null;
    }

    return normalizeWaitlistEntry(data as TableWaitlistRow);
}

/**
 * Get waitlist statistics for a restaurant
 */
export async function getWaitlistStats(restaurantId: string): Promise<WaitlistStats> {
    const supabase = createServiceRoleClient();
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const db = supabase as any;

    // Get count of waiting guests
    const { data: countData, error: countError } = await db
        .from('table_waitlist')
        .select('position, estimated_wait_minutes')
        .eq('restaurant_id', restaurantId)
        .eq('status', 'waiting')
        .order('position', { ascending: false });

    if (countError) {
        logger.error('[waitlist] Error fetching waitlist stats', countError);
        throw new Error('Failed to fetch waitlist statistics');
    }

    const waitingEntries = countData ?? [];
    const waitingCount = waitingEntries.length;

    // Calculate average wait time
    let averageWaitMinutes = 0;
    if (waitingCount > 0) {
        let totalWait = 0;
        for (const entry of waitingEntries) {
            totalWait += entry.estimated_wait_minutes ?? 0;
        }
        averageWaitMinutes = Math.round(totalWait / waitingCount);
    }

    // Estimate turnover rate (tables per hour)
    const turnoverRatePerHour = Math.round(60 / WAITLIST_CONFIG.TABLE_TURNOVER_MINUTES);

    return {
        waitingCount,
        averageWaitMinutes,
        turnoverRatePerHour,
    };
}

/**
 * Notify a guest that their table is ready
 */
export async function notifyGuest(waitlistId: string): Promise<NotifyResult> {
    const supabase = createServiceRoleClient();
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const db = supabase as any;

    // Get the waitlist entry
    const entry = await getWaitlistEntry(waitlistId);
    if (!entry) {
        return {
            success: false,
            waitlistId,
            phone: '',
            message: '',
            error: 'Waitlist entry not found',
        };
    }

    if (entry.status !== 'waiting') {
        return {
            success: false,
            waitlistId,
            phone: entry.guest_phone,
            message: '',
            error: `Cannot notify guest with status: ${entry.status}`,
        };
    }

    // Check for duplicate notification using deduplication
    const notificationType: NotificationType = 'waitlist';
    const dedupeResult = await checkAndRecord({
        guestPhone: entry.guest_phone,
        notificationType,
        relevantId: waitlistId,
    });

    if (dedupeResult.isDuplicate) {
        console.log('[waitlist] Duplicate notification detected, skipping:', waitlistId);
        // Still update the status to notified even if it's a duplicate
        await updateStatusInternal(db, waitlistId, 'notified');

        return {
            success: true,
            waitlistId,
            phone: entry.guest_phone,
            message: 'Notification already sent (duplicate)',
        };
    }

    // Send the notification
    const message = interpolateMessage(WAITLIST_MESSAGES.tableReady.en, {
        position: entry.position,
        minutes: entry.estimated_wait_minutes ?? 0,
    });
    const messageAm = interpolateMessage(WAITLIST_MESSAGES.tableReady.am, {
        position: entry.position,
        minutes: entry.estimated_wait_minutes ?? 0,
    });

    const fullMessage = `${message}\n${messageAm}`;
    const idempotencyKey = generateIdempotencyKey(waitlistId, 'table_ready');

    try {
        const result = await sendSmsWithRetry({
            to: entry.guest_phone,
            message: fullMessage,
            restaurantId: entry.restaurant_id,
            idempotencyKey,
            metadata: {
                waitlistId,
                type: 'table_ready',
            },
        });

        // Update status to notified
        await updateStatusInternal(db, waitlistId, 'notified');

        return {
            success: result.success,
            waitlistId,
            phone: entry.guest_phone,
            message,
            error: result.error,
            providerResponse: result.providerResponse,
        };
    } catch (error) {
        logger.error('[waitlist] Error sending notification', error);
        return {
            success: false,
            waitlistId,
            phone: entry.guest_phone,
            message,
            error: error instanceof Error ? error.message : 'Unknown error',
        };
    }
}

/**
 * Internal function to update waitlist status
 */
// eslint-disable-next-line @typescript-eslint/no-explicit-any
async function updateStatusInternal(
    supabase: any,
    waitlistId: string,
    status: WaitlistStatus
): Promise<void> {
    const updateData: Record<string, unknown> = {
        status,
        updated_at: new Date().toISOString(),
    };

    if (status === 'notified') {
        updateData.notified_at = new Date().toISOString();
    } else if (status === 'seated') {
        updateData.seated_at = new Date().toISOString();
    }

    const { error } = await supabase.from('table_waitlist').update(updateData).eq('id', waitlistId);

    if (error) {
        logger.error('[waitlist] Error updating status', error);
        throw new Error('Failed to update waitlist status');
    }
}

/**
 * Update waitlist entry status
 */
export async function updateStatus(params: UpdateWaitlistStatusParams): Promise<void> {
    const supabase = createServiceRoleClient();
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const db = supabase as any;

    const { waitlistId, status } = params;

    // Get the entry to check current status
    const entry = await getWaitlistEntry(waitlistId);
    if (!entry) {
        throw new Error('Waitlist entry not found');
    }

    // Update status
    await updateStatusInternal(db, waitlistId, status);

    // Recalculate positions if seated or cancelled
    if (status === 'seated' || status === 'cancelled') {
        await recalculatePositions(db, entry.restaurant_id);
    }

    // Send notification for seated status
    if (status === 'seated') {
        sendSeatedNotification(entry).catch(err => {
            logger.error('[waitlist] Failed to send seated notification', err);
        });
    }
}

/**
 * Send notification when guest is seated
 */
async function sendSeatedNotification(entry: WaitlistEntry): Promise<void> {
    const idempotencyKey = generateIdempotencyKey(entry.id, 'seated');

    const message = WAITLIST_MESSAGES.seated.en;
    const messageAm = WAITLIST_MESSAGES.seated.am;
    const fullMessage = `${message}\n${messageAm}`;

    await sendSmsWithRetry({
        to: entry.guest_phone,
        message: fullMessage,
        restaurantId: entry.restaurant_id,
        idempotencyKey,
        metadata: {
            waitlistId: entry.id,
            type: 'seated',
        },
    });
}

/**
 * Send waitlist notification (internal)
 */
async function sendWaitlistNotification(
    entry: WaitlistEntry,
    type: 'added' | 'table_ready'
): Promise<void> {
    const idempotencyKey = generateIdempotencyKey(entry.id, type);

    const template =
        type === 'added' ? WAITLIST_MESSAGES.addedToQueue : WAITLIST_MESSAGES.tableReady;

    const message = interpolateMessage(template.en, {
        position: entry.position,
        minutes: entry.estimated_wait_minutes ?? 0,
    });
    const messageAm = interpolateMessage(template.am, {
        position: entry.position,
        minutes: entry.estimated_wait_minutes ?? 0,
    });
    const fullMessage = `${message}\n${messageAm}`;

    try {
        await sendSmsWithRetry({
            to: entry.guest_phone,
            message: fullMessage,
            restaurantId: entry.restaurant_id,
            idempotencyKey,
            metadata: {
                waitlistId: entry.id,
                type,
            },
        });
    } catch (error) {
        logger.error('[waitlist] Failed to send notification', error);
    }
}

/**
 * Interpolate message with variables
 */
function interpolateMessage(template: string, vars: { position: number; minutes: number }): string {
    return template
        .replace('{{position}}', String(vars.position))
        .replace('{{minutes}}', String(vars.minutes));
}

/**
 * Remove a guest from the waitlist
 */
export async function removeFromWaitlist(waitlistId: string): Promise<void> {
    const supabase = createServiceRoleClient();
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const db = supabase as any;

    // Get the entry first
    const entry = await getWaitlistEntry(waitlistId);
    if (!entry) {
        throw new Error('Waitlist entry not found');
    }

    // Delete the entry
    const { error } = await db.from('table_waitlist').delete().eq('id', waitlistId);

    if (error) {
        logger.error('[waitlist] Error removing from waitlist', error);
        throw new Error('Failed to remove from waitlist');
    }

    // Recalculate positions
    await recalculatePositions(db, entry.restaurant_id);

    // Send cancellation notification if the entry was waiting
    if (entry.status === 'waiting') {
        sendCancellationNotification(entry).catch(err => {
            logger.error('[waitlist] Failed to send cancellation notification', err);
        });
    }
}

/**
 * Send cancellation notification
 */
async function sendCancellationNotification(entry: WaitlistEntry): Promise<void> {
    const idempotencyKey = generateIdempotencyKey(entry.id, 'cancelled');

    const message = WAITLIST_MESSAGES.cancelled.en;
    const messageAm = WAITLIST_MESSAGES.cancelled.am;
    const fullMessage = `${message}\n${messageAm}`;

    try {
        await sendSmsWithRetry({
            to: entry.guest_phone,
            message: fullMessage,
            restaurantId: entry.restaurant_id,
            idempotencyKey,
            metadata: {
                waitlistId: entry.id,
                type: 'cancelled',
            },
        });
    } catch (error) {
        logger.error('[waitlist] Failed to send cancellation notification', error);
    }
}

/**
 * Get current position in line
 */
export async function getPosition(waitlistId: string): Promise<number> {
    const entry = await getWaitlistEntry(waitlistId);
    if (!entry) {
        throw new Error('Waitlist entry not found');
    }
    return entry.position;
}

/**
 * Estimate wait time in minutes based on position
 */
export async function estimateWaitTime(position: number): Promise<number> {
    return estimateWaitTimeByPosition(position);
}

